	/**
	 * Checks the Au member (AP) is open.
	 * 
	 * @param obj
	 *            is an Object.
	 * @return the boolean value.
	 */
	public static boolean hasOpenAp(Object obj) {
		if (obj instanceof BaseAUMember) {
			BaseAUMember aumemb = (BaseAUMember) obj;
			if (aumemb.getAuMemberStatusCode().isNotEmpty()
			                && (aumemb.getAuMemberStatusCode().toString().equals(PENDING)
			                                || aumemb.getAuMemberStatusCode().toString().equals(ACTIVE) || aumemb
			                                .getAuMemberStatusCode().toString().equals(INELIGIBLE))) {
				return true;
			}
		}
		if (obj instanceof BaseClientAUMember) {
			BaseClientAUMember aumemb = (BaseClientAUMember) obj;
			if (aumemb.getAuMemberStatusCode().isNotEmpty()
			                && (aumemb.getAuMemberStatusCode().toString().equals(PENDING)
			                                || aumemb.getAuMemberStatusCode().toString().equals(ACTIVE) || aumemb
			                                .getAuMemberStatusCode().toString().equals(INELIGIBLE))) {
				return true;
			}
		}
		if (obj instanceof EDBCResultAUMember) {
			EDBCResultAUMember aumemb = (EDBCResultAUMember) obj;
			if (aumemb.getMemStatus().isNotEmpty()
			                && (aumemb.getMemStatus().toString().equals(PENDING)
			                                || aumemb.getMemStatus().toString().equals(ACTIVE) || aumemb.getMemStatus()
			                                .toString().equals(INELIGIBLE))) {
				return true;
			}
		}
		return false;
	}

	/**
	 * This method is used to form the vector for rules calculations.
	 * 
	 * @param auIds
	 *            is an Vector
	 * @param wfdata
	 *            is an instance of MAClient.
	 * @param whRule
	 *            a MAECFHousehold object
	 * @return the Vector of AUs.
	 * @throws Exception
	 */
	public static Vector getPreCalculatedAU(Vector auIds, MAClient wfdata, MAECFHousehold maECFRule,
	                                        IntegerData requestIdValue) throws Exception {
		Vector preOrder = new Vector();
		Enumeration ausEnum = auIds.elements();
		while (ausEnum.hasMoreElements()) {
			IntegerData auId = (IntegerData) ausEnum.nextElement();
			BaseAU auObj = wfdata.getAsstUnit(auId);
			preOrder.add(auObj);
		}
		preOrder = ruleSortedAus(preOrder, PGM_ORDER, maECFRule, wfdata, requestIdValue);
		return preOrder;
	}

	/**
	 * This method is used to sort the AUs for rules calculation.
	 * 
	 * @param preOrder
	 *            is an Vector contains the AUs Object.
	 * @param pgmOrder
	 *            is String array, it give the rule to ordering the AUs.
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param wfData
	 *            a MAClient object
	 * @return collection
	 * @throws Exception
	 *             ...
	 */
	public static Vector ruleSortedAus(Vector preOrder, String[] pgmOrder, MAECFHousehold maECFRule, MAClient wfData,
	                                   IntegerData requestIdValue) throws Exception {
		Vector returnVector = new Vector();
		if (preOrder.size() > 0) {
			for (int iCnt = 0; pgmOrder.length > iCnt; iCnt++) {
				String pgm = pgmOrder[iCnt];
				Enumeration ausEnum = preOrder.elements();
				while (ausEnum.hasMoreElements()) {
					BaseAU auObj = (BaseAU) ausEnum.nextElement();
					BaseAU tempObj = (BaseAU) auObj.clone(true);
					setFSCAP(tempObj, maECFRule, wfData, requestIdValue);
					if (tempObj.getProgramCode().toString().equals(pgm) && !returnVector.contains(auObj)) {
						returnVector.add(auObj);
					}
				}
			}
		}
		return returnVector;
	}

	/**
	 * This method specifies FSCAP values.
	 * 
	 * @param auObj
	 *            object of BaseAU
	 * @param maEcf
	 *            object of MAECFHousehold
	 * @param wfData
	 *            object of wfData
	 * @throws Exception
	 */
	public static void setFSCAP(BaseAU auObj, MAECFHousehold maEcf, MAClient wfData, IntegerData requestIdValue)
	                throws Exception {
		if ((auObj.getStatusCode().toString().equals(PENDING) || auObj.getStatusCode().toString().equals(ACTIVE))
		                && isVerificationSelected(maEcf, wfData, auObj.getId(), SDX_CAP_VER_ID, false, true)) {
			auObj.setProgramCode(CAP_FS);
		}
		else if (requestIdValue.isNotEmpty()
		                && (getPrevReleasedXMLValue(maEcf, auObj.getId(), requestIdValue, STANDARDAMOUNTS, CAPIND) != null)
		                && (getPrevReleasedXMLValue(maEcf, auObj.getId(), requestIdValue, STANDARDAMOUNTS, CAPIND) != "")) {
			auObj.setProgramCode(CAP_FS);
		}
	}

	/**
	 * This method is used to check whether a verification for  Batch SSI/RSDI (unearned) income is selected.
	 * 
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if verification is selected 
	 * @throws Exception
	 */
	public static boolean hasARExclusionBatchUI(MAECFHousehold maECFHouseholdDelta,
	                                                            MAClient maClientDelta, IntegerData auId)
	                throws Exception {
		boolean returnFlg = false;
		Vector clientAumemb = maClientDelta.getAllMembersInAU(auId);
		String[] batchs = AREXCLUSIONBATCHS;
		RequestId requestId = maECFHouseholdDelta.getRequestId();
		ClientUI clientUI = null;
		Vector eligibilityRequestVerDataVector = maECFHouseholdDelta.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration clientEnum = clientAumemb.elements();
		while (clientEnum.hasMoreElements()) {
			BaseAUMember auIdMemb = (BaseAUMember) clientEnum.nextElement();
			if (isClientOpenMember(maECFHouseholdDelta, auIdMemb)) {	
				Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
				while (eligibilityRequestVerDataEnum.hasMoreElements()) {
					EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
					                .nextElement();
					com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maECFHouseholdDelta
					                .getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
					                                eligibilityRequestVerData.getVerId());
					if (viewVerification != null && (viewVerification.getVerificationElementId() == MAConstants.VDE_Other_Income_42
							|| viewVerification.getVerificationElementId() == VDE_Other_Income_RENTAL_INC_328
							|| viewVerification.getVerificationElementId() == VDE_Other_Income_ROOMER_BOARDER_INC_329)
									&& auIdMemb.getClientId().intValue() == viewVerification.getClientId().intValue()) {				
						Vector<ClientUI> otherIncomeVect = null;
						otherIncomeVect = maClientDelta.getClientUI(auIdMemb.getClientId());
						if (otherIncomeVect.size() > 0) {
							Enumeration otherIncomeEnum = otherIncomeVect.elements();
							while (otherIncomeEnum.hasMoreElements()) {
								clientUI = (ClientUI) otherIncomeEnum.nextElement();	
								if (clientUI.getVerificationId().equals(viewVerification.getId()) 
									&& clientUI.getOtherIncType().isNotEmpty()) {
										for (int i = 0; i < batchs.length; i++) {
											if (clientUI.getLastUpdateUserid().equalsIgnoreCase(batchs[i])) {
												returnFlg = true;
												break;
											}
										}
								}	
								if (returnFlg) {
									break;
								}				
							}
						}
					}
					if (returnFlg) {
						break;
					}
				}
			}
			if (returnFlg) {
				break;
			}
		}
		return returnFlg;
	}

	/**
	 * This method checks for Au members who are being removed from an AR SNAP AU. If any meet the conditions, the AR
	 * SNAP benefit should be allowed to decrease.
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if removal EFRC exists
	 * @throws Exception
	 */
	public static boolean hasARExclusionEFRC(MAECFHousehold maEcf, MAClient wfData, IntegerData auId  ) throws Exception {
		
		boolean verSelectFlg = false;
		RequestId requestId = maEcf.getRequestId();
		Vector clientAumemb = wfData.getAllMembersInAU(auId);
		BaseAU baseAU = wfData.getAsstUnit(auId);
		String[] efrcs = AREXCLUSIONEFRCS;
		ClientAuMembIneligFactor clientAUMembInEligFactor = null;
		Vector eligibilityRequestVerDataVector = maEcf.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
		if ((baseAU.getStatusCode().equals(PENDING) || baseAU.getStatusCode().equals(ACTIVE)) && clientAumemb.size() > 0) {
			while (eligibilityRequestVerDataEnum.hasMoreElements()) {
				EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
				                .nextElement();
				com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maEcf
				                .getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
				                                eligibilityRequestVerData.getVerId());
				if (viewVerification != null && viewVerification.getVerificationElementId() == VER_DATA_ID_78
								&& auId.intValue() == viewVerification.getAuId().intValue()) {	
					Enumeration clientEnum = clientAumemb.elements();
					while (clientEnum.hasMoreElements()) {
						BaseAUMember auIdMemb = (BaseAUMember) clientEnum.nextElement();
						if (viewVerification.getClientId().equals(auIdMemb.getClientId()) && isClientOpenMember(maEcf, auIdMemb)) {				
							Vector eligFactor = wfData.getClientAUMembInEligFactor(auIdMemb.getClientId());	
							if (eligFactor.size() > 0) {
								Enumeration eligEnum = eligFactor.elements();
								while (eligEnum.hasMoreElements()) {
									clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
									if (clientAUMembInEligFactor != null && clientAUMembInEligFactor.getAuId().equals(viewVerification.getAuId())) {						
										for (int i = 0; i < efrcs.length; i++) {
											if (clientAUMembInEligFactor.getEligFactorReason().stringValue().equalsIgnoreCase(efrcs[i])) {
												return true;
											}
										}
									}
								}
							}
						}
					}
				}
			}
		}
		return false;
	}
	/**
	 * This method checks for Au members who are being removed from an AR SNAP AU. If any meet the conditions, the AR
	 * SNAP benefit should be allowed to decrease.
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if removal EFRC exists
	 * @throws Exception
	 */
	public static boolean hasARExclusionMatchEFRC(MAECFHousehold maEcf, MAClient wfData, IntegerData auId  ) throws Exception {
		
		boolean verSelectFlg = false;
		ParameterCache parameterCache = ParameterCache.getInstance();
		Parameter matchCloseBatchsParam = parameterCache.getParameter(wfData.getFields().getContext(), "MATCH CLOSE BATCHES");
		Vector<ParameterMatrixValue> matchCloseBatchsVect = matchCloseBatchsParam.getMatrixValues();
		RequestId requestId = maEcf.getRequestId();
		Vector clientAumemb = wfData.getAllMembersInAU(auId);
		BaseAU baseAU = wfData.getAsstUnit(auId);
		Vector eligibilityRequestVerDataVector = maEcf.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
		if ((baseAU.getStatusCode().equals(PENDING) || baseAU.getStatusCode().equals(ACTIVE)) && clientAumemb.size() > 0) {
			while (eligibilityRequestVerDataEnum.hasMoreElements()) {
				EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
				                .nextElement();
				com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maEcf
				                .getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
				                                eligibilityRequestVerData.getVerId());
				if (viewVerification != null && viewVerification.getVerificationElementId() == VER_DATA_ID_78
								&& auId.intValue() == viewVerification.getAuId().intValue()) {	
					Enumeration clientEnum = clientAumemb.elements();
					while (clientEnum.hasMoreElements()) {
						BaseAUMember auIdMemb = (BaseAUMember) clientEnum.nextElement();
						if (viewVerification.getClientId().equals(auIdMemb.getClientId()) && isClientOpenMember(maEcf, auIdMemb)) {				
							for (ParameterMatrixValue paramMatrixValues : matchCloseBatchsVect){
								if (paramMatrixValues.getValueStart() != null &&
										paramMatrixValues.getValueStart() != "") {
									if (viewVerification.getLastUpdateUserid().equalsIgnoreCase(paramMatrixValues.getConstraintStart().toString())) {
										return true;
									}
								}
							}
						}
					}
				}
			}
		}
		return false;
	}
	/**
	 * This method check the AUs Exclusion based on differnt conditions. If an AU meets any one of these conditions, it
	 * should be excluded from a calculation
	 * @param effCtx
	 * @param auObj
	 * @param wfData
	 * @param maECFRule
	 * @param recalc
	 * @return
	 * @throws Exception
	 */
	public static boolean hasAUExclusion(Context effCtx, BaseAU auObj, MAClient wfData, MAECFHousehold maECFRule, MAECFHousehold maEcf,
	                                     boolean recalc) throws Exception {
		EBCResultBase ebcResultBase = null;
		Vector eligReqVec = null;
		Enumeration eligReqEnum;
		Vector eligReqAuthVec = null;
		AuInEligFactor auInelig = null;
		EligFactorRsnDtl elifactDtl = null;
		String tbaFlg = "";
		double tbaAmt = 0;
		boolean tbaExcepFlg = false;
		String tbaReleaseDte = null;
		Vector clientAumemb = wfData.getAllMembersInAU(auObj.getId());
		if (auObj.getProgramCode().toString().equals(SNAP)) {
			ebcResultBase = maECFRule.getEBCResultBase(auObj.getId());
		}
		Boolean tbaPossibleFlg = false;
		//  AU has a Closure EFRC (see appendix entry above)
		if (hasAuClosureEFRC(effCtx, wfData, auObj.getId())) {
				return true;
		}
		//  any open SNAP AP has an active Sanction (status is Pending or Sanctioned and sanction status end date is
		// null), sanction level is 3 and the sanction reason is SNAP-FSET Requirements (FSETRQ) or
		// Voluntarily quit a job (VOLQUI)
		if (auObj.getProgramCode().equals(SNAP)
		    && (auObj.getStatusCode().equals(PENDING) || auObj.getStatusCode().equals(ACTIVE)) && clientAumemb.size() > 0) {
			// check the Active sanction
			// clientAumemb = wfData.getAllMembersInAU(auObj.getId());
			Enumeration clientEnum = clientAumemb.elements();
			while (clientEnum.hasMoreElements()) {
				BaseAUMember auIdMemb = (BaseAUMember) clientEnum.nextElement();
				if (isClientOpenMember(maEcf, auIdMemb)) {
					Vector sanctionVect = wfData.getSanction(auIdMemb.getClientId());
					Enumeration sanctionEnum = sanctionVect.elements();
					while (sanctionEnum.hasMoreElements()) {
						boolean activeSanction = false;
						Sanction sanctionObj = (Sanction) sanctionEnum.nextElement();
						SanctionDetails sanctionDetails = wfData.getSanctionDetails(sanctionObj.getSanctionId());
						if (sanctionDetails != null
						    && sanctionDetails.getStatus().isNotEmpty()
						    && (sanctionDetails.getStatus().toString().equals(SANCTION_PENDING) || sanctionDetails.getStatus()
						        .toString().equals(SANCTION_SANCTIONED)) && sanctionDetails.getSanctionLvlEndDate().isEmpty()) {
							activeSanction = true;
						}
						if (sanctionObj.getEligFactorSanctionId().isNotEmpty()) {
							EligFactorSanction eligFactorSanc = (EligFactorSanction) mapper.fetch(effCtx, EligFactorSanction.class,
							    sanctionObj.getEligFactorSanctionId().intValue());
							if (activeSanction
							    && (eligFactorSanc != null && eligFactorSanc.getLevel().equals(SANCTION_LEVEL_3))
							    && (eligFactorSanc.getReason().equals(SANCT_REASON_FSET) || eligFactorSanc.getReason().toString()
							        .equals(SANCT_REASON_VOL))) {
								return true;
							}
						}
					}
					// Grantee of a SNAP AU has a closure EFRC of Institutionalized, including incarceration (001004,
					// 001025, 002003)
					if (auIdMemb.getAuRoleCode().equals(GRANTEE)) {
						/*
						 * PMD violation fixed for CollapsibleIfStatements for version 1.2
						 */
						Vector eligFactor = wfData.getClientAUMembInEligFactor(auIdMemb.getClientId());
						if (eligFactor.size() > 0) {
							Enumeration eligEnum = eligFactor.elements();
							while (eligEnum.hasMoreElements()) {
								ClientAuMembIneligFactor clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
								if ((auObj.getProgramCode().toString().equals(SNAP) && auObj.getId().intValue() == clientAUMembInEligFactor
								    .getAuId().intValue())
								    && (clientAUMembInEligFactor != null && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty()
								        && clientAUMembInEligFactor.getEligFactorReason().toString().equals(EFRC_INSTIT_INCLU_01)
								        || clientAUMembInEligFactor.getEligFactorReason().toString().equals(EFRC_INSTIT_INCLU_02) || clientAUMembInEligFactor
								        .getEligFactorReason().toString().equals(EFRC_INSTIT_INCLU_03))) {
									return true;
								}
							}
						}
					}
				}
			}
		}
		// Grantee has a closure EFRC of Death (001011)
		if (clientAumemb.size() > 0) {
			Enumeration clientEnum = clientAumemb.elements();
			while (clientEnum.hasMoreElements()) {
				BaseAUMember auIdMemb = (BaseAUMember) clientEnum.nextElement();
				if (auIdMemb.getAuRoleCode().equals(GRANTEE)) {
					Vector eligFactor = wfData.getClientAUMembInEligFactor(auIdMemb.getClientId());
					if (eligFactor.size() > 0) {
						Enumeration eligEnum = eligFactor.elements();
						while (eligEnum.hasMoreElements()) {
							ClientAuMembIneligFactor clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
							if (auObj.getId().equals(clientAUMembInEligFactor.getAuId())
							    && (clientAUMembInEligFactor != null && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty())
							    && clientAUMembInEligFactor.getEligFactorReason().toString().equals(REASON_DEATH)) {
								return true;
							}
						}
					}
				}
			}
		}
		// Eligibility rules are being run from EBC Recalc Batch, AU is SNAP, released result.EXPEDITED_CD_CODE_K = S
		// and none of the requests to be processed for the Eligibility Group contain the AU and have been created or
		// authorized by a worker.
		if (recalc) {
			if (auObj.getProgramCode().equals(SNAP)) {
				if (ebcResultBase != null) {
					ebcResultBase = maECFRule.getEBCResultBase(auObj.getId());
					if (ebcResultBase != null && ebcResultBase.getAuStatus().equals(ACTIVE)
					    && ebcResultBase.getExpeditedCode().equals(SPECIAL_30_DAY_CODE)) {
						eligReqVec = maECFRule.getPndgRlseRequestsForRecal(effCtx, wfData.getId());
						if (eligReqVec != null && eligReqVec.size() > 0) {
							eligReqEnum = eligReqVec.elements();
							boolean hasUserRequest = false;
							while (eligReqEnum.hasMoreElements() && !hasUserRequest) {
								BaseEligReqClient eligibilityRequest = (BaseEligReqClient) eligReqEnum.nextElement();
								if (eligibilityRequest.getRequestId().isNotEmpty() && maECFRule.getRequestId().getReqId().isNotEmpty()) {
									eligReqAuthVec = maECFRule.getFields().getFields(EligibilityRequestAuth.class,
									    eligibilityRequest.getRequestId());
									if ((eligibilityRequest.getUserId().intValue() != 0 || (eligReqAuthVec != null && eligReqAuthVec
									    .size() > 0))
									    && isAUInEbcResults(maEcf, eligibilityRequest.getRequestId(), auObj.getId())) {
										hasUserRequest = true;
									}
								}
							}
							if (!hasUserRequest && !isDayTwoVerificationSelected(maEcf, auObj.getId())) {
								return true;
							}
						}
					}
				}
			}
		}
		if (auObj.getProgramCode().equals(TANF)) {
			boolean hasActiveGranteeOrOP = false;
			Enumeration clientEnum = clientAumemb.elements();
			while (clientEnum.hasMoreElements()) {
				BaseAUMember baseAUMember = (BaseAUMember) clientEnum.nextElement();
				if (isClientOpenMember(maEcf, baseAUMember)) {
					if (baseAUMember.getAuRoleCode().equals(GRANTEE)) {
						MAClientPregnancy clientPregnancy = wfData.getClientPregnancy(baseAUMember.getClientId());
						if (clientPregnancy != null && clientPregnancy.getPregnancyFlag().isTrue()) {
							return false;
						}
					}
					if (baseAUMember.getAuRoleCode().equals(GRANTEE) || baseAUMember.getAuRoleCode().equals(OTHER_PARENT)) {
						if (!(hasAUmembIneligCondition(effCtx, auObj, baseAUMember, wfData, auObj.getProgramCode(), maEcf) 
								|| hasAUmembClosure(effCtx, baseAUMember, wfData, auObj.getProgramCode(),maEcf))) {
							hasActiveGranteeOrOP = true;
						}
					}
				}
			}
			if (!hasActiveGranteeOrOP){
				// No need to exclude this AU from calc when both grantee and OP will be denied/closed/inelig since AU size will be zero if there are no dependents
				return false;
			}
			clientEnum = clientAumemb.elements();
			while (clientEnum.hasMoreElements()) {
				BaseAUMember baseAUMember = (BaseAUMember) clientEnum.nextElement();
				if (isClientOpenMember(maEcf, baseAUMember)) {
					if (!(baseAUMember.getAuRoleCode().equals(GRANTEE) || baseAUMember.getAuRoleCode().equals(OTHER_PARENT))) {
						if (!(hasAUmembIneligCondition(effCtx, auObj, baseAUMember, wfData, auObj.getProgramCode(), maEcf) 
								|| hasAUmembClosure(effCtx, baseAUMember, wfData, auObj.getProgramCode(),maEcf))) {
							return false;
						} else if (!hasAUmembClosure(effCtx, baseAUMember, wfData, auObj.getProgramCode(),maEcf)) {
							if (hasDependentChildEFRC(effCtx, baseAUMember, wfData, auObj.getProgramCode(),maEcf)
									|| hasDependentChildResp(effCtx, baseAUMember, maECFRule)) {
								return false;
							}
						}
					}
				}
			}
			return true;
		}
		return false;
	}
	/**
	 * @param household
	 * @param requestId
	 * @param auId
	 * @return
	 * @throws Exception
	 */
	public static boolean isAUInEbcResults(MAECFHousehold household, IntegerData requestId, IntegerData auId) throws Exception {
		Vector<BaseEBCResultRequest> rsltVec = household.getEBCResultRequest(requestId);
		for (BaseEBCResultRequest rslt : rsltVec) {
			if(rslt.getAuId().equals(auId)){
				return true;
			}
		}
		return false;
	}
	
	/**
	 * @param effCtx
	 * @param baseAUMember
	 * @param wfData
	 * @param pgmCode
	 * @return
	 * @throws Exception
	 */
	public static boolean hasDependentChildEFRC(Context effCtx, BaseAUMember baseAUMember, MAClient wfData, StringData pgmCode,MAECFHousehold maEcf )
	    throws Exception {
		Vector eligFactor = wfData.getClientAUMembInEligFactor(baseAUMember.getClientId());
		if (eligFactor.size() > 0) {
			Enumeration eligEnum = eligFactor.elements();
			while (eligEnum.hasMoreElements()) {
				ClientAuMembIneligFactor clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
				if (baseAUMember.getAuId().equals(clientAUMembInEligFactor.getAuId()) && clientAUMembInEligFactor != null
				    && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty()) {
					EligFactorRsnDtl elifactDtl = getEligFactorRsnDtl(effCtx, clientAUMembInEligFactor.getEligFactorReason());
					if (elifactDtl != null && elifactDtl.getNotEligibleFlag().isTrue()) {
						if (elifactDtl.getReason().equals(EFRC_ELIG_SSI)
						    || elifactDtl.getReason().equals(EF_INELIGIBLE_NON_CITIZEN)
						    || elifactDtl.getReason().equals(EFRC_FOSTER_CHILD) 
						    || elifactDtl.getReason().equals(EFRC_ADOP_CHILD)
						    || elifactDtl.getReason().equals(EFRC_FAMILY_CAP)
						    || elifactDtl.getReason().equals(EFRC_LEARNFARE)
						    ) {
							return true;
						}
						if (hasAssociatedSanction(effCtx, clientAUMembInEligFactor.getEligFactorReason(), pgmCode,maEcf,wfData)) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}
	
	/**
	 * @param effCtx
	 * @param baseAUMember
	 * @param maEcf
	 * @param pgmCode
	 * @return
	 * @throws Exception
	 */
	public static boolean hasDependentChildResp(Context effCtx, BaseAUMember baseAUMember, MAECFHousehold maEcf)
	    throws Exception {
		Vector<ClientAUMembResp> respVector = maEcf.getFields().getFields(ClientAUMembResp.class, baseAUMember.getClientId());
		for (ClientAUMembResp membResp : respVector) {
			if (baseAUMember.getAuId().equals(membResp.getAuId())) {
				if (depChildResp.contains(membResp.getMemResp())) {
					return true;
				}
			}
		}
		return false;
	}
	
	/**
	 * check if selected if its pending member
	 * @param maECF
	 * @param requestId
	 * @param baseAUMember
	 * @param baseAU
	 * @return
	 * @throws Exception
	 */
	public static boolean isClientOpenMember(MAECFHousehold maECF, BaseAUMember baseAUMember) throws Exception {
		BaseAUStatus baseAUStatus = maECF.getAssistUnitStatus(baseAUMember.getAuId());
		if (baseAUStatus != null && (baseAUStatus.getStatus().equals(ACTIVE))) {
			if ((baseAUMember.getAuMemberStatusCode().equals(PENDING) && isSelectedInPendClient(baseAUMember, maECF))
			    || baseAUMember.getAuMemberStatusCode().equals(ACTIVE)
			    || baseAUMember.getAuMemberStatusCode().equals(INELIGIBLE)) {
				return true;
			}
		}
		else {
			if (baseAUMember.getAuMemberStatusCode().equals(PENDING) || baseAUMember.getAuMemberStatusCode().equals(ACTIVE)
			    || baseAUMember.getAuMemberStatusCode().equals(INELIGIBLE)|| baseAUMember.getAuMemberStatusCode().equals(DENIED)) {
				return true;
			}
		}
		return false;
	}


	/**
	 * Check the AU members closuer conditions. if the member has the closure, member will be excluded from the rule
	 * execution.
	 * 
	 * @param effCtx
	 * @param auIdMemb
	 * @param wfData
	 * @param pgmCode
	 * @return
	 * @throws Exception
	 */
	public static boolean hasAUmembClosure(Context effCtx, BaseAUMember auIdMemb, MAClient wfData, StringData pgmCode,MAECFHousehold maEcf)
	                throws Exception {
		ClientAuMembIneligFactor clientAUMembInEligFactor = null;
		String ineligFactor = "";
		EligFactorRsnDtl elifactDtl = null;
		Vector eligFactor = wfData.getClientAUMembInEligFactor(auIdMemb.getClientId());
		if (eligFactor.size() > 0) {
			Enumeration eligEnum = eligFactor.elements();
			while (eligEnum.hasMoreElements()) {
				clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
				if ((auIdMemb.getAuId().intValue() == clientAUMembInEligFactor.getAuId().intValue())
				                && clientAUMembInEligFactor != null
				                && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty()) {
					StringData reason = clientAUMembInEligFactor.getEligFactorReason();
					elifactDtl = getEligFactorRsnDtl(effCtx, reason);
					if (elifactDtl != null && elifactDtl.getNotEligibleFlag().isNotEmpty()
					                && elifactDtl.getNotEligibleFlag().isTrue()) {
						if (auIdMemb.getAuRoleCode().isNotEmpty()
						                && auIdMemb.getAuRoleCode().stringValue().equalsIgnoreCase(GRANTEE)) {
							return false;
						}
						if (hasAssociatedSanction(effCtx, reason, pgmCode,maEcf,wfData)) {
							return false;
						}
						if (elifactDtl.getReason().isNotEmpty()) {
							ineligFactor = elifactDtl.getReason().toString(); 
						}
						if (ineligFactor.equals(EFRC_ELIG_SSI) || ineligFactor.equals(EF_INELIGIBLE_NON_CITIZEN) ||ineligFactor.equals(EFRC_ABAWD) 
						                || ineligFactor.equals(EFRC_FOSTER_CHILD) || ineligFactor.equals(EFRC_ELIG_SSI) ||  ineligFactor.equals(EFRC_DIDNT_APPLY_SSN)
						                || ineligFactor.equals(EFRC_ADOP_CHILD) || ineligFactor.equals(EFRC_FAMILY_CAP)) {
							return false;
						}
					}
					return true;
				}

			}
		}
		return false;
	}

	/**
	 * Check the AU members Inelig conditions. if the member has the closure, member will be excluded from the rule
	 * execution.
	 * @param effCtx
	 * @param auObj
	 * @param auIdMemb
	 * @param wfData
	 * @param pgmCode
	 * @param maEcf
	 * @return
	 * @throws Exception
	 */
	public static boolean hasAUmembIneligCondition(Context effCtx, BaseAU auObj, BaseAUMember auIdMemb,
	                                               MAClient wfData, StringData pgmCode, MAECFHousehold maEcf)
	                throws Exception {
		boolean ineligFlag = false;
		ClientAuMembIneligFactor clientAUMembInEligFactor = null;
		EligFactorRsnDtl elifactDtl = null;
		String ineligFactor = "";
		Vector eligFactor = wfData.getClientAUMembInEligFactor(auIdMemb.getClientId());
		if (eligFactor.size() > 0) {
			Enumeration eligEnum = eligFactor.elements();
			while (eligEnum.hasMoreElements()) {
				clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
				if ((auIdMemb.getAuId().intValue() == clientAUMembInEligFactor.getAuId().intValue())
				                && clientAUMembInEligFactor != null
				                && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty()) {
					StringData reason = clientAUMembInEligFactor.getEligFactorReason();
					elifactDtl = getEligFactorRsnDtl(effCtx, reason);
					if (hasAssociatedSanction(effCtx, reason, pgmCode,maEcf,wfData)) {
							return true;
					}
					if (elifactDtl.getReason().isNotEmpty()) {
						ineligFactor = elifactDtl.getReason().toString();
					}
					if (ineligFactor.equals(EFRC_ELIG_SSI) || ineligFactor.equals(EF_INELIGIBLE_NON_CITIZEN) ||ineligFactor.equals(EFRC_ABAWD) 
					                || ineligFactor.equals(EFRC_FOSTER_CHILD) || ineligFactor.equals(EFRC_ADOP_CHILD) || ineligFactor.equals(EFRC_DIDNT_APPLY_SSN)
					                || ineligFactor.equals(EFRC_FAMILY_CAP)) {
						return true;
					}
					if (auIdMemb.getAuRoleCode().isNotEmpty()
					                && auIdMemb.getAuRoleCode().stringValue().equalsIgnoreCase(GRANTEE)
					                && elifactDtl.getNotEligibleFlag().isTrue() && !ineligFactor.equals("004033")) {
						return true;
					}
				}
			}
		}
		Vector<ClientAUMembResp> respVector = wfData.getClientAUMembResponsibilty(auIdMemb.getClientId());
		for (ClientAUMembResp membResp : respVector) {
			if (auIdMemb.getAuId().intValue() == membResp.getAuId().intValue()) {
				ineligFlag = true;
				if (!membResp.getMemResp().toString().equals(RECIPIENT_RESP)
				                && !membResp.getMemResp().toString().equals(SANCTIONED_CHILD_SUPPORT)
				                && !(membResp.getMemResp().toString().equals(INELIG_ADD) && (isSelectedInPendClient(
				                                auIdMemb,  maEcf) || isAPInSelPendingAU(auIdMemb, wfData, maEcf)))
				                && !hasAUmembClosure(effCtx, auIdMemb, wfData, pgmCode,maEcf)) {
					return true;
				}
			}
		}
		if (!ineligFlag) {
			return true;
		}

		return false;
	}

	// new
	/**
	 * This method returns the EligFactorRsnDtl of corresponding EFRC code.
	 * @param effCtx
	 * @param reason
	 * @return
	 * @throws Exception
	 */
	public static EligFactorRsnDtl getEligFactorRsnDtl(Context effCtx, StringData reason) throws Exception {
		EligFactorRsnDtl eligFactorRsnDtl = new EligFactorRsnDtl();
		if (reason != null && reason.isNotEmpty()) {
			String key = EligFactorRsnDtl.class.getName() + reason.toString();
			if (effCtx.getAttribute(key) != null) {
				return (EligFactorRsnDtl) effCtx.getAttribute(key);
			}
			EligFactorRsnDtl tmpEFRsnDtl = new EligFactorRsnDtl();
			tmpEFRsnDtl.setReason(reason);
			Vector eligDetail = mapper.fetchMany(effCtx, tmpEFRsnDtl, null);
			if (eligDetail != null && eligDetail.size() > 0) {
				eligFactorRsnDtl = (EligFactorRsnDtl) eligDetail.elementAt(0);
				effCtx.setAttribute(key, eligFactorRsnDtl);
			}
		}
		return eligFactorRsnDtl;
	}

	// new
	/**
	 * This method identifies the associated sanction with inelig reason.
	 * 
	 * @param effCtx
	 *            workflow context
	 * @param reason
	 *            ineligible reason
	 * @param pgmCode
	 *            program code
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean hasAssociatedSanction(Context effCtx, StringData reason, StringData pgmCode,MAECFHousehold maEcf,MAClient wfData) throws Exception {
		EligFactorPgmRsn factorPgmReason = null;
		EligFactorPgmRsn eligFactorPgmReason = new EligFactorPgmRsn();
		eligFactorPgmReason.setEligFactorRsn(reason);
		EligFactorPgm eligFactPgm = null;
		EligFactorPgm eligFactorPgm = new EligFactorPgm();
		eligFactorPgm.setPgmCode(pgmCode);
		Vector eligFacrorPgmVect = mapper.fetchMany(effCtx, eligFactorPgm, null);
		if (reason != null) {
			Vector eligFactorRsn = mapper.fetchMany(effCtx, eligFactorPgmReason, null);
			if (eligFactorRsn != null && eligFactorRsn.size() > 0) {
				Enumeration eligFactor = eligFactorRsn.elements();
				while (eligFactor.hasMoreElements()) {
					factorPgmReason = (EligFactorPgmRsn) eligFactor.nextElement();
					if (eligFacrorPgmVect != null && eligFacrorPgmVect.size() > 0) {
						Enumeration eligFacPgmEnum = eligFacrorPgmVect.elements();
						while (eligFacPgmEnum.hasMoreElements()) {
							eligFactPgm = (EligFactorPgm) eligFacPgmEnum.nextElement();
							if (eligFactPgm.getId().intValue() == factorPgmReason.getPgmId().intValue()) {
								EligFactorSanction eligFactPgmRsnSanction = new EligFactorSanction();
								eligFactPgmRsnSanction.setEligFactorPgmId(factorPgmReason.getId());
								Vector eligFactorRsnSanc = mapper.fetchMany(effCtx, eligFactPgmRsnSanction, null);
								if (eligFactorRsnSanc != null && eligFactorRsnSanc.size() > 0) {
									IntegerData tanfGrantee = wfData.getGranteeIdOfTAFDCInHH(new IntegerData(maEcf.getHouseholdId()), wfData.getId());									
									if(tanfGrantee != null && hasDrugWarningSanction(effCtx, maEcf, wfData, tanfGrantee) == true) {
									  return false;
									} 
									return true;
								}
							}
						}
					} 
				}

			}
		}
		return false;
	}

