	/**
	 * This method is meant for setting all the member related details which will used in the rules calculation and same
	 * will be manipulated to display the member details in AU Member tab.
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param maClient
	 *            a MAClient object for rule
	 * @param wfData
	 *            a MAClient object for delta
	 * @throws Exception
	 */
	public static void setPreResultAUmember(EDBCResult ebcObject, MAClient maClient, MAClient wfData) throws Exception {
		HHClientPersonalRelation hhClientPersonalRelation = null;
		// Vector clientAumemb = wfData.getAllMembersInAU(ebcObject.getAuId());
		Vector clientAumemb = wfData.getEBCAUMemberInAU(ebcObject.getAuId());
		Vector ebcResultAuMeb = new Vector();
		if (clientAumemb != null && clientAumemb.size() > 0) {
			Enumeration membEnum = clientAumemb.elements();
			while (membEnum.hasMoreElements()) {
				// BaseAUMember aumemb = (BaseAUMember) membEnum.nextElement();
				EBCAUMember aumemb = (EBCAUMember) membEnum.nextElement();
				EDBCResultAUMember edbcResultMemb = new EDBCResultAUMember();
				BaseAUMember aUMember = wfData.getGranteeForAU(ebcObject.getAuId());
				edbcResultMemb.setAuId(aumemb.getAuId());
				edbcResultMemb.setClientId(aumemb.getClientId());
				edbcResultMemb.setMemStatus(aumemb.getAuMemberStatusCode());
				edbcResultMemb.setMemStatusDate(aumemb.getEffDate());
				// String otherParent = isThisMemberOtherParent(maClient,aumemb.getAuId());
				if (aumemb.getAuRoleCode().toString().equals(OTHER_PARENT)) {
					edbcResultMemb.setIsOtherParent("Yes");
				}
				else {
					edbcResultMemb.setIsOtherParent("No");
				}
				edbcResultMemb.setMemNam(maClient.getClientDisplayName(aumemb.getClientId()));

				if (aumemb.getClientId().intValue() == aUMember.getClientId().intValue()) {
					edbcResultMemb.getMemRelation().setString(GRANTEE_FULL);
				}
				Enumeration enumPersonalRelation = maClient.getHHClientPersonalRelations(aUMember.getClientId())
				                .elements();
				while (enumPersonalRelation.hasMoreElements()) {
					hhClientPersonalRelation = (HHClientPersonalRelation) enumPersonalRelation.nextElement();
					if (aumemb.getClientId().intValue() == aUMember.getClientId().intValue()) {
						edbcResultMemb.getMemRelation().setString(GRANTEE_FULL);
						break;
					}
					if (aumemb.getClientId().intValue() == hhClientPersonalRelation.getClientRelatedId().intValue()
					                && hhClientPersonalRelation.getClientId().intValue() == aUMember.getClientId()
					                                .intValue()) {
						edbcResultMemb.setMemRelation(hhClientPersonalRelation.getPersonalRelationCode());
						break;
					}
				}

				// Enumeration respEnum = wfData.getClientAUMembResponsibilty(aumemb.getClientId()).elements();
				Enumeration respEnum = wfData.getClientAUMembResponsibilty(aumemb.getClientId()).elements();
				while (respEnum.hasMoreElements()) {
					ClientAUMembResp clientAUMembResp = (ClientAUMembResp) respEnum.nextElement();
					if (ebcObject.getAuId().intValue() == clientAUMembResp.getAuId().intValue()) {
						edbcResultMemb.setMemResponsibility(clientAUMembResp.getMemResp());
						if(ebcObject.getProgramCode().equals(TANF)) {
							if(clientAUMembResp.getMemResp().isNotEmpty() && NONE.equals(clientAUMembResp.getMemResp().getString())) {
								if(edbcResultMemb.getMemRelation().equals(GRANTEE_FULL)) {
									if(clientAUMembResp.getMemMand().isNotEmpty() && NONE.equals(clientAUMembResp.getMemMand().getString()))
									   edbcResultMemb.getMemIneligReason().setString(TANF_NON_PARENT_GRANTEE);
									else
										edbcResultMemb.getMemIneligReason().setString(INELIG_GRANTEE);
								}else {
									edbcResultMemb.getMemIneligReason().setString(EBCConstant.INELIGIBLE_HH_MEMBER);
								}
							}
						}
						
					}
				}

				Enumeration reasonEnum = wfData.getClientAUMembInEligFactor(aumemb.getClientId()).elements();
				// Enumeration reasonEnum = maClient.getClientAUMembInEligFactor(aumemb.getClientId()).elements();
				while (reasonEnum.hasMoreElements()) {
					ClientAuMembIneligFactor clientauMembIneligFactor = (ClientAuMembIneligFactor) reasonEnum
					                .nextElement();
					if (ebcObject.getAuId().intValue() == clientauMembIneligFactor.getAuId().intValue()) {
						edbcResultMemb.setMemIneligReason(clientauMembIneligFactor.getEligFactorReason());
						edbcResultMemb.setMemEligFactor(clientauMembIneligFactor.getEligFactor());
						edbcResultMemb.setMemEligFactorStatus(clientauMembIneligFactor.getEligStatus());
						//edbcResultMemb.setMemStatus(INELIGIBLE);
						break;
					}
				}
				ebcResultAuMeb.addElement(edbcResultMemb);
			}
			Vector sortedMember = sortAuMembers(ebcResultAuMeb, maClient, ebcObject.getAuId());
			ebcObject.setEdbcResultAUMemberVector(sortedMember);
		}
	}

	/**
	 * This method sets the data for pre rules processing.
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param maEcf
	 *            a MACEFHousehold object
	 * @param wfData
	 *            a MAClient data
	 * @throws Exception
	 */
	public static void setPreResultData(EDBCResult ebcObject, MAECFHousehold maEcf, MAClient wfData, boolean recal)
	                throws Exception {
		Enumeration interviewWrapUpEDBCResultEnum = null;
		EDBCResultFinancial edbcResultFinancial = null;
		String recoupenType = "";
		Recoupment recoupment = null;
		double resultAmt = 0.0;
		int resultCount = 0;
		double asset = 0.0;
		double assetLimit = 0.0;
		boolean retroFlag = false;
		DoubleData benefitAmt = new DoubleData(0.0);
		DoubleData recoupAmt = new DoubleData(0.0);
		DoubleData grantAmt = new DoubleData(0.0);
		DoubleData iRSDepGrantAmt = new DoubleData(0.0);
		BooleanData isFEPSupplementCalculated = new BooleanData();
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		EDBCResultFinancial eDBCResultFinancial = null;
		EDBCResultFinancial tmpEDBCResultFinancial = null;
		Vector ebcResultVec = ebcObject.getCurrentResults();
		if (ebcObject.getProgramCode().toString().equals(EA)) {
			if (ebcResultVec != null && ebcResultVec.size() > 0) {
				interviewWrapUpEDBCResultEnum = ebcResultVec.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					if ((interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getProgram().isNotEmpty())
					                && ((interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF) || interviewWrapUpEDBCResult
					                                .getProgram().toString().equalsIgnoreCase(EAEDC)))) {
						benefitAmt = interviewWrapUpEDBCResult.getBenefitAmount();
						recoupment = (Recoupment) wfData.getFields().getField(Recoupment.class,
						                interviewWrapUpEDBCResult.getAuId());
						if (recoupment != null ) {
							recoupAmt = recoupment.getRecoupmentAmount();
						}
						if (benefitAmt != null && recoupAmt != null) {
							grantAmt = new DoubleData(benefitAmt.doubleValue() + recoupAmt.doubleValue());
						}
						ebcObject.setGrantAmount(ebcObject.getGrantAmount().doubleValue() + grantAmt.doubleValue());
					}
				}
			}
		}
		ebcResultVec =ebcObject.getCurrentResults();
		if (ebcObject.getProgramCode().toString().equals(SNAP)) {
			if (ebcResultVec != null && ebcResultVec.size() > 0) {
				interviewWrapUpEDBCResultEnum = ebcResultVec.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					boolean financialEligibility = false;
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					if ((interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getProgram().isNotEmpty())
					                && ((interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF) || interviewWrapUpEDBCResult
					                                .getProgram().toString().equalsIgnoreCase(EAEDC)))) {
						BaseAUMember granteememb = wfData.getGranteeForAU(interviewWrapUpEDBCResult.getAuId());
						if (ebcObject.getProgramCode().toString().equals(SNAP)
						                && ebcObject.fsMemberGranteeOfCashAu(granteememb)) {
							/*
							 * For each TANF and EAEDC result (cashResult) where the grantee is a member in the SNAP AU,
							 * accumulate: ebcObj.GrantAmount += cashResult.BEN_AMT ebcObj.GrantAmount +=
							 * cashResult.Recoupment if recoupment was an intentional type of recoupment
							 * (cashResult.RecoupmentType = AI, TI or SI) ebcObj.IRSDependentGrant +=
							 * cashResult.IRSDepGrant ebcObj.VendorPaymentAmount += cashResult.VendorPayment
							 * ebcObj.FSAttributedAmount += cashResult.FSAttributedAmount if cash program is TANF and
							 * cashResult.AUSize > 0
							 */
							/*
							 * if (recal && !isVerificationSelected(maEcf, wfData, interviewWrapUpEDBCResult .getAuId(),
							 * VER_DATA_ID_140, true, false)) { double prevBenefitAmount =
							 * getPreviousBenefitAmountValue(maEcf, interviewWrapUpEDBCResult.getAuId(),
							 * interviewWrapUpEDBCResult); benefitAmt = new DoubleData(prevBenefitAmount); }
							 */
							// else {
							benefitAmt = interviewWrapUpEDBCResult.getBenefitAmount();
							// }
							ebcObject.setGrantAmount(ebcObject.getGrantAmount().doubleValue()
							                + benefitAmt.doubleValue());
							
							if (HcalcUtil.isHcalcCashbenefitOverrideRequired(maEcf, wfData.getId().intValue())) {
								double hcalcCashBenefit = HcalcUtil.getCashBenefitAmount(maEcf);
								ebcObject.setGrantAmount(hcalcCashBenefit);
							}
							
							
							edbcResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT,
							                RECOUPMENTELEMENT);
							recoupenType = getFinancialObjectStringValue(interviewWrapUpEDBCResult, BENEFIT,
							                RECOUPMENTTYPE);
							double recoupmentAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue()
							                .isNotEmpty()) ? Double.parseDouble(edbcResultFinancial.getValue()
							                .toString()) : 0.00;
							recoupment = (Recoupment) wfData.getFields().getField(Recoupment.class,
							                interviewWrapUpEDBCResult.getAuId());
							if (recoupmentAmt > 0
							                && (recoupenType.equals(AI) || recoupenType.equals(TI) || recoupenType
							                                .equals(SI))) {
								grantAmt = new DoubleData(ebcObject.getGrantAmount().doubleValue() + recoupmentAmt);
								ebcObject.setGrantAmount(grantAmt.doubleValue());
							}

							iRSDepGrantAmt = interviewWrapUpEDBCResult.getIRSDepGrant();
							ebcObject.setIRSDependentGrant(ebcObject.getIRSDependentGrant().doubleValue()
							                + iRSDepGrantAmt.doubleValue());

							eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT, VENDORPAYMENT);
							if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
								resultAmt = Double.parseDouble(eDBCResultFinancial.getValue().toString());
								ebcObject.setVendorPaymentAmount(ebcObject.getVendorPaymentAmount().doubleValue()
								                + resultAmt);
							}
							eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
							                FINANCIALELIGIBILITYSTATUS);
							if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
							                && eDBCResultFinancial.getValue().toString().equalsIgnoreCase(ELIG)) {
								financialEligibility = true;
							}
							// if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)) {
							eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, AUSIZE);
							if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
								resultCount = Integer.parseInt(eDBCResultFinancial.getValue().toString());
							}
							if (resultCount > 0 && financialEligibility) {
								eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(GROSSINCOME,
								                FSATTRIBUTEDAMOUNT);
								if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
									resultAmt = Double.parseDouble(eDBCResultFinancial.getValue().toString());
									ebcObject.setFSAttributedAmount(ebcObject.getFSAttributedAmount().doubleValue()
									                + resultAmt);
								}
							}
							ebcObject.setTotalSanctionedAmt(interviewWrapUpEDBCResult.getTotalSanctionedAmt());

							if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)) {
								eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(ASSETS, ASSETLIMIT);
								tmpEDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(ASSETS, ASSETS);
								if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
								                && tmpEDBCResultFinancial != null
								                && tmpEDBCResultFinancial.getValue().isNotEmpty()) {
									assetLimit = Double.parseDouble(eDBCResultFinancial.getValue().toString());
									asset = Double.parseDouble(tmpEDBCResultFinancial.getValue().toString());
									if (asset > assetLimit) {
										// ebcObject.tafdcAssetsIneligible = "Y"
									}
								}
								eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT,
								                BUDGETINGMETHOD);
								if (ebcObject.getFutureFSAUSubtype(maEcf, wfData).equals(PUBLIC_ASSISTANCE)
								                && ebcObject.isFSGranteeAlsoTafdcGrantee(maEcf, wfData,
								                                interviewWrapUpEDBCResult.getAuId())
								                && eDBCResultFinancial != null
								                && eDBCResultFinancial.getValue().equals("Retrospective")) {
									ebcObject.setIncomeSourceType(RETROSPECTIVE);
									retroFlag = true;
								}
								if (!retroFlag) {
									ebcObject.setIncomeSourceType(PROSPECTIVE);
								}
								/*
								 * ebcObj.TAFDCisFEPSupplementCalculated = Y if any TANF result with an active status
								 * has result.isFEPSupplementCalculated = Y
								 */
								if (interviewWrapUpEDBCResult != null) {
									eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
									                ISFEPSUPPLEMENTCALCULATED);
								}
								if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
									isFEPSupplementCalculated = new BooleanData(eDBCResultFinancial.getValue()
									                .toString());
								}
								if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)
								                && interviewWrapUpEDBCResult.getStatus().toString().equals(ACTIVE)
								                && isFEPSupplementCalculated.isNotEmpty()
								                && isFEPSupplementCalculated.isTrue()) {
									ebcObject.setTafdcIsFEPSupplementCalculated(true);
								}
							}
						}
					}
				}
			}
			//if(ebcObject.getIsRetro().isFalse()) {
				setPreCatEligFlag(ebcObject, maEcf, interviewWrapUpEDBCResult, wfData);
				setPreCatEligReason(ebcObject, maEcf, interviewWrapUpEDBCResult, wfData);
			//}
			
		}
		 recoupment = (Recoupment) wfData.getFields().getField(Recoupment.class,
				 ebcObject.getAuId());
		if(recoupment == null) {
			recoupment = ARUtil.getRecoupment(maEcf.getFields().getContext(), ebcObject.getAuId());
			wfData.getFields().setField(Recoupment.class,ebcObject.getAuId(),recoupment);
		}
	}
	
	/**
	 * @param maEcf
	 */
	private static void resetWorkProgram(MAECFHousehold maEcf) throws Exception{
		maEcf.getFields().removeAll(ClientWorkRequirementStatus.class);
		maEcf.getFields().removeAll(ClientAUMembESPParticipationStatus.class);
		maEcf.getFields().removeAll(AUExemptStatus.class);
		maEcf.getFields().removeAll(ClientAUMembEligFact.class);
		maEcf.getFields().removeAll(ClientAUMembWorkProgramSearch.class);
		maEcf.getFields().removeAll(ClientAuFsetPrtn.class);
		Vector vEligReqVerData = maEcf.getFields().getFields(EligibilityRequestVerData.class, maEcf.getRequestId().getReqId());
		for(int i=0;i<vEligReqVerData.size();i++){
			EligibilityRequestVerData eligReqVerData = (EligibilityRequestVerData) vEligReqVerData.elementAt(i);
			if(eligReqVerData.getVerId().isEmpty()){
				vEligReqVerData.removeElementAt(i--);
			}
		}
		maEcf.getFields().setField(EligibilityRequestVerData.class, maEcf.getRequestId().getReqId(),vEligReqVerData);
	}
	
	
	public static void setWorkProgramReasonTAFDC(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule)
		  throws Exception {
		if (ebcObject.getProgramCode().equals(TANF)) {
			setWorkProgramReason(ctx, ebcObject, maEcf, maECFRule);
		}
	}
	
	
	public static void setWorkProgramReasonFS(Context ctx, Vector<EDBCResult> ebcObjectVector, MAECFHousehold maEcf, MAECFHousehold maECFRule)
		  throws Exception {
		for (EDBCResult ebcObject: ebcObjectVector){
			if (ebcObject.getProgramCode().equals(SNAP) && ebcObject.getIsRetro().isFalse()) {
				setWorkProgramReason(ctx, ebcObject, maEcf, maECFRule);
			}
		}
	}
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param wfData
	 * @param recal
	 * @throws Exception
	 */
	public static void setWorkProgramReason(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule)
			throws Exception {
		if (ebcObject.getProgramCode().equals(TANF)) {
			Vector<IntegerData> wprClients = new Vector<IntegerData>();
			Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
			if (vecAUMemb != null && vecAUMemb.size() > 0) {
				for (EDBCResultAUMember auMembRslt : vecAUMemb) {
					if ((auMembRslt.getMemStatus().equals(PENDING) || auMembRslt.getMemStatus().equals(ACTIVE) || auMembRslt.getMemStatus().equals(
							INELIG))
							&& isWorkProgramTAFDCEnabled(ebcObject, maEcf, auMembRslt)) {
						setWorkProgramReason(ctx, ebcObject, maEcf, maECFRule, auMembRslt);
						wprClients.add(auMembRslt.getClientId());
					}
				}
				setWorkProgramExemptStatus(ctx, ebcObject, maEcf, maECFRule, wprClients);
			}
		} else if (ebcObject.getProgramCode().equals(SNAP)) {
			Vector<InterviewWrapUpEDBCResult> rsltVec = maEcf.getInterviewWrapUpEDBCResults(maEcf.getRequestId().getReqId());
			Vector<EDBCResultAUMember> vecAUMemb = null;
			for (InterviewWrapUpEDBCResult rsltObj : rsltVec) {
				if (rsltObj.getAuId().equals(ebcObject.getAuId())) {
					vecAUMemb = rsltObj.getAuMembResults();
					Vector<IntegerData> wprClients = new Vector<IntegerData>();
					if (vecAUMemb != null && vecAUMemb.size() > 0) {
						for (EDBCResultAUMember auMembRslt : vecAUMemb) {
							if ((auMembRslt.getMemStatus().equals(PENDING) || auMembRslt.getMemStatus().equals(ACTIVE) || auMembRslt.getMemStatus()
									.equals(INELIG)) && isWorkProgramFSEnabled(ebcObject, maEcf, auMembRslt)) {
								setWorkProgramReasonFS(ctx, ebcObject, maEcf, maECFRule, auMembRslt);
								wprClients.add(auMembRslt.getClientId());
							}
						}
						if (ebcObject.getWorkProgramMessage().isNotEmpty()) {
							ebcObject.prefixWorkProgramMessage(wrkmsgHeader.toString());
						}
					}
					break;
				}
			}
		}
	}
	
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param wprClients
	 * @throws Exception
	 */
	public static void setWorkProgramExemptStatus(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
	                                              Vector<IntegerData> wprClients) throws Exception {
		if (ebcObject.getWorkProgramMessage().isNotEmpty()) {
			MAClient mAClient =null;
			Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
			if(null!=ebcObject.getGranteeSSN().getClientId().getValue())
				mAClient = maEcf.getMAClient(ebcObject.getGranteeSSN().getClientId().intValue());
			else
				mAClient = maEcf.getMAClient(maEcf.getPrimaryClientId());
			Vector<ClientWorkRequirementStatus> wpStatusVect = new Vector<ClientWorkRequirementStatus>();
			for (int i = 0; i < wprClients.size(); i++) {
				Vector<ClientWorkRequirementStatus> twpStatusVect = mAClient.getClientWorkRequirementStatus(wprClients.elementAt(i));
				for (ClientWorkRequirementStatus tCamWprStat : twpStatusVect) {
					if (tCamWprStat.getAuId().equals(ebcObject.getAuId())) {
						wpStatusVect.add(tCamWprStat);
					}
				}
			}
			AUExemptStatus aUExemptStatus = mAClient.getAUExemptStatus(ebcObject.getAuId());
			boolean exempt = true;
			for (ClientWorkRequirementStatus camWprStat : wpStatusVect) {
				if (camWprStat.getClientId().equals(ebcObject.getGranteeSSN().getClientId())) {
					if (!camWprStat.getWorkExemptFlag().isTrue()) {
						exempt = false;
						break;
					}
				}
				else if (isOtherParent(camWprStat.getClientId(), vecAUMemb)) {
					if (!camWprStat.getWorkExemptFlag().isTrue()) {
						exempt = false;
						break;
					}
				}
			}
			if (aUExemptStatus != null) {
				if (exempt) {
					aUExemptStatus.setAuExemptStatus("EXMPT");
				} else {
					aUExemptStatus.setAuExemptStatus("NEXMPT");
				}
				setAuExemptReason(maEcf, ebcObject, aUExemptStatus, wpStatusVect);
				if (aUExemptStatus.getAuExemptStatus().hasValueChanged()) {
					setWorkProgramExemptStatus(ctx, ebcObject, maEcf, maECFRule, aUExemptStatus);
				} else {
					ebcObject.prefixWorkProgramMessage(wrkmsgHeader.toString());
				}
			}
		}
	}
	
	/**
	 * @param maEcf
	 * @param ebcObject
	 * @param aUExemptStatus
	 * @param wpStatusVect
	 * @throws Exception
	 */
	private static void setAuExemptReason(MAECFHousehold maEcf, EDBCResult ebcObject, AUExemptStatus aUExemptStatus,
	                                      Vector<ClientWorkRequirementStatus> wpStatusVect) throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		if (aUExemptStatus.getAuExemptStatus().equals("EXMPT")) {
			if (isAuExemptReasonC(maEcf, ebcObject, wpStatusVect)) {
				aUExemptStatus.setAuExemptReason("C");
			}
			else {
				aUExemptStatus.setAuExemptReason("A");
			}
		}
		else if (aUExemptStatus.getAuExemptStatus().equals("NEXMPT")) {
			if (isAuExemptReason1(wpStatusVect)) {
				aUExemptStatus.setAuExemptReason("1");
			}
			else if (isAuExemptReason3(wpStatusVect)) {
				aUExemptStatus.setAuExemptReason("3");
			}
			else if (isAuExemptReason6(wpStatusVect)) {
				aUExemptStatus.setAuExemptReason("6");
			}
		}
	}
	
	
	/**
	 * @param maEcf
	 * @param ebcObject
	 * @param wpStatusVect
	 * @return
	 * @throws Exception
	 */
	private static boolean isAuExemptReasonC(MAECFHousehold maEcf, EDBCResult ebcObject, Vector<ClientWorkRequirementStatus> wpStatusVect)
	    throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		for (ClientWorkRequirementStatus camWprStat : wpStatusVect) {
			if (camWprStat.getClientId().equals(ebcObject.getGranteeSSN().getClientId())) {
				if (!isClientDisabPend(maEcf, camWprStat)) {
					return false;
				}
			}
			else if (isOtherParent(camWprStat.getClientId(), vecAUMemb)) {
				if (!isClientDisabPend(maEcf, camWprStat)) {
					return false;
				}
			}
		}
		return true;
	}
	
	/**
	 * @param wpStatusVect
	 * @return
	 * @throws Exception
	 */
	private static boolean isAuExemptReason1(Vector<ClientWorkRequirementStatus> wpStatusVect) throws Exception {
		for (ClientWorkRequirementStatus camWprStat : wpStatusVect) {
			if (!camWprStat.getWorkExemptFlag().isTrue()) {
				if (camWprStat.getWorkExemptReason().equals("TNTO07") || camWprStat.getWorkExemptReason().equals("TNTQ17")) {
					return true;
				}
			}
		}
		return false;
	}
	
	/**
	 * @param wpStatusVect
	 * @return
	 * @throws Exception
	 */
	private static boolean isAuExemptReason6(Vector<ClientWorkRequirementStatus> wpStatusVect) throws Exception {
		for (ClientWorkRequirementStatus camWprStat : wpStatusVect) {
			if (!camWprStat.getWorkExemptFlag().isTrue()) {
				if (camWprStat.getWorkExemptReason().equals("TNSN06") || camWprStat.getWorkExemptReason().equals("TNSN17")
				    || camWprStat.getWorkExemptReason().equals("TNSO17") || camWprStat.getWorkExemptReason().equals("TNSP06")
				    || camWprStat.getWorkExemptReason().equals("TNTN07") || camWprStat.getWorkExemptReason().equals("TNTN17")
				    || camWprStat.getWorkExemptReason().equals("TNTP07") || camWprStat.getWorkExemptReason().equals("TNTP17")) {
					return true;
				}
			}
		}
		return false;
	}
	
	/**
	 * @param wpStatusVect
	 * @return
	 * @throws Exception
	 */
	private static boolean isAuExemptReason3(Vector<ClientWorkRequirementStatus> wpStatusVect) throws Exception {
		for (ClientWorkRequirementStatus camWprStat : wpStatusVect) {
			if (!camWprStat.getWorkExemptFlag().isTrue()) {
				if (camWprStat.getWorkExemptReason().equals("TNSF06") || camWprStat.getWorkExemptReason().equals("TNTF07")) {
					return true;
				}
			}
		}
		return false;
	}
	
	/**
	 * @param maEcf
	 * @param camWprStat
	 * @return
	 * @throws Exception
	 */
	private static boolean isClientDisabPend(MAECFHousehold maEcf, ClientWorkRequirementStatus camWprStat) throws Exception {
		if (camWprStat.getWorkExemptReason().equals("TEN17F") || camWprStat.getWorkExemptReason().equals("TES10")
		    || camWprStat.getWorkExemptReason().equals("TET09") || camWprStat.getWorkExemptReason().equals("TET12")) {
			ClientDisabilityPage disab = maEcf.getMAClient(camWprStat.getClientId().intValue()).getClientDisabilityPage();
			if (disab != null && disab.getDisabledFlg().isTrue() && disab.getDeterminationStatus().equals("PEND")) {
				return true;
			}
		}
		return false;
	}
	
	/**
	 * @param ctx
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param aUExemptStatus
	 * @throws Exception
	 */
	private static void setWorkProgramExemptStatus(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
	                                                AUExemptStatus aUExemptStatus) throws Exception {
		aUExemptStatus.setDisplayClientId(ebcObject.getGranteeSSN().getClientId());
		aUExemptStatus.setEffDate(getEffectiveDate(ctx));
		aUExemptStatus.setDescriptiveStart(getEffectiveDate(ctx));
		aUExemptStatus.setAnswerComplete(true);
		//setWorkProgramExemptStatusR(ebcObject, maECFRule, (AUExemptStatus)aUExemptStatus.clone(true));
		aUExemptStatus.setRequiresInsert();
		aUExemptStatus.setPersistenceSortOrder(1);
		maEcf.getMAClient(ebcObject.getGranteeSSN().getClientId().intValue()).setAUExemptStatus(aUExemptStatus, aUExemptStatus.getAuId());
		RequestId requestId = maEcf.getRequestId();
		Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
		EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
		eligReqVerData.setEligRequestId(requestId.getReqId());
		eligReqVerData.setVerificationElementId(69);
		eligReqVerData.setClientId(aUExemptStatus.getDisplayClientId());
		eligReqVerData.setAuId(aUExemptStatus.getAuId());
		eligReqVerData.setVerificationValueDescription(aUExemptStatus.formatVerificationValue());
		updateVerification(eligReqVerVec, eligReqVerData, aUExemptStatus.getVerificationId());
		aUExemptStatus.getVerificationId().setNull();
		aUExemptStatus.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
		maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
	}
	
	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param aUExemptStatus
	 */
	private static void setWorkProgramExemptStatusR(EDBCResult ebcObject, MAECFHousehold maECFRule, AUExemptStatus aUExemptStatus)
	    throws Exception {
		TypeCodeCache cache = TypeCodeCache.getInstance();
		maECFRule.getMAClient(ebcObject.getGranteeSSN().getClientId().intValue()).setAUExemptStatus(aUExemptStatus, aUExemptStatus.getAuId());
		StringBuffer msg = new StringBuffer(wrkmsgHeader.toString());
		msg.append(ebcObject.getProgramCode().toString());
		TypeCode code = cache.getValue(maECFRule.getFields().getContext(), "AU EXEMPT REASON", aUExemptStatus.getAuExemptReason().toString());
		if (aUExemptStatus.getAuExemptStatus().equals("EXMPT")) {
			msg.append(": Exempt - <![CDATA[" + code.getDescription().toString()+"]]>");
		}
		else {
			msg.append(": Nonexempt - <![CDATA[" + code.getDescription().toString()+"]]>");
		}
		msg.append("|BR||BR|");
		ebcObject.prefixWorkProgramMessage(msg.toString());
	}
	
	
	
