	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @throws Exception
	 */
	public static String getWorkProgramReasonFS(EDBCResult ebcObject, MAECFHousehold maEcf,
			EDBCResultAUMember auMembRslt) throws Exception {
		if (checkForFN06SN(ebcObject, maEcf, auMembRslt)) {
			return "FN06SN";
		}
		if (checkForFE04UO(ebcObject, maEcf, auMembRslt)) {
			return "FE04UO";
		}

		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		ClientUSMilitaryService cltUsMilitaryService = mAClient.getClientUSMilitaryService();
		if (cltUsMilitaryService != null && cltUsMilitaryService.getMilitaryServiceFlg().isTrue()) {
			if (miltryService.contains(cltUsMilitaryService.getMilitaryServiceStatus().getString())) {
				return EBCConstant.VETERAN;
			}
		}

		if (checkForFE04AG(ebcObject, maEcf, auMembRslt)) {
			return EBCConstant.UNDER_AGE_18_OR_AGE_53_OR_OVER;
		}

		if (checkForFE04TE(ebcObject, maEcf, auMembRslt)) {
			return EBCConstant.PARTICIPATING_IN_JOBS;
		}

		if (auMembRslt.getMemResponsibility().equals("NCITDQ")) {
			return EBCConstant.WP_NONCITIZEN_DISQUALIFIED;
		}
		if (checkForFE17HH(ebcObject, maEcf, auMembRslt)) {
			return "FE17HH";
		}
		if (checkForFE04UD(ebcObject, maEcf, auMembRslt)) {
			return "FE04UD";
		}
		if (checkForFE04RW(ebcObject, maEcf, auMembRslt)) {
			return "FE04RW";
		}
		if (checkForFE04CD(ebcObject, maEcf, auMembRslt)) {
			return "FE04CD";
		}
		if (checkForFE04PR(ebcObject, maEcf, auMembRslt)) {
			return "FE04PR";
		}
		if (checkForFE04UM(ebcObject, maEcf, auMembRslt)) {
			return "FE04UM";
		}
		if (checkForFE04EM(ebcObject, maEcf, auMembRslt)) {
			return "FE04EM";
		}
		if (checkForFE04ST(ebcObject, maEcf, auMembRslt)) {
			return "FE04ST";
		}

		if (checkForFE04UC(ebcObject, maEcf, auMembRslt)) {
			return "FE04UC";
		}
		if (checkForFE04UT(ebcObject, maEcf, auMembRslt)) {
			return "FE04UT";
		}
		if (checkForFE04US(ebcObject, maEcf, auMembRslt)) {
			return "FE04US";
		}
		if (checkForFE04CT(ebcObject, maEcf, auMembRslt)) {
			return "FE04CT";
		}
		if (checkForFE04AD(ebcObject, maEcf, auMembRslt)) {
			return "FE04AD";
		}

		/*
		 * if(checkForFE04EX(ebcObject, maEcf, auMembRslt)){ return "FE04EX"; }
		 * 
		 * if(checkForFE04CV(ebcObject, maEcf, auMembRslt) || (covidExempt != null &&
		 * covidExempt.equals(MAConstants.FLAG_YES))){ return "FE04CV"; }
		 * if(checkForFN06ZB(ebcObject, maEcf, auMembRslt)){ return "FN06ZB"; }
		 * if(checkForFN06ZH(ebcObject, maEcf, auMembRslt)){ return "FN06ZH"; }
		 */
		return WP_ABAWD;
	}

	
	
