	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean checkForFE04EM(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		int age = getClientAge(maEcf, auMembRslt);
		if (age >= getESPDepChildMaxAge(maEcf.getFields().getContext())) {
			double weeklyAmt = 0;
			double weeklyHours = 0;
			MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
			Vector<EarnedIncome> earnedIncomeVect = mAClient.getEarnedIncome(auMembRslt.getClientId());
			for (EarnedIncome earnedIncome : earnedIncomeVect) {
				EarnedIncProspectiveAvg earnedIncProspectiveAvg = mAClient.getEarnedIncProspectiveAvg(earnedIncome.getEarnedIncomeId());
				if (earnedIncProspectiveAvg != null && earnedIncProspectiveAvg.getMonthlyProspAmount().isNotEmpty()) {
					double weeklyIncAmt = earnedIncProspectiveAvg.getMonthlyProspAmount().doubleValue() / 4.3;
					if (earnedIncome.getWageType().toString().equalsIgnoreCase(MAConstants.SELF_EMPLOYMENT)) {
						double weeklyExpAmt = ebcObject.getEarnedIncomeBusinessExpense(mAClient, earnedIncome);
						if (weeklyExpAmt > 0) {
							weeklyExpAmt = weeklyExpAmt / 4.333;
							if (weeklyIncAmt > weeklyExpAmt) {
								weeklyIncAmt = weeklyIncAmt - weeklyExpAmt;
							} else {
								weeklyIncAmt = 0;
							}
						}
					}
					weeklyAmt += weeklyIncAmt;
					weeklyHours += earnedIncProspectiveAvg.getMonthlyHours().doubleValue() / 4.3;
				}
			}
			Vector<ClientUI> otherIncomeVect = mAClient.getClientUI(auMembRslt.getClientId());
			for (ClientUI otherIncome : otherIncomeVect) {
				if (otherIncome.getOtherIncType().equals(MAConstants.INC_TYP_RENTAL) && otherIncome.getEarnedFlg().isTrue()
						&& (otherIncome.getOtherIncStatus().equals("ACTIVE") || otherIncome.getOtherIncStatus().equals("PEND"))) {
					ClientUIPspAvg uiPspAvg = mAClient.getClientUIPspAvg(otherIncome.getUiId());
					if (uiPspAvg != null && uiPspAvg.getMonthlyAmt().isNotEmpty()) {
						weeklyAmt += uiPspAvg.getMonthlyAmt().doubleValue() / 4.3;
					}
					weeklyHours += 20;
				}
			}
			if (weeklyAmt > 0) {
				Parameter parm = ParameterCache.getInstance().getParameter(maEcf.getFields().getContext(), "FEDERAL_MINIMUM_WAGE");
				if (weeklyAmt >= (Double.parseDouble(parm.getParameterValue()) * 30)) {
					return true;
				}
			}
			if (weeklyHours >= 30) {
				return true;
			}
		}
		return false;
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean checkForFE04ST(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		int age = getClientAge(maEcf, auMembRslt);
		if (age >= getESPDepChildMaxAge(maEcf.getFields().getContext())) {
			MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
			Vector<ClientEducation> eduVect = mAClient.getClientEducation();
			for (ClientEducation clEdu : eduVect) {
				ClientEducationDetail clEduDetail = mAClient.getClientEducationDetail(clEdu.getId());
				if (clEduDetail != null && clEduDetail.getGraduation().isNotEmpty()
						&& clEduDetail.getGraduation().after(maEcf.getFields().getContext().getEffectiveDate())) {
					if (clEduDetail.getEnrollmentStatus().equals("FT") || clEduDetail.getEnrollmentStatus().equals("HT")) {
						return true;
					}
				}
			}
		}
		return false;
	}
	
