	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean checkForFE04US(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		int age = getClientAge(maEcf, auMembRslt);
		if (age >= getESPDepChildMaxAge(maEcf.getFields().getContext())) {
			MAClient mAGranteeClient = maEcf.getMAClient(maEcf.getAsstUnit(ebcObject.getAuId()).getGranteeId().intValue());
			AddressClient addressGrantee = mAGranteeClient.getAddressClient();
			if (addressGrantee != null && addressGrantee.getHomeless().isTrue()) {
				//added as part of homeless clients.
				if(addressGrantee.getCurrentAddressId().isEmpty() && addressGrantee.getPermanentAddressId().isEmpty()) {
					return true;
				}
				Vector<WorkRequirementsScreeningQuestionsRslt> wrsQuestions = maEcf.getFields().getFields(
						WorkRequirementsScreeningQuestionsRslt.class, auMembRslt.getClientId());
				int count = 0;
				if (wrsQuestions != null && wrsQuestions.size() > 0) {
					for (WorkRequirementsScreeningQuestionsRslt wrsqrslt : wrsQuestions) {
						if (wrsqrslt.getAnswers().isNotEmpty()) {
							if (wrsqrslt.getQuestionsCode().equals("WFRSQ1")) {
								if (wrsqrslt.getAnswers().equals("N")) {
									return true;
								}
							} else if (wrsqrslt.getQuestionsCode().equals("WFRSQ2")) {
								if (wrsqrslt.getAnswers().equals("N")) {
									count++;
								}
							} else if (wrsqrslt.getQuestionsCode().equals("WFRSQ3")) {
								if (wrsqrslt.getAnswers().equals("N")) {
									count++;
								}
							} else if (wrsqrslt.getQuestionsCode().equals("WFRSQ4")) {
								if (wrsqrslt.getAnswers().equals("N")) {
									count++;
								}
							} else if (wrsqrslt.getQuestionsCode().equals("WFRSQ5")) {
								if (wrsqrslt.getAnswers().equals("Y")) {
									count++;
								}
							}
							if (count == 2) {
								return true;
							}
						}
					}
				}
			}
		}
		return false;
	}
	
