	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean checkForFN06ZB(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		Vector<InterviewWrapUpEDBCResult> rsltVec = maEcf.getInterviewWrapUpEDBCResults(maEcf.getRequestId().getReqId());
		for (InterviewWrapUpEDBCResult rsltObj : rsltVec) {
			if (rsltObj.getAuId().equals(ebcObject.getAuId())) {
				Context benCtx = maEcf.getFields().getContext().copy();
				if(rsltObj.getBenefitEffective().isNotEmpty()){
					benCtx.setEffectiveDate(rsltObj.getBenefitEffective());
				}
				double fsAmount = getFinancialObjectDoubleValue(rsltObj, BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT);
				int federalMin = (int) Float.parseFloat(ParameterCache.getInstance().getParameter(benCtx, MAConstants.FEDERAL_MINIMUM_WAGE)
						.getParameterValue());
				if (fsAmount <= federalMin) {
					return true;
				}
			}
		}
		return false;
	}
	
	
	private static boolean checkForFN06ZH(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		Vector<InterviewWrapUpEDBCResult> rsltVec = maEcf.getInterviewWrapUpEDBCResults(maEcf.getRequestId().getReqId());
		for (InterviewWrapUpEDBCResult rsltObj : rsltVec) {
			if (rsltObj.getAuId().equals(ebcObject.getAuId())) {
				Context benCtx = maEcf.getFields().getContext().copy();
				if(rsltObj.getBenefitEffective().isNotEmpty()){
					benCtx.setEffectiveDate(rsltObj.getBenefitEffective());
				}
				double fsAmount = getFinancialObjectDoubleValue(rsltObj, BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT);
				int federalMin = (int) Float.parseFloat(ParameterCache.getInstance()
						.getParameter(benCtx, MAConstants.FEDERAL_MINIMUM_WAGE).getParameterValue());
				int activeCnt = 0;
				Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
				for (EDBCResultAUMember tauMembRslt : vecAUMemb) {
					if (tauMembRslt.getMemStatus().equals(ACTIVE)) {
						activeCnt++;
					}
				}
				if (activeCnt > 0) {
					int hrs = ((int) fsAmount / federalMin) / activeCnt;
					if (hrs == 0) {
						return true;
					}
				}
			}
		}
		return false;
	}
	
	/**
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean isClientPregnantFS(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		MAClientPregnancy preg = maEcf.getMAClient(auMembRslt.getClientId().intValue()).getClientPregnancy();
		if (preg != null
				&& preg.getPregnancyFlag().isTrue()
				&& (preg.getExpectedDueDate().isNotEmpty() && !preg.getExpectedDueDate().before(
						new DateData(maEcf.getFields().getContext().getEffectiveDate()).addDays(-14)))) {
			return true;
		}
		return false;
	}
	
	/**
	 * @param maEcf
	 * @param auMembRslt
	 * @param wpExemptReason
	 * @return
	 * @throws Exception
	 */
	private static boolean isUserAssignedWPR(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt, String wpExemptReason) throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		Vector<ClientWorkRequirementStatus> wpStatusVect = mAClient.getClientWorkRequirementStatus(auMembRslt.getClientId());
		ClientWorkRequirementStatus camWprStat = null;
		int i = 0;
		for (; i < wpStatusVect.size(); i++) {
			ClientWorkRequirementStatus tcamWprStat = (ClientWorkRequirementStatus) wpStatusVect.elementAt(i);
			if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
				camWprStat = tcamWprStat;
				break;
			}
		}
		if (camWprStat != null) {
			if (camWprStat.getWorkExemptReason().equals(wpExemptReason) && (camWprStat.getAnticipatedDate().isEmpty()
					|| camWprStat.getAnticipatedDate().after(maEcf.getFields().getContext().getEffectiveDate()))) {
				return true;
			}
		}
		return false;
	}
	
	/**
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean isClientDisabledFS(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		ClientDisabilityPage disab = mAClient.getClientDisabilityPage();
		if (disab != null && disab.getDisabledFlg().isTrue()) {
			if (disab.getDeterminationStatus().equals("APPRVD") && !disab.getDisabilityDeterminationSrc().equals("APSTMT")) {
				if (disab.getExpirationDt().isEmpty() || disab.getExpirationDt().after(maEcf.getFields().getContext().getEffectiveDate())) {
					return true;
				}
			}
		}
		return false;
	}
	
