	/**
	 * Read from denorm client table (SNAP birth date is not mandatory verification)
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static int getClientAge(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		return getClientAge(maEcf, auMembRslt.getClientId().intValue());
	}
	
	
	/**
	 * @param maEcf
	 * @param mAClient
	 * @return
	 * @throws Exception
	 */
	private static int getClientAge(MAECFHousehold maEcf, int clientId) throws Exception {
		MAClient mAClient = maEcf.getMAClient(clientId);
		BaseClient baseClient = mAClient.getBaseClient();
		DateData birthDate = baseClient.getBirthDate();
		DateData today = mAClient.getCurrentDay();
		int yearDiff = today.getYear() - birthDate.getYear();
		if (today.getMonth() < birthDate.getMonth()) {
			yearDiff -= 1;
		} else if ((today.getMonth() == birthDate.getMonth()) && (today.getDate() < birthDate.getDate())) {
			yearDiff -= 1;
		}
		return yearDiff;

	}
	
	/**
	 * @param maEcf
	 * @param clientId
	 * @return
	 * @throws Exception
	 */
	private static boolean isNameClearedPandP(EDBCResult ebcObject, MAECFHousehold maEcf, int clientId) throws Exception {
		MAClient mAClient = maEcf.getMAClient(clientId);
		ClientNamInfo clientNamInfo = mAClient.getClientPrimaryName(mAClient.getId());
		if (clientNamInfo != null && clientNamInfo.getNameScreened().isTrue()) {
			HHMemberPurchasePrepare purchasePrepare = mAClient.getHHMemberPurchasePrepare(mAClient.getId(), maEcf
					.getAsstUnit(ebcObject.getAuId()).getGranteeId());
			if (purchasePrepare != null && purchasePrepare.getPurchasePrepareFlag().isTrue()) {
				return true;
			}
		}
		return false;
	}
	
