	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean checkForFE04TE(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		Vector<InterviewWrapUpEDBCResult> rsltVec = maEcf.getInterviewWrapUpEDBCResults(maEcf.getRequestId().getReqId());
		for (InterviewWrapUpEDBCResult rsltObj : rsltVec) {
			if (rsltObj.getProgram().equals(TANF)) {
				Vector<EDBCResultAUMember> rsltMembVec = rsltObj.getAuMembResults();
				for (EDBCResultAUMember rsltMemb : rsltMembVec) {
					if (rsltMemb.getClientId().equals(auMembRslt.getClientId()) && !rsltMemb.getAuId().equals(auMembRslt.getAuId())) {
						if (rsltMemb.getMemStatus().equals(PENDING) || rsltMemb.getMemStatus().equals(ACTIVE)
								|| rsltMemb.getMemStatus().equals(INELIGIBLE)) {
							StringData resp = rsltMemb.getMemResponsibility();
							if ((!(!rsltObj.getGranteeId().equals(rsltMemb.getClientId()) && resp.toString().equals(MAConstants.NONE)))
									&& (!resp.toString().equals(MAConstants.STEP_PRNT)) && (!resp.toString().equals(MAConstants.CHILD_OF_PREGNANT_WOMAN))
									&& (!resp.toString().equals(MAConstants.SP_PREG_WO)) && (!resp.toString().equals(MAConstants.NON_CZN_SPON))
									&& (!resp.toString().equals(MAConstants.SPO_NON_CZN_SPON)) && (!resp.toString().equals(MAConstants.PRNT_TEEN))
									&& (!resp.toString().equals(MAConstants.SP_NONPA_GRN)) && (!resp.toString().equals(MAConstants.DEP_CHILD_ADOPT_ASSIS))
									&& (!resp.toString().equals(MAConstants.DEP_CHILD_FOSTER_CARE))
									&& (!resp.toString().equals(MAConstants.DEP_CHILD_FAMILY_CAP))
									&& (!resp.toString().equals(MAConstants.DEPENDENT_CHILD_SSI)) && (!resp.toString().equals(MAConstants.SPOUSE))
									&& (!resp.toString().equals(MAConstants.DISABLED_PERSON_UNDER_CARE))) {
								return true;
							}
						}
					}
				}
			} else if (rsltObj.getProgram().equals(EAEDC)) {
				Vector<EDBCResultAUMember> rsltMembVec = rsltObj.getAuMembResults();
				for (EDBCResultAUMember rsltMemb : rsltMembVec) {
					if (rsltMemb.getClientId().equals(auMembRslt.getClientId()) && !rsltMemb.getAuId().equals(auMembRslt.getAuId())) {
						if (rsltMemb.getMemStatus().equals(PENDING) || rsltMemb.getMemStatus().equals(ACTIVE)
								|| rsltMemb.getMemStatus().equals(INELIGIBLE)) {
							StringData resp = rsltMemb.getMemResponsibility();
							if ((!(!rsltObj.getGranteeId().equals(rsltMemb.getClientId()) && resp.toString().equals(MAConstants.NONE)))
									&& (!resp.toString().equals(MAConstants.SPOUSE)) && (!resp.toString().equals(MAConstants.DISABLED_PERSON_UNDER_CARE))) {
								return true;
							}
						}
					}
				}
			}
		}
		return false;
	}
	
	private static boolean checkForFE17HH(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		if (auMembRslt.getMemStatus().equals(INELIGIBLE) && !auMembRslt.getMemResponsibility().equals("INNCIT")
				&& !auMembRslt.getMemIneligReason().equals("003030")) {
			return true;
		}
		return false;
	}
	
	private static boolean checkForFE04RW(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		MAClient mAClient = maEcf.getMAClient(maEcf.getAsstUnit(ebcObject.getAuId()).getGranteeId().intValue());
		if (!BeaconUtil.isClientInCAPFS(mAClient, auMembRslt.getClientId())) {
			BaseAddr addr = null;
			addr = mAClient.getAddressCurrent();
			if (addr.getAddressId().isEmpty()) {
				addr = mAClient.getAddressMailing();
			}
			String zip = "";
			if (addr.getPostalCode().isNotEmpty() && addr.getPostalCode().toString().length() >= 5) {
				zip = addr.getPostalCode().toString().substring(0, 5);
			} else {
				return false;
			}
			Parameter parm = ParameterCache.getInstance().getParameter(maEcf.getFields().getContext(), "ABAWD WORK PROGRAM WAIVED ZIP");
			Vector<ParameterMatrixValue> pv = parm.getMatrixValues();
			for (ParameterMatrixValue pmv : pv) {
				if (pmv.getConstraintStart().equalsIgnoreCase(zip)) {
					return true;
				}
			}
		}
		return false;
	}
	
