	private static boolean checkForTEN17B(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		if (noOtherWPexempt(ebcObject, maEcf, auMembRslt, "TEN17B")) {
			MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
			if (isClientIneligNonCit(mAClient, auMembRslt)) {
				Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
				for (EDBCResultAUMember tauMembRslt : vecAUMemb) {
					if (!auMembRslt.getClientId().equals(tauMembRslt.getClientId())) {
						if ((tauMembRslt.getMemStatus().equals(PENDING) || tauMembRslt.getMemStatus().equals(ACTIVE) || tauMembRslt.getMemStatus()
								.equals(INELIG))) {
							if (!tauMembRslt.getMemResponsibility().equals("DCHFAM") && tauMembRslt.getMemResponsibility().equals("DCHSSI")
									&& maEcf.getMAClient(tauMembRslt.getClientId().intValue()).getClientAge(tauMembRslt.getClientId()) < 2) {
								return true;
							}
						}
					}
				}
			}
		}
		return false;
	}
	
