	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean checkForTE16B(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		if (mAClient.isTeenParent(auMembRslt.getClientId())) {
			IntegerData auId = mAClient.getEspAuForTheClient(auMembRslt.getClientId());
			if (auId != null) {
				Vector<AUESPAct> auEspVect = mAClient.getAUESPAct(auId);
				for (AUESPAct auESPAct : auEspVect) {
					if (!auESPAct.getPgmStructIdComp().equals(16) && !auESPAct.getPgmStructIdComp().equals(19)) {
						AUESPActDetail auESPActDetail = (AUESPActDetail) mAClient.getAUESPActDetail(auESPAct.getEspActId());
						if (auESPActDetail != null && auESPActDetail.getStatus() != null && (auESPActDetail.getStatus().equals(MAConstants.ACTIVE) || auESPActDetail.getStatus().equals(MAConstants.ACCEPTED))) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}
	
