	/**
	 * @param maEcf
	 * @param parentMember
	 * @param childMember
	 * @return
	 * @throws Exception
	 */
	private static boolean hasParentRelationship(MAECFHousehold maEcf, EDBCResultAUMember parentMember, EDBCResultAUMember childMember) throws Exception {
		MAClient mAClient = maEcf.getMAClient(parentMember.getClientId().intValue());
		HHClientPersonalRelation hhClientPrsnRel = mAClient.getHHClientPersonalRelation(childMember.getClientId(), parentMember.getClientId());
		if (hhClientPrsnRel != null
				&& (hhClientPrsnRel.getPersonalRelationCode().equals("MO") || hhClientPrsnRel.getPersonalRelationCode().equals("FA"))) {
			return true;
		}
		return false;
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param childMemb
	 * @return
	 * @throws Exception
	 */
	private static boolean noParentInAU(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember childMemb) throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		for (EDBCResultAUMember tauMembRslt : vecAUMemb) {
			if (!childMemb.getClientId().equals(tauMembRslt.getClientId())) {
				if ((tauMembRslt.getMemStatus().equals(PENDING) || tauMembRslt.getMemStatus().equals(ACTIVE) || tauMembRslt.getMemStatus().equals(
						INELIG))) {
					if (hasParentRelationship(maEcf, tauMembRslt, childMemb)) {
						return false;
					}
				}
			}
		}
		return true;
	}
	
