	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	static IntegerData getYoungestChildHH(EDBCResult ebcObject, MAECFHousehold maEcf, EDBCResultAUMember auMembRslt)
 throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		if (maEcf.getClientIDs() == null || maEcf.getClientIDs().size() == 0) {
			addHouseHoldMembers(maEcf);
		}
		Vector<IntegerData> hhMembers = null;
		if(maEcf.getFields().getContext().getContextIdentifier().equals(ContextFacade.BASE_CONTEXT_ITENTIFIER)) {
			Context deltaCtx = maEcf.getFields().getContext().copy();
			deltaCtx.setContextIdentifier(ContextFacade.DELTA_CONTEXT_ITENTIFIER);
			hhMembers = getPresentHHMembers(deltaCtx, maEcf.getHouseholdId());
		} else {
			hhMembers = maEcf.getHHmemberInPresentOrSponsorNotPresentStat();
		}
		IntegerData yngClientId = null;
		for (IntegerData clientId : hhMembers) {
			if (!auMembRslt.getClientId().equals(clientId) && (isAUMember(ebcObject, clientId) || isNameClearedPandP(ebcObject, maEcf, clientId.intValue()))) {
				if (yngClientId == null || mAClient.getClientAgeInDays(clientId) < mAClient.getClientAgeInDays(yngClientId)) {
					yngClientId = clientId;
				}
			}
		}
		return yngClientId;
	}
	
