	public static boolean isClientEssntCare(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		BaseClientCaretaker clientCaretaker = null;
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		Vector essentialVec = mAClient.getCaretaker();
		for (int i = 0; i < essentialVec.size(); i++) {
			clientCaretaker = (BaseClientCaretaker) essentialVec.elementAt(i);
			if (clientCaretaker.getCaretakerRole().equals(MAConstants.CARETAKER)) {
				ClientCaretakerDetails caretakerDetails = mAClient.getClientCaretakerDetails(clientCaretaker.getId());
				if (caretakerDetails != null && caretakerDetails.getDescriptiveStart().isNotEmpty()
				    && caretakerDetails.getDescriptiveStart().after(
				        new DateData(maEcf.getFields().getContext().getEffectiveDate()).addMonths(-12))) {
						if(ESPUtil.isClientDisabledIncapcitated(mAClient, caretakerDetails.getClientProviderId()))
						     return true;
				}
			}
		}
		return false;
	}
	
