	/**
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean isClientDisabled(MAECFHousehold maEcf, EDBCResultAUMember auMembRslt) throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
		ClientDisabilityPage disab = mAClient.getClientDisabilityPage();
		if (disab != null && disab.getDisabledFlg().isTrue()) {
			if (disab.getDeterminationStatus().equals("APPRVD")) {
				if (disab.getExpirationDt().isEmpty() || disab.getExpirationDt().after(maEcf.getFields().getContext().getEffectiveDate())) {
					return true;
				} else if (disab.getExpirationDt().isNotEmpty()) {
					ClientDisabilityDeterminationReviewTracking disabRev = mAClient.getClientDisabilityDeterminationReviewTracking();
					if (disabRev != null && disabRev.getSupplementSentDt().isNotEmpty()) {
						DateData expDtePlus45Days = new DateData(disab.getExpirationDt()).addDays(45);
						DateData expDteMinus16Days = new DateData(disab.getExpirationDt()).addDays(-16);
						if ((disabRev.getSupplementSentDt().equals(expDteMinus16Days) || disabRev.getSupplementSentDt().after(expDteMinus16Days))
								&& (disabRev.getSupplementSentDt().equals(expDtePlus45Days) || disabRev.getSupplementSentDt().before(expDtePlus45Days))) {
							return true;
						}
					}
				}
			}
			if ((disab.getDeterminationStatus().equals("PEND") && disab.getDisabilityDeterminationSrc().equals("PRO"))
					|| disab.getDisabilityDeterminationSrc().equals("APSTMT")) {
				ClientDisabilityDeterminationReviewTracking disabRevTrk = mAClient.getClientDisabilityDeterminationReviewTracking();
				if(disabRevTrk != null){
					DateData clckStart = getClockStartDate(maEcf, auMembRslt.getClientId(), BatchConstants.CLOCK_TYPE_S60);
					if (disab.getExpirationDt().isEmpty() || (clckStart != null && disab.getExpirationDt().before(clckStart))) {
						if (clckStart == null) {
							return true;
						}
						Vector<ClientDisabilityDeterminationReviewTracking> vecDisabRev = SQLMapper.getInstance()
						                .getVersionedData(maEcf.getFields().getContext(),
						                                ClientDisabilityDeterminationReviewTracking.class,
						                                auMembRslt.getClientId().intValue());
						for (ClientDisabilityDeterminationReviewTracking disabRevVer : vecDisabRev) {
							if (disabRevVer != null && disabRevVer.getDispositionDt().isNotEmpty()
							                && disabRevVer.getDispositionDt().after(clckStart)
							                && disabRevVer.getDisposition().equals("DENIED")) {
								return false;
							}
						}
						return true;
					}
					else if (disabRevTrk.getSupplementReturnDt().isNotEmpty()
					                && disabRevTrk.getSupplementSentDt().isNotEmpty()
					                && disab.getExpirationDt().isNotEmpty()) {
						if ((disabRevTrk.getSupplementReturnDt().equals(disabRevTrk.getSupplementSentDt()) || disabRevTrk
						                .getSupplementReturnDt().after(disabRevTrk.getSupplementSentDt()))
						                && (disabRevTrk.getSupplementReturnDt().equals(disab.getExpirationDt()) || disabRevTrk
						                                .getSupplementReturnDt().before(disab.getExpirationDt()))) {
							return true;
						}
					}		
				}
			}
		}
		return false;
	}
	
	/**
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static DateData getClockStartDate(MAECFHousehold maEcf, IntegerData auMembRsltClientID, String clockCode) throws Exception {
		MAClient mAClient = maEcf.getMAClient(auMembRsltClientID.intValue());
		ClientClockDetailNew clientClockDetail = null;
		Vector<ClientClockNew> clntClockVect = mAClient.getClientClockVector();
		for (ClientClockNew clntClock : clntClockVect) {
			if (clntClock.getClockCode().equals(clockCode)) {
				clientClockDetail = mAClient.getClientClckDtlNew(clntClock.getClockId());
				if (clientClockDetail != null && clientClockDetail.getClckStartDate().isNotEmpty()  &&  clientClockDetail.getClckEndDate().isNotEmpty() ) {
					if (!maEcf.getFields().getContext().getEffectiveDate().before(clientClockDetail.getClckStartDate())
					    && !maEcf.getFields().getContext().getEffectiveDate().after(clientClockDetail.getClckEndDate())) {
						return clientClockDetail.getClckStartDate();
					}
				}
			}
		}
		return null;
	}
	
