	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isTwoParentAU(EDBCResult ebcObject) throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		int count = 0;
		for (EDBCResultAUMember tauMembRslt : vecAUMemb) {
			if ((tauMembRslt.getMemStatus().equals(PENDING) || tauMembRslt.getMemStatus().equals(ACTIVE) || tauMembRslt.getMemStatus()
			    .equals(INELIG))) {
				if (isGranteeOtherParent(ebcObject, tauMembRslt)) {
					count++;
					if (count > 1) {
						return true;
					}
				}
			}
		}
		return false;
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param auMembRslt
	 * @return
	 * @throws Exception
	 */
	private static boolean isTwoTeenParentAU(EDBCResult ebcObject, MAECFHousehold maEcf) throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		int count = 0;
		for (EDBCResultAUMember auMembRslt : vecAUMemb) {
			if ((auMembRslt.getMemStatus().equals(PENDING) || auMembRslt.getMemStatus().equals(ACTIVE) || auMembRslt.getMemStatus().equals(
			    INELIG))) {
				MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
				int clientAge = mAClient.getClientAge(auMembRslt.getClientId());
				if (clientAge > 12 && clientAge < 20) {
					Vector<HHClientPersonalRelation> vecPrsnRel = mAClient.getHHClientPersonalRelations(auMembRslt.getClientId());
					for (HHClientPersonalRelation hhClientPrsnRel : vecPrsnRel) {
						if (hhClientPrsnRel.getPersonalRelationCode().equals("CHILD")) {
							if (isValidMember(ebcObject, hhClientPrsnRel.getClientRelatedId())
							    && isOtherTeenParent(ebcObject, maEcf, auMembRslt.getClientId(), hhClientPrsnRel.getClientRelatedId())) {
								return true;
							}
						}
					}
				}
			}
		}
		return false;
	}
	
	/**
	 * @param ebcObject
	 * @param clientId
	 * @return
	 * @throws Exception
	 */
	private static boolean isValidMember(EDBCResult ebcObject, IntegerData clientId) throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		for (EDBCResultAUMember auMembRslt : vecAUMemb) {
			if (auMembRslt.getClientId().equals(clientId)) {
				if ((auMembRslt.getMemStatus().equals(PENDING) || auMembRslt.getMemStatus().equals(ACTIVE) || auMembRslt.getMemStatus()
				    .equals(INELIG))) {
					return true;
				}
			}
		}
		return false;
	}
	
	

	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param teenParentId
	 * @param childId
	 * @return
	 * @throws Exception
	 */
	private static boolean isOtherTeenParent(EDBCResult ebcObject, MAECFHousehold maEcf, IntegerData teenParentId, IntegerData childId)
	    throws Exception {
		Vector<EDBCResultAUMember> vecAUMemb = ebcObject.getEdbcResultAUMemberVector();
		int count = 0;
		for (EDBCResultAUMember auMembRslt : vecAUMemb) {
			if (!auMembRslt.getClientId().equals(teenParentId) && !auMembRslt.getClientId().equals(childId))
				if ((auMembRslt.getMemStatus().equals(PENDING) || auMembRslt.getMemStatus().equals(ACTIVE) || auMembRslt.getMemStatus()
				    .equals(INELIG))) {
					MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
					int clientAge = mAClient.getClientAge(auMembRslt.getClientId());
					if (clientAge > 12 && clientAge < 20) {
						Vector<HHClientPersonalRelation> vecPrsnRel = mAClient.getHHClientPersonalRelations(auMembRslt.getClientId());
						for (HHClientPersonalRelation hhClientPrsnRel : vecPrsnRel) {
							if (hhClientPrsnRel.getPersonalRelationCode().equals("CHILD") && hhClientPrsnRel.getClientRelatedId().equals(childId)) {
								return true;
							}
						}
					}
				}
		}
		return false;
	}
	
	/**
	 * @param ctx
	 * @return
	 */
	private static DateData getEffectiveDate(Context ctx) {
		if (ctx.getBusinessUserid() == 0) {
			return ctx.getEffectiveDate().getPreviousWorkDate();
		}
		return ctx.getEffectiveDate();
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param auMembRslt
	 * @param workExemptReason
	 * @param genWorkExemptReason 
	 * @throws Exception
	 */
	public static void setWorkProgramReason(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
	                                         EDBCResultAUMember auMembRslt, String workExemptReason, String genWorkExemptReason) throws Exception {
		ClientWorkRequirementStatus camWprStat = setWorkProgramReasonR(ctx, ebcObject, maEcf, maECFRule, auMembRslt, workExemptReason,genWorkExemptReason);
		if (camWprStat != null && workExemptReason != null) {
			camWprStat = (ClientWorkRequirementStatus) camWprStat.clone(true);
			MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
			Vector<ClientWorkRequirementStatus> wpStatusVect = mAClient.getClientWorkRequirementStatus(auMembRslt.getClientId());
			int i = 0;
			boolean fnd = false;
			for (; i < wpStatusVect.size(); i++) {
				ClientWorkRequirementStatus tcamWprStat = (ClientWorkRequirementStatus) wpStatusVect.elementAt(i);
				if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
					fnd = true;
					tcamWprStat.setWorkExemptReason(camWprStat.getWorkExemptReason());
					tcamWprStat.setWorkExemptFlag(camWprStat.getWorkExemptFlag());
					tcamWprStat.setEffDate(camWprStat.getEffDate());
					tcamWprStat.setDescriptiveStart(camWprStat.getDescriptiveStart());
					tcamWprStat.setAnswerComplete(true);
					tcamWprStat.setWpSourceCode("EBCREQ");
					tcamWprStat.setVerificationId(camWprStat.getVerificationId());
					tcamWprStat.setWppuNoticeSentDate(camWprStat.getWppuNoticeSentDate());
					tcamWprStat.setWppuNoticeReason(camWprStat.getWppuNoticeReason());
					tcamWprStat.setComplianceStatusCode(camWprStat.getComplianceStatusCode());
					tcamWprStat.setComplianceEndDate(camWprStat.getComplianceEndDate());	
					tcamWprStat.setComplianceStatusReason(camWprStat.getComplianceStatusReason());
					tcamWprStat.setAbawdHours(camWprStat.getAbawdHours());
					tcamWprStat.setWpReportStatus(camWprStat.getWpReportStatus());
					tcamWprStat.setWpRreportStatusDate(camWprStat.getWpRreportStatusDate());
					camWprStat = tcamWprStat;
					break;
				}
			}
			if (fnd) {
				//wpStatusVect.setElementAt(camWprStat, i);
			}
			else {
				wpStatusVect.add(camWprStat);
			}
			if(camWprStat.hasValueChanged()) {
				camWprStat.setRequiresInsert();
			}

			((RootObject) wpStatusVect.elementAt(0)).setPersistenceSortOrder(1);
			RequestId requestId = maEcf.getRequestId();
			Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
			EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
			eligReqVerData.setEligRequestId(requestId.getReqId());
			eligReqVerData.setVerificationElementId(65);
			eligReqVerData.setClientId(camWprStat.getClientId());
			eligReqVerData.setAuId(camWprStat.getAuId());
			eligReqVerData.setVerificationValueDescription(camWprStat.formatVerificationValue());
			if(camWprStat.hasValueChanged()) {
				updateVerification(eligReqVerVec, eligReqVerData, camWprStat.getVerificationId());
				camWprStat.getVerificationId().setNull();
				camWprStat.setIsVerNeeded(true);
				camWprStat.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
				maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
				mAClient.setClientWorkRequirementStatus(wpStatusVect, auMembRslt.getClientId());
			}
			/* SR 15130 SSS - creation of default AU_ASSNMT_RECMND starts here */
			AUReAssignmentRecommendation auReAssignmentRecommendation = mAClient.retriveAUReAssignmentRecommendation(camWprStat.getAuId());
			if (camWprStat.getPgmCode().equals(MAConstants.TANF)
					&& (auReAssignmentRecommendation == null 
						||(auReAssignmentRecommendation != null
							&& auReAssignmentRecommendation.getRecommendFlg().isEmpty() 
							&& auReAssignmentRecommendation.getJobTitle().isEmpty()))) {
				mAClient.createAUReAssignmentRecommendation(camWprStat.getAuId());
			}
			/* SR 15130 SSS - creation of default AU_ASSNMT_RECMND starts here */
		}
	}
	
	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param auMembRslt
	 * @param genWorkExemptReason 
	 * @throws Exception
	 */
	public static ClientWorkRequirementStatus setWorkProgramReasonR(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf,
	                                                                MAECFHousehold maECFRule, EDBCResultAUMember auMembRslt,
			String workExemptReason, String genWorkExemptReason) throws Exception {
		MAClient mAClient = maECFRule.getMAClient(auMembRslt.getClientId().intValue());
		Vector<ClientWorkRequirementStatus> wpStatusVect = mAClient
				.getClientWorkRequirementStatus(auMembRslt.getClientId());
		DateData appDate = getApplicationDate(mAClient, auMembRslt.getAuId());
		ClientWorkRequirementStatus camWprStat = null;
		int i = 0;
		for (; i < wpStatusVect.size(); i++) {
			ClientWorkRequirementStatus tcamWprStat = (ClientWorkRequirementStatus) wpStatusVect.elementAt(i);
			if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
				camWprStat = tcamWprStat;
				break;
			}
		}
		if (camWprStat != null) {
			if (camWprStat.getWorkExemptReason().equals(workExemptReason)
					) {
				return null;
			}
			wpStatusVect.setElementAt(camWprStat, i);
		} else if (workExemptReason != null) {
			camWprStat = new ClientWorkRequirementStatus();
			camWprStat.setClientId(auMembRslt.getClientId());
			camWprStat.setAuId(auMembRslt.getAuId());
			wpStatusVect.add(camWprStat);
		}
		String prevWorkExemptReason = null;
		if (workExemptReason != null) {
			 prevWorkExemptReason = new String(camWprStat.getWorkExemptReason().toString());
			camWprStat.setPgmCode(ebcObject.getProgramCode());
			camWprStat.setEffDate(getEffectiveDate(ctx));
			camWprStat.setDescriptiveStart(appDate);
			camWprStat.setWorkExemptReason(workExemptReason);
			camWprStat.setAnswerComplete(true);
			camWprStat.setWpSourceCode("EBCREQ");
			if (camWprStat.getWppuNoticeReason().isNotEmpty() && !camWprStat.getWorkExemptReason().stringValue()
					.substring(1, 2).equalsIgnoreCase(camWprStat.getWppuNoticeReason().stringValue().substring(1, 2))) {
				camWprStat.getWppuNoticeSentDate().setNull();
				camWprStat.getWppuNoticeReason().setNull();
			}

			if (prevWorkExemptReason.length() == 0
					|| !camWprStat.getWorkExemptReason().getString().equals(prevWorkExemptReason)) {
				if (!MANDATORY_WORK.contains(workExemptReason)) {
					camWprStat.setWorkExemptFlag(true);
					camWprStat.getComplianceStatusCode().setNull();
					camWprStat.getComplianceEndDate().setNull();
					camWprStat.getComplianceStatusReason().setNull();
					camWprStat.getAbawdHours().setNull();
					camWprStat.getWpReportStatus().setNull();
					camWprStat.getWpRreportStatusDate().setNull();
				} else if(ebcObject.getProgramCode().equals(SNAP)){
					camWprStat.setWorkExemptFlag(false);
					camWprStat.setComplianceStatusCode("NOMEET");
					camWprStat.getComplianceEndDate().setNull();
				} else {
					camWprStat.setWorkExemptFlag(false);
					camWprStat.setComplianceStatusCode("MEET");
					camWprStat.setComplianceStatusReason("PART");
					camWprStat.getComplianceEndDate().setNull();
				}
			}
		}
		if(workExemptReason != null && workExemptReason.length() > 0) {
			if (ebcObject.getWorkProgramMessage().isEmpty()) {
				ebcObject.appendWorkProgramMessage(ebcObject.getProgramCode().toString());
				ebcObject.appendWorkProgramMessage(" Members|BR|");
			} else {
				ebcObject.appendWorkProgramMessage("|BR|");
			}
		}
		if (ebcObject.getProgramCode().equals(SNAP)) {
			setClientGeneralWorkRequirments(ctx, ebcObject, maEcf, maECFRule, auMembRslt, workExemptReason,
					genWorkExemptReason);

		}
		if (camWprStat != null && workExemptReason != null) {
			TypeCodeCache cache = TypeCodeCache.getInstance();
			TypeCode code = cache.getValue(mAClient.getFields().getContext(), "EXEMPT REASON", workExemptReason);
			if (ebcObject.getProgramCode().equals(SNAP)) {
				if (camWprStat.getWorkExemptFlag().isTrue()) {
					ebcObject.appendWorkProgramMessage(
							auMembRslt.getMemNam() + ": ABAWD Time Limits Not required - <![CDATA["
									+ code.getDescription().toString() + "]]>");
				} else {
					ebcObject.appendWorkProgramMessage(auMembRslt.getMemNam()
							+ ": ABAWD Time Limits Required - <![CDATA[" + code.getDescription().toString() + "]]>");
				}
			} else {
				if (camWprStat.getWorkExemptFlag().isTrue()) {
					ebcObject.appendWorkProgramMessage(auMembRslt.getMemNam() + ": Not required - <![CDATA["
							+ code.getDescription().toString() + "]]>");
				} else {
					ebcObject.appendWorkProgramMessage(auMembRslt.getMemNam() + ": Required - <![CDATA["
							+ code.getDescription().toString() + "]]>");
				}
			}

			mAClient.setClientWorkRequirementStatus(wpStatusVect, auMembRslt.getClientId());
			if (prevWorkExemptReason.length() == 0
					|| !camWprStat.getWorkExemptReason().getString().equals(prevWorkExemptReason)) {

				if (MANDATORY_WORK.contains(workExemptReason)) {
					IntegerData espAUId = mAClient.getEspAuForTheClient();
					if (espAUId == null && ebcObject.getProgramCode().equals(TANF)) {
						createESPAU(ctx, ebcObject, maEcf, maECFRule, camWprStat);
					}
				}
				setESPPartnStatus(ctx, ebcObject, maEcf, maECFRule, camWprStat);

				setWPClientEligFactor(ctx, ebcObject, maEcf, maECFRule, camWprStat);
				if (ebcObject.getProgramCode().equals(TANF)) {
					setWPClientWorkSearch(ctx, ebcObject, maEcf, maECFRule, camWprStat);
					setClientPSS(ctx, ebcObject, maEcf, maECFRule, auMembRslt, camWprStat);
				}
			}
			if (ebcObject.getProgramCode().equals(SNAP)) {
				setFsetPrtn(ctx, ebcObject, maEcf, maECFRule, camWprStat);
			}
		}

		return camWprStat;
	}
	
	
	
	private static void setClientGeneralWorkRequirments(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf,
			MAECFHousehold maECFRule, EDBCResultAUMember auMembRslt, String workExemptReason,
			String genWorkExemptReason) throws Exception {
		MAClient mAClientRule = maECFRule.getMAClient(auMembRslt.getClientId().intValue());
		ClientGeneralWorkRequirementStatus genWorkReqStatus = null;
		Vector<ClientWorkRequirementStatus> wpStatusVect = mAClientRule.getClientWorkRequirementStatus(auMembRslt.getClientId());
		DateData appDate = getApplicationDate(mAClientRule, auMembRslt.getAuId());
		if(genWorkExemptReason != null && genWorkExemptReason.length() > 0) {
			Vector<ClientGeneralWorkRequirementStatus> genWPStatusVect = mAClientRule.getClientGeneralWorkRequirementStatus(auMembRslt.getClientId());
			ClientWorkRequirementStatus camWprStat = null;
			int i = 0;
			if(workExemptReason != null && workExemptReason.length() > 0) {
				for (; i < wpStatusVect.size(); i++) {
					ClientWorkRequirementStatus tcamWprStat = (ClientWorkRequirementStatus) wpStatusVect.elementAt(i);
					if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
						camWprStat = tcamWprStat;
						break;
					}
				}
			}
			if (camWprStat != null && (genWorkExemptReason == null || genWorkExemptReason.length() ==0)) {
				if (camWprStat.getWorkExemptReason().equals(workExemptReason)) {
					return ;
				}
				wpStatusVect.setElementAt(camWprStat, i);
			} else if(camWprStat == null && workExemptReason != null && workExemptReason.length() > 0) {
				camWprStat = new ClientWorkRequirementStatus();
				camWprStat.setClientId(auMembRslt.getClientId());
				camWprStat.setAuId(auMembRslt.getAuId());
				wpStatusVect.add(camWprStat);
			}
			i = 0;
			for (; i < genWPStatusVect.size(); i++) {
				ClientGeneralWorkRequirementStatus tcamWprStat = (ClientGeneralWorkRequirementStatus) genWPStatusVect.elementAt(i);
				if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
					genWorkReqStatus = tcamWprStat;
					break;
				}
			}
			if (genWorkReqStatus != null ) {
				if (genWorkReqStatus.getWorkExemptReason().equals(genWorkExemptReason) && (camWprStat == null || camWprStat.getWorkExemptReason().equals(workExemptReason))) {
					return;
				}
				genWPStatusVect.setElementAt(genWorkReqStatus, i);
			} else {
				genWorkReqStatus = new ClientGeneralWorkRequirementStatus();
				genWorkReqStatus.setClientId(auMembRslt.getClientId());
				genWorkReqStatus.setAuId(auMembRslt.getAuId());
				genWPStatusVect.add(genWorkReqStatus);
			}
			
			String prevGenWorkExemptReason = genWorkReqStatus.getWorkExemptReason().toString();
			genWorkReqStatus.setPgmCode(ebcObject.getProgramCode());
			genWorkReqStatus.setEffDate(getEffectiveDate(ctx));
			genWorkReqStatus.setDescriptiveStart(appDate);
			genWorkReqStatus.setWorkExemptReason(genWorkExemptReason);
			genWorkReqStatus.setAnswerComplete(true);
			genWorkReqStatus.setWpSourceCode("EBCREQ");
			if (genWorkReqStatus.getWppuNoticeReason().isNotEmpty()
					&& !genWorkReqStatus.getWorkExemptReason().stringValue().substring(1, 2)
							.equalsIgnoreCase(genWorkReqStatus.getWppuNoticeReason().stringValue().substring(1, 2))) {
				genWorkReqStatus.getWppuNoticeSentDate().setNull();
				genWorkReqStatus.getWppuNoticeReason().setNull();
			}
			
			if (prevGenWorkExemptReason.length() == 0
					|| !genWorkReqStatus.getWorkExemptReason().getString().equals(prevGenWorkExemptReason)) {
				if (!EBCWorkRequirementReasonSNAP.SUBJECT_TO_GENERAL_WORK_REQUIREMENTS.contains(genWorkExemptReason)) {
					genWorkReqStatus.setWorkExemptFlag(true);
					genWorkReqStatus.getComplianceStatusCode().setNull();
					genWorkReqStatus.getComplianceEndDate().setNull();
					genWorkReqStatus.getComplianceStatusReason().setNull();
					genWorkReqStatus.getAbawdHours().setNull();
					genWorkReqStatus.getWpReportStatus().setNull();
					genWorkReqStatus.getWpRreportStatusDate().setNull();
				} else {
					genWorkReqStatus.setWorkExemptFlag(false);
					genWorkReqStatus.setComplianceStatusCode("MEET");
					genWorkReqStatus.setComplianceStatusReason("PART");
					genWorkReqStatus.getComplianceEndDate().setNull();
				}
			}
			if(genWorkReqStatus != null) {
				if (ebcObject.getWorkProgramMessage().isEmpty()) {
					ebcObject.appendWorkProgramMessage(ebcObject.getProgramCode().toString());
					ebcObject.appendWorkProgramMessage(" Members|BR|");
				} else {
					ebcObject.appendWorkProgramMessage("|BR|");
				}
				
				TypeCodeCache cache = TypeCodeCache.getInstance();
				TypeCode code = cache.getValue(mAClientRule.getFields().getContext(), "EXEMPT REASON", genWorkExemptReason);
				if (genWorkReqStatus.getWorkExemptFlag().isTrue()) {
					ebcObject.appendWorkProgramMessage(
							auMembRslt.getMemNam() + ": General Work Requirements  Not required - <![CDATA["
									+ code.getDescription().toString() + " ]]>");
				} else {
					ebcObject.appendWorkProgramMessage(auMembRslt.getMemNam()
							+ ": General Work Requirements  Required - <![CDATA[" + code.getDescription().toString() + " ]]>");
				}
				ebcObject.appendWorkProgramMessage("|BR|");
				mAClientRule.setClientGeneralWorkRequirement(genWPStatusVect, auMembRslt.getClientId());
				MAClient mAClient = maEcf.getMAClient(auMembRslt.getClientId().intValue());
				genWPStatusVect = mAClient.getClientGeneralWorkRequirementStatus(auMembRslt.getClientId());
				genWorkReqStatus = (ClientGeneralWorkRequirementStatus) genWorkReqStatus.clone(true);
			
				 i = 0;
				boolean fnd = false;
				for (; i < genWPStatusVect.size(); i++) {
					ClientGeneralWorkRequirementStatus tcamWprStat = (ClientGeneralWorkRequirementStatus) genWPStatusVect.elementAt(i);
					if (tcamWprStat.getAuId().equals(auMembRslt.getAuId())) {
						fnd = true;
						tcamWprStat.setWorkExemptReason(genWorkReqStatus.getWorkExemptReason());
						tcamWprStat.setWorkExemptFlag(genWorkReqStatus.getWorkExemptFlag());
						tcamWprStat.setEffDate(genWorkReqStatus.getEffDate());
						tcamWprStat.setDescriptiveStart(genWorkReqStatus.getDescriptiveStart());
						tcamWprStat.setAnswerComplete(true);
						tcamWprStat.setWpSourceCode("EBCREQ");
						tcamWprStat.setVerificationId(genWorkReqStatus.getVerificationId());
						tcamWprStat.setWppuNoticeSentDate(genWorkReqStatus.getWppuNoticeSentDate());
						tcamWprStat.setWppuNoticeReason(genWorkReqStatus.getWppuNoticeReason());
						tcamWprStat.setComplianceStatusCode(genWorkReqStatus.getComplianceStatusCode());
						tcamWprStat.setComplianceEndDate(genWorkReqStatus.getComplianceEndDate());	
						tcamWprStat.setComplianceStatusReason(genWorkReqStatus.getComplianceStatusReason());
						tcamWprStat.setAbawdHours(genWorkReqStatus.getAbawdHours());
						tcamWprStat.setWpReportStatus(genWorkReqStatus.getWpReportStatus());
						tcamWprStat.setWpRreportStatusDate(genWorkReqStatus.getWpRreportStatusDate());
						genWorkReqStatus = tcamWprStat;
						break;
					}
				}
				if (fnd) {
					//genWPStatusVect.setElementAt(genWorkReqStatus, i);
				}
				else {
					genWPStatusVect.add(genWorkReqStatus);
				}
				if(genWorkReqStatus.hasValueChanged()){
					genWorkReqStatus.setRequiresInsert();
				}
				
				//((RootObject) genWPStatusVect.elementAt(0)).setPersistenceSortOrder(1);
				genWorkReqStatus.setPersistenceSortOrder(1);
				RequestId requestId = maEcf.getRequestId();
				Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
				EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
				eligReqVerData.setEligRequestId(requestId.getReqId());
				eligReqVerData.setVerificationElementId(390);
				eligReqVerData.setClientId(genWorkReqStatus.getClientId());
				eligReqVerData.setAuId(genWorkReqStatus.getAuId());
				eligReqVerData.setVerificationValueDescription(genWorkReqStatus.formatVerificationValue());
				if(genWorkReqStatus.hasValueChanged()){
					updateVerification(eligReqVerVec, eligReqVerData, genWorkReqStatus.getVerificationId());
					genWorkReqStatus.getVerificationId().setNull();
					genWorkReqStatus.setIsVerNeeded(true);
					genWorkReqStatus.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
					maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
					mAClient.setClientGeneralWorkRequirement(genWPStatusVect, auMembRslt.getClientId());
					if(genWorkReqStatus.getWorkExemptFlag().isNotEmpty() && genWorkReqStatus.getWorkExemptFlag().isTrue()) {
						
						Vector<ClientWorkRequirementStatus> clientWprStatVect = mAClient.getClientWorkRequirementStatus(auMembRslt.getClientId());

						i = 0;
						for (; i < clientWprStatVect.size(); i++) {
							ClientWorkRequirementStatus clientWprStat = (ClientWorkRequirementStatus) clientWprStatVect.elementAt(i);
							if (clientWprStat.getAuId().equals(auMembRslt.getAuId())) {
								clientWprStat.getWorkExemptReason().setNull();
								clientWprStat.getWorkExemptFlag().setNull();
								clientWprStat.getComplianceStatusCode().setNull();
								clientWprStat.getComplianceStatusReason().setNull();
								clientWprStat.getAbawdHours().setNull();
								clientWprStat.setEffDate(genWorkReqStatus.getEffDate());
								clientWprStat.setDescriptiveStart(genWorkReqStatus.getDescriptiveStart());
								clientWprStat.setAnswerComplete(true);
								clientWprStat.setWpSourceCode("EBCREQ");
								clientWprStat.setVerificationId(genWorkReqStatus.getVerificationId());
								clientWprStat.setRequiresInsert();
								clientWprStatVect.setElementAt(clientWprStat, i);
								((RootObject) clientWprStatVect.elementAt(0)).setPersistenceSortOrder(1);
								mAClient.setClientWorkRequirementStatus(clientWprStatVect, auMembRslt.getClientId());
								break;
							}
						}
					}
				}
				
			}
		}
	}

	/**
	 * @param ctx
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param camWprStat
	 * @throws Exception
	 */
	public static void setESPPartnStatus(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
	                                      ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient mAClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
		
		BaseAU baseAU = mAClient.getESPParentAU();
		if (baseAU != null && baseAU.getId().equals(ebcObject.getAuId())) {
			ClientAUMembESPParticipationStatus camEspStat = setESPPartnStatusR(ctx, ebcObject, maECFRule, camWprStat);
			if (camEspStat != null) {
				IntegerData espAUId = mAClient.getEspAuForTheClient();
				if (espAUId != null) {
					camEspStat = (ClientAUMembESPParticipationStatus) camEspStat.clone(true);
					camEspStat.setPersistenceSortOrder(1);
					camEspStat.setRequiresInsert();
					RequestId requestId = maEcf.getRequestId();
					Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
					EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
					eligReqVerData.setEligRequestId(requestId.getReqId());
					eligReqVerData.setVerificationElementId(71);
					eligReqVerData.setClientId(camEspStat.getClientId());
					eligReqVerData.setAuId(camEspStat.getAuId());
					eligReqVerData.setVerificationValueDescription(camEspStat.formatVerificationValue());
					updateVerification(eligReqVerVec, eligReqVerData, camEspStat.getVerificationId());
					camEspStat.getVerificationId().setNull();
					camEspStat.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
					maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
					mAClient.setClientAUMembESPParticipationStatus(camEspStat);
				}
			}
		}
	}
	
	
	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	public static ClientAUMembESPParticipationStatus setESPPartnStatusR(Context ctx, EDBCResult ebcObject, MAECFHousehold maECFRule,
	                                                                    ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient mAClient = maECFRule.getMAClient(camWprStat.getClientId().intValue());
		ClientAUMembESPParticipationStatus camEspStat = mAClient.getClientAUMembESPParticipationStatus(camWprStat.getClientId());
		IntegerData espAUId = mAClient.getEspAuForTheClient();
		if (espAUId != null) {
			if (camEspStat == null) {
				camEspStat = new ClientAUMembESPParticipationStatus();
				camEspStat.setClientId(camWprStat.getClientId());
				camEspStat.setAuId(espAUId);
			}
			camEspStat.setEffDate(getEffectiveDate(ctx));
			camEspStat.setDescriptiveStart(getEffectiveDate(ctx));
			camEspStat.setEspComplianceStatus(MAConstants.MEET);
			camEspStat.setEspComplianceStatusReason("PART");
			if (camWprStat.getWorkExemptReason().stringValue().substring(1, 2).equalsIgnoreCase("E")) {
				camEspStat.setEspParticipationStatusReason("ESPRQD");
			}
			else {
				camEspStat.setEspParticipationStatusReason("WPR");
			}
			camEspStat.setAnswerComplete(true);
			mAClient.setClientAUMembESPParticipationStatus(camEspStat);
			return camEspStat;
		}
		return null;
	}
	
	public static void insertWFUpdateOnline(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf) throws Exception{
		WorkflowStateUpdateReq workflowStateUpdateReq = new WorkflowStateUpdateReq();
		workflowStateUpdateReq.setClientId(maEcf.getAsstUnit(ebcObject.getAuId()).getGranteeId());
		workflowStateUpdateReq.setHouseHoldId(maEcf.getHouseholdId());
		workflowStateUpdateReq.setIntervewSessEffDate(ctx.getEffectiveDate());
		workflowStateUpdateReq.setOnlineFlag(true);
		workflowStateUpdateReq.setRequiresInsert();
		maEcf.getFields().setField(WorkflowStateUpdateReq.class, workflowStateUpdateReq.getClientId(),
		                workflowStateUpdateReq);
	}
	
	/**
	 * @param ctx
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param camWprStat
	 * @throws Exception
	 */
	public static void createESPAU(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
      ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient maClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
		MAClient maClientR = maECFRule.getMAClient(camWprStat.getClientId().intValue());
		IntegerData espAUId = maClient.getEspAuForTheClient();
		if (espAUId != null) {
			Vector<BaseClientAUMember> auMembVector = maClient.getAllClientAUMembers();
			for (BaseClientAUMember clientAuMemb : auMembVector) {
				if (clientAuMemb.getAuId().equals(espAUId)) {
					BaseAUStatus baseAuStatus = maClient.getAUStatus(clientAuMemb.getAuId());
					if (baseAuStatus.getStatus().equals(MAConstants.CLOSED)) {
						DateData effectiveDte = maClient.getFields().getContext().getEffectiveDate();
						
						baseAuStatus.setStatus(PENDING);
						baseAuStatus.setEffDate(effectiveDte);
						baseAuStatus.setRequiresUpdate();
						maClient.setAUStatus(baseAuStatus, baseAuStatus.getAuId());
						BaseAUStatus baseAuStatusR = (BaseAUStatus)baseAuStatus.clone(true);
						maClientR.setAUStatus(baseAuStatusR, baseAuStatusR.getAuId());

						// au sub type
						AUSubType subType = new AUSubType();
						subType.setAuId(clientAuMemb.getAuId());
						subType.getPgmStructId().setInteger(MAConstants.PGM_STRUCT_150BASIC);
						subType.setEffDate(effectiveDte);
						subType.setRequiresUpdate();
						maClient.setAUSubType(subType, subType.getAuId());
						AUSubType subTypeR = (AUSubType)subType.clone(true);
						maClientR.setAUSubType(subTypeR, subType.getAuId());

						BaseAU parentBaseAU = maClient.getAsstUnit(camWprStat.getAuId());
						BaseAUAssignment baseAUAssignment = new BaseAUAssignment();
						baseAUAssignment.setAnswerComplete(true);
						baseAUAssignment.setClientId(clientAuMemb.getClientId());
						baseAUAssignment.setAuId(clientAuMemb.getAuId());
						baseAUAssignment.setBuId(parentBaseAU.getBuId());
						baseAUAssignment.setRequiresUpdate();
						maClient.setAUAssignment(baseAUAssignment, baseAUAssignment.getAuId());
						BaseAUAssignment baseAUAssignmentR = (BaseAUAssignment)baseAUAssignment.clone(true);
						maClientR.setAUAssignment(baseAUAssignmentR, baseAUAssignmentR.getAuId());

						ReferralAUAssignment referralAUAssignment = new ReferralAUAssignment();
						referralAUAssignment.setAnswerComplete(true);
						referralAUAssignment.setClientId(clientAuMemb.getClientId());
						referralAUAssignment.setAuId(clientAuMemb.getAuId());
						referralAUAssignment.setBuId(parentBaseAU.getBuId());
						referralAUAssignment.setRequiresUpdate();
						maClient.setAUAssignment(referralAUAssignment, referralAUAssignment.getAuId());
						ReferralAUAssignment referralAUAssignmentR = (ReferralAUAssignment)referralAUAssignment.clone(true);
						maClientR.setAUAssignment(referralAUAssignmentR, referralAUAssignmentR.getAuId());

						// create au parent if not established or re set eff date
						createAUParent(maClient, camWprStat.getAuId(), clientAuMemb.getAuId(), true);
						createAUParent(maClientR, camWprStat.getAuId(), clientAuMemb.getAuId(), true);

						// client au memb status
						clientAuMemb.setAuMemberStatusCode(PENDING);
						clientAuMemb.setEffDate(effectiveDte);
						clientAuMemb.setRequiresUpdate();
						
						Vector<BaseClientAUMember> auMembVectorR = maClientR.getAllClientAUMembers();
						for (BaseClientAUMember clientAuMembR : auMembVectorR) {
							if (clientAuMembR.getAuId().equals(espAUId)) {
								clientAuMembR.setAuMemberStatusCode(PENDING);
								clientAuMembR.setEffDate(effectiveDte);
								clientAuMembR.setRequiresUpdate();
								break;
							}
						}
						if(ctx.getBusinessUserid() != 0){
							insertWFUpdateOnline(ctx, ebcObject, maEcf);
						}
					}
					else {
						// create if au parent is not established
						createAUParent(maClient,  camWprStat.getAuId(), clientAuMemb.getAuId(), false);
						createAUParent(maClientR, camWprStat.getAuId(), clientAuMemb.getAuId(), false);
					}
				}
			}
			// set to fields kernel if there was a status update
			maClient.setClientAUMember(auMembVector);
		}
		else {
			createNewESPAU(ctx, ebcObject, maEcf, maECFRule, camWprStat);
		}
	}
	
	
	
	
	public static void createAUParent(MAClient maClient, IntegerData parentAUID, IntegerData espAUId, boolean reactivate)
 throws Exception {
		Vector<AUParent> vAUParent = maClient.getAUParent(espAUId);
		boolean parentExists = false;
		for (AUParent auParent : vAUParent) {
			if (auParent.getAuParentId().equals(parentAUID)) {
				if (reactivate) {
					auParent.setParentEffDate(maClient.getFields().getContext().getEffectiveDate());
					auParent.getParentEndDate().setNull();
					auParent.setRequiresUpdate();
					parentExists = true;
					break;
				}
				return;
			}
		}
		if (!parentExists) {
			AUParent auParent = new AUParent();
			auParent.setAuId(espAUId);
			auParent.setAuParentId(parentAUID);
			auParent.setParentEffDate(maClient.getFields().getContext().getEffectiveDate());
			auParent.setRequiresInsert();
			vAUParent.add(auParent);

		}
		maClient.setAUParent(vAUParent, espAUId);
	}
	
	public static void createNewESPAU(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
      ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient maClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
		MAClient maClientR = maECFRule.getMAClient(camWprStat.getClientId().intValue());
		BaseAUMember members = new BaseAUMember();
		DateData effectiveDte = ctx.getEffectiveDate();
		IntegerData pgmStructId = new IntegerData(MAConstants.PGM_STRUCT_150BASIC);
		BaseAU baseAU = new BaseAU();
		baseAU.setProgramCode(MAConstants.JOBS);
		baseAU.setRequiresInsert();
		baseAU.setPersistenceSortOrder(0);
		maClient.setAsstUnit(baseAU, baseAU.getId());
		
		BaseAU baseAUR = (BaseAU)baseAU.clone(true);
		baseAUR.noPersistenceActionRequired();
		
		maClientR.setAsstUnit(baseAUR, baseAUR.getId());
		
		
		BaseAUStatus baseAUStatus = new BaseAUStatus();
		baseAUStatus.setRequiresInsert();
		baseAUStatus.setPersistenceSortOrder(1);
		baseAUStatus.setAuId(baseAU.getId());
		baseAUStatus.setStatus(PENDING);
		baseAUStatus.setEffDate(effectiveDte);
		maClient.setAUStatus(baseAUStatus, baseAU.getId());
		
		BaseAUStatus baseAUStatusR = (BaseAUStatus)baseAUStatus.clone(true);
		baseAUStatusR.noPersistenceActionRequired();
		maClientR.setAUStatus(baseAUStatusR, baseAU.getId());
		
		AUSubType subType = new AUSubType();
		subType.setAuId(baseAU.getId());
		subType.setRequiresInsert();
		subType.setPersistenceSortOrder(1);
		subType.setPgmStructId(pgmStructId);
		subType.setEffDate(effectiveDte);
		maClient.setAUSubType(subType, baseAU.getId());
		
		AUSubType subTypeR = (AUSubType)subType.clone(true);
		subTypeR.noPersistenceActionRequired();
		maClientR.setAUSubType(subTypeR, baseAU.getId());
		
		BaseAUAssignment baseAUAssignment = new BaseAUAssignment();
		ReferralAUAssignment referralAUAssignment = new ReferralAUAssignment();

		baseAUAssignment.setRequiresInsert();
		baseAUAssignment.noPersistenceActionRequired();
		baseAUAssignment.setAuId(baseAU.getId());

		referralAUAssignment.setRequiresInsert();
		referralAUAssignment.setAnswerComplete(true);
		referralAUAssignment.setPersistenceSortOrder(1);
		referralAUAssignment.setClientId(maClient.getId());
		referralAUAssignment.setAuId(baseAU.getId());
		
		BaseAU parentBaseAU = maClient.getAsstUnit(camWprStat.getAuId());
		baseAUAssignment.setBuId(parentBaseAU.getBuId());
		referralAUAssignment.setBuId(parentBaseAU.getBuId());
		maClient.setAUAssignment(referralAUAssignment, baseAU.getId());
		
		ReferralAUAssignment referralAUAssignmentR = (ReferralAUAssignment)referralAUAssignment.clone(true);
		referralAUAssignmentR.noPersistenceActionRequired();
		maClientR.setAUAssignment(referralAUAssignmentR, baseAU.getId());

		AUParent auParent = new AUParent();
		auParent.setRequiresInsert();
		auParent.setPersistenceSortOrder(1);
		auParent.setAuId(baseAU.getId());
		auParent.setAuParentId(camWprStat.getAuId());
		auParent.setParentEffDate(effectiveDte);
		Vector vAUParent = new Vector();
		vAUParent.add(auParent);
		maClient.setAUParent(vAUParent, baseAU.getId());
		AUParent auParentR = (AUParent)auParent.clone(true);
		auParentR.noPersistenceActionRequired();
		Vector vAUParentR = new Vector();
		vAUParent.add(auParentR);
		maClientR.setAUParent(vAUParentR, baseAU.getId());
		

		BaseClientAUMember clientAUMember = new BaseClientAUMember();
		clientAUMember.setRequiresInsert();
		clientAUMember.setPersistenceSortOrder(1);
		clientAUMember.setAuId(baseAU.getId());
		clientAUMember.setClientId(camWprStat.getClientId());
		clientAUMember.setAuRoleCode(MAConstants.GRANTEE);
		clientAUMember.setAuMemberStatusCode(PENDING);
		clientAUMember.setEffDate(effectiveDte);


		/*Vector membersVector = maClient.getAllMembersInAU(camWprStat.getAuId());
		if (membersVector == null) {
			membersVector = new Vector();
		}*/
		Vector membersVector = new Vector();
		members.setAuId(baseAU.getId());
		members.setClientId(camWprStat.getClientId());
		members.setAuMemberStatusCode(PENDING);
		members.setAuRoleCode(MAConstants.GRANTEE);
		members.noPersistenceActionRequired();
		membersVector.addElement(members);
		maClient.getFields().setField(BaseAUMember.class, baseAU.getId(), membersVector, BaseAU.class.getName());
		maClientR.getFields().setField(BaseAUMember.class, baseAU.getId(), membersVector, BaseAU.class.getName());
		
		Vector auMembVector = maClient.getAllClientAUMembers();
		auMembVector.addElement(clientAUMember);
		maClient.setClientAUMember(auMembVector, camWprStat.getClientId());
		
		Vector auMembVectorR = maClientR.getAllClientAUMembers();
		BaseClientAUMember clientAUMemberR = (BaseClientAUMember)clientAUMember.clone(true);
		clientAUMemberR.noPersistenceActionRequired();
		auMembVectorR.addElement(clientAUMemberR);
		maClientR.setClientAUMember(auMembVectorR, camWprStat.getClientId());
		if(ctx.getBusinessUserid() != 0){
			insertWFUpdateOnline(ctx, ebcObject, maEcf);
		}
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	public static void setWPClientEligFactor(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
	                                          ClientWorkRequirementStatus camWprStat) throws Exception {
		ClientAUMembEligFact clientEligFactor = setWPClientEligFactorR(ctx, ebcObject, maECFRule, camWprStat);
		if (clientEligFactor != null) {
			clientEligFactor = (ClientAUMembEligFact) clientEligFactor.clone(true);
			MAClient mAClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
			Vector clientEligFactorVect = mAClient.getClientAUMembEligFact(mAClient.getId());
			int i = 0;
			boolean fnd = false;
			for (; i < clientEligFactorVect.size(); i++) {
				ClientAUMembEligFact tclientEligFactor = (ClientAUMembEligFact) clientEligFactorVect.elementAt(i);
				if (tclientEligFactor.getAuId().equals(camWprStat.getAuId()) && tclientEligFactor.getEligFactor().equals("WKPROG")) {
					fnd = true;
					break;
				}
			}
			if (fnd) {
				clientEligFactorVect.setElementAt(clientEligFactor, i);
			}
			else {
				clientEligFactorVect.add(clientEligFactor);
			}
			((RootObject) clientEligFactorVect.elementAt(0)).setPersistenceSortOrder(1);
			clientEligFactor.setPersistenceSortOrder(1);
			clientEligFactor.setRequiresInsert();
			RequestId requestId = maEcf.getRequestId();
			Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
			EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
			eligReqVerData.setEligRequestId(requestId.getReqId());
			eligReqVerData.setVerificationElementId(90);
			eligReqVerData.setClientId(clientEligFactor.getClientId());
			eligReqVerData.setAuId(clientEligFactor.getAuId());
			eligReqVerData.setVerificationValueDescription(clientEligFactor.formatVerificationValue());
			updateVerification(eligReqVerVec, eligReqVerData, clientEligFactor.getVerificationId());
			clientEligFactor.getVerificationId().setNull();
			clientEligFactor.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
			maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
			mAClient.setClientAUMembEligFact(clientEligFactorVect);
		}
	}
	
	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	public static ClientAUMembEligFact setWPClientEligFactorR(Context ctx, EDBCResult ebcObject, MAECFHousehold maECFRule,
	                                                          ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient mAClient = maECFRule.getMAClient(camWprStat.getClientId().intValue());
		Vector clientEligFactorVect = mAClient.getClientAUMembEligFact(mAClient.getId());
		ClientAUMembEligFact clientEligFactor = null;
		int i = 0;
		for (; i < clientEligFactorVect.size(); i++) {
			ClientAUMembEligFact tclientEligFactor = (ClientAUMembEligFact) clientEligFactorVect.elementAt(i);
			if (tclientEligFactor.getAuId().equals(camWprStat.getAuId()) && tclientEligFactor.getEligFactor().equals("WKPROG")) {
				clientEligFactor = tclientEligFactor;
				break;
			}
		}
		if (clientEligFactor != null) {
			clientEligFactorVect.setElementAt(clientEligFactor, i);
		}
		else {
			clientEligFactor = new ClientAUMembEligFact();
			clientEligFactor.setClientId(camWprStat.getClientId());
			clientEligFactor.setAuId(camWprStat.getAuId());
			clientEligFactorVect.add(clientEligFactor);
		}
		clientEligFactor.setEligFactor("WKPROG");
		clientEligFactor.setEffDate(getEffectiveDate(ctx));
		if (camWprStat.getWorkExemptReason().stringValue().substring(1, 2).equalsIgnoreCase("E")) {
			clientEligFactor.setWpExemptFlag(true);
			clientEligFactor.setEligFactorReason("009000");
			clientEligFactor.setEligStatus("FAIL");
		}
		else {
			clientEligFactor.setWpExemptFlag(false);
			clientEligFactor.setEligFactorReason("009001");
			clientEligFactor.setEligStatus("PASS");
		}
		clientEligFactor.setPgmCode(camWprStat.getPgmCode());
		BaseAUMember ssnInfo = mAClient.getGranteeForAU(clientEligFactor.getAuId());
		if (ssnInfo != null) {
			clientEligFactor.setSsn(mAClient.getBaseClient(ssnInfo.getClientId()).getSsn());
		}
		mAClient.setClientAUMembEligFact(clientEligFactorVect);
		clientEligFactor.setAnswerComplete(true);
		return clientEligFactor;
	}
	
