	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	private static ClientAUMembWorkProgramSearch setWPClientWorkSearchR(Context ctx, EDBCResult ebcObject, MAECFHousehold maECFRule,
	                                                                    ClientWorkRequirementStatus camWprStat) throws Exception {
		if (!camWprStat.getWorkExemptReason().stringValue().substring(1, 2).equalsIgnoreCase("E")) {
			MAClient mAClient = maECFRule.getMAClient(camWprStat.getClientId().intValue());
			ClientAUMembWorkProgramSearch workProgramSearch = mAClient.getClientAUMembWorkProgramSearch(camWprStat.getClientId(), camWprStat
			    .getAuId());
			if (workProgramSearch == null
					|| workProgramSearch.getWorkSearchStartDate().isNull()
					|| workProgramSearch.getWorkSearchEndDate().isNull()) {
				workProgramSearch = new ClientAUMembWorkProgramSearch();
				workProgramSearch.setClientId(camWprStat.getClientId());
				workProgramSearch.setAuId(camWprStat.getAuId());
				workProgramSearch.setWorkSearchStartDate(ctx.getEffectiveDate());
				workProgramSearch.setWorkSearchEndDate(new DateData(ctx.getEffectiveDate()).addDays(60));
				mAClient.setClientAUMembWorkProgramSearch(workProgramSearch, camWprStat.getClientId());
				return workProgramSearch;
			} else {
				DateData clockStart = getClockStartDate(maECFRule, camWprStat.getClientId(), BatchConstants.CLOCK_TYPE_S60);
				if (clockStart != null && workProgramSearch.getWorkSearchEndDate().before(clockStart)) {
					workProgramSearch.setWorkSearchStartDate(ctx.getEffectiveDate());
					workProgramSearch.setWorkSearchEndDate(new DateData(ctx.getEffectiveDate()).addDays(60));
					mAClient.setClientAUMembWorkProgramSearch(workProgramSearch, camWprStat.getClientId());					
					return workProgramSearch;
				}
			}
		}
		return null;
	}
	
	/**
	 * @param ctx
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param auMembRslt
	 * @param camWprStat
	 * @throws Exception
	 */
	private static void setClientPSS(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
			EDBCResultAUMember auMembRslt, ClientWorkRequirementStatus camWprStat) throws Exception {
		ClientPSS clientPSS = setClientPSSR(ctx, ebcObject, maECFRule, auMembRslt, camWprStat);
		if (clientPSS != null) {
			clientPSS = (ClientPSS) clientPSS.clone(true);
			clientPSS.setRequiresInsert();
			MAClient mAClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
			Vector<ClientPSS> clientPSSVect = mAClient.getFields().getFields(ClientPSS.class, mAClient.getId());
			clientPSSVect.add(0, clientPSS);
			mAClient.getFields().setField(ClientPSS.class, mAClient.getId(), clientPSSVect);
		}
	}

	/**
	 * @param ctx
	 * @param ebcObject
	 * @param maECFRule
	 * @param auMembRslt
	 * @param camWprStat
	 * @return
	 * @throws Exception
	 */
	private static ClientPSS setClientPSSR(Context ctx, EDBCResult ebcObject, MAECFHousehold maECFRule, EDBCResultAUMember auMembRslt,
			ClientWorkRequirementStatus camWprStat) throws Exception {
		MAClient mAClient = maECFRule.getMAClient(camWprStat.getClientId().intValue());
		if (isGranteeOtherParent(ebcObject, auMembRslt)) {
			ClientAUMembESPParticipationStatus camEspStat = mAClient.getClientAUMembESPParticipationStatus(camWprStat.getClientId());
			if (!camWprStat.getWorkExemptFlag().isTrue()
					|| (camEspStat != null && (camEspStat.getEspParticipationStatusReason().equals("ESPRQD") || camEspStat.getEspParticipationStatusReason().equals("VOL")))) {
				ebcObject.setInsWFReqd(true);
				Vector<ClientPSS> clientPSSVect = mAClient.getFields().getFields(ClientPSS.class, mAClient.getId());
				if (clientPSSVect.size() > 0) {
					BEACONAUEligReevaluation eligReevaluation = mAClient.getBEACONAUEligReevaluation(camWprStat.getAuId());
					if (eligReevaluation !=null && eligReevaluation.getInitiatedFlag().isTrue() && eligReevaluation.getCompleteDate().isEmpty()) {
						ClientPSS clientPSS = clientPSSVect.elementAt(0);
						if (clientPSS.getEffDate().before(eligReevaluation.getInitiatedDate())) {
							return mAClient.createClientPSS(ctx, eligReevaluation.getRevalEndDate());
						} 
					}
				} else {
					DateData dueDate = new DateData(ctx.getEffectiveDate());
					dueDate = dueDate.addDays(60);
					if (dueDate.isHoliday()) {
						dueDate = dueDate.getNextWorkDate();
					}
					return mAClient.createClientPSS(ctx, dueDate);
				}
			}
		}
		return null;
	}
	
	/**
	 * @param ebcObject
	 * @param maEcf
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	private static void setFsetPrtn(Context ctx, EDBCResult ebcObject, MAECFHousehold maEcf, MAECFHousehold maECFRule,
			ClientWorkRequirementStatus camWprStat) throws Exception {
		ClientAuFsetPrtn clientAuFsetPrtn = setFsetPrtnR(ctx, ebcObject, maECFRule, camWprStat);
		if (clientAuFsetPrtn != null) {
			clientAuFsetPrtn = (ClientAuFsetPrtn) clientAuFsetPrtn.clone(true);
			MAClient mAClient = maEcf.getMAClient(camWprStat.getClientId().intValue());
			clientAuFsetPrtn.setPersistenceSortOrder(1);
			clientAuFsetPrtn.setRequiresInsert();
			RequestId requestId = maEcf.getRequestId();
			Vector eligReqVerVec = maEcf.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
			EligibilityRequestVerData eligReqVerData = new EligibilityRequestVerData();
			eligReqVerData.setEligRequestId(requestId.getReqId());
			eligReqVerData.setVerificationElementId(70);
			eligReqVerData.setClientId(clientAuFsetPrtn.getClientId());
			eligReqVerData.setAuId(clientAuFsetPrtn.getAuId());
			eligReqVerData.setVerificationValueDescription(clientAuFsetPrtn.formatVerificationValue());
			updateVerification(eligReqVerVec, eligReqVerData, clientAuFsetPrtn.getVerificationId());
			clientAuFsetPrtn.getVerificationId().setNull();
			clientAuFsetPrtn.getVerificationId().addPropertyChangeListener(eligReqVerData.getVerId());
			maEcf.setEligReqVerData(eligReqVerVec, requestId.getReqId().intValue());
			mAClient.setClientAuFsetPrtn(clientAuFsetPrtn);
			((RootObject) mAClient.getClientAuFsetPrtnVec().elementAt(0)).setPersistenceSortOrder(1);
		}
	}
	
	/**
	 * @param ebcObject
	 * @param maECFRule
	 * @param camWprStat
	 * @param prevWorkExemptReason
	 * @throws Exception
	 */
	private static ClientAuFsetPrtn setFsetPrtnR(Context ctx, EDBCResult ebcObject, MAECFHousehold maECFRule,
	                                                                    ClientWorkRequirementStatus camWprStat) throws Exception {
			MAClient mAClient = maECFRule.getMAClient(camWprStat.getClientId().intValue());
			ClientAuFsetPrtn clientAuFsetPrtn = mAClient.getClientAuFsetPrtn(camWprStat.getAuId());
			if (clientAuFsetPrtn == null) {
				clientAuFsetPrtn = new ClientAuFsetPrtn();
				clientAuFsetPrtn.setClientId(camWprStat.getClientId());
				clientAuFsetPrtn.setAuId(camWprStat.getAuId());
			}
			clientAuFsetPrtn.setEffDate(ctx.getEffectiveDate());
			clientAuFsetPrtn.setFsetExemptFlag(true);
			clientAuFsetPrtn.getComplianceStatusCode().setNull();
			clientAuFsetPrtn.getComplianceStatusReason().setNull();
			clientAuFsetPrtn.getComplianceEndDate().setNull();
			clientAuFsetPrtn.getVoluntaryParticipantFlag().setNull();
			clientAuFsetPrtn.setDescriptiveStart(ctx.getEffectiveDate());
			clientAuFsetPrtn.setAnswerComplete(true);
			if(camWprStat.getWorkExemptReason().equals("FE04TE")){
				clientAuFsetPrtn.setWorkProgramExemptReason("FE04TE");
			} else {
				clientAuFsetPrtn.setWorkProgramExemptReason("FE13VP");
			}
			return clientAuFsetPrtn;
	}
	/**
	 * @param vEligReqVerData
	 * @param newEligReqVerData
	 * @param oldVerId
	 */
	private static void updateVerification(Vector<EligibilityRequestVerData> vEligReqVerData,
	                                EligibilityRequestVerData newEligReqVerData, IntegerData oldVerId) {
		if (oldVerId.isNotEmpty()) {
			for (int i = 0; i < vEligReqVerData.size(); i++) {
				EligibilityRequestVerData eligReqVerData = vEligReqVerData.elementAt(i);
				if (eligReqVerData.getVerId().equals(oldVerId)) {
					if (eligReqVerData.getCreateTimestamp().isEmpty()) {
						vEligReqVerData.removeElementAt(i--);
					}
					else {
						eligReqVerData.setRequiresDelete();
					}
				} 
			}
		}
		newEligReqVerData.setRequiresInsert();
		vEligReqVerData.addElement(newEligReqVerData);
	}
	

	/**
	 * This data set for pre rules processing for TBA calculations.
	 *
	 * @param ebcObject
	 *            rules generated object
	 * @param maEcf
	 *            a MACEFHousehold object
	 * @param wfData
	 *            a MAClient data
	 * @throws Exception
	 */
	public static void setPreResultDataForTBACalculation(EDBCResult ebcObject, MAECFHousehold maEcf, MAClient wfData)
	                throws Exception {
		Enumeration interviewWrapUpEDBCResultEnum = null;
		EDBCResultFinancial edbcResultFinancial = null;
		String recoupenType = "";
		Recoupment recoupment = null;
		double resultAmt = 0.0;
		int resultCount = 0;
		double asset = 0.0;
		double assetLimit = 0.0;
		DoubleData benefitAmt = new DoubleData(0.0);
		DoubleData recoupAmt = new DoubleData(0.0);
		DoubleData grantAmt = new DoubleData(0.0);
		DoubleData iRSDepGrantAmt = new DoubleData(0.0);
		BooleanData isFEPSupplementCalculated = new BooleanData();
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		EDBCResultFinancial eDBCResultFinancial = null;
		EDBCResultFinancial tmpEDBCResultFinancial = null;
		Vector ebcResultVec = maEcf.getInterviewWrapUpEDBCResults();
		if (ebcObject.getProgramCode().toString().equals(EA)) {
			if (ebcResultVec != null && ebcResultVec.size() > 0) {
				interviewWrapUpEDBCResultEnum = ebcResultVec.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					if ((interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getProgram().isNotEmpty())
					                && ((interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF) || interviewWrapUpEDBCResult
					                                .getProgram().toString().equalsIgnoreCase(EAEDC)))) {
						benefitAmt = interviewWrapUpEDBCResult.getBenefitAmount();
						recoupment = (Recoupment) wfData.getFields().getField(Recoupment.class,
						                interviewWrapUpEDBCResult.getAuId());
						if (recoupment != null) {
							recoupAmt = recoupment.getRecoupmentAmount();
						}
						if (benefitAmt != null && recoupAmt != null) {
							grantAmt = new DoubleData(benefitAmt.doubleValue() + recoupAmt.doubleValue());
						}
						ebcObject.setGrantAmount(ebcObject.getGrantAmount().doubleValue() + grantAmt.doubleValue());
					}
				}
			}
		}
		ebcResultVec = maEcf.getInterviewWrapUpEDBCResults();
		if (ebcObject.getProgramCode().toString().equals(SNAP)) {
			BaseAUMember granteememb = wfData.getGranteeForAU(ebcObject.getAuId());
			if (ebcResultVec != null && ebcResultVec.size() > 0) {
				interviewWrapUpEDBCResultEnum = ebcResultVec.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					boolean financialEligibility = false;
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					if ((interviewWrapUpEDBCResult.getProgram().equals(TANF) && !interviewWrapUpEDBCResult
					                .getGranteeId().equals(granteememb.getClientId()))
					                || interviewWrapUpEDBCResult.getProgram().equals(EAEDC)) {
						/*
						 * For each TANF and EAEDC result (cashResult) where the grantee is a member in the SNAP AU,
						 * accumulate: ebcObj.GrantAmount += cashResult.BEN_AMT ebcObj.GrantAmount +=
						 * cashResult.Recoupment if recoupment was an intentional type of recoupment
						 * (cashResult.RecoupmentType = AI, TI or SI) ebcObj.IRSDependentGrant += cashResult.IRSDepGrant
						 * ebcObj.VendorPaymentAmount += cashResult.VendorPayment ebcObj.FSAttributedAmount +=
						 * cashResult.FSAttributedAmount if cash program is TANF and cashResult.AUSize > 0
						 */
						/*
						 * if (recal && !isVerificationSelected(maEcf, wfData, interviewWrapUpEDBCResult.getAuId(),
						 * VER_DATA_ID_140, true, false)) { double prevBenefitAmount =
						 * getPreviousBenefitAmountValue(maEcf, interviewWrapUpEDBCResult .getAuId(),
						 * interviewWrapUpEDBCResult); benefitAmt = new DoubleData(prevBenefitAmount); }
						 */
						// else {
						benefitAmt = interviewWrapUpEDBCResult.getBenefitAmount();
						// }
						ebcObject.setGrantAmount(ebcObject.getGrantAmount().doubleValue() + benefitAmt.doubleValue());
						edbcResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT, RECOUPMENTELEMENT);
						recoupenType = getFinancialObjectStringValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE);
						double recoupmentAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue()
						                .isNotEmpty()) ? Double.parseDouble(edbcResultFinancial.getValue().toString())
						                : 0.00;
						recoupment = (Recoupment) wfData.getFields().getField(Recoupment.class,
						                interviewWrapUpEDBCResult.getAuId());
						if (recoupmentAmt > 0
						                && (recoupenType.equals(AI) || recoupenType.equals(TI) || recoupenType
						                                .equals(SI))) {
							grantAmt = new DoubleData(ebcObject.getGrantAmount().doubleValue() + recoupmentAmt);
							ebcObject.setGrantAmount(grantAmt.doubleValue());
						}

						iRSDepGrantAmt = interviewWrapUpEDBCResult.getIRSDepGrant();
						ebcObject.setIRSDependentGrant(ebcObject.getIRSDependentGrant().doubleValue()
						                + iRSDepGrantAmt.doubleValue());

						eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT, VENDORPAYMENT);
						if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
							resultAmt = Double.parseDouble(eDBCResultFinancial.getValue().toString());
							ebcObject.setVendorPaymentAmount(ebcObject.getVendorPaymentAmount().doubleValue()
							                + resultAmt);
						}
						eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
						                FINANCIALELIGIBILITYSTATUS);
						if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
						                && eDBCResultFinancial.getValue().toString().equalsIgnoreCase(ELIG)) {
							financialEligibility = true;
						}
						// if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)) {
						eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, AUSIZE);
						if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
							resultCount = Integer.parseInt(eDBCResultFinancial.getValue().toString());
						}
						if (resultCount > 0 && financialEligibility) {
							eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(GROSSINCOME,
							                FSATTRIBUTEDAMOUNT);
							if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
								resultAmt = Double.parseDouble(eDBCResultFinancial.getValue().toString());
								ebcObject.setFSAttributedAmount(ebcObject.getFSAttributedAmount().doubleValue()
								                + resultAmt);
							}
						}
					}
					if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)) {
						eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(ASSETS, ASSETLIMIT);
						tmpEDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(ASSETS, ASSETS);
						if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
						                && tmpEDBCResultFinancial != null
						                && tmpEDBCResultFinancial.getValue().isNotEmpty()) {
							assetLimit = Double.parseDouble(eDBCResultFinancial.getValue().toString());
							asset = Double.parseDouble(tmpEDBCResultFinancial.getValue().toString());
							if (asset > assetLimit) {
								// ebcObject.tafdcAssetsIneligible = "Y"
							}
						}
						eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT, BUDGETINGMETHOD);
						if (ebcObject.getFutureFSAUSubtype(maEcf, wfData).equals(PUBLIC_ASSISTANCE)
						                && ebcObject.isFSGranteeAlsoTafdcGrantee(maEcf, wfData,
						                                interviewWrapUpEDBCResult.getAuId())
						                && eDBCResultFinancial.getValue().equals("Retrospective")) {
							setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Retrospective");
							ebcObject.setIncomeSourceType(RETROSPECTIVE);
						}
						else {
							setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Prospective");
							ebcObject.setIncomeSourceType(PROSPECTIVE);
						}
						/*
						 * ebcObj.TAFDCisFEPSupplementCalculated = Y if any TANF result with an active status has
						 * result.isFEPSupplementCalculated = Y
						 */
						if (interviewWrapUpEDBCResult != null) {
							eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
							                ISFEPSUPPLEMENTCALCULATED);
						}
						if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()) {
							isFEPSupplementCalculated = new BooleanData(eDBCResultFinancial.getValue().toString());
						}
						if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)
						                && interviewWrapUpEDBCResult.getStatus().toString().equals(ACTIVE)
						                && isFEPSupplementCalculated.isNotEmpty() && isFEPSupplementCalculated.isTrue()) {
							ebcObject.setTafdcIsFEPSupplementCalculated(true);
						}
					}
				}
			}
			setPreCatEligFlag(ebcObject, maEcf, interviewWrapUpEDBCResult, wfData);
			setPreCatEligReason(ebcObject, maEcf, interviewWrapUpEDBCResult, wfData);
		}
	}

	/**
	 * This method sets the cat elig reason for pre rules processing.
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param whRule
	 *            a MACFHousehold object
	 * @param interviewWrapUpEDBCResult
	 *            a view object
	 * @param wfData
	 *            a MAClient object
	 * @throws Exception
	 */
	public static void setPreCatEligReason(EDBCResult ebcObject, MAECFHousehold whRule,
	                                    InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, MAClient wfData)
	                throws Exception {
		//for historical re-calc prior to SR10044 Expanded Categorical Eligibility
		DateData dateConstantSR10044 = new DateData(2011,6,5);  //7-5-2011
		if (whRule.getFields().getContext().getEffectiveDate().before(dateConstantSR10044)) {
			setCatEligReason(ebcObject, whRule,interviewWrapUpEDBCResult, wfData);
			return;
		}
		EDBCResultAUMember fsRsltAUMember = null;
		Enumeration fsAUMembEnum;
		if (ebcObject.getPreCatEligFlag().isNotEmpty() && ebcObject.getPreCatEligFlag().isFalse()) {
			ebcObject.getPreCatEligReason().setNull();
			return;
		}
		boolean elderlyFlg = false;
		boolean disabilityFlg = false;
		boolean childFlg = false;
		boolean isNPA = (ebcObject.getFutureFSAUSubtype(whRule, wfData).equals(NON_PUBLIC_ASSISTANCE));
		Vector fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		if (fsAUMembVect != null && fsAUMembVect.size() > 0) {
			ebcObject.getPreCatEligReason().setNull();
			fsAUMembEnum = fsAUMembVect.elements();
			if (eachPendOrActiveFSMembAU(ebcObject, whRule, interviewWrapUpEDBCResult, wfData)) {
				ebcObject.setPreCatEligReason(EAEDC);
				return;
			}
			while (fsAUMembEnum.hasMoreElements()) {
				fsRsltAUMember = (EDBCResultAUMember) fsAUMembEnum.nextElement();
				if (!isNPA && (isDependentChildInAUWithMAECF(wfData, fsRsltAUMember.getClientId(), ebcObject.getAuId(),
				                whRule)
				                || isActiveOrPendingClientIsPregnant(ebcObject, wfData))) {
					ebcObject.setPreCatEligReason(TANF);
					return;
				}
				else if (isNPA) {
					if (isDependentChildInAUWithMAECF(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId(), ebcObject.getAuId(),
					                whRule)) {
						childFlg = true;					
					}
					if (isActiveOrPendingClientIsPregnant(ebcObject, wfData)) {
					childFlg = true;
					}
					if (fsRsltAUMember.getMemStatus().isNotEmpty() && (fsRsltAUMember.getMemStatus().equals(PENDING) || fsRsltAUMember.getMemStatus().equals(ACTIVE))) {
						// to determind SNAP AU's are elderly
						if (isElderlyClient(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId())) {
							elderlyFlg = true;
						}
						
							// to determine SNAP AU's are disabled
						ClientDisabilityPage clientDisability = wfData.getClientDisabilityPage(fsRsltAUMember.getClientId());
						if (clientDisability != null && ebcObject != null
						                && clientDisability.getDisabledFlg().booleanValue()
						                && ebcObject.isFSFederallyCertified(wfData, clientDisability)) {
							disabilityFlg = true;
						}	
					}					
				}
			}
			if (isNPA){
				if (elderlyFlg || disabilityFlg) {
					//group 1
					ebcObject.setPreCatEligReason(TANF);
					ebcObject.setPreCatEligGroup(NPA_TANF_ELDERLY_OR_DISABLED);
				}
				else if (childFlg) {
					//group 2
					ebcObject.setPreCatEligReason(TANF);
					ebcObject.setPreCatEligGroup(NPA_TANF_FAMILY);
				}
				else {
					//group 3
					ebcObject.setPreCatEligReason(TANF);
					ebcObject.setPreCatEligGroup(NPA_TANF_ADULTS);
				}
			}
		}
	}
	/**
	 * This method sets the cat elig reason for pre rules processing
	 * for Historical Re-calculations prior to 7/5/2011
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param whRule
	 *            a MACFHousehold object
	 * @param interviewWrapUpEDBCResult
	 *            a view object
	 * @param wfData
	 *            a MAClient object
	 * @throws Exception
	 */
	public static void setCatEligReason(EDBCResult ebcObject, MAECFHousehold whRule,
	                                    InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, MAClient wfData)
	                throws Exception {
		EDBCResultAUMember fsRsltAUMember = null;
		Enumeration fsAUMembEnum;
		if (ebcObject.getPreCatEligFlag().isNotEmpty() && ebcObject.getPreCatEligFlag().isFalse()) {
			ebcObject.getPreCatEligReason().setNull();
			return;
		}
		Vector fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		if (fsAUMembVect != null && fsAUMembVect.size() > 0) {
			ebcObject.getPreCatEligReason().setNull();
			fsAUMembEnum = fsAUMembVect.elements();
			while (fsAUMembEnum.hasMoreElements()) {
				fsRsltAUMember = (EDBCResultAUMember) fsAUMembEnum.nextElement();
				if (eachPendOrActiveFSMembAU(ebcObject, whRule, interviewWrapUpEDBCResult, wfData)) {
					ebcObject.setPreCatEligReason(EAEDC);
					return;
				}
				else if (isDependentChildInAUWithMAECF(wfData, fsRsltAUMember.getClientId(), ebcObject.getAuId(),
				                whRule)
				                || isActiveOrPendingClientIsPregnant(ebcObject, wfData)) {
					ebcObject.setPreCatEligReason(TANF);
					return;
				}
			}
		}
	}

	public static boolean eachPendOrActiveFSMembAU(EDBCResult ebcObject, MAECFHousehold whRule,
	                                               InterviewWrapUpEDBCResult rsltObj, MAClient wfData) throws Exception {
		int fsMembCnt = 0;
		int eaedcMembCnt = 0;
		Vector<EDBCResultAUMember> eaedcAUMembVec = null;
		String[] otherIncomeType = { SUPP_SEC_INC };
		Vector<EDBCResultAUMember> fsAUMembVect = null;
		Vector<InterviewWrapUpEDBCResult> ebcResultVec = whRule.getInterviewWrapUpEDBCResults();
		fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		for (EDBCResultAUMember fsMemb : fsAUMembVect) {
			if (fsMemb.getMemStatus().equals(PENDING) || fsMemb.getMemStatus().equals(ACTIVE)) {
				boolean eaedcMemFlag = false;
				fsMembCnt++;
				for (InterviewWrapUpEDBCResult eaedcRslt : ebcResultVec) {
					if (eaedcRslt.getProgram().equals(EAEDC)
					                && !resultHasClosureConditions(whRule, wfData, eaedcRslt, ebcObject)) {
						eaedcAUMembVec = eaedcRslt.getAuMembResults();
						for (EDBCResultAUMember eaedcMemb : eaedcAUMembVec) {
							if (eaedcMemb.getClientId().equals(fsMemb.getClientId())
							                && (eaedcMemb.getMemStatus().equals(PENDING) || eaedcMemb.getMemStatus()
							                                .equals(ACTIVE))) {
								eaedcMembCnt++;
								eaedcMemFlag = true;
							}
						}
					}
				}
				if (!eaedcMemFlag && ebcObject.isOtherIncomeType(wfData, fsMemb.getClientId(), otherIncomeType)) {
					eaedcMembCnt++;
				}
				if (!eaedcMemFlag && ebcObject.getAPHasSSIPreQual(whRule, wfData)) {
					eaedcMembCnt++;
				}
			}
		}
		if (fsMembCnt > 0 && (fsMembCnt == eaedcMembCnt)) {
			return true;
		}
		return false;
	}

	/**
	 * Method to check any SNAP Member has responsibility of "Other Disqualified"
	 *
	 * @param fsMembVec
	 * @return
	 * @throws Exception
	 */
	public static boolean anyFSMembHasRespOfOtherDisqualified(Vector<EDBCResultAUMember> fsMembVec) throws Exception {
		for (EDBCResultAUMember fsRsltMemb : fsMembVec) {
			if (fsRsltMemb.getMemResponsibility().equals(OTHER_DISQUALIFIED)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * This method sets the cat elig flag for pre rules processing.
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param whRule
	 *            a MACFHousehold object
	 * @param interviewWrapUpEDBCResult
	 *            a view object
	 * @param wfData
	 *            a MAClient object
	 * @throws Exception
	 */
	public static void setPreCatEligFlag(EDBCResult ebcObject, MAECFHousehold whRule,
	                                  InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, MAClient wfData)
	                throws Exception {
		//for historical re-calc prior to SR10044 Expanded Categorical Eligibility
		DateData dateConstantSR10044 = new DateData(2011,6,5);  //7-5-2011
		if (whRule.getFields().getContext().getEffectiveDate().before(dateConstantSR10044)) {
			setCatEligFlag(ebcObject, whRule,interviewWrapUpEDBCResult, wfData);
			return;
		}
		//Extended Categorical Eligibility applies to Expedited SNAP as of 03/02/2015
		Parameter p = ParameterCache.getInstance().getParameter(whRule.getFields().getContext(), EBC_EXPEDITED_CAT_ELIG_DATE_PARAM);
		DateData myExpeditedExpCatEligEffDte = null;
		if (p != null) {
			myExpeditedExpCatEligEffDte = new DateData(p.getParameterValue());
		}
		Vector fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		EDBCResultAUMember fsRsltAUMember = null;
		boolean allAdultsFlg = true;
		if (whRule.isExpeditedFS(ebcObject.getAuId()) && (myExpeditedExpCatEligEffDte == null || whRule.getFields().getContext().getEffectiveDate().before(myExpeditedExpCatEligEffDte))) {
			ebcObject.setPreCatEligFlag(false);
			return;
		}
		else if (fsAUMembVect != null && fsAUMembVect.size() > 0) {
			Enumeration fsAUMembEnum = fsAUMembVect.elements();
			ebcObject.setPreCatEligFlag(false);
			boolean isNPA = (ebcObject.getFutureFSAUSubtype(whRule, wfData).equals(NON_PUBLIC_ASSISTANCE));
			while (fsAUMembEnum.hasMoreElements()) {
				fsRsltAUMember = (EDBCResultAUMember) fsAUMembEnum.nextElement();
				/*if (anyFSMembHasRespOfOtherDisqualified(fsAUMembVect)) {
					ebcObject.setPreCatEligFlag(false);
					return;
				}*/
				if (fsRsltAUMember.checkIsDisqualifiedIndividualsForPartA(wfData, fsAUMembVect)) {
					ebcObject.setPreCatEligFlag(false);
					return;
				}
				else if (eachPendOrActiveFSMembAU(ebcObject, whRule, interviewWrapUpEDBCResult, wfData)) {
					ebcObject.setPreCatEligFlag(true);
					return;
				}
				else if (isDependentChildInAUWithMAECF(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId(), ebcObject.getAuId(),
				                whRule)
				                || isActiveOrPendingClientIsPregnant(ebcObject, wfData)) {
					ebcObject.setPreCatEligFlag(true);
					return;
				}
				else if (isNPA) {
					if (fsRsltAUMember.getMemStatus().isNotEmpty() && (fsRsltAUMember.getMemStatus().equals(PENDING) || fsRsltAUMember.getMemStatus().equals(ACTIVE))) {
						// to determind SNAP AU's are elderly
						if (isElderlyClient(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId())) {
							ebcObject.setPreCatEligFlag(true);
							return;
						}
						else {
							// to determine SNAP AU's are disabled
							ClientDisabilityPage clientDisability = wfData.getClientDisabilityPage(fsRsltAUMember
							                .getClientId());
							if (clientDisability != null && ebcObject != null
							                && clientDisability.getDisabledFlg().booleanValue()
							                && ebcObject.isFSFederallyCertified(wfData, clientDisability)) {
								ebcObject.setPreCatEligFlag(true);
								return;
							}
							else if (isDependentAgeClient(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId())
									&& !fsRsltAUMember.getClientId().equals(ebcObject.getGranteeSSN().getClientId())) {
									allAdultsFlg = false;
									/*  #134066 defect fix : a child can be present in HH for sup type NPA */
									ebcObject.setPreCatEligFlag(true);
							}
						}	
					}
					
				}
			}
			if (isNPA && allAdultsFlg) {
				// AU consists of all adults
				ebcObject.setPreCatEligFlag(true);
				return;
			}
		}
		else {
			ebcObject.setPreCatEligFlag(false);
			return;
		}
	}

	/**
	 * This method sets the cat elig flag for pre rules processing 
	 * for historical re-calculations prior to 7-5-2011
	 * 
	 * @param ebcObject
	 *            rules generated object
	 * @param whRule
	 *            a MACFHousehold object
	 * @param interviewWrapUpEDBCResult
	 *            a view object
	 * @param wfData
	 *            a MAClient object
	 * @throws Exception
	 */
	public static void setCatEligFlag(EDBCResult ebcObject, MAECFHousehold whRule,
	                                  InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, MAClient wfData)
	                throws Exception {
		/**
		 * ebcObj.CatEligFlag (Categorically Eligible) is set according to the first matching condition below:  N
		 * when the SNAP AU is expedited  N when any SNAP AU member has a Result Responsibility of Other Disqualified
		 * (OTHRDQ)  Y when each pending/active members of the SNAP AU meet any one of the following conditions: 
		 * pending/active in an EAEDC result and the EAEDC result does not meet Result has Closure Conditions (see
		 * appendix).  receiving SSI income  commonVals.APHasSSIPreQual is true  Y when there is a Dependent Child In
		 * AU (see appendix) or there is only one pending/active member in the AU and that one member is pregnant  N
		 * for all other situations
		 */
		Vector fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		EDBCResultAUMember fsRsltAUMember = null;
		if (whRule.isExpeditedFS(ebcObject.getAuId())) {
			ebcObject.setPreCatEligFlag(false);
			return;
		}
		else if (fsAUMembVect != null && fsAUMembVect.size() > 0) {
			Enumeration fsAUMembEnum = fsAUMembVect.elements();
			ebcObject.setPreCatEligFlag(false);
			while (fsAUMembEnum.hasMoreElements()) {
				fsRsltAUMember = (EDBCResultAUMember) fsAUMembEnum.nextElement();
				/* Cat Elig change (BUG133392) */
				/*if (anyFSMembHasRespOfOtherDisqualified(fsAUMembVect)) {
					ebcObject.setPreCatEligFlag(false);
					return;
				}*/
				if (fsRsltAUMember.checkIsDisqualifiedIndividualsForPartA(wfData, fsAUMembVect)) {
					ebcObject.setPreCatEligFlag(false);
					return;
				}
				else if (eachPendOrActiveFSMembAU(ebcObject, whRule, interviewWrapUpEDBCResult, wfData)) {
					ebcObject.setPreCatEligFlag(true);
					return;
				}
				else if (isDependentChildInAUWithMAECF(whRule.getMAClient(whRule.getPrimaryClientId()), fsRsltAUMember.getClientId(), ebcObject.getAuId(),
				                whRule)
				                || isActiveOrPendingClientIsPregnant(ebcObject, wfData)) {
					ebcObject.setPreCatEligFlag(true);
					return;
				}
			}
		}
		else {
			ebcObject.setPreCatEligFlag(false);
			return;
		}
	}

	/**
	 * To check whether active or pending client is pregnant.
	 * 
	 * @param auMembVect
	 *            a collection
	 * @param ebcResultAUMember
	 *            a rule members
	 * @param wfData
	 *            a MAClient object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isActiveOrPendingClientIsPregnant(EDBCResult ebcObject, 
	                                                        MAClient wfData) throws Exception {
		int cnt = 0;
		boolean isPregnant = false;
		
		EDBCResultAUMember fsRsltAUMember = null;
		Vector fsAUMembVect = null;
		Enumeration fsAUMembEnum;
		fsAUMembVect = ebcObject.getEdbcResultAUMemberVector();
		if (fsAUMembVect != null && fsAUMembVect.size() > 0) {
			fsAUMembEnum = fsAUMembVect.elements();
			while (fsAUMembEnum.hasMoreElements()) {
				fsRsltAUMember = (EDBCResultAUMember) fsAUMembEnum.nextElement();
				if (fsRsltAUMember.getMemStatus().isNotEmpty()
				                && (fsRsltAUMember.getMemStatus().toString().equals(PENDING) || fsRsltAUMember
				                                .getMemStatus().toString().equals(ACTIVE))) {
					cnt++;
					BaseClientPregnancy baseClientPregnancy = wfData.getBaseClientPregnancy(fsRsltAUMember.getClientId());
					if (baseClientPregnancy != null && baseClientPregnancy.getPregnancyFlg().booleanValue()) {
						isPregnant = true;
					}
				}
			}
			if (cnt == 1 && isPregnant) {
				return true;
			}
		}
		return false;
	}

	/**
	 * Returns a maecfhousehold object with conext "C".
	 * @param maECFHousehold
	 * @return
	 * @throws Exception
	 */
	public static MAECFHousehold getMAECFHouseholdBase(MAECFHousehold maECFHousehold) throws Exception {
		Context context = maECFHousehold.getFields().getContext();
		String key = "BASE_MAECF";
		MAECFHousehold maECFHouseholdBase = (MAECFHousehold) context.getAttribute(key);
		if (maECFHouseholdBase == null) {
			maECFHouseholdBase = (MAECFHousehold) maECFHousehold.clone(true);
			Context baseContext = context.copy();
			baseContext.setContextIdentifier(ContextFacade.BASE_CONTEXT_ITENTIFIER);
			maECFHouseholdBase.getFields().setContext(baseContext);
			maECFHouseholdBase.setContext(baseContext);
			context.setAttribute(key, maECFHouseholdBase);
		}
		return maECFHouseholdBase;
	}
	
	/**
	 * Method for creating a result object with rules generated values.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            Rules object
	 * @return view
	 * @throws Exception
	 */
	public static InterviewWrapUpEDBCResult createNewResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                              MAClient maClientDelta, MAECFHousehold whRule,
	                                                              MAClient maClientRule, EDBCResult ebcObject)
	                throws Exception {
		BaseAU asstUnit = (maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getPrimaryClientId()))
		                .getAsstUnit(ebcObject.getAuId());
		if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(TANF)) {
			return createNewTAFDCResultObject(maECFHouseholdDelta, maClientDelta, whRule, maClientRule, ebcObject,
			                asstUnit);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(SNAP)) {
			return createNewFSResultObject(maECFHouseholdDelta, maClientDelta, whRule, maClientRule, ebcObject,
			                asstUnit);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(EAEDC)) {
			return createNewEAEDCResultObject(maECFHouseholdDelta, maClientDelta, whRule, maClientRule, ebcObject,
			                asstUnit);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(EA)) {
			return createNewEAResultObject(maECFHouseholdDelta, maClientDelta, whRule, maClientRule, ebcObject,
			                asstUnit);
		}
		return null;
	}

