		BaseAUStatus assistUnitStatus = maClientRule.getAssistUnitStatus(ebcObject.getAuId());
		if (assistUnitStatus != null) {
			interviewWrapUpEDBCResult.setStatusDate(assistUnitStatus.getEffDate());
			interviewWrapUpEDBCResult.setBenefitEffective(assistUnitStatus.getBenefitEffDate());
		}

		Vector auInEligFactorVector = maClientRule.getAuInEligFactor(ebcObject.getAuId());
		if (auInEligFactorVector != null && auInEligFactorVector.size() > 0) {
			AuInEligFactor auInEligFactor = (AuInEligFactor) auInEligFactorVector.get(0);
			interviewWrapUpEDBCResult.setAuEligFactor(auInEligFactor.getEligFactor());
			interviewWrapUpEDBCResult.setAuEligFactorStatus(auInEligFactor.getEligStatus());
			interviewWrapUpEDBCResult.setAuEFRC(auInEligFactor.getEligFactorReason());
		}

		AUSubType auSubType = (AUSubType) maClientRule.getFields().getField(AUSubType.class, asstUnit.getId());
		if (auSubType != null) {
			interviewWrapUpEDBCResult.setPgmStructParId(auSubType.getPgmStructId());
			interviewWrapUpEDBCResult.setPgmSubTypeDate(auSubType.getEffDate());
		}
		setPgmSubTypeDescription(interviewWrapUpEDBCResult, maClientDelta);
