	/**
	 * Method for creating a result object with rules generated values.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            Rules object
	 * @return view
	 * @throws Exception
	 */
	public static InterviewWrapUpEDBCResult createResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                           MAECFHousehold maECFRule, EDBCResult ebcObject,
	                                                           int clientId) throws Exception {
		BaseAUStatus auStat = maECFHouseholdDelta.getMAClient(clientId).getAssistUnitStatus(ebcObject.getAuId());
		BaseAU asstUnit = (maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getPrimaryClientId()))
		                .getAsstUnit(ebcObject.getAuId());
		if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(TANF)) {
			return createTAFDCResultObject(maECFHouseholdDelta, maECFRule, ebcObject, auStat, clientId);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(SNAP)) {
			return createFSResultObject(maECFHouseholdDelta, maECFRule, ebcObject, auStat, clientId);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(EAEDC)) {
			return createEAEDCResultObject(maECFHouseholdDelta, maECFRule, ebcObject, auStat, clientId);
		}
		else if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
		                && asstUnit.getProgramCode().toString().equalsIgnoreCase(EA)) {
			return createEAResultObject(maECFHouseholdDelta, maECFRule, ebcObject, auStat, clientId);
		}
		return null;
	}

	/**
	 * Returns vector of InterviewWrapUpEDBCResult object of the specified AU program code.
	 * 
	 * @param maECFHousehold
	 *            MAECFHousehold object.
	 * @param programCode
	 *            AU program code
	 * @return vector of InterviewWrapUpEDBCResult object
	 * @throws Exception
	 *             Any exception ocurring during the process.
	 */
	public static Vector getInterviewWrapUpEDBCResultsAU(MAECFHousehold maECFHousehold, String programCode)
	                throws Exception {
		Vector interviewWrapUpEDBCResultAUVect = new Vector();
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		Vector interviewWrapUpEDBCResultVect = getInterviewWrapUpEDBCResults(maECFHousehold, maECFHousehold
		                .getRequestId().getReqId(), false);
		if (interviewWrapUpEDBCResultVect != null && interviewWrapUpEDBCResultVect.size() > 0) {
			Enumeration interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
			while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
				if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
				                && programCode.equalsIgnoreCase(interviewWrapUpEDBCResult.getProgram().toString())) {
					interviewWrapUpEDBCResultAUVect.add(interviewWrapUpEDBCResult);
				}
			}
		}
		return interviewWrapUpEDBCResultAUVect;
	}

	/**
	 * Returns double value of the EDBCResultFinancial value.
	 * 
	 * @param interviewWrapUpEDBCResult
	 *            InterviewWrapUpEDBCResult object.
	 * @param category
	 *            XML Category name.
	 * @param element
	 *            XML Element name.
	 * @return double value.
	 * @throws Exception
	 *             ...
	 */
	public static double getFinancialObjectDoubleValue(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                                   String category, String element) throws Exception {
		double value = 0;
		EDBCResultFinancial eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(category, element);
		if (eDBCResultFinancial != null && eDBCResultFinancial.getCategory().isNotEmpty()
		                && eDBCResultFinancial.getElement().isNotEmpty()
		                && eDBCResultFinancial.getCategory().toString().equals(category)
		                && eDBCResultFinancial.getElement().toString().equals(element)
		                && eDBCResultFinancial.getValue().isNotEmpty()) {
			try {
				NumberFormat format = NumberFormat.getInstance();
				Number number = (Number) format.parse(eDBCResultFinancial.getValue().toString());
				value = number.doubleValue();
			}
			catch (NumberFormatException nfe) {
				value = 0;
			}
		}
		return value;
	}

