	/**
	 * This method create the result object for the TANF Program.
	 * 
	 * @param maECFHouseholdDelta
	 *            holds data for maECFHousehold for Delta schema
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            holds data for EBC Object
	 * @param asstUnit
	 *            the Assist Unit Object
	 * @return the InterviewWrapUpEDBCResult Object
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static InterviewWrapUpEDBCResult createTAFDCResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                                MAECFHousehold maECFRule, EDBCResult ebcObject,
	                                                                BaseAUStatus auStat, int clientId) throws Exception {

		AUExemptStatus auExemptStatus = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = new InterviewWrapUpEDBCResult();
		Recoupment recoupment = null;
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		// Created a result obj with the initial value of being set from the delta db for au related data.
		interviewWrapUpEDBCResult.setAuId(ebcObject.getAuId());
		interviewWrapUpEDBCResult.setRequestId(ebcObject.getRequestId());
		interviewWrapUpEDBCResult.setProgram(ebcObject.getProgramCode());
		interviewWrapUpEDBCResult.setStatus(auStat.getStatus());

		BaseAUStatus assistUnitStatus = maClientRule.getAssistUnitStatus(ebcObject.getAuId());
		if (assistUnitStatus != null) {
			interviewWrapUpEDBCResult.setStatusDate(assistUnitStatus.getEffDate());
			interviewWrapUpEDBCResult.setBenefitEffective(assistUnitStatus.getBenefitEffDate());
		}

		Vector auInEligFactorVector = maClientRule.getAuInEligFactor(ebcObject.getAuId());
		if (auInEligFactorVector != null && auInEligFactorVector.size() > 0) {
			AuInEligFactor auInEligFactor = (AuInEligFactor) auInEligFactorVector.get(0);
			interviewWrapUpEDBCResult.setAuEligFactor(auInEligFactor.getEligFactor());
			interviewWrapUpEDBCResult.setAuEligFactorStatus(auInEligFactor.getEligStatus());
			interviewWrapUpEDBCResult.setAuEFRC(auInEligFactor.getEligFactorReason());
		}

		AUSubType auSubType = (AUSubType) maClientRule.getFields().getField(AUSubType.class, auStat.getAuId());
		if (auSubType != null) {
			interviewWrapUpEDBCResult.setPgmStructParId(auSubType.getPgmStructId());
			interviewWrapUpEDBCResult.setPgmSubTypeDate(auSubType.getEffDate());
		}
		setPgmSubTypeDescription(interviewWrapUpEDBCResult, maClientDelta);

		// Initilization starts here
		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ZERO);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARD, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, PAYMENTSTANDARDAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CHILDSUPPORTSANCTIONREDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, JOBSSANCTIONREDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS, "");
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS, "");
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, EXEMPTIONSTATUSREASON, "");
		//setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, RENTALLOWANCE, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ISFEPSUPPLEMENTCALCULATED, "");

		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMETESTED, ZERO_DOUBLE_VALUE);		
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FULLEMPLOYMENT, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, WORKRELATEDEXPENSES, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEEARNED, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEUNEARNED, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEDEEMED, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CURRENT_CHILD_SUPPORT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, VENDORPAYMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, ZERO_DOUBLE_VALUE);
		setFinancialValueInteger(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMMONTHSINELIGIBLE, ZERO);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMREMAININGAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PENALTYENDDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CLOTHINGALLOWANCE, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FEPSUPPLEMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, EBCBENEFITEFFECTIVEDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BENEFITCHANGEREASONS, "");
		setFinancialValue(interviewWrapUpEDBCResult, NOTICES, NOTICETYPE, "");
		if(ebcObject.getWorkNumberFlag().isNotEmpty()){
			setFinancialValue(interviewWrapUpEDBCResult, NOTICES, WORKNUMBERFLAG, ebcObject.getWorkNumberFlag().toString());
		}
		// Initilization ends here

		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ebcObject.getHouseHoldSize(
		                maClientRule).intValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARD, ebcObject.getNeedStandardAmount()
		                .doubleValue()
		                + ebcObject.getClothingAllowanceGrantAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, PAYMENTSTANDARDAMOUNT, BeaconUtil.getRoundMoneyWithTwoDecimal(ebcObject.getPaymentStandardAmount()
        .doubleValue()));
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CHILDSUPPORTSANCTIONREDUCTION, ebcObject
		                .getChildSupportSanctionReduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, JOBSSANCTIONREDUCTION, ebcObject
                .getJobsSanctionReduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, FINANCIALELIGIBILITYSTATUS, ebcObject
		                .getFinancialEligibilityStatus().stringValue());
		AUMonthlyReportReqd aUMonthlyReportReqd = maClientDelta.getAUMonthlyReportReqd(ebcObject.getAuId());
		if (aUMonthlyReportReqd != null && aUMonthlyReportReqd.getExists().isNotEmpty()
		                && aUMonthlyReportReqd.getExists().isTrue()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS, YES);
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS, NO);
		}
		auExemptStatus = maClientRule.getAUExemptStatus(ebcObject.getAuId());
		if (auExemptStatus != null && auExemptStatus.getAuExemptStatus().isNotEmpty()
		                && auExemptStatus.getAuExemptStatus().toString().equalsIgnoreCase(EXMPT)) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS, STATUS_EXEMPT);
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS, STATUS_NON_EXEMPT);
		}
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ISFEPSUPPLEMENTCALCULATED, NO);

		if (auExemptStatus != null) {
			TypeCodeCache cache = TypeCodeCache.getInstance();
			TypeCode code = cache.getValue(maClientDelta.getFields().getContext(), "AU EXEMPT REASON", auExemptStatus
			                .getAuExemptReason().toString());
			interviewWrapUpEDBCResult.setTafdcauExemptStatus(auExemptStatus.getAuExemptReason());
			if (code != null) {
				setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, EXEMPTIONSTATUSREASON, code
				                .getDescription().toString());
			}
			AUExemptStatus auExemptStatusBase = getMAECFHouseholdBase(maECFHouseholdDelta).getMAClient(
			                maECFHouseholdDelta.getPrimaryClientId()).getAUExemptStatus(ebcObject.getAuId());
			EDBCResultFinancial eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
			                EXEMPTIONSTATUSREASON);
			if (eDBCResultFinancial != null
			                && eDBCResultFinancial.getValue().isNotEmpty()
			                && (eDBCResultFinancial.getValue().toString().equalsIgnoreCase("5")
			                                || eDBCResultFinancial.getValue().toString().equalsIgnoreCase("7")
			                                || eDBCResultFinancial.getValue().toString().equalsIgnoreCase("8AU")
			                                || eDBCResultFinancial.getValue().toString().equalsIgnoreCase("8SS1") || eDBCResultFinancial
			                                .getValue().toString().equalsIgnoreCase("B"))
			                && auExemptStatusBase != null
			                && auExemptStatusBase.getAuExemptReason().isNotEmpty()
			                && (auExemptStatusBase.getAuExemptReason().toString().equalsIgnoreCase("5")
			                                || auExemptStatusBase.getAuExemptReason().toString().equalsIgnoreCase("7")
			                                || auExemptStatusBase.getAuExemptReason().toString()
			                                                .equalsIgnoreCase("8AU")
			                                || auExemptStatusBase.getAuExemptReason().toString().equalsIgnoreCase(
			                                                "8SS1") || auExemptStatusBase.getAuExemptReason()
			                                .toString().equalsIgnoreCase("B"))) {
				setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ISFEPSUPPLEMENTCALCULATED, YES);
			}
		}
		/*setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, RENTALLOWANCE, ebcObject.getRentAllowanceAmount()
		                .doubleValue());*/
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, BUDGETGROUP, ebcObject.getLivingArrangement(
		                maECFHouseholdDelta, maClientRule));

		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ebcObject.getAssetLimitAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ebcObject.getTotalCountableAssets().doubleValue());

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ebcObject.getIncomeTestAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMETESTED, ebcObject.getGrossIncomeTested()
                		.doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME, ebcObject.getTotalDeemedIncomeAmount()
		                .doubleValue());
		double value1 = ebcObject.getTotalUnearned().doubleValue()
		                + ebcObject.getNetChildSupportReceived().doubleValue()
		                + ebcObject.getTotalSocialSecurityRSDI().doubleValue()
		                + ebcObject.getTotalOtherResources().doubleValue();
		value1 = BeaconUtil.getRoundMoneyWithTwoDecimal(value1);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, value1);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ebcObject.getTotalEarnedIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT, ebcObject
		                .fetchchildSupportReceived(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FULLEMPLOYMENT, ebcObject.getTotalFEPIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, RSDIRESOURCEAMOUNT, ebcObject
		                .getTotalSocialSecurityRSDI().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, OTHERRESOURCEAMOUNT, ebcObject
		                .getTotalOtherResources().doubleValue()
		                + ebcObject.getFsCAPPreQualifiedSSIAmt().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEMPLOYMENTCOMP, ebcObject
		                .getUnemploymentCompensation(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, INCOMEINKINDAMOUNT, ebcObject.getTotalIncomeInKind()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FSATTRIBUTEDAMOUNT, ebcObject.getFSAttributedAmount()
		                .doubleValue());

		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, WORKRELATEDEXPENSES, ebcObject
		                .getWorkRelatedExpenseDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD, ebcObject
		                .getNetIndividualDisregardAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ebcObject
		                .getDependentCareDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSE, ebcObject
		                .getShelterExpenses(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREEXPENSE, ebcObject.getDependentCare()
		                .doubleValue());
		ClientStandardUtilityAllowance clientStandardUtilityAllowance = maClientRule
		                .getClientStandardUtilityAllowance(maClientRule.getGranteeForAU(ebcObject.getAuId())
		                                .getClientId());
		if (clientStandardUtilityAllowance != null) {
			setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYEXPENSE, ebcObject.getUtilityExpense(
			                clientStandardUtilityAllowance, maClientRule));
		}
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT, ebcObject
		                .getEdbcSupportExpenseAmount().doubleValue());
		// setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT,
		// ebcObject.getSupportExpenseAmount(maClientRule).doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTDISREGARDCOUNT, ebcObject
		                .getDependentDisregardCount(maClientRule, ebcObject.getEdbcResultAUMemberVector()));

		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ebcObject.getNeedStandardAmount()
		                .doubleValue()
		                + ebcObject.getClothingAllowanceGrantAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ebcObject.getNetIncomeAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, ebcObject
		                .getNetIndividualDisregardAmount().doubleValue()
		                + ebcObject.getWorkRelatedExpenseDeduction().doubleValue()
		                + ebcObject.getWorkRelatedExpDedDeemed().doubleValue()
		                + ebcObject.getEdbcNetDependentCareDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEEARNED, ebcObject.getCountableEarnedIncome().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEUNEARNED, ebcObject.getCountableUnearned().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEDEEMED, ebcObject.getCountableDeemedIncomeAmount().doubleValue());

		Parameter parameterAdjust = paramcache.getParameter(maECFHouseholdDelta.getFields().getContext(),
									"CLOTHING ALLOWANCE INCOME ADJUSTMENT FLAG");
		String adjustFlag = parameterAdjust.getParameterValue();

		if (ebcObject.getClothingAllowanceGrantAmount().doubleValue() == 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ebcObject.getTotalGrantAmount()
			                .doubleValue());
			interviewWrapUpEDBCResult.setBenefitAmount(ebcObject.getCurrentMonthlyPayment());
			
			if (ebcObject.getCurrentChildSupportPayment().isNotEmpty() && ebcObject.getCurrentChildSupportPayment().doubleValue() > 0.0) {
				setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CURRENT_CHILD_SUPPORT, ebcObject.getCurrentChildSupportPayment()
		                .doubleValue());
			}
			
			if (ebcObject.getArrearsChildSupportPayment().isNotEmpty() && ebcObject.getArrearsChildSupportPayment().doubleValue() > 0.0) {
				setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CS_ARREARS_ECESS_AMT, ebcObject.getArrearsChildSupportPayment()
		                .doubleValue());
			}
		}
		else if ((ebcObject.getClothingAllowanceGrantAmount().doubleValue() < ebcObject.getCurrentMonthlyPayment()
		                .doubleValue()
		          || adjustFlag.equalsIgnoreCase("NO"))
		          && ebcObject.getClothingAllowanceEligibleFlag().isTrue()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CLOTHINGALLOWANCE, ebcObject
			                .getClothingAllowanceGrantAmount().doubleValue());
		}
		else if (ebcObject.isFiveWeekMonth(maClientRule) && ebcObject.getFinancialEligibilityStatus().isNotEmpty()
		                && ebcObject.getFinancialEligibilityStatus().toString().equalsIgnoreCase("Eligible")
		                && ebcObject.getCurrentMonthlyPayment().isNotEmpty()
		                && ebcObject.getCurrentMonthlyPayment().doubleValue() == 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CLOTHINGALLOWANCE, 0.01);
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, CLOTHINGALLOWANCE, ebcObject
			                .getCurrentMonthlyPayment().doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME, ebcObject
		                .getTotalLumpSumIncome(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, VENDORPAYMENT, ebcObject.getVendorPaymentAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TOTALVENDORPAYMENT, ebcObject
		                .getTotalVendorPaymentAmount(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ebcObject.getRecoupmentCurrentAmount()
		                .doubleValue());
		recoupment = (Recoupment) maClientRule.getFields().getField(Recoupment.class, ebcObject.getAuId());
		if (recoupment != null && recoupment.getRecoupmentType().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, recoupment.getRecoupmentType()
			                .toString());
		}
		if (recoupment != null && recoupment.getRecoupmentBalanceAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, recoupment
			                .getRecoupmentBalanceAmount().doubleValue());
		}
		if (ebcObject.getIncomeSourceType().isNotEmpty()
		                && ebcObject.getIncomeSourceType().toString().equalsIgnoreCase(RETROSPECTIVE)) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Retrospective");
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Prospective");
		}
		//HEC EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(ebcObject.getAuId());
		EBCResultBase ebcRsltBase = maECFRule.getEBCResultBase(ebcObject.getAuId());	
		if (ebcRsltBase != null && ebcRsltBase.getBenefitAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ebcRsltBase.getBenefitAmount()
			                .doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ebcObject
		                .getFundingReductionAmount().doubleValue());

		interviewWrapUpEDBCResult.setIRSDepGrant(ebcObject.getIRSDependentGrant());

		interviewWrapUpEDBCResult.setLumpSumStartDate(ebcObject.getLumpSumStartDate(maClientRule));

		// These two attributes are used to set the Benefit Effective and
		// Release dates in the post-rules processing, but they are NOT
		// stored to the database.
		if (auExemptStatus != null) {
			interviewWrapUpEDBCResult.setWorkProgramExemptionStartDate(auExemptStatus.getEffDate());
			interviewWrapUpEDBCResult.setWorkProgramExemptionToDate(auExemptStatus.getEndDate());
		}
		interviewWrapUpEDBCResult.setTotalSanctionedAmt(ebcObject.getTotalSanctionedAmount());
		return interviewWrapUpEDBCResult;
	}

	/**
	 * This method create the result object for the SNAP Program.
	 * 
	 * @param maECFHouseholdDelta
	 *            holds data for maECFHousehold for Delta schema
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            holds data for EBC Object
	 * @param asstUnit
	 *            the Assist Unit Object
	 * @return the InterviewWrapUpEDBCResult Object
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static InterviewWrapUpEDBCResult createFSResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                             MAECFHousehold maECFRule, EDBCResult ebcObject,
	                                                             BaseAUStatus auStat, int clientId) throws Exception {
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = new InterviewWrapUpEDBCResult();
		double tmpEarnedIncomeDeduction = 0;
		double tmpTotalDeduction = 0;
		Parameter parameter = null;
		Recoupment recoupment = null;
		double tempValu = 0.00;
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		// Created a result obj with the initial value of being set from the delta db for au related data.
		interviewWrapUpEDBCResult.setAuId(ebcObject.getAuId());
		interviewWrapUpEDBCResult.setRequestId(ebcObject.getRequestId());
		interviewWrapUpEDBCResult.setProgram(ebcObject.getProgramCode());
		interviewWrapUpEDBCResult.setStatus(auStat.getStatus());

		BaseAUStatus assistUnitStatus = maClientRule.getAssistUnitStatus(ebcObject.getAuId());
		if (assistUnitStatus != null) {
			interviewWrapUpEDBCResult.setStatusDate(assistUnitStatus.getEffDate());
			interviewWrapUpEDBCResult.setBenefitEffective(assistUnitStatus.getBenefitEffDate());
		}

		Vector auInEligFactorVector = maClientRule.getAuInEligFactor(ebcObject.getAuId());
		if (auInEligFactorVector != null && auInEligFactorVector.size() > 0) {
			AuInEligFactor auInEligFactor = (AuInEligFactor) auInEligFactorVector.get(0);
			interviewWrapUpEDBCResult.setAuEligFactor(auInEligFactor.getEligFactor());
			interviewWrapUpEDBCResult.setAuEligFactorStatus(auInEligFactor.getEligStatus());
			interviewWrapUpEDBCResult.setAuEFRC(auInEligFactor.getEligFactorReason());
		}

		AUSubType auSubType = (AUSubType) maClientRule.getFields().getField(AUSubType.class, auStat.getAuId());
		if (auSubType != null) {
			interviewWrapUpEDBCResult.setPgmStructParId(auSubType.getPgmStructId());
			interviewWrapUpEDBCResult.setPgmSubTypeDate(auSubType.getEffDate());
		}
		setPgmSubTypeDescription(interviewWrapUpEDBCResult, maClientDelta);
		// Initialization starts here
		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ZERO);
		if (ebcObject.getFsCalculatedAUSize().isNotEmpty() && ebcObject.getFsCalculatedAUSize().intValue() > 0) {
			setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, FSCALCULATEDAUSIZE, ZERO);
		}

		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGFLAG, NO);
		if (ebcObject.getCatEligFlag().isNotEmpty() && ebcObject.getCatEligFlag().booleanValue()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGFLAG, YES);
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGREASON, "");
		}
		if (ebcObject.getCatEligFlag().isNotEmpty() && !ebcObject.getCatEligFlag().booleanValue()
			&& ebcObject.getCatEligGrossLimit().doubleValue() > ZERO_DOUBLE_VALUE) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGGROSSLIMIT, ZERO_DOUBLE_VALUE);
		}
		/*
		 * if (ebcObject.getCatEligFlag().isNotEmpty() && ebcObject.getCatEligFlag().booleanValue()) {
		 * setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGFLAG, "Yes");
		 * setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGREASON, ""); } else if
		 * (ebcObject.getCatEligFlag().isNotEmpty()) { setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS,
		 * CATELIGFLAG, "No"); }
		 */
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, "");
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MAXALLOTMENT, ZERO_DOUBLE_VALUE);
		
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, ZERO_DOUBLE_VALUE);
		// setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CASHBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FSATTRIBUTEDAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEFRAPAYMENT, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, STANDARDFSDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DISPLAYEARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, MEDICALDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTERDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYEXPENSE, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYCODE, "");
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, FARMLOSS, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TBAFLAG, NO);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TBARELEASEDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, EBCBENEFITEFFECTIVEDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BENEFITCHANGEREASONS, "");

		setFinancialValue(interviewWrapUpEDBCResult, NOTICES, NOTICETYPE, "");
		if(ebcObject.getWorkNumberFlag().isNotEmpty()){
			setFinancialValue(interviewWrapUpEDBCResult, NOTICES, WORKNUMBERFLAG, ebcObject.getWorkNumberFlag().toString());
		}
		// Initialization ends here

		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPIND, ebcObject.getCapInd());
		interviewWrapUpEDBCResult.setCapInd(ebcObject.getCapInd());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, ebcObject
		                .getCapEligibilityStatus().toString());
		// (these reasons do not get stored to the database, but are used in post-rules processing)
		interviewWrapUpEDBCResult.setCapReasons(ebcObject.getCapReasonsVector());
		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ebcObject
		                .getCommonValFederalHouseholdSize(maClientRule));
		if (ebcObject.getFsCalculatedAUSize().isNotEmpty() && ebcObject.getFsCalculatedAUSize().intValue() > 0) {
			setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, FSCALCULATEDAUSIZE, ebcObject
			                .getFsCalculatedAUSize().intValue());
		}
		if (ebcObject.getTafdcIsFEPSupplementCalculated().isNotEmpty()
		                && ebcObject.getTafdcIsFEPSupplementCalculated().booleanValue()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ISFEPSUPPLEMENTCALCULATED, "Y");
		}
		else if (ebcObject.getTafdcIsFEPSupplementCalculated().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ISFEPSUPPLEMENTCALCULATED, "N");
		}
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MAXALLOTMENT, ebcObject.getMaxAllotment().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ebcObject.getAssetLimitAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ebcObject.getTotalCountableAssets().doubleValue()
		                + ebcObject.getTotalLumpSumIncome(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ebcObject.getGrossLimit()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FSATTRIBUTEDAMOUNT, ebcObject.getFSAttributedAmount()
		                .doubleValue());
		double value2 = Double.parseDouble(Money.getUnFormattedMoney(ebcObject.getGrossUnearnedIncome().doubleValue()
		                + ebcObject.getTotalSocialSecurityRSDI().doubleValue()
		                - ebcObject.getCurrentMonthlyPaymentUsedForFS().doubleValue()
		                - ebcObject.getChildSupportPaymentUsedForFS().doubleValue()
		                - ebcObject.getFSAttributedAmount().doubleValue()));
		value2 = BeaconUtil.getRoundMoneyWithTwoDecimal(value2);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, value2);
		tempValu = getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME);

		if (tempValu <= 0.0) { 
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, 0.0);
		}
		if(ebcObject.getProRateAmount().doubleValue() > 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, "proratedAmount", ebcObject.getProRateAmount().getFormattedMoney());
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, "tanfApproved", ebcObject.getGrantAmount().getFormattedMoney() );
		}
		if(ebcObject.getSnapAttributeProrateAmt().doubleValue() > 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, IncomeConstants.SNAPATRRIBUTEDPRORATEDAMT, ebcObject.getSnapAttributeProrateAmt().getFormattedMoney());
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, IncomeConstants.TOTALSANCTIONEDAMT, ebcObject.getTotalSanctionedAmt().getFormattedMoney());
		}
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ebcObject.getTotalEarnedIncome()
		                .doubleValue());
		// setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT,
		// Math.round(ebcObject.getCurrentMonthlyPaymentUsedForFS().doubleValue()));

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEFRAPAYMENT, ebcObject
		                .getChildSupportPaymentUsedForFS().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, STANDARDFSDEDUCTION, ebcObject.getStandardFSDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, MEDICALDEDUCTION, ebcObject.getExcessMedicalCost().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ebcObject.getDependentCareDeduction()
		    .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT, ebcObject.getEdbcSupportExpenseAmount()
		    .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTERDEDUCTION, ebcObject.getShelterDeductionAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, MONTHINCOMEPERCENT, ebcObject.getMonthIncomePercent().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, FARMLOSS, 
				decimalFormater.format(ebcObject.getSelfEmploymentFarmingLoss().doubleValue() < 0 ? ebcObject.getSelfEmploymentFarmingLoss().doubleValue()*-1 : ebcObject.getSelfEmploymentFarmingLoss().doubleValue()));
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ebcObject.getNetLimit().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ebcObject.getMonthNetIncome().doubleValue());
		parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
		                "SNAP EARNED PERCENT");
		//HEC exclude unreported income from deduction
		tmpEarnedIncomeDeduction = Math.round((ebcObject.getTotalEarnedIncome().doubleValue() - ebcObject.getTotalUnreportedEarnedIncome().doubleValue())
		                * (1 - (Double.parseDouble(parameter.getParameterValue()) / 100)));
		tmpTotalDeduction = Math.abs(ebcObject.getStandardFSDeduction().doubleValue()
		                + ebcObject.getExcessMedicalCost().doubleValue()
		                + ebcObject.getEdbcSupportExpenseAmount().doubleValue()
		                + ebcObject.getDependentCareDeduction().doubleValue()
		                + (ebcObject.getTotalNetSelfEmployment().doubleValue() < 0 ? ebcObject.getSelfEmploymentFarmingLoss().doubleValue()*-1 : 0.0)
		                + ebcObject.getShelterDeductionAmount().doubleValue() + tmpEarnedIncomeDeduction);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, tmpTotalDeduction);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT, ebcObject
		                .getPreRecoupmentFederalFSAmount().doubleValue());
		interviewWrapUpEDBCResult.setBenefitAmount(ebcObject.getFederalFoodStampAllotment().doubleValue());
		if (getFinancialObjectIntegerValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, STATEAUSIZE) > 0) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, STATEFOODSTAMPAMOUNT, ebcObject
			                .getStateFoodStampAllotment().doubleValue());
		}
		if (ebcObject.getIncomeSourceType().isNotEmpty()
		                && ebcObject.getIncomeSourceType().toString().equalsIgnoreCase(RETROSPECTIVE)) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Retrospective");
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Prospective");
		}
		//HEC EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(ebcObject.getAuId());
		EBCResultBase ebcRsltBase = maECFRule.getEBCResultBase(ebcObject.getAuId());		
		if (ebcRsltBase != null && ebcRsltBase.getBenefitAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ebcRsltBase.getBenefitAmount()
			                .doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, RSDIRESOURCEAMOUNT, ebcObject
		                .getTotalSocialSecurityRSDI().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, OTHERRESOURCEAMOUNT, ebcObject
		                .getTotalOtherResources().doubleValue());
		if (ebcObject.getFsCAPPreQualifiedSSIAmt().doubleValue() > 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, SSIPREQUALIFIEDINCOMEAMOUNT, ebcObject
			                .getFsCAPPreQualifiedSSIAmt().doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSE, ebcObject.getAdjustedShelter()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSEGROSS, ebcObject.getShelter()
        .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREEXPENSE, ebcObject.getDependentCare()
		                .doubleValue());
		/*
		 * ClientStandardUtilityAllowance clientStandardUtilityAllowance =
		 * maClientRule.getClientStandardUtilityAllowance(maClientDelta.getGranteeForAU(ebcObject.getAuId()).getClientId());
		 * if (clientStandardUtilityAllowance != null) { setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS,
		 * UTILITYEXPENSE, ebcObject.getUtilityExpense(clientStandardUtilityAllowance, maClientRule)); }
		 */
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYEXPENSE, ebcObject.getAdjustedUtility()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYCODE, ebcObject.getUtilityCode().toString());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ebcObject.getRecoupmentCurrentAmount()
		                .doubleValue());
		recoupment = (Recoupment) maClientRule.getFields().getField(Recoupment.class, ebcObject.getAuId());
		if (recoupment != null && recoupment.getRecoupmentType().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, recoupment.getRecoupmentType()
			                .toString());
		}
		if (recoupment != null && recoupment.getRecoupmentBalanceAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, recoupment
			                .getRecoupmentBalanceAmount().doubleValue());
		}

		interviewWrapUpEDBCResult.setKeepAUOpen(ebcObject.getKeepAUOpen());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME, ebcObject
		                .getTotalLumpSumIncome(maClientRule));
		interviewWrapUpEDBCResult.setLumpSumStartDate(ebcObject.getLumpSumStartDate(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEMPLOYMENTCOMP, ebcObject
		                .getUnemploymentCompensation(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, INCOMEINKINDAMOUNT, ebcObject.getTotalIncomeInKind()
		                .doubleValue());
		if (ebcObject.getCatEligFlag().isNotEmpty() && ebcObject.getCatEligFlag().booleanValue()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGREASON, ebcObject.getCatEligReason()
			                .toString());
		}
		if (ebcObject.getCatEligFlag().isNotEmpty() && !ebcObject.getCatEligFlag().booleanValue()
			&& ebcObject.getCatEligGrossLimit().doubleValue() > ZERO_DOUBLE_VALUE) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGGROSSLIMIT, ebcObject.getCatEligGrossLimit().doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ebcObject
		                .getFundingReductionAmount().doubleValue());
		if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, SSIPREQUALIFIEDINCOMEAMOUNT) > 0.0) {
			setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, getFinancialObjectDoubleValue(
			                interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME)
			                - getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
			                                SSIPREQUALIFIEDINCOMEAMOUNT));
		}
		// setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GRANTAMOUNT,
		// ebcObject.getGrantAmount().doubleValue());
		
		//HEC
		//setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DISPLAYEARNEDINCOME,
		//                Math
		//                                .round(getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
		//                                                EARNEDINCOME) * 0.2));
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DISPLAYEARNEDINCOME,tmpEarnedIncomeDeduction);
		double cashBenefitAmount = 0;
		Enumeration interviewWrapupEDBCResultEnum = ebcObject.getCurrentResults().elements();
		while (interviewWrapupEDBCResultEnum.hasMoreElements()) {
			InterviewWrapUpEDBCResult interviewWrapUpEDBCResultTemp = (InterviewWrapUpEDBCResult) interviewWrapupEDBCResultEnum
			                .nextElement();
			if (interviewWrapUpEDBCResultTemp.getProgram().isNotEmpty()
			                && interviewWrapUpEDBCResultTemp.getProgram().toString().equalsIgnoreCase(TANF)) {
				cashBenefitAmount = cashBenefitAmount + interviewWrapUpEDBCResultTemp.getBenefitAmount().doubleValue();
			}
			else if (interviewWrapUpEDBCResultTemp.getProgram().isNotEmpty()
			                && interviewWrapUpEDBCResultTemp.getProgram().toString().equalsIgnoreCase(EAEDC)) {
				cashBenefitAmount = cashBenefitAmount + interviewWrapUpEDBCResultTemp.getBenefitAmount().doubleValue();
			}
		}
		// setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CASHBENEFITAMOUNT, cashBenefitAmount);
		if (ebcObject.getCurrentMonthlyPaymentUsedForFS().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ebcObject
			                .getCurrentMonthlyPaymentUsedForFS().doubleValue());
		}
		return interviewWrapUpEDBCResult;
	}

	/**
	 * This method is used to create the Result Object for EAEDC Program.
	 * 
	 * @param maECFHouseholdDelta
	 *            holds data for maECFHousehold for Delta schema
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            holds data for EBC Object
	 * @param asstUnit
	 *            the Assist Unit Object
	 * @return the InterviewWrapUpEDBCResult Object
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static InterviewWrapUpEDBCResult createEAEDCResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                                MAECFHousehold maECFRule, EDBCResult ebcObject,
	                                                                BaseAUStatus auStat, int clientId) throws Exception {
		Recoupment recoupment = null;
		ClientEAEDCDisrgdCtr clientEAEDCDisrgdCtr = null;
		EDBCResultAUMember auMembers = null;
		Vector auMemberVector = null;
		Enumeration auMemberEnum = null;
		int tmpDisregardDollarCount = 0;
		int tmpDisregardFractionCount = 0;
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = new InterviewWrapUpEDBCResult();
		// Created a result obj with the initial value of being set from the delta db for au related data.
		interviewWrapUpEDBCResult.setAuId(ebcObject.getAuId());
		interviewWrapUpEDBCResult.setRequestId(ebcObject.getRequestId());
		interviewWrapUpEDBCResult.setProgram(ebcObject.getProgramCode());
		interviewWrapUpEDBCResult.setStatus(auStat.getStatus());

		BaseAUStatus assistUnitStatus = maClientRule.getAssistUnitStatus(ebcObject.getAuId());
		if (assistUnitStatus != null) {
			interviewWrapUpEDBCResult.setStatusDate(assistUnitStatus.getEffDate());
			interviewWrapUpEDBCResult.setBenefitEffective(assistUnitStatus.getBenefitEffDate());
		}

		Vector auInEligFactorVector = maClientRule.getAuInEligFactor(ebcObject.getAuId());
		if (auInEligFactorVector != null && auInEligFactorVector.size() > 0) {
			AuInEligFactor auInEligFactor = (AuInEligFactor) auInEligFactorVector.get(0);
			interviewWrapUpEDBCResult.setAuEligFactor(auInEligFactor.getEligFactor());
			interviewWrapUpEDBCResult.setAuEligFactorStatus(auInEligFactor.getEligStatus());
			interviewWrapUpEDBCResult.setAuEFRC(auInEligFactor.getEligFactorReason());
		}

		AUSubType auSubType = (AUSubType) maClientRule.getFields().getField(AUSubType.class, auStat.getAuId());
		if (auSubType != null) {
			interviewWrapUpEDBCResult.setPgmStructParId(auSubType.getPgmStructId());
			interviewWrapUpEDBCResult.setPgmSubTypeDate(auSubType.getEffDate());
		}
		setPgmSubTypeDescription(interviewWrapUpEDBCResult, maClientDelta);

		// Initialization starts here.
		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ZERO);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, BUDGETGROUP, "");
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARD, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, PAYMENTSTANDARDAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, RENTALLOWANCE, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, WORKRELATEDEXPENSES, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEEARNED, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEUNEARNED, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEDEEMED, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, VENDORPAYMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, ZERO_DOUBLE_VALUE);
		setFinancialValueInteger(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMMONTHSINELIGIBLE, ZERO);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMREMAININGAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PENALTYENDDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, EBCBENEFITEFFECTIVEDATE, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "");
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BENEFITCHANGEREASONS, "");
		setFinancialValue(interviewWrapUpEDBCResult, NOTICES, NOTICETYPE, "");
		if(ebcObject.getWorkNumberFlag().isNotEmpty()){
			setFinancialValue(interviewWrapUpEDBCResult, NOTICES, WORKNUMBERFLAG, ebcObject.getWorkNumberFlag().toString());
		}
		// Initialization ends here.

		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ebcObject.getHouseHoldSize(
		                maClientRule).intValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARD, ebcObject.getNeedStandardAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, PAYMENTSTANDARDAMOUNT, BeaconUtil.getRoundMoneyWithTwoDecimal(ebcObject.getPaymentStandardAmount()
        .doubleValue()));
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, FINANCIALELIGIBILITYSTATUS, ebcObject
		                .getFinancialEligibilityStatus().stringValue());
		AUMonthlyReportReqd aUMonthlyReportReqd = maClientDelta.getAUMonthlyReportReqd(ebcObject.getAuId());
		if (aUMonthlyReportReqd != null && aUMonthlyReportReqd.getExists().isNotEmpty()
		                && aUMonthlyReportReqd.getExists().isTrue()) {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS, YES);
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS, NO);
		}
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS, STATUS_NON_EXEMPT);
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, RENTALLOWANCE, ebcObject.getRentAllowanceAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ebcObject.getAssetLimitAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ebcObject.getTotalCountableAssets().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ebcObject.getIncomeTestAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME, ebcObject.getTotalDeemedIncomeAmount()
		                .doubleValue());
		double value3 = ebcObject.getTotalUnearned().doubleValue()
		                + ebcObject.getNetChildSupportReceived().doubleValue()
		                + ebcObject.getTotalSocialSecurityRSDI().doubleValue()
		                + ebcObject.getTotalOtherResources().doubleValue();
		value3 = BeaconUtil.getRoundMoneyWithTwoDecimal(value3);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, value3);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ebcObject.getTotalEarnedIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT, ebcObject
		                .fetchchildSupportReceived(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FULLEMPLOYMENT, ebcObject.getTotalFEPIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, WORKRELATEDEXPENSES, ebcObject
		                .getWorkRelatedExpenseDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD, ebcObject
		                .getNetIndividualDisregardAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREDEDUCTION, ebcObject
		                .getDependentCareDeduction().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT, ebcObject.getNeedStandardAmount()
		                .doubleValue()
		                + ebcObject.getClothingAllowanceGrantAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, NETINCOME, ebcObject.getNetIncomeAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, TOTALDEDUCTION, ebcObject
		                .getNetIndividualDisregardAmount().doubleValue()
		                + ebcObject.getWorkRelatedExpenseDeduction().doubleValue()
		                + ebcObject.getWorkRelatedExpDedDeemed().doubleValue()
		                + ebcObject.getNetDependentCareDeduction());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEEARNED, ebcObject.getCountableEarnedIncome().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEUNEARNED, ebcObject.getCountableUnearned().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, COUNTABLEDEEMED, ebcObject.getCountableDeemedIncomeAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ebcObject.getTotalGrantAmount()
		                .doubleValue());
		interviewWrapUpEDBCResult.setBenefitAmount(ebcObject.getCurrentMonthlyPayment().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, VENDORPAYMENT, ebcObject.getVendorPaymentAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TOTALVENDORPAYMENT, ebcObject
		                .getTotalVendorPaymentAmount(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT, ebcObject.getRecoupmentCurrentAmount()
		                .doubleValue());
		recoupment = (Recoupment) maClientRule.getFields().getField(Recoupment.class, ebcObject.getAuId());
		if (recoupment != null && recoupment.getRecoupmentType().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTTYPE, recoupment.getRecoupmentType()
			                .toString());
		}
		if (recoupment.getRecoupmentBalanceAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTBALANCE, recoupment
			                .getRecoupmentBalanceAmount().doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Prospective");
		//HEC EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(ebcObject.getAuId());
		EBCResultBase ebcRsltBase = maECFRule.getEBCResultBase(ebcObject.getAuId());	
		
		if (ebcRsltBase != null && ebcRsltBase.getBenefitAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PREVIOUSBENEFITAMOUNT, ebcRsltBase.getBenefitAmount()
			                .doubleValue());
		}

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, RSDIRESOURCEAMOUNT, ebcObject
		                .getTotalSocialSecurityRSDI().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, OTHERRESOURCEAMOUNT, ebcObject
		                .getTotalOtherResources().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSE, ebcObject
		                .getShelterExpenses(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREEXPENSE, ebcObject.getDependentCare()
		                .doubleValue());
		ClientStandardUtilityAllowance clientStandardUtilityAllowance = maClientRule
		                .getClientStandardUtilityAllowance(maClientDelta.getGranteeForAU(ebcObject.getAuId())
		                                .getClientId());
		if (clientStandardUtilityAllowance != null) {
			setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYEXPENSE, ebcObject.getUtilityExpense(
			                clientStandardUtilityAllowance, maClientRule));
		}
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, BUDGETGROUP, ""
		                + ebcObject.getLivingArrangement(maECFHouseholdDelta, maClientRule));
		interviewWrapUpEDBCResult.setIRSDepGrant(ebcObject.getIRSDependentGrant());
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT, ebcObject
		                .getEdbcSupportExpenseAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME, ebcObject
		                .getTotalLumpSumIncome(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEMPLOYMENTCOMP, ebcObject
		                .getUnemploymentCompensation(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, INCOMEINKINDAMOUNT, ebcObject.getTotalIncomeInKind()
		                .doubleValue());
		if (interviewWrapUpEDBCResult.getAuMembResults().size() == 0) {
			auMemberVector = ebcObject.getEdbcResultAUMemberVector();
		}
		else {
			auMemberVector = interviewWrapUpEDBCResult.getAuMembResults();
		}
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTDISREGARDCOUNT, ebcObject
		                .getDependentDisregardCount(maClientRule, auMemberVector));
		auMemberEnum = auMemberVector.elements();
		while (auMemberEnum.hasMoreElements()) {
			auMembers = (EDBCResultAUMember) auMemberEnum.nextElement();
			clientEAEDCDisrgdCtr = maClientRule.getClientEAEDCDisrgdCtr(auMembers.getClientId());
			if (clientEAEDCDisrgdCtr != null && clientEAEDCDisrgdCtr.getEaedcDisrgrdCtr().intValue() < 11) {
				tmpDisregardDollarCount += 1;
			}
			if (clientEAEDCDisrgdCtr != null && clientEAEDCDisrgdCtr.getEaedcDisrgrdCtr().intValue() >= 0
			                && clientEAEDCDisrgdCtr.getEaedcDisrgrdCtr().intValue() <= 3) {
				tmpDisregardFractionCount += 1;
			}
		}
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DISREGARDDOLLARCOUNT, tmpDisregardDollarCount);
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DISREGARDFRACTIONCOUNT, tmpDisregardFractionCount);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, FUNDINGREDUCTIONAMOUNT, ebcObject
		                .getFundingReductionAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FSATTRIBUTEDAMOUNT, ebcObject.getFSAttributedAmount()
		                .doubleValue());
		return interviewWrapUpEDBCResult;
	}

	/**
	 * This method is used to create the Result Object for EA Program.
	 * 
	 * @param maECFHouseholdDelta
	 *            holds data for maECFHousehold for Delta schema
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObject
	 *            holds data for EBC Object
	 * @param asstUnit
	 *            the Assist Unit Object
	 * @return the InterviewWrapUpEDBCResult Object
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static InterviewWrapUpEDBCResult createEAResultObject(MAECFHousehold maECFHouseholdDelta,
	                                                             MAECFHousehold maECFRule, EDBCResult ebcObject,
	                                                             BaseAUStatus auStat, int dataId) throws Exception {
		IntegerData clientId = new IntegerData();
		StringData facilityType = new StringData();
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(dataId);
		MAClient maClientRule = maECFRule.getMAClient(dataId);
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = new InterviewWrapUpEDBCResult();
		// Created a result obj with the initial value of being set from the delta db for au related data.
		interviewWrapUpEDBCResult.setAuId(ebcObject.getAuId());
		interviewWrapUpEDBCResult.setRequestId(ebcObject.getRequestId());
		interviewWrapUpEDBCResult.setProgram(ebcObject.getProgramCode());
		interviewWrapUpEDBCResult.setStatus(auStat.getStatus());

		BaseAUStatus assistUnitStatus = maClientRule.getAssistUnitStatus(ebcObject.getAuId());
		if (assistUnitStatus != null) {
			interviewWrapUpEDBCResult.setStatusDate(assistUnitStatus.getEffDate());
			interviewWrapUpEDBCResult.setBenefitEffective(assistUnitStatus.getBenefitEffDate());
		}

		Vector auInEligFactorVector = maClientRule.getAuInEligFactor(ebcObject.getAuId());
		if (auInEligFactorVector != null && auInEligFactorVector.size() > 0) {
			AuInEligFactor auInEligFactor = (AuInEligFactor) auInEligFactorVector.get(0);
			interviewWrapUpEDBCResult.setAuEligFactor(auInEligFactor.getEligFactor());
			interviewWrapUpEDBCResult.setAuEligFactorStatus(auInEligFactor.getEligStatus());
			interviewWrapUpEDBCResult.setAuEFRC(auInEligFactor.getEligFactorReason());
		}

		AUSubType auSubType = (AUSubType) maClientRule.getFields().getField(AUSubType.class, auStat.getAuId());
		if (auSubType != null) {
			interviewWrapUpEDBCResult.setPgmStructParId(auSubType.getPgmStructId());
			interviewWrapUpEDBCResult.setPgmSubTypeDate(auSubType.getEffDate());
		}
		setPgmSubTypeDescription(interviewWrapUpEDBCResult, maClientDelta);

		// Initialization of elements
		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ZERO);
		// The need standard display is changed to Eligibility Standard and the value is coming from gross income limit.
		// this was updated in Interview Wrapup Results-Financial Tab-FNC-B-1402.02 version 1.12.
		EBCServices.setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ELIGIBILITYSTANDARD,
		                ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ZERO_DOUBLE_VALUE);
		// setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CASHBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ZERO_DOUBLE_VALUE);

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FULLEMPLOYMENT, ZERO_DOUBLE_VALUE);
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BENEFITCHANGEREASONS, "");

		setFinancialValue(interviewWrapUpEDBCResult, NOTICES, NOTICETYPE, "");
		if(ebcObject.getWorkNumberFlag().isNotEmpty()){
			setFinancialValue(interviewWrapUpEDBCResult, NOTICES, WORKNUMBERFLAG, ebcObject.getWorkNumberFlag().toString());
		}
		// Initialization ends

		setFinancialValueInteger(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE, ebcObject.getHouseHoldSize(
		                maClientRule).intValue());
		// The need standard display is changed to Eligibility Standard and the value is coming from gross income limit.
		// this was updated in Interview Wrapup Results-Financial Tab-FNC-B-1402.02 version 1.12.
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, ELIGIBILITYSTANDARD, ebcObject
		                .getIncomeTestAmount().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, FINANCIALELIGIBILITYSTATUS, ebcObject
		                .getFinancialEligibilityStatus().stringValue());
		setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS, STATUS_EXEMPT);

		BaseAUMember aUMembers = maClientDelta.getGranteeForAU(ebcObject.getAuId());
		if (aUMembers != null)
			clientId = aUMembers.getClientId();
		Vector clientResidentialFacility = maClientRule.getClientResidentialFacility(clientId);
		if (clientResidentialFacility != null && clientResidentialFacility.size() > 0) {
			Enumeration clientResidentialFacilityEnum = clientResidentialFacility.elements();
			while (clientResidentialFacilityEnum.hasMoreElements()) {
				ClientResidentialFacility clientResidentialFacilityObj = (ClientResidentialFacility) clientResidentialFacilityEnum
				                .nextElement();
				facilityType = clientResidentialFacilityObj.getFacilityType();
				if (facilityType.equals(LHATHP)) {
					setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ZERO);
				}
				else {
					setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ebcObject.getAssetLimitAmount()
					                .doubleValue());
				}
			}
		}
		else {
			setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT, ebcObject.getAssetLimitAmount()
			                .doubleValue());
		}
		setFinancialValue(interviewWrapUpEDBCResult, ASSETS, ASSETS, ebcObject.getTotalCountableAssets().doubleValue());

		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT, ebcObject.getIncomeTestAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME, ebcObject.getTotalDeemedIncomeAmount()
		                .doubleValue());
		double value4 = ebcObject.getTotalUnearned().doubleValue()
		                + ebcObject.getNetChildSupportReceived().doubleValue()
		                + ebcObject.getTotalSocialSecurityRSDI().doubleValue()
		                + ebcObject.getTotalOtherResources().doubleValue() - ebcObject.getGrantAmount().doubleValue();
		value4 = BeaconUtil.getRoundMoneyWithTwoDecimal(value4);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME, value4);
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME, ebcObject.getTotalEarnedIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, FULLEMPLOYMENT, ebcObject.getTotalFEPIncome()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, RSDIRESOURCEAMOUNT, ebcObject
		                .getTotalSocialSecurityRSDI().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, OTHERRESOURCEAMOUNT, ebcObject
		                .getTotalOtherResources().doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEMPLOYMENTCOMP, ebcObject
		                .getUnemploymentCompensation(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, INCOMEINKINDAMOUNT, ebcObject.getTotalIncomeInKind()
		                .doubleValue());

		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ebcObject.getTotalGrantAmount()
		                .doubleValue());
		setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, BUDGETINGMETHOD, "Prospective");

		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSE, ebcObject
		                .getShelterExpenses(maClientRule));
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, DEPENDENTCAREEXPENSE, ebcObject.getDependentCare()
		                .doubleValue());
		ClientStandardUtilityAllowance clientStandardUtilityAllowance = maClientRule
		                .getClientStandardUtilityAllowance(maClientDelta.getGranteeForAU(ebcObject.getAuId())
		                                .getClientId());
		if (clientStandardUtilityAllowance != null) {
			setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, UTILITYEXPENSE, ebcObject.getUtilityExpense(
			                clientStandardUtilityAllowance, maClientRule));
		}
		setFinancialValue(interviewWrapUpEDBCResult, DEDUCTIONS, SUPPORTEXPENSEELEMENT, ebcObject
		                .getEdbcSupportExpenseAmount().doubleValue());

		setFinancialValue(interviewWrapUpEDBCResult, NETINCOME, LUMPSUMTOTALINCOME, ebcObject
		                .getTotalLumpSumIncome(maClientRule));

		interviewWrapUpEDBCResult.setLumpSumStartDate(ebcObject.getLumpSumStartDate(maClientRule));
		Vector interviewWrapupEDBCResultVector = ebcObject.getCurrentResults();
		double cashBenefitAmount = 0;
		Enumeration interviewWrapupEDBCResultEnum = interviewWrapupEDBCResultVector.elements();
		while (interviewWrapupEDBCResultEnum.hasMoreElements()) {
			InterviewWrapUpEDBCResult interviewWrapUpEDBCResultTemp = (InterviewWrapUpEDBCResult) interviewWrapupEDBCResultEnum
			                .nextElement();
			if (interviewWrapUpEDBCResultTemp.getProgram().isNotEmpty()
			                && interviewWrapUpEDBCResultTemp.getProgram().toString().equalsIgnoreCase(TANF)) {
				cashBenefitAmount = cashBenefitAmount + interviewWrapUpEDBCResultTemp.getBenefitAmount().doubleValue();
			}
			else if (interviewWrapUpEDBCResultTemp.getProgram().isNotEmpty()
			                && interviewWrapUpEDBCResultTemp.getProgram().toString().equalsIgnoreCase(EAEDC)) {
				cashBenefitAmount = cashBenefitAmount + interviewWrapUpEDBCResultTemp.getBenefitAmount().doubleValue();
			}
		}
		// setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CASHBENEFITAMOUNT, cashBenefitAmount);
		if (ebcObject.getGrantAmount().isNotEmpty()) {
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT, ebcObject.getGrantAmount().doubleValue());
		}
		return interviewWrapUpEDBCResult;
	}

	/**
	 * Calls a series of post rule processing methods.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maECFHouseholdBase
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param maClientBase
	 *            MAClient object
	 * @param whRule
	 *            a MAECFHousehold object
	 * @param maClientRule
	 *            a MAClient object
	 * @param ebcObjectVector
	 *            rule object
	 * @param interviewWrapUpEDBCResultBaseVector
	 *            view created by base result
	 * @param batch
	 *            boolean batch
	 * @throws Exception
	 */
	public static void postRuleProcessing(Context ctx, MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFHouseholdBase,
	                                      MAECFHousehold maECFRule, Vector ebcObjectVector,
	                                      Vector interviewWrapUpEDBCResultBaseVector, boolean batch,
	                                      Vector auExcludedVec, boolean reCal, int clientId) throws Exception {
		DateData today=new DateData(maECFHouseholdDelta.getFields().getContext().getEffectiveDate());
		//Historical Calculation will not perform TBA and AR
		if(!HcalcUtil.isHcalc(maECFHouseholdDelta, clientId)){
			/*tba(maECFHouseholdDelta, maECFRule, maECFHouseholdBase, ebcObjectVector, interviewWrapUpEDBCResultBaseVector,
		                auExcludedVec, clientId);*/
			//annualSimplifiedReportingBenefitAdjustment(maECFHouseholdDelta, maECFRule,ebcObjectVector, clientId);
		}
		auClosures(maECFHouseholdDelta, maECFRule, ebcObjectVector, batch, reCal, clientId ,auExcludedVec);
		expeditedFS(maECFHouseholdDelta, ebcObjectVector, batch, clientId, interviewWrapUpEDBCResultBaseVector);
		Vector rsltVec = maECFHouseholdDelta.getInterviewWrapUpEDBCResults();
		Enumeration rsltEnum = rsltVec.elements();
		while (rsltEnum.hasMoreElements()) {
			InterviewWrapUpEDBCResult rslt = (InterviewWrapUpEDBCResult) rsltEnum.nextElement();
			auClosureReasons(maECFHouseholdDelta, maECFRule, maECFHouseholdBase.getMAClient(clientId), ebcObjectVector,
			                interviewWrapUpEDBCResultBaseVector, rslt, clientId);
			rslt.setBenefitReason(rslt.getAuEFRC());
			rslt.setBenefitEffective(today);
			setFinancialValue(rslt, BENEFIT, EBCBENEFITEFFECTIVEDATE, today.toLocaleString());
			Double firstAllotment = getProratedAmount(maECFHouseholdDelta, rslt);
			setFinancialValue(rslt, BENEFIT, PRORATEDBENEFITAMOUNT, firstAllotment);
		}
		benefitChangeReasons(maECFHouseholdDelta, maECFRule, ebcObjectVector, interviewWrapUpEDBCResultBaseVector,
		                auExcludedVec, clientId);
		auStatus(maECFHouseholdDelta, ebcObjectVector, batch, reCal, clientId);
		responsibilities(maECFHouseholdDelta);
		auSubtypes(maECFHouseholdDelta, maECFRule, ebcObjectVector, clientId);
		
		//moved the logic from runEDBCRules, because reval type calcualtion for SIMP06 requires the new workprogram reason
		if(!HcalcUtil.isHcalcRuleCalculation(maECFHouseholdDelta)){
           setWorkProgramReasonFS(ctx, maECFHouseholdDelta.getEDBCResult(), maECFHouseholdDelta, maECFRule);
		}
		reevaluationDates(maECFHouseholdDelta, maECFRule, ebcObjectVector, interviewWrapUpEDBCResultBaseVector, batch,
		                clientId);
		eaExtension(maECFHouseholdDelta);
		mrDiversions(maECFHouseholdDelta, maECFHouseholdBase, ebcObjectVector, interviewWrapUpEDBCResultBaseVector,
		                clientId);
		dever(maECFHouseholdDelta, maECFRule, ebcObjectVector, interviewWrapUpEDBCResultBaseVector, rsltVec, clientId);
		capRedetermination(maECFHouseholdDelta, maECFHouseholdBase, ebcObjectVector,
		                interviewWrapUpEDBCResultBaseVector, clientId);
		if (batch) {
			// capTransfer(maECFHouseholdDelta, maECFHouseholdBase, maClientDelta, maClientBase, ebcObjectVector,
			// interviewWrapUpEDBCResultBaseVector);
		}
		notices(maECFHouseholdDelta, maECFHouseholdDelta.getMAClient(clientId), ebcObjectVector, batch);
		//fep(maECFHouseholdDelta);
		//clothingAllowance(maECFHouseholdDelta);
	//	monthlyReporter(maECFHouseholdDelta);
	}

	/**
	 * This method is used to allow benefit a increase (no decreases) for SNAP AUs if the last released reevaluation type
	 * is Universal Semiannual Reporting / Mail-In (USAIR).
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param ebcObjectVector
	 *            rule object
	 * @throws Exception
	 */
	public static void annualSimplifiedReportingBenefitAdjustment(MAECFHousehold maECFDelta, MAECFHousehold maECFRule,Vector ebcObjectVector, int clientId) throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		EDBCResult ebcObject = null;
		String tbaFlag;
		double rsltPreRecoupFedFSAmt;
		double RelrsltPreRecoupFedFSAmt;
		double relRsltFundingReductionAmt;
		Enumeration fsRsltEnum = null;
		String fsAUSubType = "";
		MAClient maClientDelta = maECFDelta.getMAClient(clientId);
		// fetching SNAP AU results
		Vector fsRsltVec = maECFDelta.getFSInterviewWrapUpEDBCResults();
		if (fsRsltVec != null && fsRsltVec.size() > 0) {
			fsRsltEnum = fsRsltVec.elements();
			while (fsRsltEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult fsRsltObj = (InterviewWrapUpEDBCResult) fsRsltEnum.nextElement();
				if (ebcObjectVector != null && ebcObjectVector.size() > 0) {
					Enumeration ebcObjectEnum = ebcObjectVector.elements();
					while (ebcObjectEnum.hasMoreElements()) {
						EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
						if (ebcObj.getAuId().intValue() == fsRsltObj.getAuId().intValue()) {
							ebcObject = ebcObj;
							break;
						}
					}
				}
				if (ebcObject != null) {
					fsAUSubType = ebcObject.getFutureFSAUSubtype(maECFDelta, maECFRule.getMAClient(clientId));
					tbaFlag = fsRsltObj.getFinancialObject(BENEFIT, TBAFLAG).getValue().toString();
					if (fsRsltObj.getStatus().equals(ACTIVE)
							&& !isFSResultHasClosureConditions(maECFDelta, maClientDelta, fsRsltObj, ebcObject).equals(CLOSURE)
							&& (tbaFlag != null && tbaFlag.equalsIgnoreCase(NO))
							&& !isReevaluationVerificationSelected(maECFDelta, maClientDelta, fsRsltObj.getAuId(), VER_DATA_ID_140, true, false)
							&& !isARExclusion(maECFDelta, maClientDelta, fsRsltObj)) {
						// BaseEBCResultAU ebcRsltBase =
						// maECFBase.getEBCResult(ebcObject.getAuId());//@CodeClean
						EBCResultBase ebcRsltBase = maECFDelta.getEBCResultBase(ebcObject.getAuId());
						edbcResultFinancial = fsRsltObj.getFinancialObject(BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT);
						rsltPreRecoupFedFSAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? Double
								.parseDouble(edbcResultFinancial.getValue().toString()) : 0.00;
						relRsltFundingReductionAmt = getReleasedFinancialDouble(getPrevReleasedXMLValue(maECFDelta, fsRsltObj.getAuId(),
								fsRsltObj.getRequestId(), BENEFIT, FUNDINGREDUCTIONAMOUNT));
						RelrsltPreRecoupFedFSAmt = getReleasedFinancialDouble(getPrevReleasedXMLValue(maECFDelta, fsRsltObj.getAuId(),
								fsRsltObj.getRequestId(), BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT));
						if (ebcRsltBase != null
								&& ((ebcRsltBase.getRevalTypeCode().equals(ANNUAL_REPORTING) && fsAUSubType.equals(NON_PUBLIC_ASSISTANCE)) || (ebcRsltBase.getRevalTypeCode().isNotEmpty()
									    && simpReevalTypesVec.contains(ebcRsltBase.getRevalTypeCode()) && (fsAUSubType.equals(NON_PUBLIC_ASSISTANCE) || (fsAUSubType
										.equals(PUBLIC_ASSISTANCE) && doesAUHaveSSIAndNoCash(fsRsltObj.getAuMembResults(), maECFRule.getMAClient(clientId),
										maECFDelta))))) && rsltPreRecoupFedFSAmt < RelrsltPreRecoupFedFSAmt) {
							setFinancialValue(fsRsltObj, BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT, RelrsltPreRecoupFedFSAmt);
							adjustRecoupment(fsRsltObj, maClientDelta, ebcObject);
							edbcResultFinancial = fsRsltObj.getFinancialObject(BENEFIT, RECOUPMENTELEMENT);
							double recoupmentAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? Double
									.parseDouble(edbcResultFinancial.getValue().toString()) : 0.00;
							fsRsltObj.setBenefitAmount(RelrsltPreRecoupFedFSAmt - recoupmentAmt);
							setFinancialValue(fsRsltObj, BENEFIT, FUNDINGREDUCTIONAMOUNT, relRsltFundingReductionAmt);
							setFinancialValue(fsRsltObj, BENEFIT, FSBYPASSFMCSFLG, "Y");
						}
					}
				}
			}
		}
	}
	public static void adjustRecoupment(InterviewWrapUpEDBCResult fsRsltObj, MAClient maClient, EDBCResult ebcObject) throws Exception {
		Recoupment recoupment = null;
		EDBCResultFinancial edbcResultFinancial = null;
		double rsltPreRecoupFedFSAmt;
		double recoupmentAmt;
		
		recoupment = (Recoupment) maClient.getFields().getField(Recoupment.class, ebcObject.getAuId());
		if (recoupment != null && (recoupment.getRecoupmentAmount().doubleValue() > 0)) {
			recoupmentAmt = recoupment.getRecoupmentAmount().doubleValue();
			edbcResultFinancial = fsRsltObj.getFinancialObject(BENEFIT, PRERECOUPMENTFEDERALFSAMOUNT);
			rsltPreRecoupFedFSAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? Double
			                .parseDouble(edbcResultFinancial.getValue().toString())
			                : 0.00;
            if (recoupment.getRecoupmentBalanceAmount().isNotEmpty()
			                && (recoupment.getRecoupmentBalanceAmount().doubleValue() < recoupmentAmt)) {
            	recoupmentAmt = recoupment.getRecoupmentBalanceAmount().intValue();
            }
            if (recoupmentAmt >= rsltPreRecoupFedFSAmt ) {
            	recoupmentAmt = rsltPreRecoupFedFSAmt;
            	ebcObject.setFederalFoodStampAllotment(ZERO_DOUBLE_VALUE);
            }
            else {
            	ebcObject.setFederalFoodStampAllotment(Money.getInstance(rsltPreRecoupFedFSAmt - recoupmentAmt));
            }
            
        	ebcObject.setRecoupmentCurrentAmount(recoupmentAmt);
        	setFinancialValue(fsRsltObj, BENEFIT, RECOUPMENTELEMENT, recoupmentAmt);
			ebcObject.setKeepAUOpen(TRUE_VALUE);
		}
	}
	public static boolean penaltyCheck(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, DateData effDte)
	                throws Exception {
		String penaltyDte = getFinancialObjectStringValue(interviewWrapUpEDBCResult, BENEFIT, PENALTYENDDATE);
		if (penaltyDte != "") {
			SimpleDateFormat sdfOutput = new SimpleDateFormat("MM/dd/yyyy", Locale.US);
			java.util.Date tmpPenaltyDate =  sdfOutput.parse(penaltyDte);
			DateData tmpPenaltyDte = new DateData(tmpPenaltyDate);
			if (tmpPenaltyDte.after(effDte)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * This method sets the au closure reasons for the closure aus.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maECFHouseholdBase
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param maClientBase
	 *            MAClient object
	 * @param ebcObjectVector
	 *            rule object
	 * @param interviewWrapUpEDBCResultBaseVector
	 *            view created by base result
	 * @param interviewWrapUpEDBCResult
	 *            view object
	 * @throws Exception
	 */
	public static void auClosureReasons(MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFRule, MAClient maClientBase,
	                                    Vector ebcObjectVector, Vector interviewWrapUpEDBCResultBaseVector,
	                                    InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, int clientId)
	                throws Exception {
		EBCResultBase ebcResultBase = null;
		BenefitChangeRsnFactor benefitChangeRsnFactor = null;
		Enumeration tempEnum = null;
		DateData penaltyEndDate = new DateData();
		StringData eligFactStat = new StringData(ELIG_STATUS);
		EligFactorReasonCode eligFactorRsn = null;
		Enumeration eligFactorReasonCodeEnum = null;
		Vector eligFactorReasonCodeVect = null;
		ebcResultBase = maECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult.getAuId());
		Enumeration ebcObjectEnum = ebcObjectVector.elements();
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		DateData today = new DateData (maECFHouseholdDelta.getFields().getContext().getEffectiveDate());
		while (ebcObjectEnum.hasMoreElements()) {
			EDBCResult edbcResult = (EDBCResult) ebcObjectEnum.nextElement();
			if ((edbcResult.getIsRetro().isEmpty() || edbcResult.getIsRetro().isFalse())
					&& edbcResult.getAuId().isNotEmpty() && interviewWrapUpEDBCResult.getAuId().isNotEmpty()
			                && edbcResult.getAuId().intValue() == interviewWrapUpEDBCResult.getAuId().intValue()) {
				if(edbcResult.getAuEFRC().isNotEmpty()) {
					interviewWrapUpEDBCResult.setAuEFRC(edbcResult.getAuEFRC());
				}
				BaseAU asstUnit = maClientDelta.getAsstUnit(edbcResult.getAuId());
				boolean auClosureFlg = hasAuClosureEFRC(maECFRule.getMAClient(clientId), asstUnit.getId());
				if (resultHasClosureConditions(maECFHouseholdDelta, maClientDelta, interviewWrapUpEDBCResult,
				                edbcResult)
				                && (!auClosureFlg || (auClosureFlg && !isVerificationSelected(maECFHouseholdDelta,
				                		maClientDelta, asstUnit.getId(), 77, true, false))
				                				|| (auClosureFlg && isReopened(maECFHouseholdDelta,asstUnit.getId())))) {
					if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMTOTALINCOME) > 0.0
					                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS,
					                                NEEDSTANDARD) > 0.0) {
						// Determine ineligible months and penalty end date
						double tmpDouble = (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
						                LUMPSUMTOTALINCOME) / getFinancialObjectDoubleValue(interviewWrapUpEDBCResult,
						                STANDARDAMOUNTS, NEEDSTANDARD));
						Double doubleVal = new Double(tmpDouble);
						int val = doubleVal.intValue();
						setFinancialValueInteger(interviewWrapUpEDBCResult, BENEFIT, LUMPSUMMONTHSINELIGIBLE, val);
						EbcCycleDate tmpCycleMonth = getEbcCycleDate(maClientDelta,
						                interviewWrapUpEDBCResult.getAuId(), interviewWrapUpEDBCResult
						                                .getLumpSumStartDate());

						if (tmpCycleMonth == null) {
							tmpCycleMonth = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(),
							                today);
						}
						int monthsAdded = (int) (getFinancialObjectIntegerValue(interviewWrapUpEDBCResult, BENEFIT,
						                LUMPSUMMONTHSINELIGIBLE) * 30.41666);
						//penaltyEndDate.setTime(tmpCycleMonth.getFirstCycRelDate().addDays(monthsAdded));
						if(asstUnit.getProgramCode().equals(SNAP))
							penaltyEndDate.setTime(tmpCycleMonth.getFirstCycPmtDate().addDays(monthsAdded-1));
						if(asstUnit.getProgramCode().equals(TANF))
							penaltyEndDate.setTime(tmpCycleMonth.getTanfCycStdPmtDate().addDays(monthsAdded-1));
						setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PENALTYENDDATE, penaltyEndDate
						                .toLocaleString());
						interviewWrapUpEDBCResult.setPenaltyEnd(penaltyEndDate);

						// Determine lump sum remaining amount
						setFinancialValue(
						                interviewWrapUpEDBCResult,
						                BENEFIT,
						                LUMPSUMREMAININGAMOUNT,
						                getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
						                                LUMPSUMTOTALINCOME)
						                                - (getFinancialObjectIntegerValue(interviewWrapUpEDBCResult,
						                                                BENEFIT, LUMPSUMMONTHSINELIGIBLE) * getFinancialObjectDoubleValue(
						                                                interviewWrapUpEDBCResult, STANDARDAMOUNTS,
						                                                NEEDSTANDARD)));
					}
					if (!getFinancialObjectStringValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS)
					                .equals(EMPTY_STRING)
					                && edbcResult.getPriorityCAPReason() != null
					                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(PENDING)) {
						StringData reason = new StringData(edbcResult.getPriorityCAPReason());
						interviewWrapUpEDBCResult.setAuEFRC(getBenefitChangeReasonFactor(
						                maClientDelta.getFields().getContext(), reason).getEligFactorRsnInelig());
					}
					else if (!getFinancialObjectStringValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS,
					                CAPELIGIBILITYSTATUS).equals(EMPTY_STRING)
					                && edbcResult.isEBCActiveCAP(maECFHouseholdDelta, maClientDelta)
					                && edbcResult.getPriorityCAPReason() != null) {
						StringData priorityreason = new StringData(edbcResult.getPriorityCAPReason());
						benefitChangeRsnFactor = getBenefitChangeReasonFactor(maClientDelta.getFields().getContext(),
						                priorityreason);
						if (benefitChangeRsnFactor != null
						                && benefitChangeRsnFactor.getEligFactorRsnInelig().isNotEmpty()
						                && getEligFactorRsnDtl(maClientDelta.getFields().getContext(),
						                                benefitChangeRsnFactor.getEligFactorRsnInelig())
						                                .getStatCloseFlag().booleanValue()) {
							priorityreason = new StringData(edbcResult.getPriorityCAPReason());
							interviewWrapUpEDBCResult.setAuEFRC(getBenefitChangeReasonFactor(
							                maClientDelta.getFields().getContext(), priorityreason)
							                .getEligFactorRsnInelig());
						}
					}
					else if (getFinancialObjectIntegerValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE) == 0) {
						if ((maClientBase.getClientAUMembInEligFactor(maClientDelta.getGranteeForAU(
						                interviewWrapUpEDBCResult.getAuId()).getClientId()) != null || maClientDelta
						                .getClientAUMembInEligFactor(
						                                maClientDelta.getGranteeForAU(
						                                                interviewWrapUpEDBCResult.getAuId())
						                                                .getClientId()).size() > 0)
						                && (interviewWrapUpEDBCResult.getEbcEFRCFlg().isTrue() || isVerificationSelected(
						                                maECFHouseholdDelta, maClientDelta, interviewWrapUpEDBCResult
						                                                .getAuId(), 78, false, true))) {
							Vector auMembIneligFactorVector = maClientDelta.getClientAUMembInEligFactor(maClientDelta
							                .getGranteeForAU(interviewWrapUpEDBCResult.getAuId()).getClientId());
							if (auMembIneligFactorVector != null && auMembIneligFactorVector.size() > 0) {
								tempEnum = auMembIneligFactorVector.elements();
								while (tempEnum.hasMoreElements()) {
									ClientAuMembIneligFactor clientAuMembIneligFactor = (ClientAuMembIneligFactor) tempEnum
									                .nextElement();
									if (clientAuMembIneligFactor.getAuId().intValue() == interviewWrapUpEDBCResult
									                .getAuId().intValue()) {
										interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor
										                .getEligFactorReason());
										break;
									}
								}
							}
						}
						if ((interviewWrapUpEDBCResult.getProgram().isNotEmpty()
								&& interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF))
								&& (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()
										|| interviewWrapUpEDBCResult.getAuEFRC().toString().equalsIgnoreCase("001061")
										|| (interviewWrapUpEDBCResult.getStatus().equals(PENDING))
												&& interviewWrapUpEDBCResult.getAuEFRC().equals(EFRC_ELIG_SSI))) {
							// if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() ||
							// interviewWrapUpEDBCResult.getAuEFRC().toString().equalsIgnoreCase("001061")) {
							interviewWrapUpEDBCResult.setAuEFRC("001008");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							// }
						}
						if ((interviewWrapUpEDBCResult.getProgram().isNotEmpty() && interviewWrapUpEDBCResult
						                .getProgram().toString().equalsIgnoreCase(EAEDC))
						                && (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() || interviewWrapUpEDBCResult
						                                .getAuEFRC().toString().equalsIgnoreCase("001061"))) {
							/*
							 * PMD violation fixed for CollapsibleIfStatements for version 1.2
							 */
							// if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() ||
							// interviewWrapUpEDBCResult.getAuEFRC().toString().equalsIgnoreCase("001061")) {
							interviewWrapUpEDBCResult.setAuEFRC("001009");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							// }
						}
						if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
						                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                SNAP) || interviewWrapUpEDBCResult.getProgram()
						                                .toString().equalsIgnoreCase(EA))) {
							if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()) {
								Vector auMembersVector = maClientDelta.getAllMembersInAU(interviewWrapUpEDBCResult
								                .getAuId());
								Enumeration aumembersEnum = auMembersVector.elements();
								while (aumembersEnum.hasMoreElements()) {
									BaseAUMember auMembers = (BaseAUMember) aumembersEnum.nextElement();
									if ((maClientDelta.getClientAUMembInEligFactor(auMembers.getClientId()) != null && maClientDelta
									                .getClientAUMembInEligFactor(auMembers.getClientId()).size() > 0)
									                && (interviewWrapUpEDBCResult.getEbcEFRCFlg().isTrue() || isVerSelected(maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
									                		                                                                auMembers.getClientId(), 78, false, true))){									                		
										//CO:50729 replace isVerificationSelected with isVerSelected
										//isVerificationSelected(maECFHouseholdDelta, maClientDelta,interviewWrapUpEDBCResult.getAuId(), 78, false,false))){		
										Vector auMembIneligFactorVector = maClientDelta
										                .getClientAUMembInEligFactor(auMembers.getClientId());
										/*
										 * if (auMembIneligFactorVector != null && auMembIneligFactorVector.size() > 0) {
										 * ClientAuMembIneligFactor clientAuMembIneligFactor =
										 * (ClientAuMembIneligFactor) auMembIneligFactorVector.get(0);
										 * interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor.getEligFactorReason()); }
										 */
										tempEnum = auMembIneligFactorVector.elements();
										while (tempEnum.hasMoreElements()) {
											ClientAuMembIneligFactor clientAuMembIneligFactor = (ClientAuMembIneligFactor) tempEnum
											                .nextElement();
											if (clientAuMembIneligFactor.getAuId().intValue() == interviewWrapUpEDBCResult
											                .getAuId().intValue()) {
												interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor
												                .getEligFactorReason());
											}
										}
										break;
									}
								}
							}
							if(edbcResult.getAuEFRC().isNotEmpty()) {
								interviewWrapUpEDBCResult.setAuEFRC(edbcResult.getAuEFRC());
							}
							if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()) {
								if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
								                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
								                                EA)
								                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
								                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(
								                                PENDING)) {
									interviewWrapUpEDBCResult.setAuEFRC("001043");
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
								else {
									interviewWrapUpEDBCResult.setAuEFRC("001035");
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
							}
						}
					}
					else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT) > 0.0
					                && (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, ASSETS, ASSETS) > getFinancialObjectDoubleValue(
					                                interviewWrapUpEDBCResult, ASSETS, ASSETLIMIT))) {
						interviewWrapUpEDBCResult.setAuEFRC("000206");
						interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
					}
					else if (penaltyCheck(interviewWrapUpEDBCResult, maClientDelta.getFields().getContext()
					                .getEffectiveDate())
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(DENIED)) {
						interviewWrapUpEDBCResult.setAuEFRC("000218");
						interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
					}
					else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT) > 0.0 && getGrossIncome(interviewWrapUpEDBCResult) > getFinancialObjectDoubleValue(
					                interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT))
					                || (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, NETINCOME,
					                                NETINCOMELIMIT) > 0.0 && getFinancialObjectDoubleValue(
					                                interviewWrapUpEDBCResult, NETINCOME, NETINCOME) > getFinancialObjectDoubleValue(
					                                interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT)
					                || (interviewWrapUpEDBCResult.getProgram().equals(TANF)
					                	&& getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, NETINCOME,
					                                NETINCOMELIMIT) > 0.0 && getFinancialObjectDoubleValue(
					                                interviewWrapUpEDBCResult, NETINCOME, NETINCOMELIMIT) - getFinancialObjectDoubleValue(
					                                interviewWrapUpEDBCResult, NETINCOME, NETINCOME) < 1))) {
						if (interviewWrapUpEDBCResultBaseVector != null
						                && interviewWrapUpEDBCResultBaseVector.size() > 0
						                && ebcResultBase != null
						                && ebcResultBase.getAuStatus().isNotEmpty()
						                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,LUMPSUMTOTALINCOME) > getFinancialObjectDoubleValue((InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultBaseVector.get(0), BENEFIT,LUMPSUMTOTALINCOME)
						                //&& interviewWrapUpEDBCResult.getLumpSumIncome().doubleValue() > (((InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultBaseVector.get(0)).getLumpSumIncome().doubleValue())
						                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(ACTIVE)) {
							interviewWrapUpEDBCResult.setAuEFRC("000213");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) > 0.0 && getFinancialObjectDoubleValue(
						                interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT) > 0.0)
						                && ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
						                                EARNEDINCOME)
						                                + getFinancialObjectDoubleValue(interviewWrapUpEDBCResult,
						                                                GROSSINCOME, CHILDSUPPORT) > (getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME,
						                                EARNEDINCOME)) + getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME,
						                                CHILDSUPPORT)))))) {
							interviewWrapUpEDBCResult.setAuEFRC("000219");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) > getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, EARNEDINCOME))) {
							interviewWrapUpEDBCResult.setAuEFRC("000220");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT) > getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, CHILDSUPPORT))) {
							interviewWrapUpEDBCResult.setAuEFRC("000203");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME) > getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, UNEARNEDINCOME))) {
							interviewWrapUpEDBCResult.setAuEFRC("000205");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if ((interviewWrapUpEDBCResult.getProgram().isNotEmpty() && (interviewWrapUpEDBCResult
						                .getProgram().toString().equalsIgnoreCase(SNAP) || interviewWrapUpEDBCResult
						                .getProgram().toString().equalsIgnoreCase(EA)))
						                && (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
						                                UNEARNEDINCOME) + getFinancialObjectDoubleValue(
						                                interviewWrapUpEDBCResult, BENEFIT, GRANTAMOUNT)) > (getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME,
						                                UNEARNEDINCOME)) + getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                                interviewWrapUpEDBCResult.getRequestId(), BENEFIT, GRANTAMOUNT)))) {
							interviewWrapUpEDBCResult.setAuEFRC("000205");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
						                DISREGARDDOLLARCOUNT) < getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, DISREGARDDOLLARCOUNT)))
						                && ebcResultBase != null
						                && ebcResultBase.getAuStatus().isNotEmpty()
						                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(ACTIVE)) {
							interviewWrapUpEDBCResult.setAuEFRC("000202");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
				                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
				                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, ALLOWEDDISREGARD))) {
							interviewWrapUpEDBCResult.setAuEFRC("006020");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
						                DISREGARDFRACTIONCOUNT) < getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, DISREGARDFRACTIONCOUNT)))
						                && ebcResultBase != null
						                && ebcResultBase.getAuStatus().isNotEmpty()
						                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(ACTIVE)) {
							interviewWrapUpEDBCResult.setAuEFRC("000201");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME) < getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, DEEMEDINCOME)))) {
							interviewWrapUpEDBCResult.setAuEFRC("000216");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}
						/* dependent disregard count not applicable */
						/*else if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
						                DEPENDENTDISREGARDCOUNT) < getReleasedFinancialDouble(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, DEPENDENTDISREGARDCOUNT)))
						                && ebcResultBase != null
						                && ebcResultBase.getAuStatus().isNotEmpty()
						                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(ACTIVE)) {
							interviewWrapUpEDBCResult.setAuEFRC(EBCConstant.END_12_MONTH_DISREGARDS);
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
						}*/

						if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()) {
							if (interviewWrapUpEDBCResult.getLumpSumIncome().isNotEmpty()
							                && interviewWrapUpEDBCResult.getLumpSumIncome().doubleValue() > 0.0
							                && ebcResultBase.getAuStatus().isNotEmpty()
							                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(ACTIVE)) {
								interviewWrapUpEDBCResult.setAuEFRC("000213");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) > 0.0
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
							                                CHILDSUPPORT) > 0.0) {
								interviewWrapUpEDBCResult.setAuEFRC("000219");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) > 0.0) {
								interviewWrapUpEDBCResult.setAuEFRC("000220");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, CHILDSUPPORT) > 0.0) {
								interviewWrapUpEDBCResult.setAuEFRC("000203");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
							                UNEARNEDINCOME) > 0.0) {
								interviewWrapUpEDBCResult.setAuEFRC("000205");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
							                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                    SNAP) || interviewWrapUpEDBCResult.getProgram()
							                                .toString().equalsIgnoreCase(EA))
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
							                                GRANTAMOUNT) > 0) {
								interviewWrapUpEDBCResult.setAuEFRC("000205");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, DEEMEDINCOME) > 0.0) {
								interviewWrapUpEDBCResult.setAuEFRC("000216");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
							else {
								interviewWrapUpEDBCResult.setAuEFRC("000220");
								interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							}
						}
						EligFactorRsnDtl eligFactRsnDtl = getEligFactorRsnDtl(maClientDelta.getFields().getContext(),
						                interviewWrapUpEDBCResult.getAuEFRC());
						if ((getFinancialObjectIntegerValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, AUSIZE) < getReleasedFinancialInteger(getPrevReleasedXMLValue(
						                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
						                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS, AUSIZE)))
						                && (eligFactRsnDtl.getIncomeComboFlag().isNotEmpty() && eligFactRsnDtl
						                                .getIncomeComboFlag().booleanValue())) {
							Vector<ClientAuMembIneligFactor> apIneligVec = maClientDelta
							                .getClientAUMembInEligFactor(interviewWrapUpEDBCResult.getGranteeId());
							StringData granteeEFRC = new StringData();
							for (ClientAuMembIneligFactor apInelig : apIneligVec) {
								if (apInelig.getAuId().intValue() == interviewWrapUpEDBCResult.getAuId().intValue()) {
									granteeEFRC.setString(apInelig.getEligFactorReason());
									break;
								}
							}
							if (granteeEFRC.isNotEmpty()) {
								eligFactRsnDtl = getEligFactorRsnDtl(maClientDelta.getFields().getContext(),
								                granteeEFRC);
								if ((interviewWrapUpEDBCResult.getEbcEFRCFlg().booleanValue() || isVerificationSelected(
								                maECFHouseholdDelta, maClientDelta,
								                interviewWrapUpEDBCResult.getAuId(), 78, false, false))
								                && eligFactRsnDtl.getIncomeComboEFRC().isNotEmpty()) {
									interviewWrapUpEDBCResult.setAuEFRC(eligFactRsnDtl.getIncomeComboEFRC());
								}
							} 
							else {
								Vector<BaseAUMember> auMemberVector = maClientDelta
								                .getAllMembersInAU(interviewWrapUpEDBCResult.getAuId());
								StringData nonGranteeEFRC = new StringData();
								for (BaseAUMember auMemb : auMemberVector) {
									if (!auMemb.isGrantee()) {
										apIneligVec = maClientDelta.getClientAUMembInEligFactor(auMemb.getClientId());
										for (ClientAuMembIneligFactor apInelig : apIneligVec) {
											if (apInelig.getAuId().intValue() == interviewWrapUpEDBCResult.getAuId()
											                .intValue()) {
												nonGranteeEFRC.setString(apInelig.getEligFactorReason());
												break;
											}
										}
										eligFactRsnDtl = getEligFactorRsnDtl(maClientDelta.getFields().getContext(),
										                nonGranteeEFRC);
										if (nonGranteeEFRC.isNotEmpty()) {
											if ((interviewWrapUpEDBCResult.getEbcEFRCFlg().booleanValue() || isVerificationSelected(
											                maECFHouseholdDelta, maClientDelta,
											                interviewWrapUpEDBCResult.getAuId(), 78, false, false))
											                && eligFactRsnDtl.getIncomeComboEFRC().isNotEmpty()) {
												interviewWrapUpEDBCResult
												                .setAuEFRC(eligFactRsnDtl.getIncomeComboEFRC());
												break;
											}
										}
									}
								}
							}
						}
					}
					else {
						if ((maClientDelta.getClientAUMembInEligFactor(maClientDelta.getGranteeForAU(
						                interviewWrapUpEDBCResult.getAuId()).getClientId()) != null && maClientDelta
						                .getClientAUMembInEligFactor(
						                                maClientDelta.getGranteeForAU(
						                                                interviewWrapUpEDBCResult.getAuId())
						                                                .getClientId()).size() > 0)
						                && (interviewWrapUpEDBCResult.getEbcEFRCFlg().isTrue() || isVerificationSelected(
						                                maECFHouseholdDelta, maClientDelta, interviewWrapUpEDBCResult
						                                                .getAuId(), 78, false, true))) {
							Vector auMembIneligFactorVector = maClientDelta.getClientAUMembInEligFactor(maClientDelta
							                .getGranteeForAU(interviewWrapUpEDBCResult.getAuId()).getClientId());
							/*
							 * if (auMembIneligFactorVector != null && auMembIneligFactorVector.size() > 0) {
							 * ClientAuMembIneligFactor clientAuMembIneligFactor = (ClientAuMembIneligFactor)
							 * auMembIneligFactorVector.get(0);
							 * interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor.getEligFactorReason()); }
							 */
							tempEnum = auMembIneligFactorVector.elements();
							while (tempEnum.hasMoreElements()) {
								ClientAuMembIneligFactor clientAuMembIneligFactor = (ClientAuMembIneligFactor) tempEnum
								                .nextElement();
								if (clientAuMembIneligFactor.getAuId().intValue() == interviewWrapUpEDBCResult
								                .getAuId().intValue()) {
									interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor.getEligFactorReason());
								}
							}
						}
						if ((interviewWrapUpEDBCResult.getProgram().isNotEmpty() && interviewWrapUpEDBCResult
						                .getProgram().toString().equalsIgnoreCase(TANF))
						                && (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() || interviewWrapUpEDBCResult
						                                .getAuEFRC().toString().equalsIgnoreCase("001061"))) {
							/*
							 * PMD violation fixed for CollapsibleIfStatements for version 1.2
							 */
							// if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() ||
							// interviewWrapUpEDBCResult.getAuEFRC().toString().equalsIgnoreCase("001061")) {
							 if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) > 0.0) {
									interviewWrapUpEDBCResult.setAuEFRC(EFRC_000220);;
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
								else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
								                UNEARNEDINCOME) > 0.0) {
									interviewWrapUpEDBCResult.setAuEFRC(EFRC_000205);
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
								else {
									interviewWrapUpEDBCResult.setAuEFRC("001008");
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
							// }
						}
						if ((interviewWrapUpEDBCResult.getProgram().isNotEmpty() && interviewWrapUpEDBCResult
						                .getProgram().toString().equalsIgnoreCase(EAEDC))
						                && (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() || interviewWrapUpEDBCResult
						                                .getAuEFRC().toString().equalsIgnoreCase("001061"))) {
							/*
							 * PMD violation fixed for CollapsibleIfStatements for version 1.2
							 */
							// if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty() ||
							// interviewWrapUpEDBCResult.getAuEFRC().toString().equalsIgnoreCase("001061")) {
							interviewWrapUpEDBCResult.setAuEFRC("001009");
							interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
							// }
						}
						if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
						                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                SNAP) || interviewWrapUpEDBCResult.getProgram()
						                                .toString().equalsIgnoreCase(EA))) {
							if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()) {
								Vector auMembersVector = maClientDelta.getAllMembersInAU(interviewWrapUpEDBCResult
								                .getAuId());
								Enumeration aumembersEnum = auMembersVector.elements();
								while (aumembersEnum.hasMoreElements()) {
									BaseAUMember auMembers = (BaseAUMember) aumembersEnum.nextElement();
									if ((maClientDelta.getClientAUMembInEligFactor(auMembers.getClientId()) != null && maClientDelta
									                .getClientAUMembInEligFactor(auMembers.getClientId()).size() > 0)
									                && (interviewWrapUpEDBCResult.getEbcEFRCFlg().isTrue() || isVerificationSelected(
									                                maECFHouseholdDelta, maClientDelta,
									                                interviewWrapUpEDBCResult.getAuId(), 78, false,
									                                false))) {
										Vector auMembIneligFactorVector = maClientDelta
										                .getClientAUMembInEligFactor(auMembers.getClientId());
										/*
										 * if (auMembIneligFactorVector != null && auMembIneligFactorVector.size() > 0) {
										 * ClientAuMembIneligFactor clientAuMembIneligFactor =
										 * (ClientAuMembIneligFactor) auMembIneligFactorVector.get(0);
										 * interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor.getEligFactorReason()); }
										 */
										tempEnum = auMembIneligFactorVector.elements();
										while (tempEnum.hasMoreElements()) {
											ClientAuMembIneligFactor clientAuMembIneligFactor = (ClientAuMembIneligFactor) tempEnum
											                .nextElement();
											if (clientAuMembIneligFactor.getAuId().intValue() == interviewWrapUpEDBCResult
											                .getAuId().intValue()) {
												interviewWrapUpEDBCResult.setAuEFRC(clientAuMembIneligFactor
												                .getEligFactorReason());
											}
										}
										break;
									}
								}
							}
							if (interviewWrapUpEDBCResult.getAuEFRC().isEmpty()) {
								if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
								                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
								                                EA)
								                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
								                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(
								                                PENDING)) {
									interviewWrapUpEDBCResult.setAuEFRC("001043");
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
								else {
									interviewWrapUpEDBCResult.setAuEFRC("001035");
									interviewWrapUpEDBCResult.setEbcEFRCFlg(true);
								}
							}
						}
					}

					interviewWrapUpEDBCResult.setAuEligFactorStatus(eligFactStat);
					if (interviewWrapUpEDBCResult.getAuEFRC().isNotEmpty()) {
						SimpleStatement stmt = new SimpleStatement(SQLActions.SELECT, EligFactorReasonCode.class);
						eligFactorReasonCodeVect = mapper.fetchMany(maClientDelta.getFields().getContext(), stmt);
						if (eligFactorReasonCodeVect != null && eligFactorReasonCodeVect.size() > 0) {
							eligFactorReasonCodeEnum = eligFactorReasonCodeVect.elements();
							while (eligFactorReasonCodeEnum.hasMoreElements()) {
								eligFactorRsn = (EligFactorReasonCode) eligFactorReasonCodeEnum.nextElement();
								//Added the end date condition(ELIG_FACTOR_RSN_CD) to retrieve the latest eligibility factor which is not end dated
								if (eligFactorRsn.getEndDate().isEmpty() && eligFactorRsn.getCode().toString().equals(
								                interviewWrapUpEDBCResult.getAuEFRC().toString())) {
									interviewWrapUpEDBCResult.setAuEligFactor(eligFactorRsn.getEligFactorCode());
									break;
								}
							}
						}
					}
					Enumeration auMembersEnum = interviewWrapUpEDBCResult.getAuMembResults().elements();
					while (auMembersEnum.hasMoreElements()) {
						EDBCResultAUMember edbcResultAUMember = (EDBCResultAUMember) auMembersEnum.nextElement();
						if (edbcResultAUMember.getMemIneligReason().isEmpty()) {
							edbcResultAUMember.setMemIneligReason(interviewWrapUpEDBCResult.getAuEFRC());
							edbcResultAUMember
							                .setMemEligFactorStatus(interviewWrapUpEDBCResult.getAuEligFactorStatus());
							edbcResultAUMember.setMemEligFactor(interviewWrapUpEDBCResult.getAuEligFactor());

						}
					}
				}
			}
		}
	}

	/**
	 * Sets the benefit change reasons for the new result from the previous result.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maECFHouseholdBase
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param maClientBase
	 *            MAClient object
	 * @param ebcObjectVector
	 *            rule object
	 * @param interviewWrapUpEDBCResultBaseVector
	 *            view created by base result
	 * @throws Exception
	 */
	public static void benefitChangeReasons(MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFRule,
	                                        Vector ebcObjectVector, Vector interviewWrapUpEDBCResultBaseVector,
	                                        Vector auExcludedVec, int clientId) throws Exception {
		Vector descVec = null;
		BaseAU baseAU = null;
		String curTBA = "";
		Context effCtx = null;
		effCtx = maECFHouseholdDelta.getFields().getContext();
		Vector interviewWrapupEDBCResultVector = maECFHouseholdDelta.getInterviewWrapUpEDBCResults();
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		Enumeration interviewWrapupEDBCResultEnum = interviewWrapupEDBCResultVector.elements();
		while (interviewWrapupEDBCResultEnum.hasMoreElements()) {
			InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapupEDBCResultEnum
			                .nextElement();
			Enumeration ebcObjectEnum = ebcObjectVector.elements();
			while (ebcObjectEnum.hasMoreElements()) {
				EDBCResult edbcResult = (EDBCResult) ebcObjectEnum.nextElement();
				baseAU = maClientDelta.getAsstUnit(interviewWrapUpEDBCResult.getAuId());
				curTBA = getValue(interviewWrapUpEDBCResult.getResultXML(), BENEFIT, TBAFLAG);
				// AU Exclusion Conditions are not met for result AU
				if (edbcResult.getPriorityCAPReason() != null) {
					descVec = new Vector();
					String desc = "";
					Enumeration capRsnEnum = interviewWrapUpEDBCResult.getCapReasons().elements();
					while (capRsnEnum.hasMoreElements()) {
						String capRsn = (String) capRsnEnum.nextElement();
						if (capRsn != null) {
							descVec.addElement(capRsn);
						}
					}
					interviewWrapUpEDBCResult.setBenefitChangeReasonVector(descVec);
				}
				String curRsltCapInd = getFinancialObjectStringValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPIND);
				String relRsltCapInd = getPrevReleasedXMLValue(maECFHouseholdDelta,
				                interviewWrapUpEDBCResult.getAuId(), interviewWrapUpEDBCResult.getRequestId(),
				                STANDARDAMOUNTS, CAPIND);
				if (((auExcludedVec.isEmpty() || (auExcludedVec.size() > 0 && !(auExcludedVec
				                .contains(interviewWrapUpEDBCResult.getAuId()))))
				                && edbcResult.getAuId().isNotEmpty()
				                && interviewWrapUpEDBCResult.getAuId().isNotEmpty() && (edbcResult.getAuId().intValue() == interviewWrapUpEDBCResult
				                .getAuId().intValue()))
				                && !(hasAuClosureEFRC(maClientRule, baseAU.getId()))) {
					// BaseEBCResultAU ebcResultBase =
					// maECFHouseholdBase.getEBCResult(interviewWrapUpEDBCResult.getAuId()); //@CodeClean
					EBCResultBase ebcResultBase = maECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult
					                .getAuId());
					BaseAU asstUnit = maClientDelta.getAsstUnit(interviewWrapUpEDBCResult.getAuId());
					if (ebcResultBase != null
					                && (ebcResultBase.getBenefitAmount().isNotEmpty()
					                                && interviewWrapUpEDBCResult.getBenefitAmount().isNotEmpty() && (ebcResultBase
					                                .getBenefitAmount().doubleValue() > interviewWrapUpEDBCResult
					                                .getBenefitAmount().doubleValue()
					                                || ebcResultBase.getBenefitAmount().doubleValue() < interviewWrapUpEDBCResult
					                                                .getBenefitAmount().doubleValue() || getFinancialObjectStringValue(
					                                interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPIND)
					                                .equalsIgnoreCase("HIGH")))
					                && !edbcResult.isCAPAULevelDever()
					                && !(ebcResultBase.getExpeditedCode().equals("E") || ebcResultBase
					                                .getExpeditedCode().equals("S"))) {
						if ((curRsltCapInd != null && !curRsltCapInd.equals(EMPTY_STRING))
						                && (relRsltCapInd == null || relRsltCapInd.equals(EMPTY_STRING))) {
							interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CAPREQ");
						}
						else {
							if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)
							                && (curRsltCapInd != null && !curRsltCapInd.equals(EMPTY_STRING))
							                && (relRsltCapInd != null && !relRsltCapInd.equals(EMPTY_STRING))
							                && !curRsltCapInd.equals(relRsltCapInd)) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CAPSHL");
							}
							if ((curRsltCapInd == null || curRsltCapInd.equals(EMPTY_STRING))
							                && (relRsltCapInd != null && !relRsltCapInd
							                                .equals(EMPTY_STRING))
							                && ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
							                                SHELTEREXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS,
							                                SHELTEREXPENSE)))
							                                || (getFinancialObjectDoubleValue(
							                                                interviewWrapUpEDBCResult, DEDUCTIONS,
							                                                UTILITYEXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                                maECFHouseholdDelta,
							                                                interviewWrapUpEDBCResult.getAuId(),
							                                                interviewWrapUpEDBCResult.getRequestId(),
							                                                DEDUCTIONS, UTILITYEXPENSE)))
							                                || (getFinancialObjectDoubleValue(
							                                                interviewWrapUpEDBCResult, DEDUCTIONS,
							                                                DEPENDENTCAREEXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                                maECFHouseholdDelta,
							                                                interviewWrapUpEDBCResult.getAuId(),
							                                                interviewWrapUpEDBCResult.getRequestId(),
							                                                DEDUCTIONS, DEPENDENTCAREEXPENSE))) || (getFinancialObjectDoubleValue(
							                                interviewWrapUpEDBCResult, DEDUCTIONS, MEDICALDEDUCTION) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS,
							                                MEDICALDEDUCTION))))) {
								interviewWrapUpEDBCResult.getCapReasons().add("CAPEXP");
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CAPEXP");
							}
							if (getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS, AUSIZE) != null
							                && getFinancialObjectIntegerValue(interviewWrapUpEDBCResult,
							                                STANDARDAMOUNTS, AUSIZE) != getReleasedFinancialInteger(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS,
							                                AUSIZE))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("AUSIZE");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS, ALLOWEDDISREGARD) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, ALLOWEDDISREGARD))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("DSRGRD");
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CNED");
							}
							if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
							                && interviewWrapUpEDBCResult.getProgram().toString()
							                                .equalsIgnoreCase(EAEDC)
							                && getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult
							                                .getAuId(), interviewWrapUpEDBCResult.getRequestId(),
							                                STANDARDAMOUNTS, BUDGETGROUP) != null
							                && !getFinancialObjectStringValue(interviewWrapUpEDBCResult,
							                                STANDARDAMOUNTS, BUDGETGROUP).equalsIgnoreCase(
							                                getPrevReleasedXMLValue(maECFHouseholdDelta,
							                                                interviewWrapUpEDBCResult.getAuId(),
							                                                interviewWrapUpEDBCResult.getRequestId(),
							                                                STANDARDAMOUNTS, BUDGETGROUP))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("BDGTYP");
							}
							if (getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS,
							                NEEDSTANDARDPAYMENTSTATUS) != null
							                && !getFinancialObjectStringValue(interviewWrapUpEDBCResult,
							                                STANDARDAMOUNTS, NEEDSTANDARDPAYMENTSTATUS)
							                                .equalsIgnoreCase(
							                                                getPrevReleasedXMLValue(
							                                                                maECFHouseholdDelta,
							                                                                interviewWrapUpEDBCResult
							                                                                                .getAuId(),
							                                                                interviewWrapUpEDBCResult
							                                                                                .getRequestId(),
							                                                                STANDARDAMOUNTS,
							                                                                NEEDSTANDARDPAYMENTSTATUS))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("EXEMPT");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, EARNEDINCOME))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("EARINC");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, UNEARNEDINCOME) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME, UNEARNEDINCOME))) {
								if ((curRsltCapInd != null && !curRsltCapInd.equals(EMPTY_STRING))
								                && (relRsltCapInd != null && !relRsltCapInd.equals(EMPTY_STRING))) {
									interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CAPINC");
								}
								else {
									interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("UNEINC");
								}
							}
							if(isClaimPaidFull(maClientDelta,interviewWrapUpEDBCResult)) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BEN_CHG_PAID_IN_FULL_CF71);
							} else if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT) > 0 && 
									getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT, RECOUPMENTELEMENT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), BENEFIT, RECOUPMENTELEMENT))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BEN_CHG_RECOUPMENT_RCPMT);
								if (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)) {
									interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BEN_CHG_CLAIM_INIT_PAYMENT_CF01);
								}
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, RENTALLOWANCE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS, RENTALLOWANCE))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("RENT");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
							                SUPPORTEXPENSEELEMENT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, SUPPORTEXPENSEELEMENT))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("SUPPRT");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT, VENDORPAYMENT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), BENEFIT, VENDORPAYMENT))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("VNDOR");
							}
							if (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
							                DEPENDENTCAREEXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, DEPENDENTCAREEXPENSE))) {
								if (getFinancialObjectStringValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPIND)
								                .equals(EMPTY_STRING)
								                &&! getPrevReleasedXMLValue(maECFHouseholdDelta,
								                                interviewWrapUpEDBCResult.getAuId(),
								                                interviewWrapUpEDBCResult.getRequestId(),
								                                STANDARDAMOUNTS, CAPIND).equals(EMPTY_STRING)) {
									// do nothing
								}
								else {
									interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("DPNDNT");
								}
							}
							if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
							                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                    SNAP) || interviewWrapUpEDBCResult.getProgram()
							                                .toString().equalsIgnoreCase(EA))
							                && ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
							                                GRANTAMOUNT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), BENEFIT,
							                                GRANTAMOUNT))
							                // GRANTAMOUNT should be in the EBC_RSLT/RSLT Benefit Category not in the
							                // GrossIncome - Below OR condition can be removed once CONVERSION fixed.
							                // Added DTA00007164 - Sep 12,09
							                || (getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
							                                GRANTAMOUNT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME,
							                                GRANTAMOUNT)))))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CBNFT");
							}
							if ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS, SHELTEREXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, SHELTEREXPENSE)) || getPrevReleasedXMLValue(
							                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS, UTILITYEXPENSE) != null
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
							                                UTILITYEXPENSE) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS,
							                                UTILITYEXPENSE)))
							                && getPrevReleasedXMLValue(maECFHouseholdDelta,
							                                interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS,
							                                CAPIND).equals(EMPTY_STRING)) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("HSHLD");
							}
							if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
							                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                    SNAP)
							                && getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult
							                                .getAuId(), interviewWrapUpEDBCResult.getRequestId(),
							                                DEDUCTIONS, MEDICALDEDUCTION) != null
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, DEDUCTIONS,
							                                MEDICALDEDUCTION) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), DEDUCTIONS,
							                                MEDICALDEDUCTION))) {
								if (getFinancialObjectStringValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CAPIND)
								                .equals(EMPTY_STRING)
								                && relRsltCapInd != null && !relRsltCapInd.equals(EMPTY_STRING) ) {
									// do nothing
								}
								else {
									interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("MEDDCT");
								}
							}
							if (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
							                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(
                                    SNAP)
							                && getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult
							                                .getAuId(), interviewWrapUpEDBCResult.getRequestId(),
							                                GROSSINCOME, DEFRAPAYMENT) != null
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
							                                DEFRAPAYMENT) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), GROSSINCOME,
							                                DEFRAPAYMENT))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("DEFRA");
							}
							if (getPrevReleasedXMLValue(maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS,
							                CHILDSUPPORTSANCTIONREDUCTION) != null
							                && getFinancialObjectDoubleValue(interviewWrapUpEDBCResult,
							                                STANDARDAMOUNTS, CHILDSUPPORTSANCTIONREDUCTION) != getReleasedFinancialDouble(getPrevReleasedXMLValue(
							                                maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId(),
							                                interviewWrapUpEDBCResult.getRequestId(), STANDARDAMOUNTS,
							                                CHILDSUPPORTSANCTIONREDUCTION))) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CSSRED");
							}
						}
					}
				}
				if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)
				                && (curRsltCapInd != null && (curRsltCapInd.equals(YES) || curRsltCapInd.equals(Yes)))
				                && (relRsltCapInd == null || !(relRsltCapInd.equals(YES) || relRsltCapInd.equals(Yes)))
				                && interviewWrapUpEDBCResult.getCapReasons().isEmpty()) {
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add("CAPEXP");
				}
				
				if(edbcResult.getChildSupportSanctionReduction().isNotEmpty() && edbcResult.getChildSupportSanctionReduction().doubleValue() > 0.0) {
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BENEFIT_CHANGE_RSN_CS);
				}
				
				if(edbcResult.getJobsSanctionReduction().isNotEmpty() && edbcResult.getJobsSanctionReduction().doubleValue() > 0.0) {
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BENEFIT_CHANGE_RSN_JOBS);
				}
				
				//Add a RESDEN reason when there is a change in current/mailing address
				if (NoticeUtil.isClientAddressChange(effCtx, clientId)) {
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BENEFIT_RESIDENCE_CHANGE);
				}
				
//				Context baseContext = effCtx.copy();
//				baseContext.setContextIdentifier(ContextFacade.BASE_CONTEXT_ITENTIFIER);
				if (NoticeUtil.checkMemberAbawdInEligFactor(effCtx, interviewWrapUpEDBCResult)){
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BENEFIT_ABAWD_CHANGE);
				}
				
				if(NoticeUtil.isResourceChange(effCtx, interviewWrapUpEDBCResult)) {
					interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BENEFIT_RESRC_CHANGE);
				}
			}
			if(isClaimPaidFull(maClientDelta,interviewWrapUpEDBCResult)) {
				interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BEN_CHG_PAID_IN_FULL_CF71);
			}
			//Current Child Support Payment TANF Change Reason Code for Notice - CCCS
			if (isChildSupportPaymentDone(maClientDelta, interviewWrapUpEDBCResult)) {
				interviewWrapUpEDBCResult.getBenefitChangeReasonVector().add(BEN_CHG_CHILD_CARE_PAYMENT_CCCS);
			}
			Vector changeReasons = interviewWrapUpEDBCResult.getBenefitChangeReasonVector();
			if (changeReasons != null && changeReasons.size() == 0) {
				HashSet<String> benChangeReasons = new HashSet<String>();
				RequestId requestId = maECFHouseholdDelta.getRequestId();
				Vector eligibilityRequestVerDataVector = maECFHouseholdDelta.getFields()
						.getFields(EligibilityRequestVerData.class, requestId.getReqId());
					Parameter parameter = ParameterCache.getInstance().getParameter(effCtx,
						ParameterConstants.NOTICE_CHANGE_REASON);
					Enumeration<ParameterMatrixValue> enumParameter = parameter.getMatrixValues().elements();
					Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
					while (eligibilityRequestVerDataEnum.hasMoreElements()) {
						EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
								.nextElement();
						if (eligibilityRequestVerData.getVerId().isNotEmpty()) {
							ViewVerification viewVerification = (ViewVerification) maECFHouseholdDelta.getFields()
									.getSeqField(ViewVerification.class, eligibilityRequestVerData.getVerId());
							while (enumParameter.hasMoreElements()) {
								ParameterMatrixValue paramMatrixValues = (ParameterMatrixValue) enumParameter.nextElement();
							if (viewVerification != null && viewVerification.getVerificationElementId() == Integer
									.parseInt(paramMatrixValues.getConstraintStart())) {
								benChangeReasons.add(paramMatrixValues.getValueStart());
								break;
							}
						}
					}
				}
					//benChangeReasons.add(BENEFIT_RESIDENCE_CHANGE);
					setFinancialValue(interviewWrapUpEDBCResult, NOTICES, NOTICECHANGETYPE, ESPUtil.hashSetToString(benChangeReasons));	
			}
		}
	}

	
	/**
	 * 
	 * @param maClientDelta instance of MAClient
	 * @param interviewWrapUpEDBCResult  instance InterviewWrapUpEDBCResult
	 * @return
	 * @throws Exception
	 */
	private static boolean isClaimPaidFull(MAClient maClientDelta, InterviewWrapUpEDBCResult interviewWrapUpEDBCResult)
			throws Exception {
		Recoupment recoupment = (Recoupment) maClientDelta.getFields().getField(Recoupment.class,
				interviewWrapUpEDBCResult.getAuId());
		boolean isPaidFull = false;

		if (recoupment != null && recoupment.getRecoupmentType().equals(BatchConstants.RECOUPMENT_TYP_PF)) {
			EligibilityRequestStatus eligStatus = maClientDelta
					.getEligibilityRequestStatus(interviewWrapUpEDBCResult.getRequestId());
			if (eligStatus != null && eligStatus.getEligRequestType().equals(BatchConstants.ELIG_REQ_PIF)) {
				isPaidFull = true;
			}
		}
		return isPaidFull;
	}

	/**
	* 
	* @param maClientDelta instance of MAClient
	* @param interviewWrapUpEDBCResult  instance InterviewWrapUpEDBCResult
	* @return
	* @throws Exception
	*/
	private static boolean isChildSupportPaymentDone(MAClient maClientDelta, InterviewWrapUpEDBCResult interviewWrapUpEDBCResult)
			throws Exception {
		boolean isChildSupportPayment = false;
		if (interviewWrapUpEDBCResult.getProgram().isNotEmpty() && 
				interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF) &&
				getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT, CURRENT_CHILD_SUPPORT) > 0) {
			EligibilityRequestStatus eligStatus = maClientDelta.getEligibilityRequestStatus(interviewWrapUpEDBCResult.getRequestId());
			if (eligStatus != null && eligStatus.getEligRequestType().equals(BatchConstants.EBC_ACM_REQ_TYPE_CSMTCG)) {
				isChildSupportPayment = true;
			}
		}
		return isChildSupportPayment;
	}
	
