	/**
	 * @param ctx
	 * @param clientSSN
	 * @param constraintDate
	 * @return
	 * @throws Exception
	 */
	public static EbcCycleDate getEbcCycleDate(Context ctx, Integer ssnLastDigit, DateData constraintDate) throws Exception {
		DateData benMonDate = new DateData(constraintDate);
		benMonDate.setDate(1);
		String key = ssnLastDigit + benMonDate.toLocaleString();
		EbcCycleDate ebcCycleDate = ebcCycleDatesMap.get(key);
		if (ebcCycleDate == null) {
			Constraints constraints = new Constraints();
			constraints.add("benmondate", benMonDate);
			Vector ebcCycleDateVec = (Vector) mapper.fetchChildren(ctx, EbcCycleDate.class, ssnLastDigit, constraints);
			if (ebcCycleDateVec != null && ebcCycleDateVec.size() > 0) {
				ebcCycleDate = (EbcCycleDate) ebcCycleDateVec.elementAt(0);
				ebcCycleDatesMap.put(key, ebcCycleDate);
			}
		}
		if (ebcCycleDate != null) {
			return (EbcCycleDate)ebcCycleDate.clone(true);
		}
		return null;
	}

