	/**
	 * Sets the value of the financial object. Creates a new one if its not already there.
	 *  
	 * @param interviewWrapUpEDBCResult
	 *            an InterviewWrapUpEDBCResult object
	 * @param category
	 *            the financial category.
	 * @param element
	 *            the financial element.
	 * @param newValue
	 *            the value to be set.
	 */
	public static void setFinancialValue(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, String category,
	                                     String element, double newValue) {
		EDBCResultFinancial eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(category, element);
		if (eDBCResultFinancial != null) {
			eDBCResultFinancial.setValue(newValue);
		}
		else {
			eDBCResultFinancial = new EDBCResultFinancial();
			eDBCResultFinancial.setCategory(category);
			eDBCResultFinancial.setElement(element);
			eDBCResultFinancial.setCategoryDisplayName(descriptions.getString(category));
			eDBCResultFinancial.setAuId(interviewWrapUpEDBCResult.getAuId());
			eDBCResultFinancial.setValue(newValue);
			eDBCResultFinancial.setCategoryDisplayName(descriptions.getString(category));
			if (element.equalsIgnoreCase(AUSIZE) && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP))) {
				eDBCResultFinancial.setElementDisplayName("Federal AU Size");
			}
			else if (element.equalsIgnoreCase(FUNDINGREDUCTIONAMOUNT)
			                && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP))) {
				eDBCResultFinancial.setElementDisplayName("Federal Funding Reduction");
			}
			else if (element.equalsIgnoreCase(GRANTAMOUNT)
			                && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP) || interviewWrapUpEDBCResult
			                                .getProgram().toString().equalsIgnoreCase(EA))) {
				eDBCResultFinancial.setElementDisplayName("Cash Benefit Amount");
			}
			else if (element.equalsIgnoreCase(GROSSINCOMELIMIT) && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(EA))) {
				eDBCResultFinancial.setElementDisplayName("Eligibility Standard");
			}
			else if (element.equalsIgnoreCase(PREVIOUSBENEFITAMOUNT)
			                && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF))) {
				eDBCResultFinancial.setElementDisplayName("Previous Monthly Allotment");
			}
			else if (element.equalsIgnoreCase(BENEFITAMOUNT) && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP))) {
				eDBCResultFinancial.setElementDisplayName("Benefit Amount");
			}
			else if (element.equalsIgnoreCase(SUPPORTEXPENSEELEMENT)
			                && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP))) {
				eDBCResultFinancial.setElementDisplayName("Child Support");
			}
			else if (element.equalsIgnoreCase(ASSETS)) {
				eDBCResultFinancial.setElementDisplayName("Total Countable Assets");
			}
			else {
				eDBCResultFinancial.setElementDisplayName(descriptions.getString(element));
			}
			interviewWrapUpEDBCResult.getFinancials().add(eDBCResultFinancial);
		}
	}

