	/**
	 * Check if members qualify the SNAP AU for TBA calculation.
	 * Use rule result memberships for comparisons.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param interviewWrapUpEDBCResult
	 *            an InterviewWrapUpEDBCResult object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean doFSMembersQualifyForTBA(MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFRule, InterviewWrapUpEDBCResult fsRslt, Vector interviewWrapUpEDBCResultBaseVector, Vector auExcludedVec, int clientId)
	                throws Exception {
		// Compile full list of calculated and excluded AUs (logic copied from doesTAFDCHaveTBAClosure)
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		
		Vector intWrapUpEDBCResultBaseVect = new Vector();
		intWrapUpEDBCResultBaseVect.addAll(interviewWrapUpEDBCResultBaseVector);
		Vector baseTAFDCVect = new Vector();
		Vector resultTAFDCVect = new Vector();

		// to find the TANF au's in the released result objects
		if (intWrapUpEDBCResultBaseVect != null && intWrapUpEDBCResultBaseVect.size() > 0) {
			Enumeration intWrapUpEDBCResultBaseEnum = intWrapUpEDBCResultBaseVect.elements();
			while (intWrapUpEDBCResultBaseEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult interviewWrapUpEDBCRsltBase = (InterviewWrapUpEDBCResult) intWrapUpEDBCResultBaseEnum
				                .nextElement();
				BaseAU asstUnit = maClientDelta.getAsstUnit(interviewWrapUpEDBCRsltBase.getAuId());
				if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
				                && asstUnit.getProgramCode().toString().equalsIgnoreCase(TANF)) {
					baseTAFDCVect.addElement(interviewWrapUpEDBCRsltBase.getAuId());
					resultTAFDCVect.add(interviewWrapUpEDBCRsltBase);
				}
			}
		}

		Enumeration auExcludedEnum = auExcludedVec.elements();
		BaseEBCResultAU ebcRsltBase = null;
		while (auExcludedEnum.hasMoreElements()) {
			IntegerData excludedAu = (IntegerData) auExcludedEnum.nextElement();
			BaseAU asstUnit = maClientDelta.getAsstUnit(excludedAu);
			// ebcRsltBase = getMAECFHouseholdBase(maECFHouseholdDelta).getEBCResult(ebcObject.getAuId());
			if (asstUnit != null && asstUnit.getProgramCode().isNotEmpty()
			                && asstUnit.getProgramCode().toString().equalsIgnoreCase(TANF)) {
				baseTAFDCVect.add(excludedAu);
			}
		}

		// TBA member conditions
 		boolean relatedTAFDCFlg = false;
		Enumeration baseTAFDCEnum = baseTAFDCVect.elements();
		Context ctx = maECFHouseholdDelta.getFields().getContext();
		while (baseTAFDCEnum.hasMoreElements()) {
			IntegerData baseTAFDCAuId = (IntegerData) baseTAFDCEnum.nextElement();
			Vector tafdcMembVec = maClientRule.getEBCAUMemberInAU(baseTAFDCAuId);
			if (isFSGranteeInTAFDC(maECFHouseholdDelta, fsRslt, baseTAFDCAuId.intValue(), tafdcMembVec, clientId, maClientRule)){
				if (getOpenMembersCount(fsRslt.getAuMembResults(), "SNAP", baseTAFDCVect, maClientRule) > getOpenMembersCount(fsRslt
		                .getAuMembResults(), "TANF", baseTAFDCVect, maClientRule)) {
					return false;
				}
				if (didOpenResultMembHasEFRC(ctx, fsRslt.getAuMembResults())) {
					return false;
				}
				BaseAU asstUnit = maClientDelta.getAsstUnit(baseTAFDCAuId);
				if (fsRslt.getGranteeId().intValue() == asstUnit.getGranteeId().intValue()
				                && didOpenEBCMembHasEFRC(ctx, baseTAFDCAuId, maClientRule, tafdcMembVec)) {
					return false;
				}
				relatedTAFDCFlg = true;
			}
		}

		return relatedTAFDCFlg;
	}

	/**
	 * Method to get the count of open Members for the given program
	 * 
	 * @param fsMembVec
	 * @param pgm
	 * @param rsltVec
	 * @return
	 * @throws Exception
	 */
	public static int getOpenMembersCount(Vector<EDBCResultAUMember> fsMembVec, String pgm,
	                                      Vector<IntegerData> baseTAFDCVect, MAClient maClient) throws Exception {
		int iCnt = 0;
		if (pgm.equals("SNAP")) {
			for (EDBCResultAUMember rsltMemb : fsMembVec) {
				if (rsltMemb.getMemStatus().equals(PENDING) || rsltMemb.getMemStatus().equals(ACTIVE)
				                || rsltMemb.getMemStatus().equals(INELIGIBLE)) {
					iCnt++;
				}
			}
		}
		else if (pgm.equals("TANF")) {
			Vector<EDBCResultAUMember> tmpFSMembVec = new Vector(fsMembVec);
			int fsMembSize = tmpFSMembVec.size();
			for (EDBCResultAUMember fsMemb : tmpFSMembVec) {
				Enumeration baseTAFDCEnum = baseTAFDCVect.elements();
				while (baseTAFDCEnum.hasMoreElements()) {
					IntegerData baseTAFDCAuId = (IntegerData) baseTAFDCEnum.nextElement();
					Vector<EBCAUMember> tafdcMembVec = maClient.getEBCAUMemberInAU(baseTAFDCAuId);					
					for (EBCAUMember tafdcMemb : tafdcMembVec) {
						if ((tafdcMemb.getClientId().intValue() == fsMemb.getClientId().intValue())
						                && (tafdcMemb.getAuMemberStatusCode().equals(PENDING)
						                                || tafdcMemb.getAuMemberStatusCode().equals(ACTIVE) || tafdcMemb
						                                .getAuMemberStatusCode().equals(INELIGIBLE))) {
							fsMembSize--;
						}
					}
				}
			}
			if (fsMembSize == 0) {
				iCnt = fsMembVec.size();
			}
		}
		return iCnt;
	}

	public static boolean didOpenResultMembHasEFRC(Context ctx, Vector<EDBCResultAUMember> rsltMembVec) throws Exception {
		boolean fsMembEFRCFlg = false;
		EligFactorRsnDtl eligFacRsnDtl = null;
		for (EDBCResultAUMember rsltMemb : rsltMembVec) {
			if ((rsltMemb.getMemStatus().equals(PENDING) || rsltMemb.getMemStatus().equals(ACTIVE)
			                || rsltMemb.getMemStatus().equals(INELIGIBLE)) && rsltMemb.getMemIneligReason().isNotEmpty()) {
				eligFacRsnDtl = getEligFactorRsnDtl(ctx, rsltMemb.getMemIneligReason());
				if (eligFacRsnDtl != null && eligFacRsnDtl.getTbaSanctionFlag().isNotEmpty()
				                && eligFacRsnDtl.getTbaSanctionFlag().booleanValue()) {
					fsMembEFRCFlg = true;
					break;
				}
			}
		}
		return fsMembEFRCFlg;
	}

	public static boolean didOpenEBCMembHasEFRC(Context ctx, IntegerData auId, MAClient maClient, Vector<EBCAUMember> membVec) throws Exception {
		boolean efrcFlg = false;
		EligFactorRsnDtl eligFacRsnDtl = null;
		BaseAU auObj = maClient.getAsstUnit(auId);
		for (EBCAUMember ebcMemb : membVec) {
			if (ebcMemb.getAuMemberStatusCode().equals(PENDING) || ebcMemb.getAuMemberStatusCode().equals(ACTIVE)
			                || ebcMemb.getAuMemberStatusCode().equals(INELIGIBLE)) {
				ClientAuMembIneligFactor membIneligibleReason = getSingleCAMInEligFactor(maClient, ebcMemb.getClientId(), auObj);
				if (membIneligibleReason != null){					
					eligFacRsnDtl = getEligFactorRsnDtl(ctx, membIneligibleReason.getEligFactorReason());
					if (eligFacRsnDtl != null && eligFacRsnDtl.getTbaSanctionFlag().isNotEmpty()
					                && eligFacRsnDtl.getTbaSanctionFlag().booleanValue()) {
						efrcFlg = true;
						break;
					}
				}
			}
		}
		return efrcFlg;
	}

	/**
	 * * First, find one TANF AU which does not meet Result has Closure Conditions (see appendix) and is related to the
	 * SNAP AU according to the following hierarchy:  SNAP grantee is a pending or active grantee in a TANF result  SNAP
	 * grantee is an ineligible grantee in a TANF result and does not meet AU Member Ineligibility Conditions (see
	 * appendix)  SNAP grantee is an ineligible grantee in a TANF result with a TANF EFRC that is associated with a
	 * sanction (EFRC has a related row in ELIG_FACTOR_PGM_RSN_SANCT)  SNAP grantee is an ineligible grantee in a TANF
	 * result  SNAP grantee is an pending, active or ineligible member in a TANF result
	 * 
	 * @param fsResult
	 * @param otherResult
	 * @return
	 * @throws Exception
	 */
	public static boolean isFSGranteeInTAFDC(MAECFHousehold maECFHouseholdDelta, InterviewWrapUpEDBCResult fsResult,
											int tafdcAUId, Vector tafdcMembVec, int clientId, MAClient maClientRule) throws Exception {
		boolean returnFlag = false;
		EBCAUMember ebcAuMember = null;
		
		if (tafdcMembVec != null && tafdcMembVec.size() > 0) {
			Enumeration aumeberEnum = tafdcMembVec.elements();
			while (aumeberEnum.hasMoreElements()) {
				ebcAuMember = (EBCAUMember) aumeberEnum.nextElement();
				ClientAUMembResp ebcAuMembResp = getClientAUMembResponsibilty(maClientRule, ebcAuMember.getClientId(), ebcAuMember.getAuId());
				if (ebcAuMember.getClientId().intValue() == fsResult.getGranteeId().intValue()) {
					if ((ebcAuMember.getAuMemberStatusCode().equals(PENDING) || ebcAuMember.getAuMemberStatusCode().equals(ACTIVE))) {
						returnFlag = true;
					}
					else if (ebcAuMember.getAuMemberStatusCode().equals(INELIGIBLE)
					                && isAuMemberInelig(maECFHouseholdDelta, ebcAuMember, ebcAuMembResp, fsResult)) {
						returnFlag = true;
					}
					else if (ebcAuMember.getAuMemberStatusCode().equals(INELIGIBLE)) {
						returnFlag = true;
					}
					else if (ebcAuMember.getAuMemberStatusCode().equals(PENDING)
					                || ebcAuMember.getAuMemberStatusCode().equals(ACTIVE)
					                || ebcAuMember.getAuMemberStatusCode().equals(INELIGIBLE)) {
						returnFlag = true;
					}
				}
			}
		}
		return returnFlag;
	}

	/**
	 * This method find the if the AU member is eligible for TBA calculation or not.
	 * 
	 * @param maECFHouseholdDelta
	 *            is an instance of MAECFHousehold.
	 * @param auMember
	 *            is an instance of EDBCResultAUMember.
	 * @param fsResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @return the boolean value.
	 * @throws Exception
	 */
	public static boolean isAuMemberInelig(MAECFHousehold maECFHouseholdDelta, EBCAUMember auMember, ClientAUMembResp ebcAuMembResp,
	                                       InterviewWrapUpEDBCResult fsResult) throws Exception {
		boolean returnValue = false;
		MAClient wfData = maECFHouseholdDelta.getMAClient(auMember.getClientId().intValue());
		ClientAuMembIneligFactor clientAUMembInEligFactor = null;
		String ineligFactor = "";
		EligFactorRsnDtl elifactDtl = null;
		Vector eligFactor = wfData.getClientAUMembInEligFactor(auMember.getClientId());
		if (eligFactor.size() > 0) {
			Enumeration eligEnum = eligFactor.elements();
			while (eligEnum.hasMoreElements()) {
				clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum.nextElement();
				if ((auMember.getAuId().intValue() == clientAUMembInEligFactor.getAuId().intValue())
				                && clientAUMembInEligFactor != null
				                && clientAUMembInEligFactor.getEligFactorReason().isNotEmpty()) {
					StringData reason = clientAUMembInEligFactor.getEligFactorReason();
					elifactDtl = getEligFactorRsnDtl(maECFHouseholdDelta.getFields().getContext(), reason);
					if (elifactDtl != null && elifactDtl.getNotEligibleFlag().isNotEmpty()
					                && elifactDtl.getNotEligibleFlag().isTrue()) {
						if (!returnValue
						                && hasAssociatedSanction(maECFHouseholdDelta.getFields().getContext(), reason,
						                                fsResult.getProgram(),maECFHouseholdDelta,wfData)) {
							returnValue = true;
						}
						if (elifactDtl.getReason().isNotEmpty()) {
							ineligFactor = elifactDtl.getReason().toString();
						}
						if (!returnValue && ineligFactor.equals(EFRC_ELIG_SSI)
						                || ineligFactor.equals(EF_INELIGIBLE_NON_CITIZEN)
						                || ineligFactor.equals(EFRC_FOSTER_CHILD)
						                || ineligFactor.equals(EFRC_ADOP_CHILD) || ineligFactor.equals(EFRC_FAMILY_CAP)) {
							returnValue = true;
						}
					}
					break;
				}
			}
		}
		Vector auMembVect = wfData.getAllMembersInAU(fsResult.getAuId());
		if (auMembVect.size() > 0) {
			Enumeration auMembEnum = auMembVect.elements();
			while (auMembEnum.hasMoreElements()) {
				BaseAUMember auMembers = (BaseAUMember) auMembEnum.nextElement();
				if (!returnValue
				                && fsResult.getGranteeId().intValue() == auMember.getClientId().intValue()
				                && fsResult.getGranteeId().intValue() == auMembers.getClientId().intValue()
				                && hasAUmembClosure(maECFHouseholdDelta.getFields().getContext(), auMembers, wfData,
				                                fsResult.getProgram(),maECFHouseholdDelta)) {
					returnValue = true;
				}
			}
		}
		if (!returnValue && ebcAuMembResp != null 
						&& ebcAuMembResp.getMemResp().isNotEmpty()
		                && ebcAuMembResp.getMemResp().toString().equals(RECIPIENT_RESP)
		                && ebcAuMembResp.getMemResp().toString().equals(SANCTIONED_CS)
		                && ebcAuMembResp.getMemResp().toString().equals(INELIG_ADD)) {
			returnValue = true;
		}
		return returnValue;
	}

