	/**
	 * Special 30 Day SNAP AU. called from the method expeditedFS.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param auId
	 *            int value
	 * @param interviewWrapUpEDBCResultBaseVector
	 *            InterviewWrapUpEDBCResult-Base Object collections.
	 * @param interviewWrapUpEDBCResult
	 *            Result object AU status is pending Current result status is pending or active Current result is not
	 *            CAP (result.CAPEligibilityStatus is null) Latest released result does not exist or latest released
	 *            result does not have a pending status with EXPEDITED_CD_CODE_K = 'E' application date is exactly 30
	 *            days from current date and request is not a reinstatement
	 */
	private static boolean spl30DayFSAUProcess(MAECFHousehold maECF, MAClient maClient, int auId, Vector interviewWrapUpEDBCResultBaseVector,
	                                           InterviewWrapUpEDBCResult interviewWrapUpEDBCResult) throws Exception {
		boolean spl30DayFSAUProcessFlg = false;
		int reinstmtVerDataElementId = 68;
		
		if ((interviewWrapUpEDBCResult.getCapEligibilityStatus().isEmpty())
		                && (interviewWrapUpEDBCResult.getStatus().equals(AU_PENDING) || interviewWrapUpEDBCResult
		                                .getStatus().equals(AU_ACTIVE))
		                 && !isVerificationSelected(maECF, maClient, interviewWrapUpEDBCResult.getAuId(), reinstmtVerDataElementId, true, false)) {
			if (interviewWrapUpEDBCResultBaseVector != null && interviewWrapUpEDBCResultBaseVector.size() > 0) {
				Enumeration intWrapUpEDBCResultBaseEnum = interviewWrapUpEDBCResultBaseVector.elements();
				while (intWrapUpEDBCResultBaseEnum.hasMoreElements()) {
					InterviewWrapUpEDBCResult interviewWrapUpEDBCRsltBase = (InterviewWrapUpEDBCResult) intWrapUpEDBCResultBaseEnum
					                .nextElement();
					if (interviewWrapUpEDBCRsltBase != null && auId == interviewWrapUpEDBCRsltBase.getAuId().intValue()
					                && interviewWrapUpEDBCRsltBase.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCRsltBase.getStatus().equals(AU_PENDING)
					                && interviewWrapUpEDBCRsltBase.getExpedited().isNotEmpty()
					                && interviewWrapUpEDBCRsltBase.getExpedited().equals(EXPEDITED_CODE)) {
						spl30DayFSAUProcessFlg = false;
						break;
					}
					else {
						spl30DayFSAUProcessFlg = true;
					}
				}
			}
			else {
				spl30DayFSAUProcessFlg = true;
			}
		}
		return spl30DayFSAUProcessFlg;
	}
	/**
	 * Returns number of days between two DateData objects.
	 * 
	 * @param fromDate From DateData object.
	 * @param toDate To DateData object
	 * @return number of days.
	 */
	public static final int getNumberOfDays(DateData fromDate, DateData toDate) {
		long chronoDiff = ChronoUnit.DAYS.between(toDate.getSQLDate().toLocalDate(), fromDate.getSQLDate().toLocalDate());
		int days = (int) chronoDiff;	
		return days;
	}
	/**
	 * To calculate the prorated amount for expedited fs.
	 * 
	 * @param maECFHouseholdDelta
	 *            MAECFHousehold object
	 * @param maClientDelta
	 *            MAClient object
	 * @param interviewWrapUpEDBCResult
	 *            view object
	 * @param programApplicationHistory
	 *            PGM_APP_HIST object
	 * @return double
	 * @throws Exception
	 */
	/**
	 * PMD Error Fixed for ScandentRobsRule21 for version 1.9
	 */
	public static double proratedAmount(MAECFHousehold maECFHouseholdDelta, MAClient maClientDelta,
	                                    InterviewWrapUpEDBCResult interviewWrapUpEDBCResult, DateData tmpAppDate)
	                throws Exception {
		ParameterCache paramcache = null;
		Parameter parameter = null;
		int tmpNumDays = 0;
		EbcCycleDate ebcCycleDate = null;
		EbcCycleDate tmpCycleMonth = null;
		double tmpBenefitAmt = 0;
		double tmpFedAmt = 0;
		DateData pgmAppDate_1, pgmAppDate_2 = null;
		DateData curEffDte = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
		paramcache = ParameterCache.getInstance();
		parameter = paramcache.getParameter(maClientDelta.getFields().getContext(), FS_MIN_BENEFIT_AMT);
		double fsminimumamount = Double.parseDouble(parameter.getParameterValue());
		if (tmpAppDate.isNotEmpty()) {
			pgmAppDate_1 = new DateData(tmpAppDate);
			EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult.getAuId());
			if(ebcRsltBase !=null){
				if(!tmpAppDate.after(ebcRsltBase.getBenefitEffective())){
					pgmAppDate_1 = (new DateData(ebcRsltBase.getBenefitEffective())).addDays(1);
				}
			}
			tmpCycleMonth = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(), curEffDte);
			EbcCycleDate tmpCurrentCycleMonth = tmpCycleMonth;
			if(tmpCycleMonth != null){
				if(pgmAppDate_1.before(tmpCycleMonth.getFirstCycStdPmtDate())){
					tmpCycleMonth = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(), curEffDte.addMonths(-1));
				}
				// Note:  tmpNumDays can be greater than 30 due to date subtraction
				tmpNumDays = 30 - (getNumberOfDays(pgmAppDate_1, tmpCycleMonth.getFirstCycStdPmtDate()));
			}
			tmpBenefitAmt = (interviewWrapUpEDBCResult.getBenefitAmount().doubleValue() / 30) * tmpNumDays;
			if (tmpBenefitAmt < fsminimumamount) {
				tmpBenefitAmt = 0.0;
			}
			tmpBenefitAmt = Math.floor(tmpBenefitAmt);
			/*if ((tmpCurrentCycleMonth != null && (maClientDelta.getFields().getContext().getEffectiveDate().after(tmpCurrentCycleMonth.getFirstCycRelDate())
													|| maClientDelta.getFields().getContext().getEffectiveDate().equals(tmpCurrentCycleMonth.getFirstCycRelDate()))
											  && tmpAppDate.before(tmpCurrentCycleMonth.getFirstCycStdPmtDate()))
			                || (interviewWrapUpEDBCResult.getExpedited().isNotEmpty()
			                                && interviewWrapUpEDBCResult.getExpedited().toString().equalsIgnoreCase(
			                                                AlphaS) && tmpNumDays < 31)) {
				tmpBenefitAmt += interviewWrapUpEDBCResult.getBenefitAmount().doubleValue();
			}*/
			if (((interviewWrapUpEDBCResult.getRevalEnd().daysBetween(interviewWrapUpEDBCResult.getRevalStart()))>31)
					|| (interviewWrapUpEDBCResult.getExpedited().isNotEmpty()
							&& interviewWrapUpEDBCResult.getExpedited()
									.toString().equalsIgnoreCase(AlphaS) && tmpNumDays < 31)) {
				tmpBenefitAmt += interviewWrapUpEDBCResult.getBenefitAmount()
						.doubleValue();
			}
			setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PRORATEDBENEFITAMOUNT, tmpBenefitAmt);			
			//interviewWrapUpEDBCResult.setBenefitAmount(tmpBenefitAmt);
			//setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, PRORATEDBENEFITIND, "Y");
		}
		return interviewWrapUpEDBCResult.getBenefitAmount().doubleValue();
		//return tmpBenefitAmt;
	}

	/**
	 * This method is used to Set AP `responsibilities in the following circumstances.
	 * 
	 * @param mAECFHousehold
	 *            is an instance of MAECFHousehold.
	 * @throws Exception
	 */
	public static void responsibilities(MAECFHousehold mAECFHousehold) throws Exception {
		Vector interviewWrapUpEDBCResultsVect = null;
		Vector edbcResultsVect = null;
		Enumeration interviewWrapUpEDBCResultsEnum = null;
		Enumeration edbcResultsEnum = null;
		InterviewWrapUpEDBCResult interviewwrapupEDBCResult = null;
		EDBCResultAUMember edbcResultAUMember = null;
		MAClient maclient = null;
		BaseAU au = null;
		if (mAECFHousehold != null) {
			maclient = mAECFHousehold.getMAClient(mAECFHousehold.getPrimaryClientId());
			interviewWrapUpEDBCResultsVect = mAECFHousehold.getInterviewWrapUpEDBCResults();
			if (interviewWrapUpEDBCResultsVect != null && interviewWrapUpEDBCResultsVect.size() > 0) {
				interviewWrapUpEDBCResultsEnum = interviewWrapUpEDBCResultsVect.elements();
				while (interviewWrapUpEDBCResultsEnum.hasMoreElements()) {
					interviewwrapupEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultsEnum
					                .nextElement();
					if (interviewwrapupEDBCResult != null) {
						edbcResultsVect = interviewwrapupEDBCResult.getAuMembResults();
						if (edbcResultsVect != null && edbcResultsVect.size() > 0) {
							edbcResultsEnum = edbcResultsVect.elements();
							while (edbcResultsEnum.hasMoreElements()) {
								edbcResultAUMember = (EDBCResultAUMember) edbcResultsEnum.nextElement();
								au = maclient.getAsstUnit(edbcResultAUMember.getAuId());
								if (edbcResultAUMember.getMemResponsibility().isNotEmpty()) {
									/*
									 * for each result Add a Person If an AP has status of active in the result and has
									 * a Responsibility of Ineligible/ Add a Person (INGADD) then set the
									 * Responsibility to Recipient (RECPNT).
									 */
									if (edbcResultAUMember.getMemStatus().toString().equalsIgnoreCase(ACTIVE)
									                && edbcResultAUMember.getMemResponsibility().toString()
									                                .equalsIgnoreCase(INELIG_ADD)) {
										edbcResultAUMember.setMemResponsibility(RECIPIENT_RESP);
									}
									/*
									 * Sanctioned Grantee If a grantee has a status of Ineligible in the result, the
									 * latest AP EFRC is associated with a Sanction and the Responsibility is Recipient
									 * then set the Responsibility to None (NONE).
									 */
									if (au != null
									                && interviewwrapupEDBCResult.getGranteeId().isNotEmpty()
									                && au.getGranteeId().isNotEmpty()
									                && edbcResultAUMember.getMemStatus().isNotEmpty()
									                && interviewwrapupEDBCResult.getGranteeId().intValue() == au
									                                .getGranteeId().intValue()
									                && edbcResultAUMember.getMemStatus().toString().equals(INELIGIBLE)) {
										if (!edbcResultAUMember.getMemIneligReason().toString().equals(SANCTIONED)
										                && edbcResultAUMember.getMemResponsibility().toString()
										                                .equalsIgnoreCase(RECIPIENT_RESP)) {
											edbcResultAUMember.setMemResponsibility(NONE);
										}
										return;
									}
								}
							}
						}
					}
				}
			}
		}
	}

	/**
	 * Return true if the AU has a closure reason that is allowed for a TBA case (i.e. the AU will close even
	 * if it otherwise qualifies for TBA).
	 * @param baEcf
	 * @param auId
	 * @return
	 * @throws Exception
	 */
	public static boolean doesAUHaveClosureReasonAllowedForTBA(Context effCtx, MAECFHousehold baEcf, BaseAU fsAU) throws Exception {
		if (fsAU != null) {			
			MAClient maClientDelta = baEcf.getMAClient(fsAU.getGranteeId().intValue());
			Vector auIneligVect = maClientDelta.getAuInEligFactor(fsAU.getId());
			AuInEligFactor auInelig = null;
			EligFactorRsnDtl elifactDtl = null;
			if (auIneligVect.size() > 0) {
				Enumeration auIneligEnum = auIneligVect.elements();
				while (auIneligEnum.hasMoreElements()) {
					auInelig = (AuInEligFactor) auIneligEnum.nextElement();
					if (auInelig != null && auInelig.getEligFactorReason().isNotEmpty()) {
						StringData reason = auInelig.getEligFactorReason();
						elifactDtl = getEligFactorRsnDtl(effCtx, reason);
						if (elifactDtl != null
						    && elifactDtl.getTbaExceptionFlag().isTrue()) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

	/**
	 * This process will add the non-financial closure/denial AUs to Request.
	 * @param maECFHouseholdDelta
	 * @param maECFRule
	 * @param ebcObjVector
	 * @param batch
	 * @param reCalc
	 * @param clientId
	 * @param auExcludedVec
	 * @throws Exception
	 */
	public static void auClosures(MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFRule, Vector ebcObjVector,
	                              boolean batch, boolean reCalc, int clientId, Vector auExcludedVec) throws Exception {
		int ssiCount = 0;
		int auMembLen = 0;
		BaseAUEligReevaluation eligibleReevaluation = null;
		HHClientPersonalRelation hhClientPersonalRelation = null;
		BeaconEligibilityGroup beaconEligGroup = null;
		BaseAU asstUnit = null;
		Context effCtx = null;
		InterviewWrapUpEDBCResult resultObject = null;
		Vector interviewWrapUpEDBCResultVect = null;
		Vector releaseBenEffVec = null;
		RequestId requestId = null;
		Vector tempResultVector = null;
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientRule = maECFRule.getMAClient(clientId);
		if (maECFHouseholdDelta != null) {
			effCtx = maECFHouseholdDelta.getFields().getContext();
			requestId = maECFHouseholdDelta.getRequestId();
			MAClient mAClient = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getPrimaryClientId());
			interviewWrapUpEDBCResultVect = new Vector(maECFHouseholdDelta
			    .getInterviewWrapUpEDBCResults(requestId.getReqId()));
			Vector eligibilityGroupVect = maECFHouseholdDelta.getAllEligibilityGroupCached();
			Enumeration eligibilityGroupEnum = eligibilityGroupVect.elements();
			while (eligibilityGroupEnum.hasMoreElements()) {
				beaconEligGroup = (BeaconEligibilityGroup) eligibilityGroupEnum.nextElement();
				if (beaconEligGroup != null && beaconEligGroup.getCunrrentElig().isTrue()) {
					Enumeration auObjet = beaconEligGroup.getAssistUnitObj().elements();
					while (auObjet.hasMoreElements()) {
						asstUnit = (BaseAU) auObjet.nextElement();
						if (asstUnit != null
						    && !(asstUnit.getProgramCode().equals(JOBS) || asstUnit.getProgramCode().equals(CHILDCARE))
						    && (asstUnit.getStatusCode().equals(ACTIVE) || isAuExistInSelection(maECFHouseholdDelta, asstUnit
						        .getId()))
						    && !isAuExistInResult(interviewWrapUpEDBCResultVect, asstUnit.getId(), auExcludedVec)
						    && (hasAUExclusion(effCtx, asstUnit, maClientRule, maECFHouseholdDelta, maECFHouseholdDelta, false)
						    	|| (hasAuClosureEFRC(maClientRule, asstUnit.getId())))
						    && !(asstUnit.getStatusCode().equals(ACTIVE) && reCalc)) {
							boolean alreadyExist = false;
							Enumeration ebcObjEnum = ebcObjVector.elements();
							while (ebcObjEnum.hasMoreElements()) {
								EDBCResult ebcObject = (EDBCResult) ebcObjEnum.nextElement();
								if (ebcObject.getAuId().equals(asstUnit.getId())) {
									alreadyExist = true;
									break;
								}
							}
							double previousAmt = 0.00;
							// creating a result object and attaching it to the request.
							EDBCResult ebcObject = new EDBCResult();
							ebcObject.setAuId(asstUnit.getId());
							ebcObject.setProgramCode(asstUnit.getProgramCode());
							ebcObject.setRequestId(requestId.getReqId());
							BaseClientSSN clientSSN = (BaseClientSSN) maECFRule.getClientPrimarySSN(maECFRule.getGrantee(asstUnit.getId()));
							if (clientSSN != null) {
							   	ebcObject.setGranteeSSN(clientSSN);
							}
							if (!alreadyExist) {
								ebcObjVector.add(ebcObject);
								maECFHouseholdDelta.setEDBCResult(ebcObjVector);
							}
							resultObject = createNewResultObject(maECFHouseholdDelta, maClientDelta, maECFRule, maClientRule,
							    ebcObject);
							// resultObject = new InterviewWrapUpEDBCResult();
							resultObject.setAuId(ebcObject.getAuId());
							// BaseEBCResultAU ebcResultBase = maECFHouseholdBase.getEBCResult(ebcObject.getAuId());
							// //@CodeClean
							EBCResultBase ebcResultBase = maECFHouseholdDelta.getEBCResultBase(ebcObject.getAuId());
							// previousAmt = getReleasedFinancialDouble(getPrevReleasedXMLValue(maECFHouseholdDelta,
							// ebcObject.getAuId(), maECFHouseholdDelta.getRequestId().getReqId(), BENEFIT,
							// BENEFITAMOUNT));
							if (ebcResultBase != null) {
								previousAmt = ebcResultBase.getBenefitAmount().doubleValue();
							}
							setFinancialValue(resultObject, BENEFIT, PREVIOUSBENEFITAMOUNT, ZERO_DOUBLE_VALUE);
							setFinancialValue(resultObject, BENEFIT, PREVIOUSBENEFITAMOUNT, previousAmt);
							resultObject.setAuId(ebcObject.getAuId());
							resultObject.setClientId(maECFHouseholdDelta.getPrimaryClientId());
							resultObject.setRequestId(ebcObject.getRequestId());
							resultObject.setProgram(asstUnit.getProgramCode());
							resultObject.setGranteeId(maClientDelta.getGranteeForAU(ebcObject.getAuId()).getClientId());
							resultObject.setGranteeName(maClientDelta.getClientDisplayName(resultObject.getGranteeId()));
							resultObject.setEnteredDate(DateData.getToday());
							resultObject.setCapFlg(getFinancialObjectStringValue(resultObject, STANDARDAMOUNTS, CAPIND));
							resultObject.setTbaFlg(getFinancialObjectStringValue(resultObject, BENEFIT, TBAFLAG));
							resultObject.setAppDte(getApplicationDate(maClientDelta, ebcObject.getAuId()));
							// SNAP AU is assigned to a worker in a Regional SSI office
							if (asstUnit.getProgramCode().isNotEmpty() && asstUnit.getProgramCode().toString().equals(SNAP)) {
								ReferralAUAssignment refAuAssignment = (ReferralAUAssignment) maClientDelta.getFields().getField(
								    ReferralAUAssignment.class, resultObject.getAuId());
								if (refAuAssignment != null && refAuAssignment.getBuId().isNotEmpty()) {
									ApplicationUser appUser = (ApplicationUser) maClientDelta.getFields().getSeqField(
									    ApplicationUser.class, refAuAssignment.getBuId());
									if (appUser != null && appUser.getOfficeLocationId().isNotEmpty()) {
										OrganizationLocationItem orgLocItem = maClientDelta.getOrganizationLocationItem(appUser
										    .getOfficeLocationId());
										if (orgLocItem != null && orgLocItem.getSsiFlag().isNotEmpty()
										    && orgLocItem.getSsiFlag().booleanValue()) {
											resultObject.setSsiOfficeFlg(true);
										}
										else {
											resultObject.setSsiOfficeFlg(false);
										}
									}
								}
							}
							releaseBenEffVec = getReleaseDate(maECFHouseholdDelta, resultObject, ebcObject, batch, clientId);
							if (releaseBenEffVec != null && releaseBenEffVec.size() > 0) {
								setFinancialValue(resultObject, BENEFIT, EBCBENEFITEFFECTIVEDATE, ((DateData) releaseBenEffVec.get(1))
								    .toLocaleString());
							}
							/*
							 * setFinancialValue(interviewWrapUpEDBCResult, EBCDATA, RELEASEDATE, ((DateData) getReleaseDate(maEcf,
							 * interviewWrapUpEDBCResult, ebcObject).get(0)).toLocaleString());
							 * interviewWrapUpEDBCResult.setStatusDate((DateData) getReleaseDate(maEcf, interviewWrapUpEDBCResult,
							 * ebcObject).get(0));
							 */
							if (asstUnit.getStatusCode().isNotEmpty() && asstUnit.getStatusCode().toString().equals(ACTIVE)) {
								resultObject.setIsAlreadyActiveAU(true);
							}
							else {
								resultObject.setIsAlreadyActiveAU(false);
							}
							eligibleReevaluation = maClientDelta.getBaseAUEligReevaluation(ebcObject.getAuId());
							if (eligibleReevaluation != null && eligibleReevaluation.getRevalEndDate().isNotEmpty()) {
								resultObject.setOrginalRevalEnd(eligibleReevaluation.getRevalEndDate());
							}
							Enumeration auMembEnum = ebcObject.getEdbcResultAUMemberVector().elements();
							while (auMembEnum.hasMoreElements()) {
								EDBCResultAUMember resultAUMember = (EDBCResultAUMember) auMembEnum.nextElement();

								if (maClientDelta.isOtherParent(resultAUMember.getClientId())) {
									resultObject.setOtherParent(true);
									resultObject.setOtherParentStatus(maClientDelta.getOtherParentStatus(resultAUMember.getClientId()));
								}
								if (((resultAUMember.getMemRelation().isNotEmpty()
								    && resultAUMember.getMemRelation().toString().equalsIgnoreCase(GRANTEE_FULL)
								    && resultAUMember.getMemStatus().isNotEmpty() && (resultAUMember.getMemStatus().toString()
								    .equalsIgnoreCase(PENDING) || resultAUMember.getMemStatus().toString().equalsIgnoreCase(ACTIVE))) || (maClientDelta
								    .isOtherParent(resultAUMember.getClientId()) && maClientDelta.getOtherParentStatus(
								    resultAUMember.getClientId()).equalsIgnoreCase(INELIGIBLE)))
								    && (resultAUMember.getMemResponsibility().isNotEmpty() && (resultAUMember.getMemResponsibility()
								        .toString().equalsIgnoreCase("STPPNT")
								        || resultAUMember.getMemResponsibility().toString().equalsIgnoreCase("SPPRWO")
								        || resultAUMember.getMemResponsibility().toString().equalsIgnoreCase("SANCTN") || resultAUMember
								        .getMemResponsibility().toString().equalsIgnoreCase("INNCIT")))) {
									Vector clientEarnedIncomeVector = maClientDelta.getEarnedIncome(resultAUMember.getClientId());
									Enumeration clientEarnedIncomeEnum = clientEarnedIncomeVector.elements();
									while (clientEarnedIncomeEnum.hasMoreElements()) {
										EarnedIncome earnedIncome = (EarnedIncome) clientEarnedIncomeEnum.nextElement();
										if (earnedIncome.getWageType().isNotEmpty()
										    && earnedIncome.getWageType().toString().equalsIgnoreCase(WAGES)
										    && earnedIncome.getCountableCash().isNotEmpty()
										    && earnedIncome.getCountableCash().booleanValue()
										    && isVerificationSelected(maECFHouseholdDelta, maClientDelta, resultObject.getAuId(), 38,
										        false, false)) {
											resultObject.setIsMonthlyReporterOne(true);
											break;
										}
									}
									if (resultObject.getIsMonthlyReporterOne().isNotEmpty()
									    && !resultObject.getIsMonthlyReporterOne().booleanValue()) {
										maClientDelta.getFields().removeAll(EarnedIncome.class);
										Vector clientEarnedIncomeBaseVector = (getMAECFHouseholdBase(maECFHouseholdDelta)
										    .getMAClient(maClientDelta.getId().intValue())).getEarnedIncome(resultAUMember.getClientId());
										Enumeration clientEarnedIncomBaseEnum = clientEarnedIncomeBaseVector.elements();
										while (clientEarnedIncomBaseEnum.hasMoreElements()) {
											EarnedIncome earnedIncome = (EarnedIncome) clientEarnedIncomBaseEnum.nextElement();
											if (earnedIncome.getWageType().isNotEmpty()
											    && earnedIncome.getWageType().toString().equalsIgnoreCase(WAGES)
											    && earnedIncome.getCountableCash().isNotEmpty()
											    && earnedIncome.getCountableCash().booleanValue()
											    && isVerificationSelected(maECFHouseholdDelta, maClientDelta, resultObject.getAuId(), 38,
											        false, false)) {
												resultObject.setIsMonthlyReporterOne(true);
												break;
											}
										}
									}
								}
								if (resultObject.getProgram().equals(SNAP) && resultAUMember != null
								    && resultAUMember.getMemStatus().equals(ACTIVE)
								    && (resultObject.getOthIncSSIRSDIFlg().isEmpty() || resultObject.getOthIncSSIRSDIFlg().isFalse())) {
									if (isReevaluationEndDate(maClientDelta, resultAUMember.getClientId())) {
										resultObject.setOthIncSSIRSDIFlg(true);
									}
									else {
										resultObject.setOthIncSSIRSDIFlg(false);
									}
								}
							}
							Enumeration auMembEnumtmp = ebcObject.getEdbcResultAUMemberVector().elements();
							while (auMembEnumtmp.hasMoreElements()) {
								EDBCResultAUMember resultAUMember = (EDBCResultAUMember) auMembEnumtmp.nextElement();
								if ((resultAUMember != null && resultAUMember.getMemStatus().isNotEmpty() && (resultAUMember
								    .getMemStatus().toString().equals(PENDING) || resultAUMember.getMemStatus().toString().equals(
								    ACTIVE)))
								    && (haveSSIIncome(maClientDelta, resultAUMember))) {
									ssiCount++;
								}
								auMembLen++;
							}
							if (ssiCount == auMembLen) {
								resultObject.setHaveSSIIncome(true);
							}
							else {
								resultObject.setHaveSSIIncome(false);
							}
							tempResultVector = new Vector();
							tempResultVector = sortAuMembers(ebcObject.getEdbcResultAUMemberVector(), mAClient, ebcObject.getAuId());
							resultObject.setAuMembResults(tempResultVector);
							if (!hasAuClosureEFRC(effCtx, maClientRule, asstUnit.getId())) {
								BaseAUMember granteeAUMemb = mAClient.getGranteeForAU(asstUnit.getId());
								ClientAuMembIneligFactor granteeIneligFactor = getGranteePriorityClosureEFRC(effCtx, mAClient, asstUnit,
								    granteeAUMemb,maECFRule);
								if (granteeIneligFactor != null) {
									resultObject.setAuEFRC(granteeIneligFactor.getEligFactorReason());
									resultObject.setAuEligFactorStatus(granteeIneligFactor.getEligStatus());
									resultObject.setAuEligFactor(granteeIneligFactor.getEligFactor());
								}
								else if (asstUnit.getProgramCode().equals(SNAP)
								    && (asstUnit.getStatusCode().equals(PENDING) || asstUnit.getStatusCode().equals(ACTIVE))) {
									Vector auMemberVect = mAClient.getAllMembersInAU(asstUnit.getId());
									Enumeration auMemberEnum = auMemberVect.elements();
									AUMEMBLOOP: while (auMemberEnum.hasMoreElements()) {
										BaseAUMember auMember = (BaseAUMember) auMemberEnum.nextElement();
										if (isClientOpenMember(maECFHouseholdDelta, auMember)) {
											Vector sanctionVect = mAClient.getSanction(auMember.getClientId());
											Enumeration sanctionEnum = sanctionVect.elements();
											while (sanctionEnum.hasMoreElements()) {
												Sanction sanctionObj = (Sanction) sanctionEnum.nextElement();
												resultObject.setAuEFRC(getSanctionPriorityClosureEFRC(effCtx, mAClient, sanctionObj));
												if (resultObject.getAuEFRC().equals(EFRC_FAIL_FS_ET)) {
													resultObject.setAuEligFactor(FSET);
													resultObject.setAuEligFactorStatus(ELIG_STATUS_FAIL);
													resultObject.setEbcEFRCFlg(true);
													break AUMEMBLOOP;// FSET has priority
												}
												else if (resultObject.getAuEFRC().equals(EFRC_VOLUN_QUIT_JOB)) {
													resultObject.setAuEligFactor(JOBTST);
													resultObject.setAuEligFactorStatus(ELIG_STATUS_FAIL);
													resultObject.setEbcEFRCFlg(true);
												}
											}
										}
									}
								}
								else if (asstUnit.getProgramCode().equals(TANF)) {
									resultObject.setAuEligFactor("DEPRIV");
									resultObject.setAuEFRC("001008");
									resultObject.setAuEligFactorStatus(ELIG_STATUS_FAIL);
									resultObject.setEbcEFRCFlg(true);
								}
							}
							// AU should only have open APs and set EFRC
							Vector auMembVect = maClientDelta.getAllMembersInAU(asstUnit.getId());
							Vector auMembVecTmp = (Vector) auMembVect.clone();
							Enumeration auMembEnumTmp = auMembVecTmp.elements();
							int i = -1;
							while (auMembEnumTmp.hasMoreElements()) {
								i++;
								BaseAUMember baseAUMember = (BaseAUMember) auMembEnumTmp.nextElement();
								if (baseAUMember.getAuId().intValue() != asstUnit.getId().intValue()) {
									auMembVecTmp.removeElementAt(i);
								}
							}
							auMembVect = (Vector) auMembVecTmp.clone();
							Vector apVector = new Vector();
							if (auMembVect.size() > 0) {
								BaseAUMember granteeAUMember = maClientDelta.getGranteeForAU(ebcObject.getAuId());
								auMembEnum = auMembVect.elements();
								while (auMembEnum.hasMoreElements()) {
									BaseAUMember auMember = (BaseAUMember) auMembEnum.nextElement();
									if (isClientOpenMember(maECFHouseholdDelta, auMember)) {
										EDBCResultAUMember edbcResultMemb = new EDBCResultAUMember();
										edbcResultMemb.setAuId(auMember.getAuId());
										edbcResultMemb.setClientId(auMember.getClientId());
										edbcResultMemb.setMemNam(maClientDelta.getClientDisplayName(auMember.getClientId()));
										if (auMember.getClientId().equals(granteeAUMember.getClientId())) {
											edbcResultMemb.getMemRelation().setString(GRANTEE_FULL);
										}
										else {
											hhClientPersonalRelation = maClientDelta.getHHClientPersonalRelation(granteeAUMember
											    .getClientId(), auMember.getClientId());
											if (hhClientPersonalRelation != null) {
												edbcResultMemb.setMemRelation(hhClientPersonalRelation.getPersonalRelationCode());
											}
										}
										Enumeration respEnum = maClientDelta.getClientAUMembResponsibilty(auMember.getClientId())
										    .elements();
										while (respEnum.hasMoreElements()) {
											ClientAUMembResp clientAUMembResp = (ClientAUMembResp) respEnum.nextElement();
											if (clientAUMembResp.getAuId().intValue() == auMember.getAuId().intValue()) {
												edbcResultMemb.setMemResponsibility(clientAUMembResp.getMemResp());
												break;
											}
										}
										boolean flag = false;
										EligFactorRsnDtl elifactDtl = null;
										edbcResultMemb.setMemStatus(auMember.getAuMemberStatusCode());
										edbcResultMemb.setMemStatusDate(auMember.getEffDate());
										Vector<ClientAuMembIneligFactor> reasonVec = maClientRule.getClientAUMembInEligFactor(auMember
										    .getClientId());
										for (ClientAuMembIneligFactor membInelig : reasonVec) {
											if (membInelig.getAuId().intValue() == auMember.getAuId().intValue()
											    && (auMember.getAuMemberStatusCode().equals(INELIGIBLE) || isVerSelected(
											        maECFHouseholdDelta, resultObject.getAuId(), auMember.getClientId(), 78, false, true))) {
												elifactDtl = getEligFactorRsnDtl(effCtx, membInelig.getEligFactorReason());
												if (elifactDtl.getNotEligibleFlag().booleanValue()) {
													edbcResultMemb.setMemIneligReason(membInelig.getEligFactorReason());
													edbcResultMemb.setMemEligFactor(membInelig.getEligFactor());
													edbcResultMemb.setMemEligFactorStatus(membInelig.getEligStatus());
													flag = true;
													break;
												}
											}
										}
										if (!flag) {
											edbcResultMemb.setMemIneligReason(resultObject.getAuEFRC());
											edbcResultMemb.setMemEligFactor(resultObject.getAuEligFactor());
											edbcResultMemb.setMemEligFactorStatus(resultObject.getAuEligFactorStatus());
										}
										apVector.add(edbcResultMemb);
									}
								}
							}
							if (asstUnit.getProgramCode().equals(SNAP)
							    && ebcObject.isEBCActiveCAP(maECFHouseholdDelta, maClientDelta)) {
								ebcObject.setCapEligibilityStatus(CLOSED_DESC);
								setFinancialValue(resultObject, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, CLOSED_DESC);
							}
							else if (ebcObject.isAUInCAPRequest(maECFHouseholdDelta)) {
								ebcObject.setCapEligibilityStatus(DENIED_LOWER);
								setFinancialValue(resultObject, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, DENIED_LOWER);
							}
							tempResultVector = sortAuMembers(apVector, mAClient, ebcObject.getAuId());
							resultObject.setAuMembResults(tempResultVector);
							interviewWrapUpEDBCResultVect.add(resultObject);
						}
					}
				}
			}
		}
		maECFHouseholdDelta.getFields().setField(InterviewWrapUpEDBCResult.class, requestId.getReqId(),
		    interviewWrapUpEDBCResultVect);
	}

	/**
	 * This method provides a check whether a pending au is been selected in Selection page.
	 * 
	 * @param maecfHousehold
	 *          MAECFHousehold object
	 * @param auId
	 *          BaseAU object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isAuExistInSelection(MAECFHousehold maecfHousehold, IntegerData auId) throws Exception {
		/*
		 * PMD violation fixed for ScandentVectorWithInitializer for version 1.5
		 */
		Vector eligReqAUs = new Vector(maecfHousehold.getFields().getFields(BaseEligReqAU.class,
		                maecfHousehold.getRequestId().getReqId()));
		eligReqAUs.trimToSize();
		Enumeration eligReqAUsEnum = eligReqAUs.elements();
		while (eligReqAUsEnum.hasMoreElements()) {
			BaseEligReqAU eligibilityRequestAU = (BaseEligReqAU) eligReqAUsEnum.nextElement();
			if (eligibilityRequestAU.requiresDelete()) {
				continue;
			}
			if (eligibilityRequestAU.getAuid().isNotEmpty() && auId.isNotEmpty()
			                && eligibilityRequestAU.getAuid().intValue() == auId.intValue()) {
				return true;
			}
		}
		return false;
	}

	/**
	 * This method is used to check whether a grantee has a closure EFRC with specific reasons.
	 * @param effCtx
	 * @param mAClient
	 * @param asstUnit
	 * @param auMembers
	 * @return
	 * @throws Exception
	 */
	public static ClientAuMembIneligFactor getGranteePriorityClosureEFRC(Context effCtx, MAClient mAClient, BaseAU asstUnit,
	                                                         BaseAUMember auMembers,MAECFHousehold maECF) throws Exception {
		String granteeEFRC = null;
		if (auMembers != null && auMembers.getClientId().isNotEmpty() && mAClient != null && asstUnit != null
		                && auMembers.getAuRoleCode().isNotEmpty()
		                && auMembers.getAuRoleCode().stringValue().equalsIgnoreCase(GRANTEE)
		                && EBCServices.hasAUmembClosure(effCtx, auMembers, mAClient, asstUnit.getProgramCode(),maECF)) {
			Vector eligFactor = mAClient.getClientAUMembInEligFactor(auMembers.getClientId());
			if (eligFactor.size() > 0) {
				Enumeration eligEnum = eligFactor.elements();
				while (eligEnum.hasMoreElements()) {
					ClientAuMembIneligFactor clientAUMembInEligFactor = (ClientAuMembIneligFactor) eligEnum
					                .nextElement();
					if ((clientAUMembInEligFactor != null && clientAUMembInEligFactor.getEligFactorReason()
					                .isNotEmpty())
					                && (clientAUMembInEligFactor.getEligFactorReason().toString().equals(REASON_DEATH) || ((asstUnit
					                                .getProgramCode().toString().equals(SNAP) && ((clientAUMembInEligFactor
					                                .getEligFactorReason().toString().equals(EFRC_INSTIT_INCLU_01)
					                                || clientAUMembInEligFactor.getEligFactorReason().toString()
					                                                .equals(EFRC_INSTIT_INCLU_02) || clientAUMembInEligFactor
					                                .getEligFactorReason().toString().equals(EFRC_INSTIT_INCLU_03))))))) {
						return clientAUMembInEligFactor;
					}
				}
			}
		}
		return null;
	}

	/**
	 * This method is used to check whether Any open SNAP AP has an active Sanction or not.
	 * @param effCtx
	 * @param mAClient
	 * @param sanctionObj
	 * @return
	 * @throws Exception
	 */
	public static String getSanctionPriorityClosureEFRC(Context effCtx, MAClient mAClient, Sanction sanctionObj)
	                throws Exception {
		String eFRCValue = null;
		if (mAClient != null && sanctionObj != null && sanctionObj.getSanctionId().isNotEmpty()) {
			SanctionDetails sanctionDetails = mAClient.getSanctionDetails(sanctionObj.getSanctionId());
			if (sanctionDetails != null
			    && (sanctionDetails.getStatus().equals(SANCTION_PENDING) || sanctionDetails.getStatus().equals(
			        SANCTION_SANCTIONED)) && sanctionDetails.getSanctionLvlEndDate().isEmpty()) {
				EligFactorSanction eligFactorSanc = (EligFactorSanction) mapper.fetch(effCtx, EligFactorSanction.class,
				    sanctionObj.getEligFactorSanctionId().intValue());
				if (eligFactorSanc != null && eligFactorSanc.getLevel().equals(SANCTION_LEVEL_3)
				    && eligFactorSanc.getReason().equals(SANCT_REASON_FSET)) {
					eFRCValue = EFRC_FAIL_FS_ET;
				}
				else if (eligFactorSanc != null && eligFactorSanc.getLevel().equals(SANCTION_LEVEL_3)
				    && eligFactorSanc.getReason().equals(SANCT_REASON_VOL)) {
					eFRCValue = EFRC_VOLUN_QUIT_JOB;
				}
			}
		}
		return eFRCValue;
	}

	/**
	 * To check is au in result.
	 * 
	 * @param interviewWrapupEDBCResultVect
	 *          Instance of {@link InterviewWrapUpEDBCResult}
	 * @param auId
	 *          is an {@link IntegerData}
	 * @return boolean value of this method
	 */
	public static boolean isAuExistInResult(Vector<InterviewWrapUpEDBCResult> interviewWrapupEDBCResultVect, IntegerData auId, Vector auExcludedVec) {
		boolean isAuExist = false;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		if (interviewWrapupEDBCResultVect != null && interviewWrapupEDBCResultVect.size() > 0) {
			Enumeration eDBCResultEnum = interviewWrapupEDBCResultVect.elements();
			while (eDBCResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) eDBCResultEnum.nextElement();
				if(auExcludedVec.size() > 0 && auExcludedVec
				                .contains(interviewWrapUpEDBCResult.getAuId()) 
				                && auId.intValue()== interviewWrapUpEDBCResult.getAuId().intValue()){
					interviewWrapupEDBCResultVect.remove(interviewWrapUpEDBCResult);
					eDBCResultEnum = interviewWrapupEDBCResultVect.elements();
				}
			}
			Enumeration interviewWrapupEDBCResultEnum = interviewWrapupEDBCResultVect.elements();
			while (interviewWrapupEDBCResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapupEDBCResultEnum.nextElement();
				if (interviewWrapUpEDBCResult.getAuId().isNotEmpty() && auId.isNotEmpty()
				                && interviewWrapUpEDBCResult.getAuId().intValue() == auId.intValue()) {
					
					isAuExist = true;
					break;
				}
				
			}
		}
		return isAuExist;
	}

	/**
	 * This method is used to set notice suppression indicator based on AU level result EFRC.
	 * 
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param ebcObjectVector
	 *            Instance of {@link Vector}
	 * @param batch
	 *            boolean
	 * @throws Exception
	 */
	public static void notices(MAECFHousehold mAECFHouseholdDelta, MAClient maClient, Vector ebcObjectVector, boolean batch)
	                throws Exception {
		Vector interviewWrapUpEDBCResultVect = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		EBCResultBase ebcResultBase = null;
		Context effCtx = null;
		EligFactorRsnDtl eligFacRsnDtl = null;
		if (mAECFHouseholdDelta != null && ebcObjectVector != null) {
			effCtx = mAECFHouseholdDelta.getFields().getContext();
			interviewWrapUpEDBCResultVect = mAECFHouseholdDelta.getInterviewWrapUpEDBCResults();
			if (interviewWrapUpEDBCResultVect != null && interviewWrapUpEDBCResultVect.size() > 0) {
				Enumeration interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					boolean isNoChangeInBenefit = false;
					BooleanData suppressNoticeVal = null;
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					int requestId = interviewWrapUpEDBCResult.getRequestId().intValue();
					ebcResultBase = EBCServices.getEBCResultBase(effCtx,interviewWrapUpEDBCResult.getAuId());
					if (null != ebcResultBase && ebcResultBase.getAuStatus().toString().equals(ACTIVE) 
							&& interviewWrapUpEDBCResult.getStatus().equals(ACTIVE)) {
						isNoChangeInBenefit = ebcResultBase.getBenefitAmount().equals(interviewWrapUpEDBCResult.getBenefitAmount());
					}
					// batch EBC calculation is not performed here.
					if (batch && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
					                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(SNAP)) {
						Enumeration ebcObjectEnum = ebcObjectVector.elements();
						while (ebcObjectEnum.hasMoreElements()) {
							EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
							if (ebcObj.getPriorityCAPReason() != null
							                && ebcObj.getPriorityCAPReason().toString().equalsIgnoreCase(CAPOUT)) {
								suppressNoticeVal = new BooleanData(true);
								interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);
							}
						}
					}
					eligFacRsnDtl = getEligFactorRsnDtl(effCtx, interviewWrapUpEDBCResult.getAuEFRC());
					if (eligFacRsnDtl != null && eligFacRsnDtl.getNoticeSuppressedFlag().isNotEmpty()
					                && eligFacRsnDtl.getNoticeSuppressedFlag().booleanValue()) {
						suppressNoticeVal = new BooleanData(true);
						interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);
					}
					//SNAP Specific notice related block
					if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)) {
						if(interviewWrapUpEDBCResult.getStatus().equals(CLOSED)	&& interviewWrapUpEDBCResult.getAuEFRC().equals(EFRC_FAIL_KEEP_APPOINTMENT)){
							BEACONAUEligReevaluation auEligReeval = (BEACONAUEligReevaluation) maClient.getFields().getField(
									BEACONAUEligReevaluation.class, interviewWrapUpEDBCResult.getAuId());
							if (interviewWrapUpEDBCResult.getBenefitEffective().after(auEligReeval.getRevalEndDate())){
								suppressNoticeVal = new BooleanData(true);
								interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);							
							}
						} else if (batch && isNoChangeInBenefit && isColaEligReqTypeCode(effCtx, requestId)) {
							suppressNoticeVal = new BooleanData(true);
							interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);	
						} /*else if(!isNoChangeBenefit && reason.equalsIgnoreCase(BEN_CHG_RECOUPMENT_RCPMT)) {
							suppressNoticeVal = new BooleanData(true);
							interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);	
						}*/
						else if(isBenefitChaneReasons(interviewWrapUpEDBCResult,BENEFIT_ABAWD_CHANGE)) {
							boolean ineligibleAbawd = false;
							Vector<EBCResultClientAUMembStat> ebcResultClientAUMembStatVector = mAECFHouseholdDelta.getMAClient(interviewWrapUpEDBCResult.getClientId().intValue())
								    .getEBCResultClientAUMembStat(ebcResultBase.getId());
							for(EBCResultClientAUMembStat ebcRsltClientMembStat : ebcResultClientAUMembStatVector) {
								if(interviewWrapUpEDBCResult.getAuId().equals(ebcRsltClientMembStat.getAuId()) && interviewWrapUpEDBCResult.getClientId().equals(ebcRsltClientMembStat.getClientId())) {
									if(ebcRsltClientMembStat.getBenefitEnd().isEmpty()) {
										ineligibleAbawd = true;
									}
								}
							}
							if(ineligibleAbawd) {
								interviewWrapUpEDBCResult.getBenefitChangeReasonVector().remove(BENEFIT_ABAWD_CHANGE);
							}
						}
					}
					//TANF Specific notice related block
					if (interviewWrapUpEDBCResult.getProgram().equals(TANF)) {
						if (batch && null != ebcResultBase && ebcResultBase.getAuStatus().toString().equals(ACTIVE) && 
								interviewWrapUpEDBCResult.getStatus().equals(ACTIVE) && 
								!EBCServices.isReevaluationVerificationSelected(mAECFHouseholdDelta, maClient, interviewWrapUpEDBCResult.getAuId(), 140,
										true, false)) {
							//Suppress notice when there is not change in a TANF benefit
							if (isNoChangeInBenefit) {
								suppressNoticeVal = new BooleanData(true);
								interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);	
							} else {
								//Generate notice ONLY for SSI OR Recoupment OR ChildSupport OR Income Disregard
								Stream<String> noticeReasons = Stream.of(BEN_CHG_CHILD_CARE_PAYMENT_CCCS, BEN_CHG_CLAIM_INIT_PAYMENT_CF01, BEN_CHG_PAID_IN_FULL_CF71, BEN_CHG_INC_DISREG_CNED);
								Set<String> changeReasonstringSet = new HashSet<>(interviewWrapUpEDBCResult.getBenefitChangeReasonVector());
								if (isColaEligReqTypeCode(effCtx, requestId) ||  noticeReasons.anyMatch(changeReasonstringSet::contains)) {
									// Do Not Suppress the notice
								} else {
									suppressNoticeVal = new BooleanData(true);
									interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);	
								}
							}
						}
					}
					if (hasIWResultClothingAllowance(interviewWrapUpEDBCResult)) {
						suppressNoticeVal = new BooleanData(true);
						interviewWrapUpEDBCResult.setSuppressNotice(suppressNoticeVal);							
					}
				}
			}
		}
	}

	/**
	 * This method is used to Set the AU status, benefit effective date and release date for each result in the Request.
	 * Each AU result will be processed either as a closure or an active result depending on whether the Result has
	 * Closure Conditions.
	 * 
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param ebcObjVect
	 *            collection of Instances of {@link EDBCResult}
	 * @throws Exception
	 */
	public static void auStatus(MAECFHousehold mAECFHouseholdDelta, Vector ebcObjVect, boolean batch, boolean reCalc,
	                            int clientId) throws Exception {
		Vector interviewWrapUpEDBCResultVect = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		MAClient mAClient = null;
		BaseAUStatus auStat = null;
		EDBCResultAUMember edbcResultAUMember = null;
		EDBCResult ebcObj = null;
		Vector auMemberVect = null;
		RequestId requestId = null;
		Enumeration auMemberEnum = null;
		DateData releaseDate = null;// (DateData) getReleaseDate(mAECFHouseholdDelta, interviewWrapUpEDBCResult,
		// ebcObj).get(0);
		DateData benefitDate = null; // (DateData) getReleaseDate(mAECFHouseholdDelta, interviewWrapUpEDBCResult,
		// ebcObj).get(1);
		Vector benefitAndReleaseDate = new Vector();
		if (mAECFHouseholdDelta != null) {
			mAClient = mAECFHouseholdDelta.getMAClient(clientId);
			interviewWrapUpEDBCResultVect = mAECFHouseholdDelta.getInterviewWrapUpEDBCResults();
			requestId = mAECFHouseholdDelta.getRequestId();
			if (interviewWrapUpEDBCResultVect != null && mAClient != null && interviewWrapUpEDBCResultVect.size() > 0) {
				Enumeration interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					// if(interviewWrapUpEDBCResult.get)
					auStat = mAClient.getAssistUnitStatus(interviewWrapUpEDBCResult.getAuId());
					if (ebcObjVect != null && ebcObjVect.size() > 0) {
						Enumeration ebcObjectEnum = ebcObjVect.elements();
						while (ebcObjectEnum.hasMoreElements()) {
							ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
							if (ebcObj.getAuId().intValue() == interviewWrapUpEDBCResult.getAuId().intValue()) {
								// Result has Closure Conditions
								if (resultHasClosureConditions(mAECFHouseholdDelta, mAClient,
								                interviewWrapUpEDBCResult, ebcObj)) {
									// If AU is Active
									if (auStat.getStatus().equals(ACTIVE)) {
										interviewWrapUpEDBCResult.setStatus(CLOSED);
										benefitAndReleaseDate = getReleaseDate(mAECFHouseholdDelta,
										                interviewWrapUpEDBCResult, ebcObj, batch, clientId);
										if (benefitAndReleaseDate.size() > 0) {
											releaseDate = (DateData) benefitAndReleaseDate.get(0);
											benefitDate = (DateData) benefitAndReleaseDate.get(1);
										}
										interviewWrapUpEDBCResult.setStatusDate(releaseDate);
										// interviewWrapUpEDBCResult.setRsltReleaseDte(releaseDate);
										setFinancialValue(interviewWrapUpEDBCResult, EBCDATA, RELEASEDATE,
										                interviewWrapUpEDBCResult.getStatusDate().toLocaleString());
										// 
										interviewWrapUpEDBCResult.setBenefitEffective(benefitDate);
										setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, EBCBENEFITEFFECTIVEDATE,
										                interviewWrapUpEDBCResult.getBenefitEffective()
										                                .toLocaleString());

										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										if (auMemberVect != null && auMemberVect.size() > 0) {
											auMemberEnum = auMemberVect.elements();
											while (auMemberEnum.hasMoreElements()) {
												edbcResultAUMember = (EDBCResultAUMember) auMemberEnum.nextElement();
												if (edbcResultAUMember.getMemStatus().isNotEmpty()
												                && !edbcResultAUMember.getMemStatus().toString()
												                                .equalsIgnoreCase(CLOSED)) {
													edbcResultAUMember.setMemStatus(CLOSED);
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
											}
										}
										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										Vector clientAuMembVect = mAClient.getAllMembersInAU(interviewWrapUpEDBCResult
										                .getAuId());
										Enumeration clientAuMembEnum = clientAuMembVect.elements();
										if (clientAuMembVect.size() > auMemberVect.size()) {
											while (clientAuMembEnum.hasMoreElements()) {
												BaseAUMember clientAuMemb = (BaseAUMember) clientAuMembEnum
												                .nextElement();
												if (clientAuMemb.getAuId().equals(interviewWrapUpEDBCResult.getAuId())
												                && !(clientAuMemb.getAuMemberStatusCode()
												                                .equals(CLOSED) || clientAuMemb
												                                .getAuMemberStatusCode().equals(DENIED))) {
													if (isThisAUMembExcludedFromCal(mAClient, mAECFHouseholdDelta,
													                auMemberVect, clientAuMemb, "")) {
														addExcludedMemberInResult(interviewWrapUpEDBCResult.getAuId(),
														                interviewWrapUpEDBCResult.getAuMembResults(),
														                clientAuMemb.getClientId().intValue(),
														                mAClient, releaseDate, "RESULT_HAS_CLOSURE",
														                CLOSED);
													}
												}
											}
										}
									}
									else if (auStat.getStatus().equals(PENDING)) {
										interviewWrapUpEDBCResult.setStatus(DENIED);
										if (reCalc) {// reCalc flag is set on split scenario recalculation.
											/*
											 * This object is excluded on prerule process calcultion as it has the
											 * closure reason, we are reconstructing the object in post rule processing
											 * recalculation and setting the split pending flag as true.
											 */
											interviewWrapUpEDBCResult.setSplitPendFlg(true);
										}
										benefitAndReleaseDate = getReleaseDate(mAECFHouseholdDelta,
										                interviewWrapUpEDBCResult, ebcObj, batch, clientId);
										if (benefitAndReleaseDate.size() > 0) {
											releaseDate = (DateData) benefitAndReleaseDate.get(0);
											benefitDate = (DateData) benefitAndReleaseDate.get(1);
										}
										interviewWrapUpEDBCResult.setStatusDate(releaseDate);
										// interviewWrapUpEDBCResult.setRsltReleaseDte(releaseDate);
										setFinancialValue(interviewWrapUpEDBCResult, EBCDATA, RELEASEDATE,
										                interviewWrapUpEDBCResult.getStatusDate().toLocaleString());

										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										if (auMemberVect != null && auMemberVect.size() > 0) {
											auMemberEnum = auMemberVect.elements();
											while (auMemberEnum.hasMoreElements()) {
												edbcResultAUMember = (EDBCResultAUMember) auMemberEnum.nextElement();
												if (edbcResultAUMember.getMemStatus().isNotEmpty()
												                && !(edbcResultAUMember.getMemStatus().toString()
												                                .equalsIgnoreCase(DENIED))) {
													edbcResultAUMember.setMemStatus(DENIED);
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
											}
										}
										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										Vector clientAuMembVect = mAClient.getAllMembersInAU(interviewWrapUpEDBCResult
										                .getAuId());
										Enumeration clientAuMembEnum = clientAuMembVect.elements();
										if (clientAuMembVect.size() > auMemberVect.size()) {
											while (clientAuMembEnum.hasMoreElements()) {
												BaseAUMember clientAuMemb = (BaseAUMember) clientAuMembEnum
												                .nextElement();
												if (clientAuMemb.getAuId().equals(interviewWrapUpEDBCResult.getAuId())
												                && !(clientAuMemb.getAuMemberStatusCode()
												                                .equals(CLOSED) || clientAuMemb
												                                .getAuMemberStatusCode().equals(DENIED))) {
													if (isThisAUMembExcludedFromCal(mAClient, mAECFHouseholdDelta,
													                auMemberVect, clientAuMemb, "")) {
														addExcludedMemberInResult(interviewWrapUpEDBCResult.getAuId(),
														                interviewWrapUpEDBCResult.getAuMembResults(),
														                clientAuMemb.getClientId().intValue(),
														                mAClient, releaseDate, RESULT_HAS_CLOSURE,
														                DENIED);
													}
												}
											}
										}
									}
									if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)) {
										setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TBAAMOUNT, 0);
										setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TBARELEASEDATE, "");
										setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, TBAFLAG, NO);
										setFinancialValue(interviewWrapUpEDBCResult, STANDARDAMOUNTS, CATELIGFLAG, NO);
									}
									if (interviewWrapUpEDBCResult.getProgram().equals(EA)
									                && (interviewWrapUpEDBCResult.getStatus().equals(CLOSED) || interviewWrapUpEDBCResult
									                                .getStatus().equals(DENIED))) {
										setFinancialValue(interviewWrapUpEDBCResult, GROSSINCOME, CASHBENEFITAMOUNT,
										                ZERO_DOUBLE_VALUE);
									}
								}
								else if (!resultHasClosureConditions(mAECFHouseholdDelta, mAClient,
								                interviewWrapUpEDBCResult, ebcObj)) {
									if (!(mAECFHouseholdDelta.isExpeditedFS(auStat.getAuId()))
									                && (!(interviewWrapUpEDBCResult.getExpedited().isNotEmpty() && interviewWrapUpEDBCResult
									                                .getExpedited().toString().equals(CAP_EXPEDITED)))
													&& !(resultHasClothingAllowance(interviewWrapUpEDBCResult, ebcObj))
									                && !auStat.getStatus().equals(ACTIVE)) {
										interviewWrapUpEDBCResult.setStatus(ACTIVE);
									}
									benefitAndReleaseDate = getReleaseDate(mAECFHouseholdDelta,
									                interviewWrapUpEDBCResult, ebcObj, batch, clientId);
									releaseDate = (DateData) benefitAndReleaseDate.get(0);
									benefitDate = (DateData) benefitAndReleaseDate.get(1);
									// releaseDate = (DateData) getReleaseDate(mAECFHouseholdDelta,
									// interviewWrapUpEDBCResult, ebcObj,batch).get(0);
									// benefitDate = (DateData) getReleaseDate(mAECFHouseholdDelta,
									// interviewWrapUpEDBCResult, ebcObj,batch).get(1);
									auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
									Vector clientAuMembVect = mAClient.getAllMembersInAU(interviewWrapUpEDBCResult
									                .getAuId());
									Enumeration clientAuMembEnum = clientAuMembVect.elements();
									if (clientAuMembVect.size() > auMemberVect.size()) {
										while (clientAuMembEnum.hasMoreElements()) {
											BaseAUMember clientAuMemb = (BaseAUMember) clientAuMembEnum.nextElement();
											// If the excluded member has closure EFRC
											if (clientAuMemb.getAuId().equals(interviewWrapUpEDBCResult.getAuId())) {
												if (isThisAUMembExcludedFromCal(mAClient, mAECFHouseholdDelta,
												                auMemberVect, clientAuMemb, "CLOSURE_EFRC")) {
													Vector<ClientAuMembIneligFactor> eligFactor = mAClient
													                .getClientAUMembInEligFactor(clientAuMemb
													                                .getClientId());
													boolean hasClosureEFRCFlg = false;
													for (ClientAuMembIneligFactor membInelig : eligFactor) {
														if (membInelig.getAuId().intValue() == interviewWrapUpEDBCResult
														                .getAuId().intValue()) {
															hasClosureEFRCFlg = true;
														}
													}
													if (hasClosureEFRCFlg) {
														addExcludedMemberInResult(interviewWrapUpEDBCResult.getAuId(),
														                interviewWrapUpEDBCResult.getAuMembResults(),
														                clientAuMemb.getClientId().intValue(),
														                mAClient, releaseDate, RESULT_HAS_NO_CLOSURE,
														                CLOSED);
													}
												}
											}
										}
									}
									benefitAndReleaseDate = getReleaseDate(mAECFHouseholdDelta,
									                interviewWrapUpEDBCResult, ebcObj, batch, clientId);
									if (benefitAndReleaseDate.size() > 0) {
										releaseDate = (DateData) benefitAndReleaseDate.get(0);
										benefitDate = (DateData) benefitAndReleaseDate.get(1);
									}
									if (!auStat.getStatus().equals(ACTIVE)
							                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
							                && interviewWrapUpEDBCResult.getStatus().toString()
							                                .equalsIgnoreCase(ACTIVE)) {
										interviewWrapUpEDBCResult.setStatusDate(releaseDate);
									}
									interviewWrapUpEDBCResult.setRsltReleaseDte(releaseDate);
									// interviewWrapUpEDBCResult.setStatusDate(releaseDate);
									interviewWrapUpEDBCResult.setBenefitEffective(benefitDate);
									setFinancialValue(interviewWrapUpEDBCResult, EBCDATA, RELEASEDATE, releaseDate
									                .toLocaleString());
									setFinancialValue(interviewWrapUpEDBCResult, BENEFIT, EBCBENEFITEFFECTIVEDATE,
									                interviewWrapUpEDBCResult.getBenefitEffective().toLocaleString());
									if(mAECFHouseholdDelta.isExpeditedFS(auStat.getAuId())
											|| resultHasClothingAllowance(interviewWrapUpEDBCResult, ebcObj)){
										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										if (auMemberVect != null && auMemberVect.size() > 0) {
											auMemberEnum = auMemberVect.elements();
											while (auMemberEnum.hasMoreElements()) {
												edbcResultAUMember = (EDBCResultAUMember) auMemberEnum.nextElement();
												if (edbcResultAUMember.getMemStatusDate().isEmpty()) {
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
											}
										}
									}
									if (!mAECFHouseholdDelta.isExpeditedFS(auStat.getAuId())
											&& !(resultHasClothingAllowance(interviewWrapUpEDBCResult, ebcObj))) {
										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										if (auMemberVect != null && auMemberVect.size() > 0) {
											auMemberEnum = auMemberVect.elements();
											while (auMemberEnum.hasMoreElements()) {
												edbcResultAUMember = (EDBCResultAUMember) auMemberEnum.nextElement();
												if (edbcResultAUMember.getMemStatus().isNotEmpty()
												                && edbcResultAUMember.getMemStatus().toString()
												                                .equalsIgnoreCase(PENDING)) {
													edbcResultAUMember.setMemStatus(ACTIVE);
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
												else if (edbcResultAUMember.getMemStatus().isNotEmpty()
												                && (edbcResultAUMember.getMemStatus().toString()
												                                .equalsIgnoreCase(CLOSED) || edbcResultAUMember
												                                .getMemStatus().toString()
												                                .equalsIgnoreCase(DENIED))) {
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
												if (edbcResultAUMember.getMemStatusDate().isEmpty()) {
													edbcResultAUMember.setMemStatusDate(releaseDate);
												}
											}
										}
										auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
										clientAuMembVect = mAClient.getAllMembersInAU(interviewWrapUpEDBCResult
										                .getAuId());
										clientAuMembEnum = clientAuMembVect.elements();
										if (clientAuMembVect.size() > auMemberVect.size()) {
											while (clientAuMembEnum.hasMoreElements()) {
												BaseAUMember clientAuMemb = (BaseAUMember) clientAuMembEnum
												                .nextElement();
												// If the member was not selected in the selection page.
												if (clientAuMemb.getAuId().equals(interviewWrapUpEDBCResult.getAuId())
												                && !(clientAuMemb.getAuMemberStatusCode()
												                                .equals(CLOSED) || clientAuMemb
												                                .getAuMemberStatusCode().equals(DENIED))) {
													if (isThisAUMembExcludedFromCal(mAClient, mAECFHouseholdDelta,
													                auMemberVect, clientAuMemb,
													                "PEND_MEMB_NOT_SELECTED")
													                && clientAuMemb.getAuMemberStatusCode()
													                                .isNotEmpty()
													                && clientAuMemb.getAuMemberStatusCode().toString()
													                                .equals(PENDING)) {
														addExcludedMemberInResult(interviewWrapUpEDBCResult.getAuId(),
														                interviewWrapUpEDBCResult.getAuMembResults(),
														                clientAuMemb.getClientId().intValue(),
														                mAClient, releaseDate, "RESULT_HAS_NO_CLOSURE",
														                PENDING);
													}
												}
											}
										}
									}
								}
							}
						}
					}
			}
				adjustNonPrimeAU(mAECFHouseholdDelta, interviewWrapUpEDBCResultVect);
				setBenefitBeginAndEndDatesECF(mAECFHouseholdDelta, interviewWrapUpEDBCResultVect);
				resetStatusEffectiveDates(mAECFHouseholdDelta, interviewWrapUpEDBCResultVect, batch);
				setInitialTBAReleaseDates(mAECFHouseholdDelta, interviewWrapUpEDBCResultVect, batch);
				mAECFHouseholdDelta.getFields().setField(InterviewWrapUpEDBCResult.class, requestId.getReqId(),
				                interviewWrapUpEDBCResultVect);
			}
		}
	}

	/**
	 * Return true when an EBC result has a clothing allowance amount calculated.
	 * This is sometimes called a "partial payment" because no TANF benefit is paid
	 * but the client's children do qualify for a Clothing Allowance. The AU status
	 * will be Pending in the result and the AU will be re-calculated the day after
	 * the Pending status release, likely resulting in a denial.
	 *
	 * @param mAClient
	 *            Instance of {@link MAClient}
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean resultHasClothingAllowance(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                                 EDBCResult edbcResult) throws Exception {
		boolean returnCondition = false;		
		if (interviewWrapUpEDBCResult != null
				&& edbcResult != null) {
			if (interviewWrapUpEDBCResult.getProgram().equals(TANF)
					&& edbcResult.getClothingAllowanceEligibleFlag().isTrue()
			        && edbcResult.getClothingAllowanceGrantAmount().doubleValue() > 0) {
					returnCondition = true;
			}
		}
		return returnCondition;
	}

	
	/**
	 * Determine if the EBC calculated benefit effective date should be set on the result
	 * in a pending AU scenario.
	 * 
	 * @param mAClient
	 *            Instance of {@link MAClient}
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean isReinstatedFSAUAtFault(MAECFHousehold maECFHouseholdDelta, MAClient mAClient,
						InterviewWrapUpEDBCResult interviewWrapUpEDBCResult) throws Exception {
		boolean isReinstatedFault = false;
		if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)
				&& interviewWrapUpEDBCResult.getStatus().equals(ACTIVE)){
			MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(interviewWrapUpEDBCResult.getAuId()).intValue());
			BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(interviewWrapUpEDBCResult.getAuId());
			// AU is being reinstated
			if (isReinstated(maECFHouseholdDelta, interviewWrapUpEDBCResult.getAuId())) {
				EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult.getAuId());
				if (ebcRsltBase != null 
						&& ebcRsltBase.getAuStatus().equals(DENIED) || ebcRsltBase.getAuStatus().equals(CLOSED)) {
					DateData testDate = new DateData();
					if (ebcRsltBase.getAuStatus().equals(DENIED)){
						testDate.setTime(ebcRsltBase.getAuStatusEffDate());
					}else if (ebcRsltBase.getAuStatus().equals(CLOSED)){
						testDate.setTime(ebcRsltBase.getBenefitEffective());					
					}
					AUFault auFault = mAClient.getAUFault(interviewWrapUpEDBCResult.getAuId());
					if ((auFault != null && auFault.getFaultTypeCd().isNotEmpty() && auFault.getFaultDte().isNotEmpty())
							&& (auFault.getFaultDte().equals(testDate) || auFault.getFaultDte().after(testDate))) {
						isReinstatedFault = true;
					}
				}
			}
		}
		return isReinstatedFault;
	}
	
	/**
	 * @param mAClient
	 *            Instance of MAClient
	 * @param maECF
	 *            Instance of MAECFHousehold
	 * @param rsltMemberVect
	 * @param clientAuMemb
	 *            Instance of BaseAUMember.
	 * @return
	 * @throws Exception
	 */
	public static boolean isThisAUMembExcludedFromCal(MAClient mAClient, MAECFHousehold maECF, Vector rsltMemberVect,
	                                                  BaseAUMember clientAuMemb, String inParm) throws Exception {
		Vector<EligibilityRequestPendClient> eligReqPendClientVec = null;
		RequestId requestId = null;
		Enumeration rsltMemberEnum = rsltMemberVect.elements();
		while (rsltMemberEnum.hasMoreElements()) {
			EDBCResultAUMember resultAUMember = (EDBCResultAUMember) rsltMemberEnum.nextElement();
			if (resultAUMember.getClientId().intValue() == clientAuMemb.getClientId().intValue()) {
				return false;
			}
		}
		// inParm will be empty when this is called if the AU has Closure conditions
		if (inParm.equals("")) {
			Vector eligFactor = mAClient.getClientAUMembInEligFactor(clientAuMemb.getClientId());
			if ((eligFactor != null && eligFactor.size() > 0 && (clientAuMemb.getAuMemberStatusCode().equals(PENDING)
			                || clientAuMemb.getAuMemberStatusCode().equals(ACTIVE) || clientAuMemb
			                .getAuMemberStatusCode().equals(INELIGIBLE)))
			                || !isSelectedInPendClient(clientAuMemb,  maECF)) {
				return true;
			}
		}
		else {
			if(inParm.equals("PEND_MEMB_NOT_SELECTED")){
				requestId = maECF.getRequestId();
				eligReqPendClientVec = maECF.getFields().getFields(
				                EligibilityRequestPendClient.class, requestId.getReqId());
			}
			// inParm will have value when this is called if the AU has no Closure conditions.
			if (inParm.equals("CLOSURE_EFRC")) {
				Vector eligFactor = mAClient.getClientAUMembInEligFactor(clientAuMemb.getClientId());
				if (eligFactor != null
				                && eligFactor.size() > 0
				                && (clientAuMemb.getAuMemberStatusCode().equals(PENDING)
				                                || clientAuMemb.getAuMemberStatusCode().equals(ACTIVE) || clientAuMemb
				                                .getAuMemberStatusCode().equals(INELIGIBLE))) {
					return true;
				}
			}
			else if (inParm.equals("PEND_MEMB_NOT_SELECTED")
							&& (eligReqPendClientVec.size()==0
			                || (eligReqPendClientVec != null 
			                				&& eligReqPendClientVec.size() > 0 
			                				&& !isSelectedInPendClient(clientAuMemb, maECF)))) {
				return true;
			}
		}
		return false;
	}

	/**
	 * @param interviewWrapUpEDBCResult
	 * @param clientId
	 * @param wfData
	 * @throws Exception
	 */
	public static void addExcludedMemberInResult(IntegerData auId, Vector auMembRsltVec, int clientId, MAClient wfData,
	                                             DateData releaseDate, String inParm1, String inParm2) throws Exception {
		HHClientPersonalRelation hhClientPersonalRelation = null;
		Vector clientAumemb = wfData.getAllMembersInAU(auId);
		if (clientAumemb != null && clientAumemb.size() > 0) {
			BaseAUMember granteeAUMember = wfData.getGranteeForAU(auId);
			Enumeration membEnum = clientAumemb.elements();
			while (membEnum.hasMoreElements()) {
				BaseAUMember aumemb = (BaseAUMember) membEnum.nextElement();
				if (aumemb.getClientId().intValue() == clientId) {
					EDBCResultAUMember edbcResultMemb = new EDBCResultAUMember();
					edbcResultMemb.setAuId(aumemb.getAuId());
					edbcResultMemb.setClientId(aumemb.getClientId());
					if (inParm1.equalsIgnoreCase(RESULT_HAS_CLOSURE)) {
						if (inParm2.equalsIgnoreCase(CLOSED)) {
							edbcResultMemb.setMemStatus(CLOSED);
						}
						else if (inParm2.equalsIgnoreCase(DENIED)) {
							edbcResultMemb.setMemStatus(DENIED);
						}
					}
					if (inParm1.equalsIgnoreCase(RESULT_HAS_NO_CLOSURE) && inParm2.equalsIgnoreCase(PENDING)) {
						edbcResultMemb.setMemStatus(PENDING);
					}
					else if (inParm1.equalsIgnoreCase(RESULT_HAS_NO_CLOSURE)) {
						if (aumemb.getAuMemberStatusCode().isNotEmpty()) {
							if (aumemb.getAuMemberStatusCode().toString().equalsIgnoreCase(PENDING)) {
								edbcResultMemb.setMemStatus(DENIED);
							}
							else {
								edbcResultMemb.setMemStatus(CLOSED);
							}
						}
					}
					edbcResultMemb.setMemStatusDate(releaseDate);
					// String otherParent = isThisMemberOtherParent(maClient,aumemb.getAuId());
					if (aumemb.getAuRoleCode().toString().equals(OTHER_PARENT)) {
						edbcResultMemb.setIsOtherParent("Yes");
					}
					else {
						edbcResultMemb.setIsOtherParent("No");
					}
					edbcResultMemb.setMemNam(wfData.getClientDisplayName(aumemb.getClientId()));

					if (aumemb.getClientId().intValue() == granteeAUMember.getClientId().intValue()) {
						edbcResultMemb.getMemRelation().setString(GRANTEE_FULL);
					}
					else {
						hhClientPersonalRelation = wfData.getHHClientPersonalRelation(granteeAUMember
						    .getClientId(), aumemb.getClientId());
						if (hhClientPersonalRelation != null) {
							edbcResultMemb.setMemRelation(hhClientPersonalRelation.getPersonalRelationCode());
						}
					}
					Enumeration respEnum = wfData.getClientAUMembResponsibilty(aumemb.getClientId()).elements();
					while (respEnum.hasMoreElements()) {
						ClientAUMembResp clientAUMembResp = (ClientAUMembResp) respEnum.nextElement();
						if (auId.intValue() == clientAUMembResp.getAuId().intValue()) {
							edbcResultMemb.setMemResponsibility(clientAUMembResp.getMemResp());
							break;
						}
					}
					if (edbcResultMemb.getMemStatus().equals(DENIED) || edbcResultMemb.getMemStatus().equals(CLOSED)) {
						Enumeration reasonEnum = wfData.getClientAUMembInEligFactor(aumemb.getClientId()).elements();
						while (reasonEnum.hasMoreElements()) {
							ClientAuMembIneligFactor clientauMembIneligFactor = (ClientAuMembIneligFactor) reasonEnum
							                .nextElement();
							if (auId.intValue() == clientauMembIneligFactor.getAuId().intValue()) {
								edbcResultMemb.setMemIneligReason(clientauMembIneligFactor.getEligFactorReason());
								edbcResultMemb.setMemEligFactor(clientauMembIneligFactor.getEligFactor());
								edbcResultMemb.setMemEligFactorStatus(clientauMembIneligFactor.getEligStatus());
								// edbcResultMemb.setMemStatus(INELIGIBLE);
							}
						}
					}
					if (edbcResultMemb.getAuId().equals(auId)) {
						auMembRsltVec.addElement(edbcResultMemb);
					}
					// ebcResultAuMeb.addElement(edbcResultMemb);
				}
			}
			// interviewWrapUpEDBCResult.setEdbcResultAUMemberVector(ebcResultAuMeb);
		}
	}

	/**
	 * This method is used to set the Benefit Begin Date and Benefit End Date to the current result being processed
	 * based upon the AU or AUMember Status.
	 * 
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param ebcObj
	 *            Instance of {@link EDBCResult}
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @param mAClientDelta
	 *            Instance of {@link MAClient}
	 * @param benefitDate
	 *            a DateData object
	 * @throws Exception
	 */
	public static void setBenefitBeginAndEndDatesECF(MAECFHousehold mAECFHouseholdDelta,
	                                                 Vector interviewWrapUpEDBCResultVect) throws Exception {
		//MAECFHousehold mAECFHouseholdBase = null;
		EBCResultBase ebcResultBase = null;
		Enumeration currentResultEnum = null;
		Vector curMembRsltVec = null;
		Enumeration curMembRsltEnum;
		DateData prevRelRsltMembBegin = null;
		DateData prevRelRsltMembEnd = null;
		StringData prevRelRsltStat = null;
		InterviewWrapUpEDBCResult prevRelRsltObj = null;
		Hashtable prevBenefitBegin = null;
		Hashtable prevBenefitEnd = null;
		Hashtable prevMembStatus = null;
		Vector prevRelRsltMemVec = null;
		Enumeration prevRelRsltMemEnum;
		IntegerData resultId = new IntegerData();
		MAClient mAClientDelta = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		DateData benefitDate = null;
		//mAECFHouseholdBase = getMAECFHouseholdBase(mAECFHouseholdDelta);
		mAClientDelta = mAECFHouseholdDelta.getMAClient(mAECFHouseholdDelta.getPrimaryClientId());
		if (interviewWrapUpEDBCResultVect != null && interviewWrapUpEDBCResultVect.size() > 0) {
			currentResultEnum = interviewWrapUpEDBCResultVect.elements();
			while (currentResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) currentResultEnum.nextElement();
				if (mAECFHouseholdDelta != null && mAClientDelta != null) {
					// ebcResultBase= mAECFHouseholdBase.getEBCResult(interviewWrapUpEDBCResult.getAuId());//@CodeClean
					ebcResultBase = mAECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult.getAuId());
					if (ebcResultBase != null) {
						if (ebcResultBase.getBenefitBegin().isNotEmpty() && !ebcResultBase.getAuStatus().equals(DENIED)) {
							interviewWrapUpEDBCResult.setBenefitBegin(ebcResultBase.getBenefitBegin());
						}
						if (ebcResultBase.getBenefitEnd().isNotEmpty()) {
							interviewWrapUpEDBCResult.setBenefitEnd(ebcResultBase.getBenefitEnd());
						}
						resultId.setInteger(ebcResultBase.getId());
					}
					benefitDate = interviewWrapUpEDBCResult.getBenefitEffective();
					// AU Benefit begin & End dates starts here

					if (ebcResultBase != null
					                && ebcResultBase.getAuStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(
					                                interviewWrapUpEDBCResult.getStatus().toString())) {
						// no change for Active to Active
					}
					/*
					 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Pending, BEN_EFF_DTE null expedited SNAP
					 */
					else if (interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && (interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(PENDING) && (mAECFHouseholdDelta
					                                .isExpeditedFS(interviewWrapUpEDBCResult.getAuId()) && interviewWrapUpEDBCResult
					                                .getProgram().toString().equalsIgnoreCase(SNAP)))) {
						interviewWrapUpEDBCResult.setBenefitBegin(benefitDate);
						interviewWrapUpEDBCResult.getBenefitEnd().setNull();
					}
					/*
					 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Pending, Active no change no change expedited SNAP
					 */
					else if (ebcResultBase != null && ebcResultBase.getAuStatus().isNotEmpty()
					                && ebcResultBase.getAuStatus().toString().equalsIgnoreCase(PENDING)
					                && ebcResultBase.getExpeditedCode().toString().equals(EXPEDITED_CODE)
					                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(ACTIVE)) {
						// no change
					}
					/*
					 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Active BEN_EFF_DTE null
					 */
					else if (interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(ACTIVE)) {
						interviewWrapUpEDBCResult.setBenefitBegin(benefitDate);
						interviewWrapUpEDBCResult.getBenefitEnd().setNull();
					}
					/*
					 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Closed no change BEN_EFF_DTE
					 */
					else if (interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(CLOSED)) {
						// no change in Benefit gegin
						interviewWrapUpEDBCResult.setBenefitEnd(benefitDate.getLastDateOfTheMonth());
					}
					/*
					 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Denied no change no change
					 */
					else if (interviewWrapUpEDBCResult.getStatus().isNotEmpty()
					                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(DENIED)) {
						// no change
					}

					// AU Benefit begin & End dates ends here

					// AU Member Benefit begin & End dates starts here

					if (ebcResultBase != null && resultId.isNotEmpty()) {
						prevRelRsltMemVec = mAECFHouseholdDelta.getMAClient(mAECFHouseholdDelta.getPrimaryClientId())
						                .getEBCResultClientAUMembStat(resultId);
						if (prevRelRsltMemVec != null && prevRelRsltMemVec.size() > 0) {
							prevRelRsltMemEnum = prevRelRsltMemVec.elements();
							prevBenefitBegin = new Hashtable();
							prevBenefitEnd = new Hashtable();
							prevMembStatus = new Hashtable();
							while (prevRelRsltMemEnum.hasMoreElements()) {
								EBCResultClientAUMembStat prevEBCResultClientAUMembStat = (EBCResultClientAUMembStat) prevRelRsltMemEnum
								                .nextElement();
								if (prevEBCResultClientAUMembStat.getClientId().isNotEmpty()
								                && prevEBCResultClientAUMembStat.getAuId().isNotEmpty()) {
									String key = prevEBCResultClientAUMembStat.getClientId().toString() + "-"
									                + prevEBCResultClientAUMembStat.getAuId().toString();
									if (prevEBCResultClientAUMembStat.getBenefitBegin().isNotEmpty() && !prevEBCResultClientAUMembStat.getEligStatus().equals(FAIL)) {
										prevBenefitBegin.put(key, prevEBCResultClientAUMembStat.getBenefitBegin());
									}
									if (prevEBCResultClientAUMembStat.getBenefitEnd().isNotEmpty()) {
										prevBenefitEnd.put(key, prevEBCResultClientAUMembStat.getBenefitEnd());
									}
									if (prevEBCResultClientAUMembStat.getClientAuMemberStatus().isNotEmpty()) {
										prevMembStatus
										                .put(key, prevEBCResultClientAUMembStat
										                                .getClientAuMemberStatus());
									}
								}
							}
						}
					}
					curMembRsltVec = interviewWrapUpEDBCResult.getAuMembResults();
					if (curMembRsltVec != null && curMembRsltVec.size() > 0) {
						curMembRsltEnum = curMembRsltVec.elements();
						while (curMembRsltEnum.hasMoreElements()) {
							EDBCResultAUMember curEDBCRsltAUMemb = (EDBCResultAUMember) curMembRsltEnum.nextElement();
							String key = curEDBCRsltAUMemb.getClientId().toString() + "-"
							                + curEDBCRsltAUMemb.getAuId().toString();
							if (prevBenefitBegin != null) {
								prevRelRsltMembBegin = (DateData) prevBenefitBegin.get(key);
							}
							if (prevBenefitEnd != null) {
								prevRelRsltMembEnd = (DateData) prevBenefitEnd.get(key);
							}
							if (prevRelRsltMembBegin != null && prevRelRsltMembBegin.isNotEmpty()) {
								curEDBCRsltAUMemb.setMemBenefitBegin(prevRelRsltMembBegin);
							}
							if (prevRelRsltMembEnd != null && prevRelRsltMembEnd.isNotEmpty()) {
								curEDBCRsltAUMemb.setMemBenefitEnd(prevRelRsltMembEnd);
							}
							if (prevMembStatus != null) {
								prevRelRsltStat = (StringData) prevMembStatus.get(key);
							}
							if (prevRelRsltStat != null
							                && prevRelRsltStat.isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && prevRelRsltStat.toString().equalsIgnoreCase(
							                                curEDBCRsltAUMemb.getMemStatus().toString())) {
								// no change for Active to Active
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Pending, BEN_EFF_DTE null expedited
							 * SNAP
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(PENDING)
							                && mAECFHouseholdDelta.isExpeditedFS(interviewWrapUpEDBCResult.getAuId())) {
								curEDBCRsltAUMemb.setMemBenefitBegin(interviewWrapUpEDBCResult.getBenefitEffective());
								curEDBCRsltAUMemb.getMemBenefitEnd().setNull();
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Pending, Active no change no change
							 * expedited SNAP
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(ACTIVE)
							                && prevRelRsltStat != null && prevRelRsltStat.equals(PENDING)
							                && ebcResultBase != null && ebcResultBase.getAuId().isNotEmpty()
							                && ebcResultBase.getExpeditedCode().toString().equals(EXPEDITED_CODE)) {
								// no change
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Active BEN_EFF_DTE null
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(ACTIVE)) {
								curEDBCRsltAUMemb.setMemBenefitBegin(interviewWrapUpEDBCResult.getBenefitEffective());
								curEDBCRsltAUMemb.getMemBenefitEnd().setNull();
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Ineligible Active no change no change *
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(CLOSED)
							                && prevRelRsltStat != null && prevRelRsltStat.equals(INELIGIBLE)
							                && isGrantee(mAClientDelta, interviewWrapUpEDBCResult.getAuId(),
													curEDBCRsltAUMemb) == false) {
								// no change

							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Closed no change BEN_EFF_DTE
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(CLOSED)
							                && curEDBCRsltAUMemb.getMemBenefitBegin().isNotEmpty()) {
								// No change in Begin date
								DateData memberEnd = interviewWrapUpEDBCResult.getBenefitEnd();
								if(memberEnd.isEmpty()) {
									memberEnd = new DateData(interviewWrapUpEDBCResult.getBenefitEffective()).addDays(-1);
								}
								curEDBCRsltAUMemb.setMemBenefitEnd(memberEnd);
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Denied no change no change
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(DENIED)) {
								// no change
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Active Ineligible no change BEN_EFF_DTE
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(INELIGIBLE)
							                && prevRelRsltStat != null && prevRelRsltStat.equals(ACTIVE)) {
								// No change in Begin date
								DateData memberEnd = interviewWrapUpEDBCResult.getBenefitEnd();
								if(memberEnd.isEmpty()) {
									memberEnd = new DateData(interviewWrapUpEDBCResult.getBenefitEffective()).addDays(-1);
								}
								curEDBCRsltAUMemb.setMemBenefitEnd(memberEnd);
							}
							/*
							 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Ineligible no change no change
							 */
							else if (curEDBCRsltAUMemb.getMemStatus().isNotEmpty()
							                && curEDBCRsltAUMemb.getMemStatus().toString().equals(INELIGIBLE)) {
								// no change
							}
						}
					}
					// AU Member Benefit begin & End dates ends here
				}
			}
		}
	}

	/**
	 *  Check current member is grantee
	 *  
	 * @param mAClientDelta
	 * @param auId
	 * @param curEDBCRsltAUMemb
	 * @return
	 * @throws Exception 
	 */
	private static boolean isGrantee(MAClient maClient, IntegerData auId, EDBCResultAUMember auMember) throws Exception {
		Vector vectAUMember = maClient.getAllClientAUMembers(auMember.getClientId());
		Enumeration enumAUMemb = vectAUMember.elements();
		while (enumAUMemb.hasMoreElements()) {
			BaseClientAUMember auMemb = (BaseClientAUMember) enumAUMemb.nextElement();
			if (auId.equals(auMemb.getAuId())&& auMemb.getAuRoleCode().isNotEmpty()
					&& (auMemb.getAuRoleCode().toString().equals(MAConstants.GRANTEE))) {
				return true;
			}
		}
		return false;
	}
	
	/**
	 * This method is used to set the Benefit Begin Date and Benefit End Date to the current result being processed
	 * based upon the AU or AUMember Status.
	 * 
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param ebcObj
	 *            Instance of {@link EDBCResult}
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @param mAClientDelta
	 *            Instance of {@link MAClient}
	 * @param benefitDate
	 *            a DateData object
	 * @throws Exception
	 */
	public static void setBenefitBeginAndEndDates(MAECFHousehold mAECFHouseholdDelta, EDBCResult ebcObj,
	                                              InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                              DateData benefitDate, boolean batch, int clientId) throws Exception {
	//	MAECFHousehold mAECFHouseholdBase = null;
		EBCResultBase ebcResultBase = null;
		BaseAUStatus auStatus = null;
		EDBCResultAUMember edbcResultAUMember = null;
		DateData benefitBegin = null;
		DateData benefitEnd = null;
		MAClient mAClientDelta = mAECFHouseholdDelta.getMAClient(clientId);
		if (benefitDate == null) {
			benefitDate = (DateData) getReleaseDate(mAECFHouseholdDelta, interviewWrapUpEDBCResult, ebcObj, batch,
			                clientId).get(1);
		}
		if (mAECFHouseholdDelta != null && ebcObj != null && ebcObj.getAuId().isNotEmpty()
		                && interviewWrapUpEDBCResult != null && mAClientDelta != null) {
			ebcResultBase = mAECFHouseholdDelta.getEBCResultBase(interviewWrapUpEDBCResult.getAuId());
			if (ebcResultBase != null) {
				benefitBegin = ebcResultBase.getBenefitBegin();
				benefitEnd = ebcResultBase.getBenefitEnd();
			}
			auStatus = mAClientDelta.getAssistUnitStatus(ebcObj.getAuId());
			if (auStatus != null && auStatus.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().toString().equals(auStatus.getStatus().toString())) {
				// no change in status
			}
			/*
			 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Pending, expedited SNAP BEN_EFF_DTE null
			 */
			else if (auStatus != null
			                && auStatus.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && (interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(PENDING) || (interviewWrapUpEDBCResult
			                                .getProgram().isNotEmpty()
			                                && SNAP.equalsIgnoreCase(interviewWrapUpEDBCResult.getProgram()
			                                                .toString())
			                                && interviewWrapUpEDBCResult.getExpedited().isNotEmpty() && interviewWrapUpEDBCResult
			                                .getExpedited().toString().equalsIgnoreCase(EXPEDITED_CODE)))) {
				interviewWrapUpEDBCResult.setBenefitBegin(benefitDate);
				interviewWrapUpEDBCResult.getBenefitEnd().setNull();
			}
			/*
			 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Pending, expedited SNAP Active no change no change
			 */
			else if (auStatus != null
			                && auStatus.getStatus().isNotEmpty()
			                && (auStatus.getStatus().toString().equalsIgnoreCase(PENDING) && (mAECFHouseholdDelta
			                                .isExpeditedFS(ebcObj.getAuId()) && ebcObj.getProgramCode().toString()
			                                .equalsIgnoreCase(SNAP)))
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(ACTIVE)) {
				interviewWrapUpEDBCResult.setBenefitBegin(benefitBegin);
				interviewWrapUpEDBCResult.setBenefitEnd(benefitEnd);
			}
			/*
			 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Active BEN_EFF_DTE null
			 */
			else if (auStatus != null && auStatus.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(ACTIVE)) {
				interviewWrapUpEDBCResult.setBenefitBegin(benefitDate);
				interviewWrapUpEDBCResult.getBenefitEnd().setNull();
			}
			/*
			 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Closed no change BEN_EFF_DTE
			 */
			else if (auStatus != null && auStatus.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(CLOSED)) {
				interviewWrapUpEDBCResult.setBenefitBegin(benefitBegin);
				interviewWrapUpEDBCResult.setBenefitEnd(benefitDate.getLastDateOfTheMonth());
			}
			/*
			 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Denied no change no change
			 */
			else if (auStatus != null && auStatus.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().isNotEmpty()
			                && interviewWrapUpEDBCResult.getStatus().toString().equalsIgnoreCase(DENIED)) {
				interviewWrapUpEDBCResult.setBenefitBegin(benefitBegin);
				interviewWrapUpEDBCResult.setBenefitEnd(benefitEnd);
			}
			Vector ebcAUMemberVector = null;
			Hashtable benefitBeginDate = null;
			Hashtable benefitEndDate = null;
			if ( ebcResultBase != null && ebcResultBase.getId().isNotEmpty()) {
				ebcAUMemberVector = mAECFHouseholdDelta.getMAClient(mAECFHouseholdDelta.getPrimaryClientId())
				                .getEBCResultClientAUMembStat(ebcResultBase.getId());
				benefitBeginDate = new Hashtable();
				benefitEndDate = new Hashtable();
				if (ebcAUMemberVector != null && ebcAUMemberVector.size() > 0) {
					Enumeration ebcResultClientAUMembStatEnum = ebcAUMemberVector.elements();
					while (ebcResultClientAUMembStatEnum.hasMoreElements()) {
						EBCResultClientAUMembStat ebcResultClientAUMembStat = (EBCResultClientAUMembStat) ebcResultClientAUMembStatEnum
						                .nextElement();
						benefitBeginDate.put(ebcResultClientAUMembStat.getClientId().toString(),
						                ebcResultClientAUMembStat.getBenefitBegin());
						benefitEndDate.put(ebcResultClientAUMembStat.getClientId().toString(),
						                ebcResultClientAUMembStat.getBenefitEnd());
					}
				}
			}
			Vector clientAuMembVect = mAClientDelta.getAllMembersInAU(interviewWrapUpEDBCResult.getAuId());
			if (clientAuMembVect != null && clientAuMembVect.size() > 0) {
				Enumeration clientAuMembEnum = clientAuMembVect.elements();
				while (clientAuMembEnum.hasMoreElements()) {
					BaseAUMember clientAuMemb = (BaseAUMember) clientAuMembEnum.nextElement();
					// String prevStatus = clientAuMemb.getAuMemberStatusCode().toString();
					Vector auMemberVect = interviewWrapUpEDBCResult.getAuMembResults();
					if (auMemberVect != null && auMemberVect.size() > 0) {
						Enumeration auMemberEnum = auMemberVect.elements();
						while (auMemberEnum.hasMoreElements()) {
							edbcResultAUMember = (EDBCResultAUMember) auMemberEnum.nextElement();
							if (clientAuMemb.getClientId() != null
							                && edbcResultAUMember.getClientId() != null
							                && clientAuMemb.getClientId().toString().equalsIgnoreCase(
							                                edbcResultAUMember.getClientId().toString())) {
								benefitBegin = null;
								if (benefitBeginDate != null
								                && benefitBeginDate.get(clientAuMemb.getClientId().toString()) != null) {
									benefitBegin = (DateData) benefitBeginDate.get(clientAuMemb.getClientId()
									                .toString());
								}
								benefitEnd = null;
								if (benefitEndDate != null
								                && benefitEndDate.get(clientAuMemb.getClientId().toString()) != null) {
									benefitEnd = (DateData) benefitEndDate.get(clientAuMemb.getClientId().toString());
								}
								if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString().equalsIgnoreCase(
								                                clientAuMemb.getAuMemberStatusCode().toString())) {
									// no change in member status
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Pending, expedited SNAP BEN_EFF_DTE
								 * null
								 */
								else if ((clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty() && edbcResultAUMember
								                .getMemStatus().toString().equalsIgnoreCase(PENDING))
								                || (interviewWrapUpEDBCResult.getProgram().isNotEmpty()
								                                && SNAP
								                                                .equalsIgnoreCase(interviewWrapUpEDBCResult
								                                                                .getProgram()
								                                                                .toString()) && (interviewWrapUpEDBCResult
								                                .getExpedited().isNotEmpty() && interviewWrapUpEDBCResult
								                                .getExpedited().toString().equalsIgnoreCase(
								                                                EXPEDITED_CODE)))) {
									edbcResultAUMember.setMemBenefitBegin(benefitDate);
									edbcResultAUMember.getMemBenefitEnd().setNull();
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Pending, expedited SNAP Active no
								 * change no change
								 */
								else if ((clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && clientAuMemb.getAuMemberStatusCode().toString().equalsIgnoreCase(
								                                PENDING)
								                && mAECFHouseholdDelta.isExpeditedFS(ebcObj.getAuId()) && ebcObj
								                .getProgramCode().toString().equalsIgnoreCase(SNAP))
								                && (edbcResultAUMember.getMemStatus().isNotEmpty() && edbcResultAUMember
								                                .getMemStatus().toString().equalsIgnoreCase(ACTIVE))) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Active BEN_EFF_DTE null
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString()
								                                .equalsIgnoreCase(ACTIVE)) {
									edbcResultAUMember.setMemBenefitBegin(benefitDate);
									edbcResultAUMember.getMemBenefitEnd().setNull();
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Ineligible Closed no change no change
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && (clientAuMemb.getAuMemberStatusCode().toString()
								                                .equalsIgnoreCase(INELIGIBLE))
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString()
								                                .equalsIgnoreCase(CLOSED)) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Closed no change BEN_EFF_DTE
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString()
								                                .equalsIgnoreCase(CLOSED)) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Denied no change no change
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString()
								                                .equalsIgnoreCase(DENIED)) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE Active Ineligible no change
								 * BEN_EFF_DTE
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && (clientAuMemb.getAuMemberStatusCode().toString()
								                                .equalsIgnoreCase(ACTIVE))
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString().equalsIgnoreCase(
								                                INELIGIBLE)) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}
								/*
								 * Old Status New Status BEN_BEGIN_DTE BEN_END_DTE any Ineligible no change no change
								 */
								else if (clientAuMemb.getAuMemberStatusCode().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().isNotEmpty()
								                && edbcResultAUMember.getMemStatus().toString().equalsIgnoreCase(
								                                INELIGIBLE)) {
									setMemberBenefitBegin(edbcResultAUMember, benefitBegin);
									setMemberBenefitEnd(edbcResultAUMember, benefitEnd);
								}

							}
						}
					}
				}
			}

		}
	}

	/**
	 * This method is used to Check the benefitBegin date isNull and set that in the memberBegin field.
	 * 
	 * @param edbcResultAUMember
	 *            EDBCResultAUMember object
	 * @param benefitBegin
	 *            benefit begin date
	 * @throws Exception
	 */
	public static void setMemberBenefitBegin(EDBCResultAUMember edbcResultAUMember, DateData benefitBegin)
	                throws Exception {
		if (benefitBegin != null) {
			edbcResultAUMember.setMemBenefitBegin(benefitBegin);
		}
		else {
			edbcResultAUMember.getMemBenefitBegin().setNull();
		}
	}

	/**
	 * This method is used to Check the benefitEnd date isNull and set that in the memberEnd field.
	 * 
	 * @param edbcResultAUMember
	 *            EDBCResultAUMember object
	 * @param benefitEnd
	 *            a DateData object
	 * @throws Exception
	 */
	public static void setMemberBenefitEnd(EDBCResultAUMember edbcResultAUMember, DateData benefitEnd) throws Exception {
		if (benefitEnd != null) {
			edbcResultAUMember.setMemBenefitEnd(benefitEnd);
		}
		else {
			edbcResultAUMember.getMemBenefitEnd().setNull();
		}
	}

