	/**
	 * This method checks whether the Monthly Reporter Verification is selected or not based upon the verification id.
	 *
	 * @param maECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param verDataElementId
	 *            VER_DATA_ELEMENT/ID
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean isMonthlyReporterVerificationSelected(MAECFHousehold maECFDelta, int verDataElementId)
	                throws Exception {
		RequestId requestId = maECFDelta.getRequestId();
		Vector eligReqVerDataVec = maECFDelta.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		if(eligReqVerDataVec != null && eligReqVerDataVec.size() > 0){
			Enumeration eligReqVerDataEnum = eligReqVerDataVec.elements();
			while (eligReqVerDataEnum.hasMoreElements()) {
				EligibilityRequestVerData eligReqVerData = (EligibilityRequestVerData) eligReqVerDataEnum
				                .nextElement();
				if (eligReqVerData.getPersistenceState().intValue() == 3) {
					continue;
				}
				ViewVerification viewVer = (ViewVerification) maECFDelta.getFields().getSeqField(
				                ViewVerification.class, eligReqVerData.getVerId());
				if (viewVer != null && viewVer.getVerificationElementId() == verDataElementId) {
					return true;
				}
			}
		}
		return false;
	}

	/**
	 * @param maECFDelta
	 * @return
	 * @throws Exception
	 */
	public static Vector<ViewVerification> getSelectedMonthlyReporterVer(MAECFHousehold maECFDelta)
	    throws Exception {
		RequestId requestId = maECFDelta.getRequestId();
		Vector<ViewVerification> vMonthlyVer = new Vector<ViewVerification>();
		Vector eligReqVerDataVec = maECFDelta.getFields().getFields(EligibilityRequestVerData.class, requestId.getReqId());
		if (eligReqVerDataVec != null && eligReqVerDataVec.size() > 0) {
			Enumeration eligReqVerDataEnum = eligReqVerDataVec.elements();
			while (eligReqVerDataEnum.hasMoreElements()) {
				EligibilityRequestVerData eligReqVerData = (EligibilityRequestVerData) eligReqVerDataEnum.nextElement();
				if (eligReqVerData.getPersistenceState().intValue() == 3) {
					continue;
				}
				ViewVerification viewVer = (ViewVerification) maECFDelta.getFields().getSeqField(ViewVerification.class,
				    eligReqVerData.getVerId());
				if (viewVer != null && viewVer.getVerificationElementId() == 74) {
					vMonthlyVer.add(viewVer);
				}
			}
		}
		return vMonthlyVer;
	}
	/**
	 * Method to check whether the result contains newly denied or closed member with adverse action
	 * @param maECFDelta
	 * @param maClient
	 * @param rslt
	 * @return
	 * @throws Exception
	 */
	public static boolean doesTheRsltContainNewlyDeniedORClosedMembWithAdverseAction(MAECFHousehold maECFDelta,
	                                                                                 MAClient maClient,
	                                                                                 InterviewWrapUpEDBCResult rslt)throws Exception {
		boolean retFlg = false;
		EligFactorRsnDtl eligFactorRsnDtl = null;
		Vector<EDBCResultAUMember> rsltMembVec = rslt.getAuMembResults();
		if (rsltMembVec != null && rsltMembVec.size() > 0) {
			for (EDBCResultAUMember rsltMemb : rsltMembVec) {
				if ((rsltMemb.getMemStatus().equals(DENIED)
								|| rsltMemb.getMemStatus().equals(CLOSED))
								|| (rslt.getEbcEFRCFlg().booleanValue()
												|| isVerSelected(maECFDelta,rslt.getAuId(),rsltMemb.getClientId(), 78, false,true))) {
					eligFactorRsnDtl = getEligFactorRsnDtl(maClient.getFields().getContext(),rsltMemb.getMemIneligReason());
					if (eligFactorRsnDtl != null
									&& eligFactorRsnDtl.getStatusPendingInd().isNotEmpty()
									&& eligFactorRsnDtl.getStatusPendingInd().isTrue()) {
						retFlg = true;
						break;
					}
				}
			}
		}
		if(!retFlg){
			ViewVerification viewVer = null;
			VerificationElement verElement = null;
			IntegerData verElementId = null;
			Vector<EligibilityRequestVerData> eligReqVerVec = maECFDelta.getFields().getFields(
			                EligibilityRequestVerData.class, maECFDelta.getRequestId().getReqId());
			if(eligReqVerVec != null && eligReqVerVec.size() > 0){
				for (EligibilityRequestVerData eligReqVer : eligReqVerVec) {
					if (eligReqVer.getPersistenceState().intValue() == 3) {
						continue;
					}
					viewVer = (ViewVerification) maECFDelta.getFields().getSeqField(ViewVerification.class,eligReqVer.getVerId());
					if (viewVer != null) {
						verElementId = new IntegerData(viewVer.getVerificationElementId());
						verElement = (VerificationElement) maECFDelta.getFields().getSeqField(
						                VerificationElement.class, verElementId);
						if ((viewVer.getVerificationElementId() != 77
										&& viewVer.getVerificationElementId() != 78
						                && viewVer.getVerificationElementId() != 89
						                && viewVer.getVerificationElementId() != 90
						                && viewVer.getVerificationElementId() != 145
						                && viewVer.getVerificationElementId() != 146)
						                && verElement.isEligibilityInfluencing()) {
							retFlg = true;
							break;
						}
					}
				}
			}
		}
		return retFlg;
	}
	/**
	 * This method checks whether the result is Immediate Release or not.
	 *
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @param maECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param mAClient
	 *            Instance of {@link MAClient}
	 * @param auId
	 *            program auid
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean isResultImmediateRelease(InterviewWrapUpEDBCResult rslt,
	                                                 MAECFHousehold maECFDelta, MAClient maClient,
	                                                 IntegerData auId) throws Exception {
		boolean statusFlag = false;
		boolean memberstatusFlag = false;
		boolean memberstatusineligFlag = false;
		IntegerData verificationElementId = null;
		
		if (maClient != null) {
			if (rslt.getAuEFRC().isNotEmpty() && rslt.getAuEFRC().equals("003030")) {
				if (isVerificationSelectedForForcedPendRelease(maECFDelta, maClient)) {
					return false;
				}
			}
		}
		
		if (maClient != null
						&& rslt.getWaivePendPeriod().isNotEmpty()
		                && rslt.getWaivePendPeriod().booleanValue()) {
			return true;
		}
		// Result AU status is Closed or Denied, and the ineligible Reason (EFRC) for the AU does not have an
		// adverse action pending period indicator (ELIG_FACTOR_RSN_DTL.STAT_PEND_IND = N).
		if (maClient != null
		                && (rslt.getStatus().equals(DENIED)
		                				|| rslt.getStatus().equals(CLOSED))) {
			if (rslt.getAuEFRC().isNotEmpty()) {
				EligFactorRsnDtl eligFactorRsnDtl = getEligFactorRsnDtl(maClient.getFields().getContext(),rslt.getAuEFRC());
				if (eligFactorRsnDtl != null && !(eligFactorRsnDtl.getStatusPendingInd().booleanValue())) {
					return true;
				}
			}
		}
		// Result AU status is Pending or Active, the result does not contain a newly denied or closed member
		// with an EFRC that has an adverse action pending period indicator (ELIG_FACTOR_RSN_DTL.STAT_PEND_IND = Y),
		// and the Request does not contain any verifications which are eligibility influencing (VER_DATA_ELEMENT.ELIG_INFLUENCING_FLG = Y).
		if ((rslt.getStatus().equals(PENDING)
		                				|| rslt.getStatus().equals(ACTIVE))
		                				&& !doesTheRsltContainNewlyDeniedORClosedMembWithAdverseAction(maECFDelta, maClient, rslt)) {
			return true;
		}
		return false;
	}

	/**
	 * After the Benefit Effective date and Release date has been determined for all AUs
	 * in the Request, the Prime AU must be determined and adjustments must be made to the dates of the other, non-prime
	 * AUs.
	 *
	 * @param mAECFHouseholdDelta
	 *            is an instance of MAECFHousehold.
	 * @param interviewWrapUpEDBCResultVect
	 *            is an Vector.
	 * @throws Exception
	 */
	public static InterviewWrapUpEDBCResult adjustNonPrimeAU(MAECFHousehold mAECFHouseholdDelta, Vector<InterviewWrapUpEDBCResult> rsltVec)
	                throws Exception {
		MAClient mAClientDelta = null;
		DateData primeRelDte = null;
		DateData nonPrimeRelDte = null;
		InterviewWrapUpEDBCResult primeAU = getPrimeAu(mAECFHouseholdDelta, rsltVec);
		mAClientDelta = mAECFHouseholdDelta.getMAClient(mAECFHouseholdDelta.getPrimaryClientId());
		if (primeAU != null) {
			EDBCResultFinancial eDBCResultFinancial = primeAU.getFinancialObject(EBCDATA, RELEASEDATE);
			if(eDBCResultFinancial != null) {
				primeRelDte = DateData.getInstance(eDBCResultFinancial.getValue().toString());
			}
			for (InterviewWrapUpEDBCResult rstlObj : rsltVec) {
				EDBCResultFinancial tmpEDBCResultFinancial = rstlObj.getFinancialObject(EBCDATA, RELEASEDATE);
				if(tmpEDBCResultFinancial != null) {
					nonPrimeRelDte = DateData.getInstance(tmpEDBCResultFinancial.getValue().toString());
				}
				if (rstlObj.getAuId().intValue() != primeAU.getAuId().intValue()
				                && !rstlObj.getNotAdjustRelDteFlag().booleanValue()
				                && primeRelDte != null && !primeRelDte.equals(nonPrimeRelDte)) {
					setFinancialValue(rstlObj, EBCDATA, RELEASEDATE, primeRelDte.toLocaleString());
					
					DateData benEffDte = new DateData(primeRelDte);
					benEffDte.addMonths(1);
					benEffDte.setDate(1);
					
					if (rstlObj.getStatus().equals(CLOSED) || rstlObj.getStatus().equals(DENIED)) {
						setFinancialValue(rstlObj, BENEFIT, EBCBENEFITEFFECTIVEDATE, primeRelDte.toLocaleString());
						rstlObj.setBenefitEffective(primeRelDte);
					}else {
						setFinancialValue(rstlObj, BENEFIT, EBCBENEFITEFFECTIVEDATE, benEffDte.toLocaleString());
						rstlObj.setBenefitEffective(benEffDte);
					}
				}
			}
		}
		return primeAU;
	}

	/**
	 * To get the interviewWrapUpEDBCResult object with max release date.
	 *
	 * @param interviewWrapUpEDBCResultVect
	 *            Instance of {@link Vector}
	 * @param ebcObjectVector
	 *            Instance of {@link Vector}
	 * @throws Exception
	 */
	public static Vector sortReleaseDates(Vector interviewWrapUpEDBCResultVect) throws Exception {
		Vector sortedAUsVect = new Vector();
		Object[] obArr = new Object[interviewWrapUpEDBCResultVect.size()];
		for (int i = 0; i < interviewWrapUpEDBCResultVect.size(); i++) {
			obArr[i] = interviewWrapUpEDBCResultVect.elementAt(i);
		}
		for (int i = 0; i < obArr.length; i++) {
			for (int j = i + 1; j < obArr.length; j++) {
				InterviewWrapUpEDBCResult IWER1 = (InterviewWrapUpEDBCResult) obArr[i];
				InterviewWrapUpEDBCResult IWER2 = (InterviewWrapUpEDBCResult) obArr[j];
				if (IWER2.getTempReleaseDate().isNotEmpty() && IWER1.getTempReleaseDate().isNotEmpty()
				                && (IWER2.getTempReleaseDate().after(IWER1.getTempReleaseDate()))) {
					InterviewWrapUpEDBCResult IWER3 = new InterviewWrapUpEDBCResult();
					IWER3 = IWER2;
					obArr[j] = obArr[i];
					obArr[i] = IWER3;
				}
			}
		}
		for (int i = 0; i < interviewWrapUpEDBCResultVect.size(); i++) {
			sortedAUsVect.add(obArr[i]);
		}
		return sortedAUsVect;
	}
	public static boolean doesRequestContainDecOrIncInCashBenefits(MAECFHousehold maECF, Vector<InterviewWrapUpEDBCResult> cashRsltVec)throws Exception{
		if(cashRsltVec != null && cashRsltVec.size() > 0){
			for(InterviewWrapUpEDBCResult cashRslt: cashRsltVec){
				if (isBenefitIncreased(cashRslt)
								|| isBenefitDecreased(maECF,cashRslt)) {
					return true;
				}
			}
		}
		return false;
	}
	/**
	 * To get the prime au.
	 *
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param ebcObjectVector
	 *            Instance of {@link Vector}
	 * @throws Exception
	 */
	public static InterviewWrapUpEDBCResult getPrimeAu(MAECFHousehold mAECFHouseholdDelta,
	                                                   Vector interviewWrapUpEDBCResultVect) throws Exception {
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResultCash = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResultFS = null;
		InterviewWrapUpEDBCResult primeAUResult = null;
		InterviewWrapUpEDBCResult intWrapUpEDBCResultCash = null;
		DateData fsRelDte = null;
		DateData cashRelDte = null;
		MAClient mAClientDelta = null;
		Vector finalCashAUVect = new Vector();
		Vector finalFSAUVect = new Vector();
		Vector nonSortedCashVect = new Vector();
		Vector nonSortedFSVect = new Vector();
		Enumeration interviewWrapUpEDBCResultEnum = null;
		if (interviewWrapUpEDBCResultVect != null && interviewWrapUpEDBCResultVect.size() > 0) {
			interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
			while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
				if (interviewWrapUpEDBCResult != null
				                && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
				                && (TANF.equals(interviewWrapUpEDBCResult.getProgram().toString())
				                                || EAEDC.equals(interviewWrapUpEDBCResult.getProgram().toString()) || EA
				                                .equals(interviewWrapUpEDBCResult.getProgram().toString()))) {
					nonSortedCashVect.add(interviewWrapUpEDBCResult);
				}
				else if (interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getProgram().isNotEmpty()
				                && SNAP.equals(interviewWrapUpEDBCResult.getProgram().toString())) {
					nonSortedFSVect.add(interviewWrapUpEDBCResult);
				}
			}
		}
		if (nonSortedCashVect.size() > 0) {
			finalCashAUVect = sortReleaseDates(nonSortedCashVect);
			if (finalCashAUVect != null && finalCashAUVect.size() > 0) {
				intWrapUpEDBCResultCash = (InterviewWrapUpEDBCResult) finalCashAUVect.elementAt(0);
			}
		}
		if (nonSortedFSVect.size() > 0) {
			finalFSAUVect = sortReleaseDates(nonSortedFSVect);
		}
		if (mAECFHouseholdDelta != null) {
			mAClientDelta = mAECFHouseholdDelta.getMAClient(mAECFHouseholdDelta.getPrimaryClientId());
			if (finalFSAUVect != null && finalFSAUVect.size() > 0) {
				interviewWrapUpEDBCResultFS = (InterviewWrapUpEDBCResult) finalFSAUVect.elementAt(0);
				String delayedByReeval = getFinancialObjectStringValue(interviewWrapUpEDBCResult, EBCDATA, RELEASEDELAYEDBYREEVAL);
				EDBCResultFinancial eDBCResultFinancial = interviewWrapUpEDBCResultFS.getFinancialObject(EBCDATA, RELEASEDATE);
				if(eDBCResultFinancial != null) {
					fsRelDte = DateData.getInstance(eDBCResultFinancial.getValue().toString());
				}
				if (intWrapUpEDBCResultCash != null) {
					EDBCResultFinancial tmpEDBCResultFinancial = intWrapUpEDBCResultCash.getFinancialObject(EBCDATA, RELEASEDATE);
					if(tmpEDBCResultFinancial != null) {
						cashRelDte = DateData.getInstance(tmpEDBCResultFinancial.getValue().toString());
					}
				}
				if (delayedByReeval != null && delayedByReeval != "" && delayedByReeval.equalsIgnoreCase("Y")
						&& fsRelDte != null && cashRelDte !=null && fsRelDte.after(cashRelDte) ) {
					primeAUResult = interviewWrapUpEDBCResultFS;
				} else if (isBenefitDecreased(mAECFHouseholdDelta, interviewWrapUpEDBCResultFS)) {
					if (finalCashAUVect.size() < 1) {
						primeAUResult = interviewWrapUpEDBCResultFS;
					}
					else {
						interviewWrapUpEDBCResultCash = (InterviewWrapUpEDBCResult) finalCashAUVect.elementAt(0);
						if(!doesRequestContainDecOrIncInCashBenefits(mAECFHouseholdDelta, finalCashAUVect)){
							primeAUResult = interviewWrapUpEDBCResultFS;
						}else{
							primeAUResult = interviewWrapUpEDBCResultCash;
						}
					}
				}
				else if (finalCashAUVect != null && finalCashAUVect.size() > 0) {
					interviewWrapUpEDBCResultCash = (InterviewWrapUpEDBCResult) finalCashAUVect.elementAt(0);
					primeAUResult = interviewWrapUpEDBCResultCash;
				}
				else {
					primeAUResult = interviewWrapUpEDBCResultFS;
				}
			}
			else if (finalCashAUVect != null && finalCashAUVect.size() > 0) {
				interviewWrapUpEDBCResultCash = (InterviewWrapUpEDBCResult) finalCashAUVect.elementAt(0);
				primeAUResult = interviewWrapUpEDBCResultCash;
			}
		}
		if (primeAUResult != null) {
			primeAUResult.setPrimeAu(true);
		}
		return primeAUResult;
	}

	/**
	 * To check is benefit decreased.
	 *
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @param mAECFHouseholdBase
	 *            Instance of {@link MAECFHousehold}
	 * @param asstUnit
	 *            Instance of {@link BaseAU}
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean isBenefitDecreased(MAECFHousehold maECf, InterviewWrapUpEDBCResult rslt)
	                throws Exception {
		EBCResultBase baseRslt = null;
		if(maECf != null){
			baseRslt = maECf.getEBCResultBase(rslt.getAuId());
			if(baseRslt != null
							&& ((baseRslt.getAuStatus().equals(PENDING) && baseRslt.getExpeditedCode().equals(AlphaE))
											|| (baseRslt.getAuStatus().equals(ACTIVE) && baseRslt.getExpeditedCode().equals(AlphaS)))){
				return false;
			}
		}
		if (rslt != null) {
			double prevBenAmt = getFinancialObjectDoubleValue(rslt, BENEFIT,PREVIOUSBENEFITAMOUNT);
			if (rslt.getBenefitAmount().isNotEmpty()
							&& (rslt.getBenefitAmount().doubleValue() < prevBenAmt)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * To check is benefit increased.
	 *
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @param mAECFHouseholdBase
	 *            Instance of {@link MAECFHousehold}
	 * @param asstUnit
	 *            Instance of {@link BaseAU}
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean isBenefitIncreased(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult)
	                throws Exception {
		boolean isBenefitIncreased = false;
		if (interviewWrapUpEDBCResult != null) {
			double prevBenefitAmount = getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
			                PREVIOUSBENEFITAMOUNT);
			double clothingAllowance = getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
			                CLOTHINGALLOWANCE);
			if ((interviewWrapUpEDBCResult.getBenefitAmount().isNotEmpty() && prevBenefitAmount < interviewWrapUpEDBCResult
			                .getBenefitAmount().doubleValue())
			                || clothingAllowance > 0) {
				isBenefitIncreased = true;
			}
		}

		return isBenefitIncreased;
	}

	/**
	 * After EBC is performed we must determine if an AU should be closed or denied. There are different rules depending
	 * on the AU program.
	 *
	 * @param mAClient
	 *            Instance of {@link MAClient}
	 * @param interviewWrapUpEDBCResult
	 *            Instance of {@link InterviewWrapUpEDBCResult}
	 * @return boolean value of this method
	 * @throws Exception
	 */
	public static boolean resultHasClosureConditions(MAECFHousehold maECFHouseholdDelta, MAClient mAClient,
	                                                 InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                                 EDBCResult edbcResult) throws Exception {
		boolean returnCondition = false;
		if (interviewWrapUpEDBCResult != null) {
			if (interviewWrapUpEDBCResult.getProgram().equals(TANF)
			                || interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(EAEDC)) {
				String tafdcOrEaedcStr = isCashResultHasClosureConditions(interviewWrapUpEDBCResult,mAClient);
				if (tafdcOrEaedcStr.equals(CLOSURE)) {
					returnCondition = true;
				}
			}
			if (interviewWrapUpEDBCResult.getProgram().equals(EA)) {
				String eaStr = isEAResultHasClosureConditions(interviewWrapUpEDBCResult);
				if (eaStr.equals(CLOSURE)) {
					returnCondition = true;
				}
			}
			if (interviewWrapUpEDBCResult.getProgram().equals(SNAP)) {
				String fsStr = isFSResultHasClosureConditions(maECFHouseholdDelta, mAClient, interviewWrapUpEDBCResult,
				                edbcResult);
				if (fsStr.equals(CLOSURE)) {
					returnCondition = true;
				}
			}
		}
		return returnCondition;
	}

	/**
	 * This method is used to determine the closure conditions for EA if an AU should be closed or denied. There are
	 * different rules depending on the AU program.
	 *
	 * @param interviewWrapUpEDBCResult
	 *            Instance of InterviewWrapUpEDBCResult
	 * @return String value
	 */
	public static String isEAResultHasClosureConditions(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult) {
		String returnCondition = null;
		EDBCResultFinancial eDBCResultFinancial = null;
		if (interviewWrapUpEDBCResult != null) {
			/* Closure condition when AUSize < 1 */
			eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, AUSIZE);
			if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
			                && (Integer.parseInt(eDBCResultFinancial.getValue().toString()) < 1)) {
				returnCondition = CLOSURE;
			}
			else {
				/* Open when FinancialEligibilityStatus = Eligible */
				eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
				                FINANCIALELIGIBILITYSTATUS);
				if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
				                && eDBCResultFinancial.getValue().toString().equalsIgnoreCase(ELIG)) {
					returnCondition = OPEN;
				}
			}
			if (returnCondition == null) {
				returnCondition = CLOSURE;
			}
		}
		return returnCondition;
	}

	/**
	 * This method is used to determine the closure conditions for CashResult(TANF/EAEDC) Objects if an AU should be
	 * closed or denied. There are different rules depending on the AU program.
	 *
	 * @param interviewWrapUpEDBCResult
	 *            Instance of InterviewWrapUpEDBCResult
	 * @return String value
	 */
	public static String isCashResultHasClosureConditions(InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,MAClient mAClient) {
		String returnCondition = null;
		EDBCResultFinancial eDBCResultFinancial = null;
		ParameterCache paramcache = null;
		Parameter parameter = null;
		paramcache = ParameterCache.getInstance();
		parameter = paramcache.getParameter(mAClient.getFields().getContext(), TANF_MIN_BENEFIT_AMT);
		double cashMinimumamount = Double.parseDouble(parameter.getParameterValue());
		if (interviewWrapUpEDBCResult != null) {
			/* Closure condition when AUSize < 1 */
			eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, AUSIZE);
			if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
			                && (Integer.parseInt(eDBCResultFinancial.getValue().toString()) < 1)) {
				returnCondition = CLOSURE;
			}
			/* Open when BEN_AMT > 0 */
			else if (interviewWrapUpEDBCResult.getBenefitAmount().isNotEmpty()
			                && interviewWrapUpEDBCResult.getBenefitAmount().doubleValue() < cashMinimumamount) {
				returnCondition = CLOSURE;
			}
			else if (interviewWrapUpEDBCResult.getBenefitAmount().isNotEmpty()
	                && interviewWrapUpEDBCResult.getBenefitAmount().doubleValue() >= cashMinimumamount) {
				returnCondition = OPEN;
			}
			else {
				/* Open when FinancialEligibilityStatus = Eligible */
				eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS,
				                FINANCIALELIGIBILITYSTATUS);
				if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
				                && eDBCResultFinancial.getValue().toString().equalsIgnoreCase(ELIG)) {
					returnCondition = OPEN;
				}
				else {
					/* Open when ClothingAllowance > 0 */
					eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(BENEFIT, CLOTHINGALLOWANCE);
					if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
					                && (Double.parseDouble(eDBCResultFinancial.getValue().toString()) > 0)) {
						returnCondition = OPEN;
					}
					else
						returnCondition = CLOSURE;
				}
			}
		}
		return returnCondition;
	}

	/**
	 * This method is used to determine the closure conditions for SNAP if an AU should be closed or denied. There are
	 * different rules depending on the AU program.
	 *
	 * @param mAClient
	 *            Instance of MAClient
	 * @param interviewWrapUpEDBCResult
	 *            Instance of InterviewWrapUpEDBCResult
	 * @return String value
	 * @throws Exception
	 */
	public static String isFSResultHasClosureConditions(MAECFHousehold maECFHouseholdDelta, MAClient mAClient,
	                                                    InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                                    EDBCResult edbcResult) throws Exception {
		String returnCondition = null;
		EDBCResultFinancial eDBCResultFinancial = null;
		BaseAU asstUnit = null;
		StringData cAPEligibilityStatus = null;
		if (mAClient != null && interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getAuId().isNotEmpty()) {
			asstUnit = mAClient.getAsstUnit(interviewWrapUpEDBCResult.getAuId());
			/* Closure condition when AUSize < 1 */
			eDBCResultFinancial = interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, AUSIZE);
			cAPEligibilityStatus = interviewWrapUpEDBCResult.getCapEligibilityStatus();
			if (eDBCResultFinancial != null && eDBCResultFinancial.getValue().isNotEmpty()
			                && (Integer.parseInt(eDBCResultFinancial.getValue().toString()) < 1)) {
				returnCondition = CLOSURE;
			}
			/* Open when keep AU open flag is true (set in the SNAP rules) */
			else if (interviewWrapUpEDBCResult.getKeepAUOpen().isTrue()) {
				returnCondition = OPEN;
			}
			/* Open when BEN_AMT > 0 */
			else if (interviewWrapUpEDBCResult.getBenefitAmount().isNotEmpty()
			                && interviewWrapUpEDBCResult.getBenefitAmount().doubleValue() > 0) {
				returnCondition = OPEN;
			}
			/*
			 *  Closure condition when result.CAPEligibilityStatus is not null, and the AU status is Pending or
			 * commonVals.EBCActiveCAP (i.e. new or existing CAP AU with a zero benefit amount)
			 */
			else if ((cAPEligibilityStatus.isNotEmpty())
			                && (asstUnit.getStatusCode().equals(PENDING) || edbcResult.isEBCActiveCAP(
			                                maECFHouseholdDelta, mAClient))) {
				returnCondition = CLOSURE;
			}
			/* Open when result has CatEligFlag = Y and the CatEligReason != TANF */
			else if (interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGFLAG) != null
			                && interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGFLAG).getValue()
			                                .toString().equals(YES)
			                && !interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGREASON).getValue()
			                                .toString().equalsIgnoreCase(TANF)) {
				returnCondition = OPEN;
			}
			/*
			 * Open when result has CatEligFlag = Y, the CatEligReason = TANF and the gross income is above the limit
			 * (GrossIncomeLimit = 0 or (EarnedIncome + UnearnedIncome + GrantAmount + DefraPayment) > GrossIncomeLimit)
			 */
			else if (interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGFLAG) != null
			                && interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGFLAG).getValue()
			                                .toString().equals(YES)
			                && interviewWrapUpEDBCResult.getFinancialObject(STANDARDAMOUNTS, CATELIGREASON).getValue()
			                                .toString().equalsIgnoreCase(TANF)
			                && ((getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT) == ZERO_DOUBLE_VALUE) || (getFinancialObjectDoubleValue(
			                                interviewWrapUpEDBCResult, GROSSINCOME, EARNEDINCOME)
			                                + getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, GROSSINCOME,
			                                                UNEARNEDINCOME)
			                                + getFinancialObjectDoubleValue(interviewWrapUpEDBCResult, BENEFIT,
			                                                GRANTAMOUNT) + getFinancialObjectDoubleValue(
			                                interviewWrapUpEDBCResult, GROSSINCOME, DEFRAPAYMENT)) <= (getFinancialObjectDoubleValue(
			                                interviewWrapUpEDBCResult, GROSSINCOME, GROSSINCOMELIMIT)))) {
				returnCondition = OPEN;
			}
			else {
				returnCondition = CLOSURE;
			}
		}
		return returnCondition;
	}

	/**
	 * This method is used for Processing that takes place after the EBC rules are run and after split pending
	 * processing is complete.
	 *
	 * @param mAECFHouseholdDelta
	 *            Instance of {@link MAECFHousehold}
	 * @param mAClientDelta
	 *            Instance of {@link MAClient}
	 * @throws Exception
	 */
	public static void postRuleProcessingPartII(MAECFHousehold mAECFHouseholdDelta, MAClient mAClientDelta)
	                throws Exception {
		Vector interviewWrapUpEDBCResultVect = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		BaseEBCResultRequest ebcResult = null;
		Vector ebcRsltVec = null;
		Enumeration ebcRsltEnum;
		Context effCtx = null;
		String monRep = "";
		if (mAECFHouseholdDelta != null) {
			effCtx = mAECFHouseholdDelta.getFields().getContext();
			interviewWrapUpEDBCResultVect = mAECFHouseholdDelta.getInterviewWrapUpEDBCResults();
			if (interviewWrapUpEDBCResultVect != null && interviewWrapUpEDBCResultVect.size() > 0) {
				Enumeration interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
				while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
					interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
					if (interviewWrapUpEDBCResult != null && interviewWrapUpEDBCResult.getAuId().isNotEmpty()) {
						ebcRsltVec = mAECFHouseholdDelta.getEBCResultRequest(interviewWrapUpEDBCResult.getRequestId());
						if (ebcRsltVec != null && ebcRsltVec.size() > 0) {
							ebcRsltEnum = ebcRsltVec.elements();
							while (ebcRsltEnum.hasMoreElements()) {
								ebcResult = (BaseEBCResultRequest) ebcRsltEnum.nextElement();
								if (ebcResult.getAuId().intValue() == interviewWrapUpEDBCResult.getAuId().intValue()) {
									if (ebcResult != null
									                && ((interviewWrapUpEDBCResult.getExpedited().isEmpty() && ebcResult
									                                .getExpeditedCode().isEmpty()) || (interviewWrapUpEDBCResult
									                                .getExpedited().toString().equalsIgnoreCase(ebcResult
									                                .getExpeditedCode().toString())))
									                // condition modified for the defect DTA00009382 -
									                // as per b2:Don't copy dates from previous results if the
									                // new result is TBA or USAIR since they have specific reeval periods.
									                // need to check with Dan regarding document update.
									                // && (NO.equals(getFinancialObjectStringValue(interviewWrapUpEDBCResult,
									                // BENEFIT, TBAFLAG)))
									                && !(interviewWrapUpEDBCResult.getProgram().equals(SNAP) && YES
									                                .equals(EBCServices
									                                                .getFinancialObjectStringValue(
									                                                                interviewWrapUpEDBCResult,
									                                                                BENEFIT, TBAFLAG)))
									                && !(interviewWrapUpEDBCResult.getRevalType().toString()
									                                .equalsIgnoreCase(ANNUAL_REPORTING))
									                && !(interviewWrapUpEDBCResult.getRevalType().isNotEmpty() && simpReevalTypesVec.contains(interviewWrapUpEDBCResult.getRevalType()))
									                && !(interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(EA) && (interviewWrapUpEDBCResult
									                                .getPgmStructParId().intValue() != ebcResult
									                                .getCoverageGroupId().intValue()))
									                && !(interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(EA)
									                                && interviewWrapUpEDBCResult.getPgmStructParId().intValue() == 24 && ebcResult
									                                .getCreateTimestamp().getUtilDate().before(
									                                                effCtx.getEffectiveDate().getUtilDate()))) {
										// Copy reevaluation data from previous result
										if (!interviewWrapUpEDBCResult.getReevalTypeFlg().isTrue()){
											if (ebcResult.getRevalStart().isNotEmpty()) {
												interviewWrapUpEDBCResult.setRevalStart(ebcResult.getRevalStart());
											}
											if (ebcResult.getRevalEnd().isNotEmpty()) {
												interviewWrapUpEDBCResult.setRevalEnd(ebcResult.getRevalEnd());
											}
											interviewWrapUpEDBCResult.setRevalType(ebcResult.getRevalTypeCode());
										}
										monRep = EBCServices.getValue(ebcResult.getResultXML(), STANDARDAMOUNTS,
										                MONTHLYREPORTERREQUIRED);
										if (monRep != "") {
											interviewWrapUpEDBCResult.setMonReporter(monRep);
										}
										// Display message explaining data change. This message is also
										// documented in Interview Wrapup Results-Updates Tab-FNC-
										// B-1402.03.doc
										if (interviewWrapUpEDBCResult.getBenefitEffective().isNotEmpty()
										                && !(interviewWrapUpEDBCResult.getBenefitEffective().compareTo(
										                                ebcResult.getBenefitEffective()) == 0)) {
											interviewWrapUpEDBCResult.setBenefitDateChangeFlag(true);
											interviewWrapUpEDBCResult.setOldBenefitEffDate(ebcResult.getBenefitEffective());
											// As a result of the benefit recalculation the benefit effective date on the
											// {result AU program name} AU has been changed from {previousResult.BEN_EFF_DTE }
											// to {result.BEN_EFF_DTE}.
										}
									}
									break;
								}
							}
						}
					}
				}
			}
		}
	}

