	/**
	 * Creates a xml document using the vector of EDBCResultFinancial objects and then returns the xml document as
	 * string.
	 *
	 * @param edbcRsltFinancialVect
	 *            vector of EDBCResultFinancial objects
	 * @return xml document as string
	 * @throws Exception
	 *             Any exception ocurring during the process.
	 */
	public static String createFinancialXMLAsDisplayStringValue(Vector edbcRsltFinancialVect,
	                                                            Vector benefitChangeReasonVector) throws Exception {
		String xmlString = "";
		if (amountFields == null || amountFields.isEmpty()) {
			amountFields = getAmountFields();
		}
		if (edbcRsltFinancialVect != null && edbcRsltFinancialVect.size() > 0) {
			Document doc = XMLDocHelper.getDocument();
			NodeList nodeList = null;
			Element ebcResultElement = doc.createElement("ebcResults");
			Element financialElement = doc.createElement("Financial");
			Element categoryElement = null;
			Element element = null;
			EDBCResultFinancial edbcResultFinancial = null;
			Enumeration edbcRsltFinancialEnum = edbcRsltFinancialVect.elements();
			while (edbcRsltFinancialEnum.hasMoreElements()) {
				edbcResultFinancial = (EDBCResultFinancial) edbcRsltFinancialEnum.nextElement();
				categoryElement = null;
				nodeList = financialElement.getElementsByTagName(TAG_CATEGORY);
				if (nodeList != null && nodeList.getLength() > 0) {
					Element tempElement = null;
					for (int i = 0; i < nodeList.getLength(); i++) {
						tempElement = (Element) nodeList.item(i);
						if (tempElement.getAttribute("Nm").equals(edbcResultFinancial.getCategory().toString())) {
							categoryElement = tempElement;
							break;
						}
					}
				}
				if (categoryElement == null && edbcResultFinancial != null) {
					categoryElement = doc.createElement(TAG_CATEGORY);
					categoryElement.setAttribute("Nm", edbcResultFinancial.getCategory().toString());
					financialElement.appendChild(categoryElement);
				}

				if (edbcResultFinancial != null && categoryElement != null) {
					element = doc.createElement(TAG_ELEMENT);
					element.setAttribute("Nm", edbcResultFinancial.getElement().toString());
					element.setAttribute("Vl", edbcResultFinancial.getValue().toString());
					if (edbcResultFinancial.getElement().isNotEmpty()
					                && amountFields.contains(edbcResultFinancial.getElement().toString())) {
						// System.out.println(edbcResultFinancial.getElement().toString()+"--"+edbcResultFinancial.getValue().toString());
						double tempValue = Double.parseDouble(edbcResultFinancial.getValue().toString());
						tempValue = BeaconUtil.getRoundMoneyWithTwoDecimal(tempValue);
						element.setAttribute("Vl", decimalFormater.format(tempValue));
					}
					categoryElement.appendChild(element);
				}
				if (edbcResultFinancial != null && categoryElement != null
				                && edbcResultFinancial.getElement().toString().equalsIgnoreCase(BENEFITCHANGEREASONS)) {
					element = doc.createElement(TAG_ELEMENT);
					element.setAttribute("Nm", edbcResultFinancial.getElement().toString());
					element.setAttribute("DisplayName", edbcResultFinancial.getElementDisplayName().toString());
					if (benefitChangeReasonVector != null && benefitChangeReasonVector.isEmpty()) {
						element.setAttribute("Vl", "");
					}
					int i = 0;
					String reasonName = "reasonName";
					Enumeration benefitChangeEnum = benefitChangeReasonVector.elements();
					while (benefitChangeEnum.hasMoreElements()) {
						String benefitChange = (String) benefitChangeEnum.nextElement();
						Element subElement = doc.createElement("SubElement");
						subElement.setAttribute("Nm", reasonName + i);
						subElement.setAttribute("Vl", benefitChange);
						element.appendChild(subElement);
						i++;
					}
					categoryElement.appendChild(element);
				}
			}
			ebcResultElement.appendChild(financialElement);
			doc.appendChild(ebcResultElement);
			xmlString = XMLUtil.serializeAsXML(doc);
		}
		return xmlString;
	}

