	/**
	 * @param maECFDelta
	 * @param intWrapRsltVect
	 * @return
	 * @throws Exception
	 */
	public static boolean hasActiveCashReinstatement(MAECFHousehold maECFDelta, Vector intWrapRsltVect, IntegerData granteeID
	                                                   ) throws Exception {

		if (intWrapRsltVect != null && intWrapRsltVect.size() > 0) {
			Enumeration intWrapUpEDBCResultEnum = intWrapRsltVect.elements();
			while (intWrapUpEDBCResultEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult intWrapRslt = (InterviewWrapUpEDBCResult) intWrapUpEDBCResultEnum.nextElement();
				if (intWrapRslt.getGranteeId().equals(granteeID)
						&& (intWrapRslt.getProgram().equals(TANF) || intWrapRslt.getProgram().equals(EAEDC))
						&& intWrapRslt.getStatus().equals(ACTIVE)
						&& isReinstated(maECFDelta, intWrapRslt.getAuId())){
					return true;
				}
			}
		}
		return false;
	}


	/**
	 * @param maECFDelta
	 * @param rsltBaseVec
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isDayTwoSpl30DayFSExpedited(MAECFHousehold maECFDelta, Vector rsltBaseVec,
	                                                   InterviewWrapUpEDBCResult intWrapRslt) throws Exception {
		if (rsltBaseVec != null && rsltBaseVec.size() > 0) {
			Enumeration rsltBaseEnum = rsltBaseVec.elements();
			while (rsltBaseEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult baseRslt = (InterviewWrapUpEDBCResult) rsltBaseEnum.nextElement();
				if (baseRslt.getAuId().equals(intWrapRslt.getAuId()) && baseRslt.getExpedited().equals(SPECIAL_30_DAY_CODE)
								&& baseRslt.getStatus().equals(AU_ACTIVE) ) {
					if (maECFDelta.getFields().getContext().getBusinessUserid() != 0 || !isBatchCreatedReq(maECFDelta)
					    || isDayTwoVerificationSelected(maECFDelta, intWrapRslt.getAuId())) {
						return true;
					}
				}
			}
		}
		return false;
	}

	/**
	 * @param maECFDelta
	 * @param auId
	 * @return
	 * @throws Exception
	 */
	public static boolean isDayTwoVerificationSelected(MAECFHousehold maECFDelta, IntegerData auId)
	    throws Exception {
		RequestId requestId = maECFDelta.getRequestId();
		Vector eligibilityRequestVerDataVector = maECFDelta.getFields().getFields(EligibilityRequestVerData.class,
		    requestId.getReqId());
		if (eligibilityRequestVerDataVector != null && eligibilityRequestVerDataVector.size() > 0) {
			Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
			while (eligibilityRequestVerDataEnum.hasMoreElements()) {
				EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum.nextElement();
				if (eligibilityRequestVerData.getPersistenceState().intValue() == 3) {
					continue;
				}
				ViewVerification viewVerification = (ViewVerification) maECFDelta.getFields().getSeqField(ViewVerification.class,
				    eligibilityRequestVerData.getVerId());
				if (viewVerification != null && viewVerification.getVerificationElementId() == 140) {
					if (viewVerification.getAuId().equals(auId) && viewVerification.getTableSetKeyId() == 200) {
						return true;
					}
				}
			}
		}
		return false;
	}

	/**
	 * @param maECF
	 * @return
	 * @throws Exception
	 */
	public static boolean isBatchCreatedReq(MAECFHousehold maECF) throws Exception {
		Vector<BaseEligReqClient> eligReqVec = maECF.getPrimaryClientEligReq();
		for (BaseEligReqClient eligReq : eligReqVec) {
			if (maECF.getRequestId().getReqId().equals(eligReq.getRequestId()) && eligReq.getUserId().equals(0)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * @param maECFHouseholdDelta
	 * @param intWrapRslt
	 * @return True when a Closed AU has been reinstated or an Denied AU has been reinstated and previous benefit
	 *         effective date is one day before the new result benefit effective date (no gap in benefits, i.e.
	 *         continuation).
	 * @throws Exception
	 */
	public static boolean isReinstatedContinuation(MAECFHousehold maECFHouseholdDelta, InterviewWrapUpEDBCResult intWrapRslt)
	    throws Exception {

		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(intWrapRslt.getAuId()).intValue());
		BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(intWrapRslt.getAuId());
		if (auStatus.getStatus().equals(AU_PENDING)) {
			EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(intWrapRslt.getAuId());
			if (ebcRsltBase == null) {
				return false;
			} else if (ebcRsltBase.getAuStatus().equals(AU_CLOSED)
						&& isVerificationSelected(maECFHouseholdDelta, maClientDelta, intWrapRslt.getAuId(), 68, true, false)){
				return true;
			} else if (ebcRsltBase.getAuStatus().equals(AU_DENIED)
						&& ebcRsltBase.getBenefitEnd() != null && ebcRsltBase.getBenefitEnd().isNotEmpty()) {
				AuReinstatement auReinst = null;
				auReinst = (AuReinstatement) maClientDelta.getAuReinstatement(intWrapRslt.getAuId());
				if (auReinst != null && auReinst.getReinstateFlag() != null && auReinst.getReinstateFlag().isTrue()){
					DateData currentDate = (DateData)getBusinessDate(maClientDelta.getFields().getContext()).copy();
					DateData deniedDate = ((DateData)ebcRsltBase.getBenefitEnd().copy()).addDays(1);
					EbcCycleDate ebcCycleMonth;
					// Current month
					ebcCycleMonth = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), currentDate);
					if (ebcCycleMonth.getFirstCycStdPmtDate().equals(deniedDate)
						|| ebcCycleMonth.getTanfCycStdPmtDate().equals(deniedDate)){
						return true;
					}
					// Previous month
					ebcCycleMonth = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), currentDate.addMonths(-1));
					if (ebcCycleMonth.getFirstCycStdPmtDate().equals(deniedDate)
						|| ebcCycleMonth.getTanfCycStdPmtDate().equals(deniedDate)){
						return true;
					}
					// Next month
					ebcCycleMonth = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), currentDate.addMonths(2));
					if (ebcCycleMonth.getFirstCycStdPmtDate().equals(deniedDate)
						|| ebcCycleMonth.getTanfCycStdPmtDate().equals(deniedDate)){
						return true;
					}
				}
			}
		}
		return false;
	}

	/**
	 * Return the business effective date. When running from the online application, returns
	 * the context date. When running from a batch application, returns the working day
	 * prior to the rundate argument supplied to the batch.
	 *
	 * @param ctx
	 * @return DateData
	 * @throws Exception
	 */
	public static DateData getBusinessDate(Context ctx) throws Exception {
		DateData businessDate;
		if (ctx.getBusinessUserid() == 0){
			businessDate = ctx.getEffectiveDate().getPreviousWorkDate();
		} else {
			businessDate = ctx.getEffectiveDate();
		}
		return businessDate;
	}

	/**
	 * @param maECF
	 * @param resetDate
	 * @throws Exception
	 */
	public static void alignReevaluationDates(MAECFHousehold maECF, Vector<InterviewWrapUpEDBCResult> vIntWrapup, boolean resetDate)
	    throws Exception {
		if (vIntWrapup != null && vIntWrapup.size() > 0) {
			boolean overrider = isCashFSReevalDateOverrider(maECF);
			for (InterviewWrapUpEDBCResult intWrapRslt : vIntWrapup) {
				boolean overrideAllowed = overrider
						&& !(intWrapRslt.getRevalType().equals(ANNUAL_REPORTING)
								|| (intWrapRslt.getRevalType().isNotEmpty() && simpReevalTypesVec.contains(intWrapRslt.getRevalType())))
						&& !intWrapRslt.getExpedited().equals(EXPEDITED_CODE)
						&& !intWrapRslt.getExpedited().equals(SPECIAL_30_DAY_CODE);
				
				if ((intWrapRslt.getProgram().equals(TANF) || intWrapRslt.getProgram().equals(EAEDC))
					    && (intWrapRslt.getStatus().equals(ACTIVE) || hasIWResultClothingAllowance(intWrapRslt)) && isAUNewReinDenialOReevaluated(maECF, intWrapRslt)) {

					// Need to reset flag in case user changes dates back/forth, should allow field to be disabled then enabled
					intWrapRslt.setReevalTypeFlg(false);

					InterviewWrapUpEDBCResult fsRslt = getFSIntWrapRslt(maECF, vIntWrapup, intWrapRslt.getGranteeId());

					if (fsRslt != null && isTAFDCSemiAnnualReporting(intWrapRslt, maECF.getMAClient(intWrapRslt.getGranteeId().intValue())) ) {
						DateData effDte = (DateData) maECF.getFields().getContext().getEffectiveDate().copy();
						if (((DateData)fsRslt.getRevalEnd().copy()).addMonths(-6).after(((DateData) effDte.copy()).addDays(45))
							&& intWrapRslt.getRevalStart() != null && intWrapRslt.getRevalStart().isNotEmpty()
                            && !fsRslt.getRevalEnd().after(((DateData)intWrapRslt.getRevalStart().copy()).addMonths(13).addDays(-1))) {
							if (resetDate) {
								DateData reevalEndDate = (((DateData)fsRslt.getRevalEnd().copy()).addDays(1)).addMonths(-6).addDays(-1);
								intWrapRslt.setRevalEnd(reevalEndDate);
							}
							if (!overrideAllowed) {
								intWrapRslt.setReevalTypeFlg(true);
							}
							continue;
						}
					}

					if (fsRslt != null) {
						DateData effDte = (DateData) maECF.getFields().getContext().getEffectiveDate().copy();
						if (fsRslt.getRevalEnd().after(((DateData) effDte.copy()).addDays(45))
							&& intWrapRslt.getRevalStart() != null && intWrapRslt.getRevalStart().isNotEmpty()
                            && !fsRslt.getRevalEnd().after(((DateData)intWrapRslt.getRevalStart().copy()).addMonths(13).addDays(-1))) {
							if (resetDate) {
								intWrapRslt.setRevalEnd(fsRslt.getRevalEnd());
							}
							if (!overrideAllowed) {
								intWrapRslt.setReevalTypeFlg(true);
							}
							continue;
						}
					}
					InterviewWrapUpEDBCResult cashIntWrapRslt = getCashIntWrapRslt(maECF, vIntWrapup, intWrapRslt);

					if (cashIntWrapRslt != null  && isTAFDCSemiAnnualReporting(intWrapRslt, maECF.getMAClient(intWrapRslt.getGranteeId().intValue()))) {
						DateData effDte = (DateData) maECF.getFields().getContext().getEffectiveDate().copy();
						if (((DateData)cashIntWrapRslt.getRevalEnd().copy()).addMonths(-6).after(((DateData) effDte.copy()).addDays(45))
							&& intWrapRslt.getRevalStart() != null && intWrapRslt.getRevalStart().isNotEmpty()
                            && !cashIntWrapRslt.getRevalEnd().after(((DateData)intWrapRslt.getRevalStart().copy()).addMonths(12).addDays(-1))) {
							if (resetDate) {
								DateData reevalEndDate = (((DateData)cashIntWrapRslt.getRevalEnd().copy()).addDays(1)).addMonths(-6).addDays(-1);
								intWrapRslt.setRevalEnd(reevalEndDate);
							}
							if (!overrideAllowed) {
								intWrapRslt.setReevalTypeFlg(true);
							}
							continue;
						}
					}

					if (cashIntWrapRslt != null) {
						DateData effDte = (DateData) maECF.getFields().getContext().getEffectiveDate().copy();
						if (cashIntWrapRslt.getRevalEnd().after(((DateData) effDte.copy()).addDays(45))
							&& intWrapRslt.getRevalStart() != null && intWrapRslt.getRevalStart().isNotEmpty()
                            && !cashIntWrapRslt.getRevalEnd().after(((DateData)intWrapRslt.getRevalStart().copy()).addMonths(12).addDays(-1))) {
							if (resetDate) {
								intWrapRslt.setRevalEnd(cashIntWrapRslt.getRevalEnd());
							}
							if (!overrideAllowed) {
								intWrapRslt.setReevalTypeFlg(true);
							}
						}
					}
				}
			}
		}
	}


	/**
	 * @param maECFHouseholdDelta
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isAUNewReinDenialOReevaluated(MAECFHousehold maECFHouseholdDelta, InterviewWrapUpEDBCResult intWrapRslt)
	    throws Exception {

		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(intWrapRslt.getAuId()).intValue());
		BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(intWrapRslt.getAuId());
		if ((auStatus.getStatus().equals(AU_PENDING) && !isVerificationSelected(maECFHouseholdDelta, maClientDelta,
		    intWrapRslt.getAuId(), 68, true, false))
		    || isReinstatedDenial(maECFHouseholdDelta, intWrapRslt)
		    || isReinstatedClosure(maECFHouseholdDelta, intWrapRslt)
		    || isReevaluationVerificationSelected(maECFHouseholdDelta, maClientDelta, intWrapRslt.getAuId(),
		        VER_DATA_ID_140, true, false)) {
			return true;
		}
		return false;
	}

	/**
	 * @param maECFHouseholdDelta
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isReinstated(MAECFHousehold maECFHouseholdDelta, IntegerData auId) throws Exception {
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(auId).intValue());
		BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(auId);
		if (auStatus.getStatus().equals(AU_PENDING)){
			EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(auId);
			if (ebcRsltBase == null) {
				return false;
			} else if (ebcRsltBase.getAuStatus().equals(AU_CLOSED)
						&& isVerificationSelected(maECFHouseholdDelta, maClientDelta, auId, 68, true, false)){
				return true;
			} else if (ebcRsltBase.getAuStatus().equals(AU_DENIED)) {
				AuReinstatement auReinst = null;
				auReinst = (AuReinstatement) maClientDelta.getAuReinstatement(auId);
				if (auReinst != null && auReinst.getReinstateFlag() != null && auReinst.getReinstateFlag().isTrue()){
					return true;
				}
			}
		}
		return false;
	}
	
	
	/**
	 * @param maECFHouseholdDelta
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isReopened(MAECFHousehold maECFHouseholdDelta, IntegerData auId) throws Exception {
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(auId).intValue());
		BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(auId);
		if (auStatus.getStatus().equals(AU_PENDING)) {
			EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(auId);
			if (ebcRsltBase == null) {
				return false;
			} else if (ebcRsltBase.getAuStatus().equals(AU_CLOSED)) {
				return true;
			} else if (ebcRsltBase.getAuStatus().equals(AU_DENIED)
					&& (ebcRsltBase.getBenefitEnd().isEmpty() || ebcRsltBase.getBenefitEnd()
							.before(maECFHouseholdDelta.getFields().getContext().getEffectiveDate()))) {
				return true;
			}
		}
		return false;
	}
	
