	/**
	 * @param maECFHouseholdDelta
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static boolean isReinstatedClosure(MAECFHousehold maECFHouseholdDelta, InterviewWrapUpEDBCResult intWrapRslt)
	    throws Exception {
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(maECFHouseholdDelta.getGrantee(intWrapRslt.getAuId())
		    .intValue());
		BaseAUStatus auStatus = maClientDelta.getAssistUnitStatus(intWrapRslt.getAuId());
		if (auStatus.getStatus().equals(AU_PENDING)
		    && isVerificationSelected(maECFHouseholdDelta, maClientDelta, intWrapRslt.getAuId(), 68, true, false)) {
			BEACONAUEligReevaluation auEligReeval = maClientDelta.getBEACONAUEligReevaluation(intWrapRslt.getAuId());
			DateData curEffDte = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
			EBCResultBase ebcRsltBase = maECFHouseholdDelta.getEBCResultBase(intWrapRslt.getAuId());
			if (ebcRsltBase != null && ebcRsltBase.getAuStatus().equals(AU_CLOSED) && auEligReeval != null
			    && !auEligReeval.getRevalEndDate().after(curEffDte.addDays(45))
			    && isReevaluationReleased(maECFHouseholdDelta, ebcRsltBase)) {
				return true;
			}
		}
		return false;
	}
	
	


