	public static boolean isVerificationSelectedForExtensionRequest(MAECFHousehold maECFHouseholdDelta,
	                                                                MAClient maClientDelta, IntegerData auId,
	                                                                String status, IntegerData verId,
	                                                                boolean auIdChkFlg, boolean grntChkFlg)
	                throws Exception {
		boolean verSelectFlg = false;
		RequestId requestId = maECFHouseholdDelta.getRequestId();
		Vector eligibilityRequestVerDataVector = maECFHouseholdDelta.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
		while (eligibilityRequestVerDataEnum.hasMoreElements()) {
			EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
			                .nextElement();
			if (eligibilityRequestVerData.getPersistenceState().intValue() == 3) {
				continue;
			}
			com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maECFHouseholdDelta
			                .getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
			                                eligibilityRequestVerData.getVerId());
			
			if (viewVerification != null && viewVerification.getVerificationElementId() == 60 ) {
				boolean verIdFlg = false;
				verId.setInteger(viewVerification.getId());
				// BCN 2777 - check for AU_EXT_REQ status APPRVD with ver_id_k has elementID =60
				Vector<AUExtensionRequest> extReqVec = maClientDelta.getAUExtensionRequest(auId);
				for (AUExtensionRequest extReq : extReqVec) {
					if (extReq.getVerificationId().isNotEmpty() && verId.intValue() == extReq.getVerificationId().intValue()
							&& ( extReq.getExtRequestStatus().isNotEmpty() && extReq.getExtRequestStatus().equals(EXTENSION_REQUEST_STATUS_APPROVED))) {
						verIdFlg = true;
						break;
					}
				}
				// check for auid
				if (verIdFlg) {
					if (auIdChkFlg && (auId.intValue() == viewVerification.getAuId().intValue())) {
						verSelectFlg = true;
						break;
					}
					// check for grantee
					else if (grntChkFlg
					                && maClientDelta.getGranteeForAU(auId).getClientId().intValue() == viewVerification
					                                .getClientId().intValue()) {
						verSelectFlg = true;
						break;
					}
					else if (!(auIdChkFlg || grntChkFlg)) {
						verSelectFlg = true;
						break;
					}
				}
			}
		}
		return verSelectFlg;
	}

