	/**
	 * This method is used to check whether a SNAP AR case should allow a benefit change.
	 *
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if verification is selected for reevaluation
	 * @throws Exception
	 */
	public static boolean isARExclusion(MAECFHousehold maECFHouseholdDelta,
	                                                            MAClient maClientDelta, InterviewWrapUpEDBCResult fsRsltObj)
	                throws Exception {

		if (!fsRsltObj.getProgram().equals(SNAP)) {
			return false;
		}
		IntegerData auId = fsRsltObj.getAuId();

		if (isVerificationSelectedForARRecalculation(maECFHouseholdDelta, maClientDelta, auId, true, false)) {
			return true;
		}

		if (isVerificationSelectedForIPV(maECFHouseholdDelta, maClientDelta, auId)) {
			return true;
		}
		if (hasARExclusionEFRC(maECFHouseholdDelta, maClientDelta, auId)) {
			return true;
		}
		if (hasARExclusionMatchEFRC(maECFHouseholdDelta, maClientDelta, auId)) {
			return true;
		}
		if (hasARExclusionBatchUI(maECFHouseholdDelta, maClientDelta, auId)) {
			return true;
		}
		//if cash changes, allow benefit decrease
		EDBCResultFinancial edbcResultFinancial = null;
		double baseGrantAmt;
		double rsltGrantAmt;
		baseGrantAmt = getReleasedFinancialDouble(getPrevReleasedXMLValue(maECFHouseholdDelta, fsRsltObj
		                .getAuId(), fsRsltObj.getRequestId(), BENEFIT, GRANTAMOUNT));
		edbcResultFinancial = fsRsltObj.getFinancialObject(BENEFIT, GRANTAMOUNT);
		rsltGrantAmt = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? Double
		                .parseDouble(edbcResultFinancial.getValue().toString())
		                : 0.00;
		if (baseGrantAmt != rsltGrantAmt) {
			return true;
		}
		return false;
	}

	/**
	 * This method is used to check whether the verification for an IPV ineligibilty factor is selected.
	 *
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if verification is selected for reevaluation
	 * @throws Exception
	 */
	public static boolean isVerificationSelectedForIPV(MAECFHousehold maECFHouseholdDelta,
	                                                            MAClient maClientDelta, IntegerData auId)
	                throws Exception {
		boolean verSelectFlg = false;
		RequestId requestId = maECFHouseholdDelta.getRequestId();
		ClientAuMembIneligFactorEntityExists clientAUMembInEligFactor = null;
		Vector eligibilityRequestVerDataVector = maECFHouseholdDelta.getFields().getFields(
		                EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
		while (eligibilityRequestVerDataEnum.hasMoreElements()) {
			EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
			                .nextElement();
			com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maECFHouseholdDelta
			                .getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
			                                eligibilityRequestVerData.getVerId());
			if (viewVerification != null && viewVerification.getVerificationElementId() == VER_DATA_ID_78
							&& auId.intValue() == viewVerification.getAuId().intValue()) {
				Vector eligFactor = maClientDelta.ClientAuMembIneligFactorEntityExists(viewVerification.getClientId());
				if (eligFactor.size() > 0) {
					Enumeration eligEnum = eligFactor.elements();
					while (eligEnum.hasMoreElements()) {
						clientAUMembInEligFactor = (ClientAuMembIneligFactorEntityExists) eligEnum.nextElement();
						if (clientAUMembInEligFactor.getVerId().isNotEmpty() && clientAUMembInEligFactor.getVerId().intValue() == viewVerification.getId()) {
							if (clientAUMembInEligFactor.getEligFactor().equals(IPV_FACTOR)) {
								verSelectFlg = true;
								break;
							}
						}
					}
				}
			}
			if (verSelectFlg) {
				break;
			}
		}
		return verSelectFlg;
	}

