	/**
	 * This method is used to determine whether the reevaluation type can be changed to AR.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param ebcObjectVector
	 *            is a Vector of EDBCResult instances.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @return true if AR reevaluation type
	 * @throws Exception
	 */
	public static boolean annualReportingReevaluationType(MAClient maClientDelta, MAClient maClientBase,
	                                              Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec,
	                                              InterviewWrapUpEDBCResult fsRlt) throws Exception {
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());
		EDBCResult ebcObject = null;
		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP)) {
			// checks the current SNAP auid in the EDBCResult object vector and assigns the matched EDBCResult object
			if (ebcObjectVector != null && ebcObjectVector.size() > 0) {
				Enumeration ebcObjectEnum = ebcObjectVector.elements();
				while (ebcObjectEnum.hasMoreElements()) {
					EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
					if (ebcObj.getAuId().intValue() == fsRlt.getAuId().intValue()) {
						ebcObject = ebcObj;
						break;
					}
				}
			}
			if (!preCheckForAnnualReporting(maClientDelta, maClientBase, fsRlt, rsltVec, ebcObject)) {
				if (fsRlt.getStatus().equals(ACTIVE) && ebcObject != null
				                && ebcObject.getPotentialUniversalFlag().isNotEmpty()
				                && ebcObject.getPotentialUniversalFlag().booleanValue()) {
					return true;
				}
			}
		}
		return false;
	}

	public static InterviewWrapUpEDBCResult getTAFDCWhereFSGranteeIsAlsoAGrantee(
	                                                                             IntegerData fsGranteeId,
	                                                                             Vector<InterviewWrapUpEDBCResult> rsltDeltaVec)
	                throws Exception {
		for (InterviewWrapUpEDBCResult tafdcRslt : rsltDeltaVec) {
			if (tafdcRslt.getProgram().equals(TANF) && tafdcRslt.getGranteeId().intValue() == fsGranteeId.intValue()) {
				return tafdcRslt;
			}
		}
		return null;
	}

	/**
	 * This method is used to determine whether the reevaluation type can be changed to AR.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if AR
	 * @throws Exception
	 */
	public static boolean preCheckForAnnualReporting(MAClient maClientDelta, MAClient maClientBase,
	                                       InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                       Vector<InterviewWrapUpEDBCResult> rsltVec, EDBCResult ebcObject)
	                throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		String monthlyReportingStatus;
		String tbaFlag;
		boolean granteeFlg = false;
		boolean elderlyFlg = false;
		boolean disabilityFlg = false;
		boolean tafdcExtFlg = false;
		boolean fsNPAGranteeFlg = false;
		boolean monRepFlg = false;
		boolean noIncomeFlg = false;
		boolean adultFlg = false;
		Vector<ClientAUMembWorkProgramStatus> workProgStatusVect = null;
		InterviewWrapUpEDBCResult relatedTAFDC = null;
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
		                ELDERLY_DEPENDENT_AGE);
		for (InterviewWrapUpEDBCResult rslt : rsltVec) {
			if (rslt.getProgram().equals(SNAP)) {
				int adultCnt = 0;
				int fsMembCnt = 0;
				// using Rule data (selected DELTA + BASE)
				Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
				for (EDBCResultAUMember fsRsltMemb : fsRsltMemVec) {
					elderlyFlg = false;
					disabilityFlg = false;
					noIncomeFlg = false;
					adultFlg = false;
					if (!isDependentChildInAU(maClientBase, fsRsltMemb.getClientId(), rslt.getAuId())) {
						int elderlyDependentAge = Integer.parseInt(parameter.getParameterValue());
						adultCnt++;
						adultFlg = true;
						// to determind SNAP AU's are elderly
						if (maClientDelta.findClientAge(fsRsltMemb.getClientId()) > elderlyDependentAge) {
							elderlyFlg = true;
						}
					}
					// to determine SNAP AU's are disabled
					ClientDisabilityPage clientDisability = maClientBase.getClientDisabilityPage(fsRsltMemb
					                .getClientId());
					if (clientDisability != null && ebcObject != null
					                && clientDisability.getDisabledFlg().booleanValue()
					                && ebcObject.isFSFederallyCertified(maClientBase, clientDisability)) {
						disabilityFlg = true;
					}
					Vector earnedIncomeVect = maClientBase.getEarnedIncome(fsRsltMemb.getClientId());
					if (earnedIncomeVect == null || earnedIncomeVect.size() == 0) {
						noIncomeFlg = true;
					}
					if (adultFlg && (elderlyFlg || disabilityFlg) && noIncomeFlg) {
						fsMembCnt++;
					}
					workProgStatusVect = maClientBase.getClientAUMembWorkProgramStatus(fsRsltMemb.getAuId());
					for (ClientAUMembWorkProgramStatus workPgmStat : workProgStatusVect) {
						if (workPgmStat != null
						                && (fsRsltMemb.getClientId().intValue() == workPgmStat.getClientId().intValue())
						                && workPgmStat.getWorkExemptFlag().isNotEmpty()
						                && workPgmStat.getWorkExemptFlag().isFalse()) {
							return true;
						}
					}
				}
				if (fsMembCnt == adultCnt) {
					return true;
				}
				// SNAP AU is assigned to a worker in a Regional SSI office
				BaseAUAssignment auAssignment = (BaseAUAssignment) maClientBase.getFields().getField(
				                BaseAUAssignment.class, rslt.getAuId());
				if (auAssignment != null && auAssignment.getBuId().isNotEmpty()) {
					ApplicationUser appUser = (ApplicationUser) maClientDelta.getFields().getSeqField(
					                ApplicationUser.class, auAssignment.getBuId());
					if (appUser != null && appUser.getOfficeLocationId().isNotEmpty()) {
						OrganizationLocationItem orgLocItem = maClientDelta.getOrganizationLocationItem(appUser
						                .getOfficeLocationId());
						if (orgLocItem != null && orgLocItem.getSsiFlag().isNotEmpty()
						                && orgLocItem.getSsiFlag().booleanValue()) {
							return true;
						}
					}
				}
				// using Result data (post-rules processing result values)
				edbcResultFinancial = rslt.getFinancialObject(BENEFIT, TBAFLAG);
				tbaFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? edbcResultFinancial
				                .getValue().stringValue()
				                : null;
				// SNAP AU result is set to TBA (result.TBAFlag=Y)
				if (tbaFlag != null && tbaFlag.equalsIgnoreCase(YES)) {
					return true;
				}
				if (rslt.getPgmSubType().equals(NPA)) {
					relatedTAFDC = getTAFDCWhereFSGranteeIsAlsoAGrantee(rslt.getGranteeId(), rsltVec);
					if (relatedTAFDC != null) {
						if (relatedTAFDC.getPgmStructParId().intValue() == 115) {
							return true;
						}
						edbcResultFinancial = relatedTAFDC.getFinancialObject(STANDARDAMOUNTS, MONTHLYREPORTINGSTATUS);
						monthlyReportingStatus = (edbcResultFinancial != null && edbcResultFinancial.getValue()
						                .isNotEmpty()) ? edbcResultFinancial.getValue().stringValue() : null;
						if (monthlyReportingStatus != null
						                && (monthlyReportingStatus.equals("Y") || monthlyReportingStatus.equals("Yes"))) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

	/**
	 * This method is used to determine whether the AU has a member who is a dependent child .
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData object
	 * @param auId
	 *            an IntegerData value.
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isDependentChildInAU(MAClient maClientDelta, IntegerData clientId, IntegerData auId)
	                throws Exception {
		Vector personalRelVect = null;
		Vector clientCaretakerVect = null;
		boolean dependentAgeFlg = false;
		boolean personalRelFlg = false;
		boolean caretakerRoleFlg = false;

		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
		                DEPENDENT_AGE_CUTOFF);
		int dependentAge = Integer.parseInt(parameter.getParameterValue());
		if (maClientDelta.findClientAge(clientId) < dependentAge) {
			dependentAgeFlg = true;
		}
		/*
		 * Enumeration enumPersonalRelation = maClientDelta.getHHClientPersonalRelations().elements();
		 * while(enumPersonalRelation.hasMoreElements()){ HHClientPersonalRelation hhClientPersonalRelation =
		 * (HHClientPersonalRelation) enumPersonalRelation.nextElement();
		 * if(hhClientPersonalRelation.getClientRelatedId().intValue() == clientId.intValue()){ if
		 * (hhClientPersonalRelation.getPersonalRelationCode().isNotEmpty() &&
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_MOTHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_FATHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_MOTHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_FATHER)) { personalRelFlg =
		 * true; break; } } }
		 */
		// maClientDelta.getFields().removeField(HHClientPersonalRelation.class,clientId);
		personalRelVect = maClientDelta.getHHClientPersonalRelations(clientId);
		if (personalRelVect != null && personalRelVect.size() > 0) {
			Enumeration personalRelEnum = personalRelVect.elements();
			while (personalRelEnum.hasMoreElements()) {
				HHClientPersonalRelation hhClientPersonalRelation = (HHClientPersonalRelation) personalRelEnum
				                .nextElement();
				if (hhClientPersonalRelation.getPersonalRelationCode().isNotEmpty()
				                && hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
				                                REL_MOTHER)
				                || hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
				                                REL_FATHER)
				                || hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
				                                STEP_MOTHER)
				                || hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
				                                STEP_FATHER)
				                || hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
		                                MAConstants.REL_ADOPTIVE_FATHER)
				                || hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(
				                		  MAConstants.REL_ADOPTIVE_MOTHER)) {
					personalRelFlg = true;
					break;
				}
			}
		}
		clientCaretakerVect = maClientDelta.getClientCaretaker(clientId);
		if (clientCaretakerVect != null && clientCaretakerVect.size() > 0) {
			Enumeration clientCaretakerEnum = clientCaretakerVect.elements();
			while (clientCaretakerEnum.hasMoreElements()) {
				ClientCaretakerInfo clientCaretakerInfo = (ClientCaretakerInfo) clientCaretakerEnum.nextElement();
				ClientCaretakerDetails clientCaretakerDetails = maClientDelta
				                .getClientCaretakerDetails(clientCaretakerInfo.getId());
				if (clientCaretakerDetails != null
				                && clientCaretakerDetails.getClientProviderId().isNotEmpty()
				                && isOpenAUMember(maClientDelta, clientCaretakerDetails.getClientProviderId(), auId)
				                && clientCaretakerInfo.getCaretakerRole().isNotEmpty()
				                && clientCaretakerInfo.getCaretakerRole().toString().equalsIgnoreCase(
				                                CARETAKER_ROLE_CARCON)
				                || clientCaretakerInfo.getCaretakerRole().toString().equalsIgnoreCase(
				                                CARETAKER_ROLE_PRTCON)) {
					caretakerRoleFlg = true;
					break;
				}
			}
		}
		if (isOpenAUMember(maClientDelta, clientId, auId) && dependentAgeFlg && (personalRelFlg || caretakerRoleFlg))
			return true;
		return false;
	}

	/**
	 * This method is used to determine whether the AU has a member who is a dependent child .
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData object
	 * @param auId
	 *            an IntegerData value.
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isDependentChildInAUWithMAECF(MAClient maClientDelta, IntegerData clientId, IntegerData auId,
	                                                    MAECFHousehold whRule) throws Exception {
		Vector personalRelVect = null;
		Vector clientCaretakerVect = null;
		boolean dependentAgeFlg = false;
		boolean personalRelFlg = false;
		boolean caretakerRoleFlg = false;
		int yearDiff = 0;
		DateData today = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
		                DEPENDENT_AGE_CUTOFF);
		ClientBirthDate clientBirthDate = (ClientBirthDate) maClientDelta.getClientBirthDate(clientId);
		if (clientBirthDate != null && clientBirthDate.getBirthDate().isNotEmpty()) {
			DateData birthDate = clientBirthDate.getBirthDate();
			yearDiff = today.getYear() - birthDate.getYear();
			if (today.getMonth() < birthDate.getMonth())
				yearDiff -= 1;
			else if ((today.getMonth() == birthDate.getMonth()) && (today.getDate() < birthDate.getDate())) {
				yearDiff -= 1;
			}
		}
		int dependentAge = Integer.parseInt(parameter.getParameterValue());
		if (yearDiff < dependentAge) {
			dependentAgeFlg = true;
		}
		/*
		 * Enumeration enumPersonalRelation = maClientDelta.getHHClientPersonalRelations().elements();
		 * while(enumPersonalRelation.hasMoreElements()){ HHClientPersonalRelation hhClientPersonalRelation =
		 * (HHClientPersonalRelation) enumPersonalRelation.nextElement();
		 * if(hhClientPersonalRelation.getClientRelatedId().intValue() == clientId.intValue()){ if
		 * (hhClientPersonalRelation.getPersonalRelationCode().isNotEmpty() &&
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_MOTHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_FATHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_MOTHER) ||
		 * hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_FATHER)) { personalRelFlg =
		 * true; break; } } }
		 */
		// maClientDelta.getFields().removeField(HHClientPersonalRelation.class,clientId);
		personalRelVect = whRule.getMAClient(whRule.getPrimaryClientId()).getHHClientPersonalRelations(clientId);
		if (personalRelVect != null && personalRelVect.size() > 0) {
			Enumeration personalRelEnum = personalRelVect.elements();
			while (personalRelEnum.hasMoreElements()) {
				HHClientPersonalRelation hhClientPersonalRelation = (HHClientPersonalRelation) personalRelEnum
						.nextElement();
				if (hhClientPersonalRelation.getPersonalRelationCode().isNotEmpty()
						&& hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_MOTHER)
						|| hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(REL_FATHER)
						|| hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_MOTHER)
						|| hhClientPersonalRelation.getPersonalRelationCode().toString().equalsIgnoreCase(STEP_FATHER)
						|| hhClientPersonalRelation.getPersonalRelationCode().toString()
								.equalsIgnoreCase(MAConstants.REL_ADOPTIVE_FATHER)
						|| hhClientPersonalRelation.getPersonalRelationCode().toString()
								.equalsIgnoreCase(MAConstants.REL_ADOPTIVE_MOTHER)) {
					if (isOpenAUMember(maClientDelta, hhClientPersonalRelation.getClientRelatedId(), auId)) {
						personalRelFlg = true;
						break;
					}
				}
			}
		}
		clientCaretakerVect = maClientDelta.getClientCaretaker(clientId);
		if (clientCaretakerVect != null && clientCaretakerVect.size() > 0) {
			Enumeration clientCaretakerEnum = clientCaretakerVect.elements();
			while (clientCaretakerEnum.hasMoreElements()) {
				ClientCaretakerInfo clientCaretakerInfo = (ClientCaretakerInfo) clientCaretakerEnum.nextElement();
				ClientCaretakerDetails clientCaretakerDetails = maClientDelta
				                .getClientCaretakerDetails(clientCaretakerInfo.getId());
				if (clientCaretakerDetails != null
				                && clientCaretakerDetails.getClientProviderId().isNotEmpty()
				                && isOpenAUMember(maClientDelta, clientCaretakerDetails.getClientProviderId(), auId)
				                && clientCaretakerInfo.getCaretakerRole().isNotEmpty()
				                && (clientCaretakerInfo.getCaretakerRole().toString().equalsIgnoreCase(
				                                CARETAKER_ROLE_CARCON)
				                || clientCaretakerInfo.getCaretakerRole().toString().equalsIgnoreCase(
				                                CARETAKER_ROLE_PRTCON))) {
					caretakerRoleFlg = true;
					break;
				}
			}
		}
		if (isOpenAUMember(maClientDelta, clientId, auId) && dependentAgeFlg && (personalRelFlg || caretakerRoleFlg))
			return true;
		return false;
	}
	/**
	 * This method is used to determine whether the AU member is elderly .
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isElderlyClient(MAClient maClientDelta, IntegerData clientId) throws Exception {
		boolean dependentAgeFlg = false;
		int yearDiff = 0;
		DateData today = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
						ELDERLY_DEPENDENT_AGE);
		ClientBirthDate clientBirthDate = (ClientBirthDate) maClientDelta.getClientBirthDate(clientId);
		if (clientBirthDate != null && clientBirthDate.getBirthDate().isNotEmpty()) {
			DateData birthDate = clientBirthDate.getBirthDate();
			yearDiff = today.getYear() - birthDate.getYear();
			if (today.getMonth() < birthDate.getMonth())
				yearDiff -= 1;
			else if ((today.getMonth() == birthDate.getMonth()) && (today.getDate() < birthDate.getDate())) {
				yearDiff -= 1;
			}
		}
		int dependentAge = Integer.parseInt(parameter.getParameterValue());
		if (yearDiff > dependentAge) {
			dependentAgeFlg = true;
		}
		return dependentAgeFlg;
	}
	/**
	 * This method is used to determine whether the AU member is of dependent age .
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isDependentAgeClient(MAClient maClientDelta, IntegerData clientId) throws Exception {
		boolean dependentAgeFlg = false;
		DateData today = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
		int apage = maClientDelta.getAgeOfClient(clientId);
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
				DEPENDENT_AGE_CUTOFF);

		int dependentAge = Integer.parseInt(parameter.getParameterValue());
		if (apage < dependentAge) {
			dependentAgeFlg = true;
		}
		return dependentAgeFlg;
	}

	/**
	 * This method is used to determine whether the AU member is of dependent age .
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData object
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isDependentAgeClientSNAP(MAClient maClientDelta, IntegerData clientId) throws Exception {
		boolean dependentAgeFlg = false;
		int apage = maClientDelta.getAgeOfClient(clientId);
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
				DEPENDENT_AGE_CUTOFF_SNAP);
		int dependentAge = Integer.parseInt(parameter.getParameterValue());
		if (apage < dependentAge) {
			dependentAgeFlg = true;
		}
		return dependentAgeFlg;
	}

	/**
	 * This method is used to determine whether the member is a open member in the given AU.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param clientId
	 *            an IntegerData value.
	 * @param auId
	 *            an IntegerData value.
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isOpenAUMember(MAClient maClientDelta, IntegerData clientId, IntegerData auId)
	                throws Exception {
		Vector clientAUMembersVect = maClientDelta.getAllClientAUMembers(clientId);
		if (clientAUMembersVect != null && clientAUMembersVect.size() > 0) {
			Enumeration clientAUMembersEnum = clientAUMembersVect.elements();
			while (clientAUMembersEnum.hasMoreElements()) {
				BaseClientAUMember clientAUMember = (BaseClientAUMember) clientAUMembersEnum.nextElement();
				if (clientAUMember.getClientId().isNotEmpty()
				                && clientAUMember.getClientId().intValue() == clientId.intValue()
				                && clientAUMember.getAuId().isNotEmpty()
				                && clientAUMember.getAuId().intValue() == auId.intValue()
				                && clientAUMember.getAuMemberStatusCode().isNotEmpty()
				                && (clientAUMember.getAuMemberStatusCode().toString().equalsIgnoreCase(PENDING)
				                                || clientAUMember.getAuMemberStatusCode().toString().equalsIgnoreCase(
				                                                ACTIVE) || clientAUMember.getAuMemberStatusCode()
				                                .toString().equalsIgnoreCase(INELIGIBLE))) {
					return true;
				}
			}
		}
		return false;
	}

