	/** add to print the rule trace as a XML file -Sathishkumar.N * */
	// modifed Dever logic
	/**
	 * This method is called in the Post Rule Processing: Process SNAP AUs which are in a Dever situation. In general
	 * terms, a Dever situation exists when one or more members of a SNAP AU have been closed in a TANF or EAEDC AU (when
	 * previously, all SNAP members were active in TANF or EAEDC).
	 *
	 * @param maECFHouseholdDelta
	 * @param maECFHouseholdBase
	 * @param maClientDelta
	 * @param maClientBase
	 * @param ebcObjectVector
	 * @param interviewWrapUpEDBCResultBaseVector
	 * @throws Exception
	 */
	public static void dever(MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECF, Vector ebcObjectVector,
	                         Vector rstlBaseVec, Vector<InterviewWrapUpEDBCResult> ebcRsltVec, int clientId)
	                throws Exception {
		String deverSituation = "";
		String deverReason = "";
		for (InterviewWrapUpEDBCResult fsRslt : ebcRsltVec) {
			if (fsRslt.getProgram().equals(SNAP)) {
				deverSituation = identifyDeverSituation(maECFHouseholdDelta, ebcObjectVector, rstlBaseVec, fsRslt,
				                clientId);
				if (!deverSituation.equals("")) {
					fsRslt.setDeverSituationFlag(true);
					deverReason = determineDeverReasonLogic(fsRslt, maECFHouseholdDelta, maECF, ebcObjectVector,
					                deverSituation, clientId);
					if (deverReason.length() > 0 && deverReason.compareTo("EXCLUDE") != 0) {
						fsRslt.setDeverReason(deverReason);
						processDever(maECFHouseholdDelta, maECF, fsRslt, ebcObjectVector, rstlBaseVec, ebcRsltVec,
						                deverSituation, clientId);
					}
					else {
						fsRslt.setDeverSituationFlag(false);
					}
				}
			}
		}
	}

	/**
	 * @param maECFDelta
	 * @param maECF
	 * @param fsRslt
	 * @param ebcObjectVector
	 * @param rsltBaseVec
	 * @param rsltDeltaVec
	 * @param deverSituation
	 * @param clientId
	 * @throws Exception
	 */
	public static void processDever(MAECFHousehold maECFDelta, MAECFHousehold maECF, InterviewWrapUpEDBCResult fsRslt,
	                                Vector<EDBCResult> ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltBaseVec,
	                                Vector<InterviewWrapUpEDBCResult> rsltDeltaVec, String deverSituation, int clientId)
	                throws Exception {
		StringData deverReasonWrapper = null;
		DateData tmpStart = null;
		IntegerData reqId = null;
		String xmlValue = null;
		int noticeId = 0;
		String noticeType = null;
		EBCNotice ebcNotice = null;
		Vector<InterviewWrapUpEDBCResult> baseRsltVec = null;
		// BaseEBCResultAU fsBaseRslt = maECFHouseholdBase.getEBCResult(fsRslt.getAuId());//@CodeClean
		EBCResultBase fsBaseRslt = maECFDelta.getEBCResultBase(fsRslt.getAuId());
		MAClient maClientDelta = maECFDelta.getMAClient(clientId);
		MAClient maClientBase = maECF.getMAClient(clientId);
		if (fsRslt.getDeverReason().isNotEmpty()) {
			deverReasonWrapper = new StringData(fsRslt.getDeverReason().toString());
			setFinancialValue(fsRslt, BENEFIT, DEVERREASON, fsRslt.getDeverReason().toString());
		}
		String capRsn = null;
		EligFactorRsnDtl eligFacRsnDtl = getEligFactorRsnDtl(maClientDelta.getFields().getContext(), deverReasonWrapper);
		String tbaFlg = getFinancialObjectStringValue(fsRslt, BENEFIT, TBAFLAG).toString();
		for (EDBCResult ebcObj : ebcObjectVector) {
			if (ebcObj.getAuId().intValue() == fsRslt.getAuId().intValue()) {
				capRsn = ebcObj.getPriorityCAPReason();
				break;
			}
		}
		if (deverSituation.equals(CAP_DEVER)) {
			EligFactorRsnDtl capEligFacRsn = null;
			BenefitChangeRsnFactor benChangeRsnFactor = (BenefitChangeRsnFactor) mapper.fetch(maClientDelta.getFields()
			                .getContext(), BenefitChangeRsnFactor.class, capRsn);
			if (benChangeRsnFactor != null) {
				capEligFacRsn = (EligFactorRsnDtl) mapper.fetch(maClientDelta.getFields().getContext(),
				                EligFactorRsnDtl.class, benChangeRsnFactor.getEligFactorRsnElig().toString());
				if (capEligFacRsn != null
				                && (capEligFacRsn.getDeverFsRecalcFlag().isEmpty() || (capEligFacRsn
				                                .getDeverFsRecalcFlag().isNotEmpty() && capEligFacRsn
				                                .getDeverFsRecalcFlag().isFalse()))
				                && !capEligFacRsn.getDeverCode().toString().equals("T78")) {

					InterviewWrapUpEDBCResult tmpFSRslt = (InterviewWrapUpEDBCResult) fsRslt.clone(true);
					fsRslt = copyReleaseRsltToCurRslt(maECFDelta, maClientDelta, tmpFSRslt.getAuId(), tmpFSRslt.getRequestId());
					/*
					 * Reset the potential universal flag to null when we copy released result to the result which is
					 * being processed
					 */
					resetPotentialUniversalFlg(fsRslt, ebcObjectVector);
					fsRslt.setBenefitEffective(tmpFSRslt.getBenefitEffective());
					fsRslt.setRevalStart(tmpFSRslt.getRevalStart());
					fsRslt.setRevalEnd(tmpFSRslt.getRevalEnd());
					fsRslt.setRevalType(tmpFSRslt.getRevalType());
					setFinancialValue(fsRslt, BENEFIT, EBCBENEFITEFFECTIVEDATE, tmpFSRslt.getBenefitEffective()
					                .toLocaleString());
					double prevBenAmt = Double.parseDouble(getFinancialObjectStringValue(tmpFSRslt, BENEFIT,
					                PREVIOUSBENEFITAMOUNT));
					setFinancialValue(fsRslt, BENEFIT, PREVIOUSBENEFITAMOUNT, prevBenAmt);
					String relDte = getFinancialObjectStringValue(tmpFSRslt, EBCDATA, RELEASEDATE);
					setFinancialValue(fsRslt, EBCDATA, RELEASEDATE, relDte);
					fsRslt.setRsltReleaseDte(tmpFSRslt.getRsltReleaseDte());
					fsRslt.setPgmStructParId(tmpFSRslt.getPgmStructParId());
					fsRslt.setPgmSubTypeDate(tmpFSRslt.getPgmSubTypeDate());
					ProgramStructure programStructure = (ProgramStructure) maClientDelta.getFields().getSeqField(
					                ProgramStructure.class, tmpFSRslt.getPgmStructParId());
					if (programStructure != null && programStructure.getProgramCode().isNotEmpty()) {
						fsRslt.setPgmSubType(programStructure.getDisplayCode());
					}
					xmlValue = getFinancialObjectStringValue(tmpFSRslt, NOTICES, "NoticeTypeID");
					// xmlValue = EBCServices.getValue(interviewWrapUpEDBCResult.getResultXML(), NOTICES,
					// "NoticeTypeID");
					if (xmlValue != null && !xmlValue.equals("")) {
						noticeId = Integer.parseInt(xmlValue);
						ebcNotice = (EBCNotice) mapper.fetch(maClientDelta.getFields().getContext(), EBCNotice.class,
						                noticeId);
						if (ebcNotice != null && ebcNotice.getGenericDsc().isNotEmpty()) {
							noticeType = ebcNotice.getGenericDsc().toString();
						}
					}
					else {
						noticeType = getFinancialObjectStringValue(tmpFSRslt, NOTICES, NOTICETYPE);
					}
					removeIneligRsnWhileCopyingRelasedResult(fsRslt.getAuMembResults());
					setFinancialValue(fsRslt, NOTICES, NOTICETYPE, noticeType);
					setFinancialValue(fsRslt, NOTICES, "NoticeTypeID", xmlValue);
					setFinancialValue(fsRslt, STANDARDAMOUNTS, CAPIND, getFinancialObjectStringValue(tmpFSRslt,
					                STANDARDAMOUNTS, CAPIND));
					setFinancialValue(fsRslt, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, getFinancialObjectStringValue(
					                tmpFSRslt, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS));
					setFinancialValue(fsRslt, STANDARDAMOUNTS, CAPELIGIBILITYSTATUS, tmpFSRslt
					                .getCapEligibilityStatus().toString());
					fsRslt.getBenefitChangeReasonVector().addAll(tmpFSRslt.getBenefitChangeReasonVector());
					fsRslt.getCapReasons().addAll(tmpFSRslt.getCapReasons());

					fsRslt.setWaivePendPeriod(false);
					setFinancialValue(fsRslt, EBCDATA, WAIVEPENDINGPERIOD, NO);
					fsRslt.setSuppressNotice(false);
					fsRslt.setSuppAppealsLang(false);
					setFinancialValue(fsRslt, STANDARDAMOUNTS, FSCAPDEFAULTSFLAG, YES);
					addResultToVector(fsRslt, rsltDeltaVec);

				}
			}
		}
		else if (fsRslt.getProgram().equals(SNAP) && (tbaFlg != null && tbaFlg.equalsIgnoreCase(YES))) {
			// Do not use released result
			// Do not transfer to a Dever specialist
		}
		else if (fsRslt.getProgram().equals(SNAP)
					&& isReevaluationVerificationSelected(maECFDelta, maClientDelta,
							fsRslt.getAuId(), VER_DATA_ID_140, true, false)) {
			// Do not use released result
			// Do not reset reevaluation data
			// Do not transfer to a Dever specialist

			return;
		}

		// Set Categorical Eligibility information for TANF closure
		for (InterviewWrapUpEDBCResult rslt : rsltDeltaVec) {
			if (rslt.getProgram().equals(TANF)) {
				if (rslt.getStatus().equals(CLOSED)) {
					setFinancialValue(fsRslt, STANDARDAMOUNTS, CATELIGFLAG, YES);
					setFinancialValue(fsRslt, STANDARDAMOUNTS, CATELIGREASON, TANF);
				}
			}
		}

		// Set Reevaluation information
		tmpStart = getFirstCyclePymtDateOnOrAfterBenEffDate(maClientDelta, fsRslt);
		BEACONAUEligReevaluation auEligReeval = maClientDelta.getBEACONAUEligReevaluation(fsRslt.getAuId());
		DateData curEffDte = new DateData(maClientDelta.getFields().getContext().getEffectiveDate());
		if (deverSituation.equals(CAP_DEVER)) {
			// CAP Dever, evaluate for EDSAP vs SIMRPT reevaluation type. Do not change the start/end dates.
			Vector intWrapRsltVect = maECF.getInterviewWrapUpEDBCResults();
			boolean isEDSAPReportingFlag = isEDSAPReporting(maECF, maClientDelta, maECF.getMAClient(clientId), ebcObjectVector, intWrapRsltVect, fsRslt);
			if (isEDSAPReportingFlag) {
				fsRslt.setRevalType(EDSAP_REPORTING);
			}
			else {
				fsRslt.setRevalType(SIMPLIFIED_REPORTING);
			}
		}
		else if (fsRslt != null && fsRslt.getProgram().equals(SNAP) && tbaFlg.equalsIgnoreCase(YES)) {
			//fsRslt.setRevalType(RECERTIFICATION);
			if(auEligReeval !=null && auEligReeval.getReevalType().isNotEmpty()) {
				fsRslt.setRevalType(auEligReeval.getReevalType());
			}
			fsRslt.setRevalStart(tmpStart);
			fsRslt.setRevalEnd(getEbcCycleEndDate(maClientDelta, fsRslt, tmpStart.addMonths(4)));
		}
	}

	/*
	 * The method is called from processDever method when copyReleaseRsltToCurRslt is performed. potentialUniversalFlag
	 * is reset to null in this case. Reset the potential universal flag to null when we copy released result to the
	 * result which is being processed.
	 */
	private static void resetPotentialUniversalFlg(InterviewWrapUpEDBCResult fsRslt, Vector<EDBCResult> ebcObjVect) {
		for (EDBCResult ebcObj : ebcObjVect) {
			if (ebcObj.getAuId().isNotEmpty() && fsRslt.getAuId().isNotEmpty()
			                && ebcObj.getAuId().equals(fsRslt.getAuId())) {
				ebcObj.setPotentialUniversalFlag(null);
				break;
			}
		}
	}

	public static void addResultToVector(InterviewWrapUpEDBCResult rslt, Vector<InterviewWrapUpEDBCResult> rsltVec) {
		int iCnt = 0;
		for (InterviewWrapUpEDBCResult tmpRslt : rsltVec) {
			if (tmpRslt.getAuId().intValue() == rslt.getAuId().intValue()) {
				if (tmpRslt.getTemporaryId() > 0) {
					rslt.temporaryId = tmpRslt.temporaryId;
				}
				rsltVec.set(iCnt, rslt);
				break;
			}
			iCnt++;
		}
	}

	/**
	 * Method to supress the selected Member Inelig reasons while copying the base result in Dever logic.
	 *
	 * @param rsltMembVec
	 * @throws Exception
	 */
	public static void removeIneligRsnWhileCopyingRelasedResult(Vector<EDBCResultAUMember> rsltMembVec)
	                throws Exception {
		for (EDBCResultAUMember rsltMemb : rsltMembVec) {
			if (rsltMemb.getMemIneligReason().equals("009000") || rsltMemb.getMemIneligReason().equals("009001")
			                || rsltMemb.getMemIneligReason().equals("009002")
			                || rsltMemb.getMemIneligReason().equals("009003")
			                || rsltMemb.getMemIneligReason().equals("009004")
			                || rsltMemb.getMemIneligReason().equals("009005")
			                || rsltMemb.getMemIneligReason().equals("009006")) {
				rsltMemb.getMemIneligReason().setNull();
			}
		}
	}

	/**
	 * This method Do the Below: When a Dever situation exists, a Dever Reason must be determined. A Dever Reason is
	 * nothing more thaneither the EFRC associated with the CAP closing reason or the EFRC which was used to close the
	 * related cash AU or AU member. This reason will determine what impact the Dever situation will have on the SNAP
	 * eligibility result.
	 *
	 * @param deverFSResult
	 * @param maECFHouseholdDelta
	 * @param maECFHouseholdBase
	 * @param maClientDelta
	 * @param maClientBase
	 * @param ebcObjectVector
	 * @param interviewWrapUpEDBCResultBaseVector
	 * @return
	 * @throws Exception
	 */
	public static String determineDeverReasonLogic(InterviewWrapUpEDBCResult deverFSResult,
	                                               MAECFHousehold maECFHouseholdDelta, MAECFHousehold maECFRule,
	                                               Vector ebcObjectVector,
	                                               String deverSituation, int clientId) throws Exception {
		String deverEFRC = "";
		StringData deverReason = new StringData();
		AuInEligFactor auInEligFactor = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		EDBCResult edbcResult = null;
		Vector interviewWrapupEDBCResultVector = null;
		Enumeration ebcObjectEnum = null;
		Enumeration interviewWrapupEDBCResultEnum = null;
		interviewWrapupEDBCResultVector = maECFHouseholdDelta.getInterviewWrapUpEDBCResults();
		interviewWrapupEDBCResultEnum = interviewWrapupEDBCResultVector.elements();
		boolean reasonFlag = false;
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		MAClient maClientECFRule = maECFRule.getMAClient(clientId);
		while (interviewWrapupEDBCResultEnum.hasMoreElements()) {
			interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) interviewWrapupEDBCResultEnum.nextElement();
			BenefitChangeRsnFactor benefitChangeRsnFactor = null;
			EligFactorRsnDtl elifactDtl = null;
			Vector auIneligFactorVect = maClientECFRule.getAuInEligFactor(interviewWrapUpEDBCResult.getAuId());
			BaseAUStatus asstStatus = maClientDelta.getAssistUnitStatus(interviewWrapUpEDBCResult.getAuId());
			if (auIneligFactorVect != null && auIneligFactorVect.size() > 0) {
				auInEligFactor = (AuInEligFactor) auIneligFactorVect.get(0);
				elifactDtl = getEligFactorRsnDtl(maClientECFRule.getFields().getContext(), auInEligFactor
				                .getEligFactorReason());
			}
			if (deverSituation.equals(CAP_DEVER)) {
				ebcObjectEnum = ebcObjectVector.elements();
				while (ebcObjectEnum.hasMoreElements()) {
					edbcResult = (EDBCResult) ebcObjectEnum.nextElement();
					if (deverFSResult.getDeverSituationFlag().booleanValue()
					                && interviewWrapUpEDBCResult.getAuId().intValue() == edbcResult.getAuId()
					                                .intValue() && edbcResult.getPriorityCAPReason() != null
					                && !edbcResult.getPriorityCAPReason().equals("")) {
						StringData priorityReason = new StringData(edbcResult.getPriorityCAPReason());
						benefitChangeRsnFactor = getBenefitChangeReasonFactor(maClientDelta.getFields().getContext(),
						                priorityReason);
						EligFactorRsnDtl eligFactorRsnDtl = (EligFactorRsnDtl) mapper.fetch(maClientDelta.getFields()
						                .getContext(), EligFactorRsnDtl.class, benefitChangeRsnFactor
						                .getEligFactorRsnElig().toString());
						deverEFRC = eligFactorRsnDtl.getDeverCode().toString();
						reasonFlag = true;
					}
				}
			}
			if (!reasonFlag
			                && deverFSResult.getProgram().equals(SNAP)
			                && (deverFSResult.getFinancials() != null && deverFSResult.getFinancialValueString(BENEFIT,
			                                TBAFLAG).equalsIgnoreCase(YES))
			                && isFSGranteeAlsoClosingTafdcGrantee(maECFHouseholdDelta, SNAP, TANF)
			                && interviewWrapUpEDBCResult.getProgram().toString().equalsIgnoreCase(TANF)
			                && (elifactDtl != null && elifactDtl.getTbaFlag().isNotEmpty() && elifactDtl.getTbaFlag()
			                                .toString().equalsIgnoreCase(TRUE))) {
				// TBA Dever Reason
				deverEFRC = interviewWrapUpEDBCResult.getAuEFRC().toString();
				reasonFlag = true;
			}
			if (!reasonFlag
			                && (interviewWrapUpEDBCResult.getProgram().equals(TANF) || interviewWrapUpEDBCResult
			                                .getProgram().equals(EAEDC))
			                && interviewWrapUpEDBCResult.getStatus().equals(CLOSED)
			                && isFSMembInCashResult(deverFSResult, maECFHouseholdDelta, maClientDelta, "", deverReason)) {
				if (deverReason.isNotEmpty()) {
					deverEFRC = deverReason.toString();
				}
				reasonFlag = true;
			}
			if (!reasonFlag
			                && (interviewWrapUpEDBCResult.getProgram().equals(TANF) || interviewWrapUpEDBCResult
			                                .getProgram().equals(EAEDC))
			                && isBenefitDecreased(maECFHouseholdDelta, interviewWrapUpEDBCResult)
			                && isFSMembInCashResult(deverFSResult, maECFHouseholdDelta, maClientDelta,
			                                "WITH_CLOSED_OR_INELIG", deverReason)) {
				if (deverReason.isNotEmpty()) {
					deverEFRC = deverReason.toString();
				}
				reasonFlag = true;
			}
			if (!reasonFlag) {
				// Dever Reason could not be determined from an EFRC. This situation
				// will occur for a switch from PA to NPA without any cash closure (i.e.
				// due to loss of SSI income or loss of a PA responsibility. See process
				// section below for actions taken (1. use new calculation; 2. set reeval
				// period to 45 days; 3. do not transfer to a specialist)
				deverEFRC = "EBCdefault";
			}
		}
		return deverEFRC;
	}

	/**
	 * it checks the any active SNAP member is also in the TANF/EAEDC AU
	 *
	 * @param deverFSResult
	 *            is an InterviewWrapUpEDBCResult.
	 * @param maECFHouseholdDeltais
	 *            an MAECFHousehold
	 * @return
	 * @throws Exception
	 */
	public static boolean isFSMembInCashResult(InterviewWrapUpEDBCResult deverFSResult,
	                                           MAECFHousehold maECFHouseholdDelta, MAClient maClient, String inParm,
	                                           StringData deverReason) throws Exception {
		boolean returnFlag = false;
		Vector<InterviewWrapUpEDBCResult> rsltVec = maECFHouseholdDelta.getInterviewWrapUpEDBCResults();
		Vector<EDBCResultAUMember> fsRsltMembVector = deverFSResult.getAuMembResults();
		Vector<EDBCResultAUMember> rsltMembVec = null;

		// parameter for historical calculation purposes
		Parameter p = ParameterCache.getInstance().getParameter(maECFHouseholdDelta.getFields().getContext(), EBC_EAEDC_NODEVER_000402_DATE_PARAM);
		DateData myEAEDCDate = new DateData();
		if (p != null) {
			myEAEDCDate = new DateData(p.getParameterValue());
		}

		for (EDBCResultAUMember fsRsltMemb : fsRsltMembVector) {
			// Active SNAP member
			if (fsRsltMemb.getMemStatus().equals(ACTIVE)) {
				for (InterviewWrapUpEDBCResult rsltObj : rsltVec) {
					if (rsltObj.getProgram().equals(TANF) || rsltObj.getProgram().equals(EAEDC)) {
						rsltMembVec = rsltObj.getAuMembResults();
						for (EDBCResultAUMember rsltMemb : rsltMembVec) {
							if (rsltMemb.getClientId().intValue() == fsRsltMemb.getClientId().intValue()) {
								// Any active SNAP member is also in the TANF/EAEDC AU and
								// TAFD/EAEDC member status was changed from active to closed or ineligible
								if (inParm.equals("WITH_CLOSED_OR_INELIG")) {
									if (maClient.isClientStatusInPgm(rsltMemb.getClientId(), rsltObj.getAuId(),
									                ACTIVE_STATUS)
									                && (rsltMemb.getMemStatus().equals(CLOSED) || rsltMemb
									                                .getMemStatus().equals(INELIGIBLE))) {
										deverReason.setString(rsltMemb.getMemIneligReason());
										return true;
									}
								}
								else {
									// any active SNAP member is also in the closing TANF/EAEDC AU
									if (rsltObj.getStatus().equals(CLOSED)) {
										if (rsltObj.getProgram().equals(TANF)) {
											deverReason.setString(rsltObj.getAuEFRC());
											return true;
										}
										if (rsltObj.getProgram().equals(EAEDC)) {
											//don't set dever reason
											if (rsltObj.getAuEFRC().equals(BatchConstants.ELIG_FACTOR_RSN_CODE) && myEAEDCDate.isNotEmpty() && !maECFHouseholdDelta.getFields().getContext().getEffectiveDate().before(myEAEDCDate)) {
												deverReason.setString("EXCLUDE");
												return true;
											}
											else {
												deverReason.setString(rsltObj.getAuEFRC());
												return true;
											}
										}
									}
								}
							}
						}
					}
				}
			}
		}
		return false;
	}

	/**
	 * This method is used to identify the dever situation for the result.
	 *
	 * @param maECFHouseholdDelta
	 *            holds data for maECFHousehold for Delta schema
	 * @param maECFHouseholdBase
	 *            holds data for maECFHousehold for Base schema
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param maClientBase
	 *            holds data for maClient for Base schema
	 * @param ebcObjectVector
	 *            the edbc Result object
	 * @param interviewWrapUpEDBCResultBaseVector
	 *            holds data for interviewWrapUpEDBCResult for Base schema
	 * @return the boolean to identify the dever situation.
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static String identifyDeverSituation(MAECFHousehold maECFHouseholdDelta, Vector<EDBCResult> ebcObjectVector,
	                                            Vector<InterviewWrapUpEDBCResult> baseEBCRsltVec,
	                                            InterviewWrapUpEDBCResult fsRslt, int clientId) throws Exception {
		String deverSituation = "";
		boolean isRelRsltFSActiveORPendFlg = false;
		EDBCResultFinancial financialRsltCAPVal = fsRslt.getFinancialObject("StandardAmounts", "CAPInd");
		MAClient maClientDelta = maECFHouseholdDelta.getMAClient(clientId);
		if (fsRslt != null && fsRslt.getProgram().equals(SNAP) && fsRslt.getStatus().equals(ACTIVE)
		                && (financialRsltCAPVal != null && financialRsltCAPVal.getValue().equals(""))) {
			// CAP Dever Situation
			for (EDBCResult edbcRslt : ebcObjectVector) {
				if (edbcRslt.getAuId().equals(fsRslt.getAuId())) {
					if (edbcRslt.isEBCActiveCAP(maECFHouseholdDelta, maClientDelta)) {
						StringData priorityReason = new StringData(edbcRslt.getPriorityCAPReason());
						EligFactorRsnDtl eligFactorRsnDtl = null;
						BenefitChangeRsnFactor benChangeRsnFactor = (BenefitChangeRsnFactor) mapper.fetch(maClientDelta
						                .getFields().getContext(), BenefitChangeRsnFactor.class, priorityReason
						                .toString());
						if (benChangeRsnFactor != null) {
							eligFactorRsnDtl = (EligFactorRsnDtl) mapper.fetch(maClientDelta.getFields().getContext(),
							                EligFactorRsnDtl.class, benChangeRsnFactor.getEligFactorRsnElig()
							                                .toString());
							if (eligFactorRsnDtl != null
							                && eligFactorRsnDtl.getDeverCode().isNotEmpty()
							                && (eligFactorRsnDtl.getDeverCode().toString().equals("T6") || eligFactorRsnDtl
							                                .getDeverCode().toString().equals("T78"))) {
								deverSituation = CAP_DEVER;
								break;
							}
						}
					}
				}
			}
			// Dever Situation
			if (!deverSituation.equals(CAP_DEVER)) {
				if (baseEBCRsltVec != null && baseEBCRsltVec.size() > 0) {
					for (InterviewWrapUpEDBCResult baseRslt : baseEBCRsltVec) {
						if (baseRslt.getAuId().equals(fsRslt.getAuId())
						                && (baseRslt.getStatus().equals(PENDING) || baseRslt.getStatus().equals(ACTIVE))) {
							isRelRsltFSActiveORPendFlg = true;
							break;
						}
					}
				}
				AUSubType auSubType = maClientDelta.getAUSubType(fsRslt.getAuId());
				if (isRelRsltFSActiveORPendFlg && auSubType.getPgmStructId().intValue() == 100 // SNAP current subtype is
				                // PA (100)
				                && doesRequestContainACashResult(maECFHouseholdDelta) // request contains a TANF or
				                // EAEDC result
				                && (fsRslt.getPgmStructParId().intValue() == 101 // Result SNAP subtype is PA (100)
				                || (doesRequestContainCashClosureForFSMembers(fsRslt.getAuMembResults(),
				                                maECFHouseholdDelta) && doesAUHaveSSIAndNoCash(fsRslt
				                                .getAuMembResults(), maClientDelta, maECFHouseholdDelta)))) {
					deverSituation = NORMAL_DEVER;
				}
			}
		}
		return deverSituation;
	}

	public static boolean doesRequestContainACashResult(MAECFHousehold household) throws Exception {
		Vector<InterviewWrapUpEDBCResult> rsltVec = household.getInterviewWrapUpEDBCResults();
		for (InterviewWrapUpEDBCResult rslt : rsltVec) {
			if (rslt.getProgram().toString().equals(TANF) || rslt.getProgram().toString().equals(EAEDC)) {
				return true;
			}
		}
		return false;
	}

	public static boolean doesRequestContainCashClosureForFSMembers(Vector<EDBCResultAUMember> rsltMembVec,
	                                                                MAECFHousehold household) throws Exception {
		for (EDBCResultAUMember rsltMemb : rsltMembVec) {
			if (rsltMemb.getMemStatus().equals(ACTIVE)) {
				Vector<InterviewWrapUpEDBCResult> rsltVec = household.getInterviewWrapUpEDBCResults();
				for (InterviewWrapUpEDBCResult rslt : rsltVec) {
					if (rslt.getProgram().equals(TANF) || rslt.getProgram().equals(EAEDC)) {
						if (isAPClosedInAU(rslt, rsltMemb.getClientId().intValue())) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

	public static boolean isAPClosedInAU(InterviewWrapUpEDBCResult inRslt, int clientId) throws Exception {
		Vector rsltMembVec = inRslt.getAuMembResults();
		if (rsltMembVec != null && rsltMembVec.size() > 0) {
			Enumeration rsltMembEnum = rsltMembVec.elements();
			while (rsltMembEnum.hasMoreElements()) {
				EDBCResultAUMember edbcResultAUMember = (EDBCResultAUMember) rsltMembEnum.nextElement();
				if ((edbcResultAUMember.getClientId().isNotEmpty() && edbcResultAUMember.getClientId().intValue() == clientId)
				                && edbcResultAUMember.getMemStatus().isNotEmpty()
				                && edbcResultAUMember.getMemStatus().toString().equals(CLOSED)) {
					return true;
				}
			}
		}
		return false;
	}

	public static boolean doesAUHaveSSIAndNoCash(Vector rsltMembVec, MAClient maClient, MAECFHousehold household)
	                throws Exception {
		boolean retFlg = true;
		if (rsltMembVec != null && rsltMembVec.size() > 0) {
			// All active SNAP members must be active in cash
			Enumeration rsltMembEnum = rsltMembVec.elements();
			while (rsltMembEnum.hasMoreElements()) {
				EDBCResultAUMember edbcResultAUMember = (EDBCResultAUMember) rsltMembEnum.nextElement();
				if (edbcResultAUMember.getMemStatus().isNotEmpty()
				                && edbcResultAUMember.getMemStatus().toString().equals(ACTIVE)) {
					if (isAPActiveinCashAU(edbcResultAUMember.getClientId().intValue(), household)) {
						retFlg = false;
						break;
					}
				}
			}

			// All active SNAP members msut have SSI
			Enumeration rsltMembEnum1 = rsltMembVec.elements();
			while (rsltMembEnum1.hasMoreElements()) {
				EDBCResultAUMember edbcResultAUMember = (EDBCResultAUMember) rsltMembEnum1.nextElement();
				if (edbcResultAUMember.getMemStatus().isNotEmpty()
				                && edbcResultAUMember.getMemStatus().toString().equals(ACTIVE)) {
					if (!allHaveSSIIncome(maClient, edbcResultAUMember)) {
						retFlg = false;
						break;
					}
				}
			}
		}
		return retFlg;
	}

	public static boolean isAPActiveinCashAU(int clientId, MAECFHousehold household) throws Exception {
		// Method determines if the input AP is active in a TANF AU within finaicial eligibility results
		Vector rsltMembVec = null;
		Enumeration rsltMembEnum;
		Vector rsltVec = household.getInterviewWrapUpEDBCResults();
		Enumeration rsltEnum;
		if (rsltVec != null && rsltVec.size() > 0) {
			rsltEnum = rsltVec.elements();
			while (rsltEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult rsltObj = (InterviewWrapUpEDBCResult) rsltEnum.nextElement();
				if (rsltObj.getProgram().isNotEmpty()
				                && (rsltObj.getProgram().toString().equals(TANF) || rsltObj.getProgram().toString()
				                                .equals(EAEDC))) {
					rsltMembVec = rsltObj.getAuMembResults();
					if (rsltMembVec != null && rsltMembVec.size() > 0) {
						rsltMembEnum = rsltMembVec.elements();
						while (rsltMembEnum.hasMoreElements()) {
							EDBCResultAUMember rsltMembObj = (EDBCResultAUMember) rsltMembEnum.nextElement();
							if ((rsltMembObj.getClientId().intValue() == clientId)
							                && rsltMembObj.getMemStatus().isNotEmpty()
							                && rsltMembObj.getMemStatus().toString().equals(ACTIVE)) {
								return true;
							}
						}
					}
				}
			}
		}
		return false;
	}

	public static boolean allHaveSSIIncome(MAClient maClientDelta, EDBCResultAUMember edbcResultAUMember)
	                throws Exception {
		Vector<ClientUI> clientUIVector = maClientDelta.getClientUI(edbcResultAUMember.getClientId());
		for (ClientUI otherIncome : clientUIVector) {
			if (otherIncome.getOtherIncType().equals("SSI")) {
				return true;
			}
		}
		return false;
	}


	/**
	 * The method identify that the client have SSI income or not.
	 *
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param edbcResultAUMember
	 *            an EDBCResultAUMember object
	 * @return the boolean to identify that the client have SSI income or not
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static boolean haveSSIIncome(MAClient maClientDelta, EDBCResultAUMember edbcResultAUMember) throws Exception {
		Vector clientUIVector = maClientDelta.getClientUI(edbcResultAUMember.getClientId());
		Enumeration clientUIEnum = clientUIVector.elements();
		while (clientUIEnum.hasMoreElements()) {
			ClientUI clientUI = (ClientUI) clientUIEnum.nextElement();
			if (clientUI.getOtherIncType().isNotEmpty()
			                && clientUI.getOtherIncType().toString().equalsIgnoreCase("SSI")) {
				return true;
			}
		}
		return false;
	}

	public static boolean haveActiveSSIIncome(MAClient maClientDelta, EDBCResultAUMember edbcResultAUMember) throws Exception {
		Vector clientUIVector = maClientDelta.getClientUI(edbcResultAUMember.getClientId());
		Enumeration clientUIEnum = clientUIVector.elements();
		while (clientUIEnum.hasMoreElements()) {
			ClientUI clientUI = (ClientUI) clientUIEnum.nextElement();
			if (clientUI.getOtherIncType().isNotEmpty()
			                && clientUI.getOtherIncType().toString().equalsIgnoreCase("SSI")
			                && clientUI.getOtherIncStatus().isNotEmpty()
			                && clientUI.getOtherIncStatus().toString().equalsIgnoreCase("ACTIVE") ) {
				return true;
			}
		}
		return false;
	}
	/**
	 * The method identify Reevaluation end date to more than 12 months from the Reevaluation start date for an active SNAP.
	 *
	 * @param maECFRule
	 *            holds data for mAECFHousehold for Delta schema
	 * @param clientId
	 *            an IntegerData object
	 * @return the boolean to identify If the worker changed the Reevaluation end date to more than 12 months from the Reevaluation start date for an active SNAP AU
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static boolean isReevaluationEndDate(MAClient maClient , IntegerData clientId)throws Exception {
		ClientDisabilityPage clientDisability = maClient.getClientDisabilityPage(clientId);
        int age = maClient.getAgeOfClient(clientId);
        if(age >= 18 && age <= 59
        				&& (clientDisability == null
        								|| (clientDisability != null
        												&& clientDisability.getDisabledFlg().isNotEmpty()
        												&& clientDisability.getDisabledFlg().isFalse()))){
              return true;
        }

		return false;
	}

	/**
	 * The method used to reterive the First Cycle Payment Date for after benefit date from EBC_CYCLE_DTE.
	 *
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param interviewWrapUpEDBCResult
	 *            holds the interviewWrapUpEDBCResult object.
	 * @return holds DateData of First Cycle Payment Date.
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static DateData getFirstCyclePymtDateAfterBenEffDate(MAClient maClientDelta,
	                                                            InterviewWrapUpEDBCResult cashRslt) throws Exception {
		DateData tmpStartDate = null;
		EbcCycleDate ebcCycleDate = getEbcCycleDate(maClientDelta, cashRslt.getAuId(), cashRslt.getBenefitEffective());
		if (ebcCycleDate != null && ebcCycleDate.getFirstCycStdPmtDate().isNotEmpty()) {
			if (ebcCycleDate.getFirstCycStdPmtDate().after(cashRslt.getBenefitEffective())) {
				return ebcCycleDate.getFirstCycStdPmtDate();
			}
			else {
				DateData effectiveDate = new DateData(cashRslt.getBenefitEffective());
				EbcCycleDate ebcCycleFirstPymtDate = getEbcCycleDate(maClientDelta, cashRslt.getAuId(), effectiveDate
				                .addMonths(1));
				return ebcCycleFirstPymtDate.getFirstCycStdPmtDate();
			}
		}
		return tmpStartDate;
	}

	/**
	 * The method used to reterive the First Cycle Payment Date for on or after benefit date from EBC_CYCLE_DTE.
	 *
	 * @param maClientDelta
	 * @param interviewWrapUpEDBCResult
	 * @return
	 * @throws Exception
	 */
	public static DateData getFirstCyclePymtDateOnOrAfterBenEffDate(MAClient maClientDelta,
	                                                                InterviewWrapUpEDBCResult interviewWrapUpEDBCResult)
	                throws Exception {
		EbcCycleDate ebcCycleDate = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(),
		    interviewWrapUpEDBCResult.getBenefitEffective());
		if (!ebcCycleDate.getFirstCycStdPmtDate().before(interviewWrapUpEDBCResult.getBenefitEffective())) {
			return ebcCycleDate.getFirstCycStdPmtDate();
		}
		else {
			DateData effectiveDate = new DateData(interviewWrapUpEDBCResult.getBenefitEffective());
			EbcCycleDate ebcCycleFirstPymtDate = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(),
			    effectiveDate.addMonths(1));
			return ebcCycleFirstPymtDate.getFirstCycStdPmtDate();
		}
	}

	/**
	 * The method used to reterive the First Cycle Payment Date on or before benefit date from EBC_CYCLE_DTE.
	 *
	 * @param maClientDelta
	 * @param intWrapRslt
	 * @return
	 * @throws Exception
	 */
	public static DateData getFirstCyclePymtDateOnOrBeforeBenEffDate(MAClient maClientDelta,
	                                                                InterviewWrapUpEDBCResult intWrapRslt)
	                throws Exception {
		EbcCycleDate ebcCycleDate = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), intWrapRslt.getBenefitEffective());
	
		if(ebcCycleDate != null) {
			if(intWrapRslt.getProgram().equals(SNAP)) {
			if (!ebcCycleDate.getFirstCycStdPmtDate().after(intWrapRslt.getBenefitEffective())) {
				return ebcCycleDate.getFirstCycStdPmtDate();
			}
			else {
				DateData effectiveDate = new DateData(intWrapRslt.getBenefitEffective());
				ebcCycleDate = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), effectiveDate.addMonths(-1));
				return ebcCycleDate.getFirstCycStdPmtDate();
			}
		 } else {
			 if (!ebcCycleDate.getTanfCycStdPmtDate().after(intWrapRslt.getBenefitEffective())) {
					return ebcCycleDate.getTanfCycStdPmtDate();
				}
				else {
					DateData effectiveDate = new DateData(intWrapRslt.getBenefitEffective());
					ebcCycleDate = getEbcCycleDate(maClientDelta, intWrapRslt.getAuId(), effectiveDate.addMonths(-1));
					return ebcCycleDate.getTanfCycStdPmtDate();
				}
		 }
		} else {
			return null;
		}
	}

	/**
	 * The method used to reterive the EBC Cycle End Date from EBC_CYCLE_DTE.
	 *
	 * @param maClientDelta
	 * @param interviewWrapUpEDBCResult
	 * @param tempStartDate
	 * @return
	 * @throws Exception
	 */
	public static DateData getEbcCycleEndDate(MAClient maClientDelta,
	                                          InterviewWrapUpEDBCResult interviewWrapUpEDBCResult,
	                                          DateData tempStartDate) throws Exception {

		EbcCycleDate ebcCycleDate = getEbcCycleDate(maClientDelta, interviewWrapUpEDBCResult.getAuId(), tempStartDate);
		if (ebcCycleDate != null && ebcCycleDate.getEnddate().isNotEmpty()) {
			return ebcCycleDate.getEnddate();
		}else
			return null;
	}

	/**
	 * The method identify whether worker assigned to SSI office or not.
	 *
	 * @param maClientDelta
	 *            holds data for maClient for Delta schema
	 * @param interviewWrapUpEDBCResult
	 *            holds the interviewWrapUpEDBCResult object.
	 * @return the boolean, whether worker assigned to SSI office or not.
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static boolean isAUAssignedWorkerInRegionalSSIOffice(MAClient maClientDelta,
	                                                            InterviewWrapUpEDBCResult interviewWrapUpEDBCResult)
	                throws Exception {
		// AU is assigned to a worker in a Regional SSI office
		BaseAUAssignment auAssignment = (BaseAUAssignment) maClientDelta.getFields().getField(
		                BaseAUAssignment.class, interviewWrapUpEDBCResult.getAuId());
		if (auAssignment != null && auAssignment.getBuId().isNotEmpty()) {
			ApplicationUser appUser = (ApplicationUser) maClientDelta.getFields().getSeqField(
			                ApplicationUser.class, auAssignment.getBuId());
			if (appUser != null && appUser.getOfficeLocationId().isNotEmpty()) {
				OrganizationLocationItem orgLocItem = maClientDelta.getOrganizationLocationItem(appUser
				                .getOfficeLocationId());
				if (orgLocItem != null && orgLocItem.getSsiFlag().isNotEmpty()
				                && orgLocItem.getSsiFlag().booleanValue()) {
					return true;
				}
			}
		}
		return false;
	}

	/**
	 * The method used to identify whether the SNAP grantee is also a closing grantee in TANF.
	 *
	 * @param maECFHousehold
	 *            holds data for maECFHousehold for Delta schema
	 * @param fsGrantee
	 *            hold the program code for SNAP.
	 * @param tafdcGrantee
	 *            hold the program code for TANF.
	 * @return the boolean to identify active SNAP is also TANF/EAEDC.
	 * @throws Exception
	 *             if any exception Occurs.
	 */
	public static boolean isFSGranteeAlsoClosingTafdcGrantee(MAECFHousehold maECFHousehold, String fsGrantee,
	                                                         String tafdcGrantee) throws Exception {
		InterviewWrapUpEDBCResult fsRslt = null;
		InterviewWrapUpEDBCResult tafdcRslt = null;
		Vector resultFS = getInterviewWrapUpEDBCResultsAU(maECFHousehold, fsGrantee);
		Vector resultTAFDC = getInterviewWrapUpEDBCResultsAU(maECFHousehold, tafdcGrantee);
		for (int i = 0; i < resultFS.size(); i++) {
			fsRslt = (InterviewWrapUpEDBCResult) resultFS.get(i);
			for (int j = 0; j < resultTAFDC.size(); j++) {
				tafdcRslt = (InterviewWrapUpEDBCResult) resultTAFDC.get(j);
				if (fsRslt.getGranteeId().isNotEmpty() && tafdcRslt.getGranteeId().isNotEmpty()
				                && (fsRslt.getGranteeId().intValue() == tafdcRslt.getGranteeId().intValue())
				                && tafdcRslt.getStatus().equals(CLOSED)) {
					return true;
				}
			}
		}
		return false;
	}

