	/**
	 * This method is used to validate the Re-evaluation End date.
	 *
	 * @param ctx
	 *            is an instance of Context.
	 * @param client
	 *            client id
	 * @param ebcRsltObj
	 *            view object
	 * @param reqReleaseDte
	 *            request release date
	 * @param curRevalEnd
	 *            current reevaluation end date
	 * @return boolean
	 * @throws Exception
	 */
	public static boolean isRevaluationEndValid(Context ctx, MAClient client, InterviewWrapUpEDBCResult ebcRsltObj,
	                                            DateData reqReleaseDte, DateData curRevalEnd) throws Exception {
		EbcCycleDate prevEbcCycleDate = null;
		EbcCycleDate curEbcCycleDate = null;
		EbcCycleDate nextEbcCycleDate = null;
		DateData prevRevalEnd = null;
		DateData nextRevalEnd = null;
		DateData tmpRevalEnd = null;
		DateData tmpRequestDte = null;
		int businessDays = 0;
		DateData assRelDate = null;
		OrganisationNonWorkingDay nonWorkingDay = null;
		if (reqReleaseDte != null
		                && !(ebcRsltObj.getExpedited().toString().equals(EXPEDITED_CODE) || ebcRsltObj.getExpedited()
		                                .toString().equals(SPECIAL_30_DAY_CODE))) {
			prevRevalEnd = new DateData(curRevalEnd);
			nextRevalEnd = new DateData(curRevalEnd);
			tmpRevalEnd = new DateData(curRevalEnd);
			tmpRevalEnd.addDays(1);
			prevEbcCycleDate = getEbcCycleDate(client, ebcRsltObj.getAuId(), prevRevalEnd.addMonths(-1));
			curEbcCycleDate = getEbcCycleDate(client, ebcRsltObj.getAuId(), curRevalEnd);
			nextEbcCycleDate = getEbcCycleDate(client, ebcRsltObj.getAuId(), nextRevalEnd.addMonths(1));

			if (prevEbcCycleDate != null && curEbcCycleDate != null && nextEbcCycleDate != null) {
				if (tmpRevalEnd.equals(curEbcCycleDate.getFirstCycStdPmtDate())) {
					assRelDate = curEbcCycleDate.getFirstCycRelDate();
				}
				else if (tmpRevalEnd.equals(prevEbcCycleDate.getFirstCycStdPmtDate())) {
					assRelDate = prevEbcCycleDate.getFirstCycRelDate();
				}
				else if (tmpRevalEnd.equals(nextEbcCycleDate.getFirstCycStdPmtDate())) {
					assRelDate = nextEbcCycleDate.getFirstCycRelDate();
				}
			}
			tmpRequestDte = new DateData(reqReleaseDte);
			if (assRelDate != null && assRelDate.isNotEmpty()) {
				int i = 0;
				for (; i <= 5;) {
					tmpRequestDte.addDays(1);
					nonWorkingDay = getOrgNonWorkDay(ctx, tmpRequestDte);
					if (nonWorkingDay == null) {
						i++;
					}
				}
				if (tmpRequestDte.after(assRelDate)) {
					return true;
				}
			}
		}
		return false;
	}

	/**
	 * This method returns the OrganisationNonWorkingDay of corresponding Non Work Dte code.
	 *
	 * @param effCtx
	 *            is an instance of Context.
	 * @param nonWorkDte
	 *            is an String Data
	 * @return the OrganisationNonWorkingDay object.
	 * @throws Exception
	 */
	public static OrganisationNonWorkingDay getOrgNonWorkDay(Context effCtx, DateData nonWorkDte) throws Exception {
		OrganisationNonWorkingDay orgNonWorkingDay = null;
		OrganisationNonWorkingDay organisationNonWorkingDay = new OrganisationNonWorkingDay();
		if (nonWorkDte != null) {
			organisationNonWorkingDay.setNonWorkDte(nonWorkDte);
			Vector orgNonWorkDay = mapper.fetchMany(effCtx, organisationNonWorkingDay, null);
			if (orgNonWorkDay != null && orgNonWorkDay.size() > 0) {
				orgNonWorkingDay = (OrganisationNonWorkingDay) orgNonWorkDay.elementAt(0);
			}
		}
		return orgNonWorkingDay;
	}

	/**
	 * To get the application date.
	 *
	 * @param mAClient
	 *            a MAClient object
	 * @param auId
	 *            program auid
	 * @return DateData
	 * @throws Exception
	 */
	public static DateData getApplicationDate(MAClient mAClient, IntegerData auId) throws Exception {
		DateData appdate = new DateData();
		ProgramApplicationHistory programApplicationHistory = null;
		ProgramApplicationHistoryAU pgmAppHist = (ProgramApplicationHistoryAU) mAClient.getFields().getField(
		                ProgramApplicationHistoryAU.class, auId);
		if ((pgmAppHist != null) && (pgmAppHist.getPgmAppDate().isNotEmpty())) {
			appdate.setTime( pgmAppHist.getPgmAppDate());
		}
		return appdate;
	}

