	/**
	 * @param categoryCode
	 *            the CategoryCode.
	 * @param ElementCode
	 *            the ElementCode.
	 * @return Returns the Corresponding value. Overloaded for Benefit Change Rules development.
	 */

	public static String getValue(Object resultXML, String categoryCode, String elementCode) throws Exception {
		Document resultDoc = null;
		String returnValue = "";
		String elementName = null;
		int categoryLen = 0;
		NodeList categoryList;
		String categoryName = null;
		Element root;
		StringData resultXMLStr = null;
		List<String>  tagLelementList = new ArrayList<String>(Arrays.asList(TAG_ELEMENT, TAG_ELEMENT_0));
		// Checking if the Object is String, StringData or ClobData,
		// based on that typecastng Object value.
		if (resultXML != null) {
			if (resultXML instanceof StringData) {
				resultXMLStr = (StringData) resultXML;
			}
			else if (resultXML instanceof ClobData) {
				resultXMLStr = new StringData(resultXML.toString());
			}
			else if (resultXML instanceof String) {
				resultXMLStr = new StringData(resultXML.toString());
			}
		}
		if ((resultDoc == null) && (resultXMLStr.isNotEmpty())) {
			StringReader reader = new StringReader(resultXMLStr.toString());
			resultDoc = XMLDocHelper.getInstance().getDocBuilder().parse(new InputSource(reader));
		}
		if (resultDoc != null) {
			categoryList = resultDoc.getElementsByTagName(TAG_CATEGORY);
			categoryLen = categoryList.getLength();
			for (int i = 0; i < categoryLen; i++) {
				root = (Element) categoryList.item(i);
				categoryName = root.getAttribute(TAG_ATTRIBUTE_NAME);
				if (categoryName.equalsIgnoreCase(categoryCode)) {
					for (Iterator<String> iterator = tagLelementList.iterator(); iterator.hasNext();) {
						String tagElement = (String) iterator.next();
						NodeList elementList = root.getElementsByTagName(tagElement);
						Element childNodes;
						int len = elementList.getLength();
						for (int j = 0; j < len; j++) {
							childNodes = (Element) elementList.item(j);
							elementName = childNodes.getAttribute(TAG_ATTRIBUTE_NAME);
							if (elementName.equalsIgnoreCase(elementCode)) {
								returnValue = childNodes.getAttribute(TAG_ATTRIBUTE_VALUE);
								break;
							}
						}
					}
					
				}
			}
		}
		return returnValue;
	}



