	/**
	 * This method checks the wether an AU is grantee of another au grantee.
	 *
	 * @param maEcf
	 *            is an instance of MAECFHousehold.
	 * @param wfData
	 *            is an instance of MAClient.
	 * @param currentResult
	 *            is an instance InterviewWrapUpEDBCResult.
	 * @param program
	 *            is a String value,
	 * @return the boolean value.
	 * @throws Exception
	 */
	public static boolean isOneAUGranteeInAnotherAUGrantee(MAECFHousehold maEcf, MAClient wfData,
	                                                       InterviewWrapUpEDBCResult currentResult, String program)
	                throws Exception {
		boolean returnFlag = false;
		InterviewWrapUpEDBCResult interViewResult = null;
		BaseAUMember baseAUMemb = null;
		BaseAUMember baseAUMembCurrent = null;
		Vector interviewWrapUpEDBCResultVect = maEcf.getInterviewWrapUpEDBCResults();
		Enumeration interviewWrapUpEDBCResultEnum = interviewWrapUpEDBCResultVect.elements();
		while (interviewWrapUpEDBCResultEnum.hasMoreElements()) {
			interViewResult = (InterviewWrapUpEDBCResult) interviewWrapUpEDBCResultEnum.nextElement();
			if (interViewResult.getProgram().toString().equals(program)) {
				baseAUMemb = wfData.getGranteeForAU(interViewResult.getAuId());
				baseAUMembCurrent = wfData.getGranteeForAU(currentResult.getAuId());
				if (baseAUMemb.getClientId().intValue() == baseAUMembCurrent.getClientId().intValue()) {
					returnFlag = true;
					break;
				}
			}
		}
		return returnFlag;
	}

	/**
	 * This method do the logic to find the Release date and Benefit Effective Date for each Result as per doc Benefit
	 * Effective Date and Release Date.doc (5 & 6).
	 *
	 * @param ctx
	 *            is an Context object.
	 * @param maEcf
	 *            is an instance of MAECFHousehold.
	 * @param wfData
	 *            is an instance of MAClient.
	 * @param interViewResult
	 *            is an Instance of InterviewWrapUpEDBCResult.
	 * @param ebcObj
	 *            is an instance of EDBCResult.
	 * @param releaseDate
	 *            is an DateData.
	 * @param benEffDate
	 *            is an DateData.
	 * @return the boolean value
	 * @throws Exception
	 */
	public static boolean conditionThree(Context ctx, MAECFHousehold maEcf, InterviewWrapUpEDBCResult interViewResult,
	                                     DateData releaseDate, DateData benEffDate, boolean batch, int clientId)
	                throws Exception {
		BaseAU asstUnit = null;
		boolean returnFlag = false;
		MAClient wfData = maEcf.getMAClient(clientId);
		asstUnit = wfData.getAsstUnit(interViewResult.getAuId());
		DateData dateValue = new DateData (ctx.getEffectiveDate());//DateData.getToday();
		if (interViewResult.getProgram().isNotEmpty()
		                && (interViewResult.getProgram().toString().equalsIgnoreCase(TANF) || interViewResult
		                                .getProgram().toString().equalsIgnoreCase(SNAP))) {
			// FEP change

			if (!returnFlag && interViewResult.getStatus().isNotEmpty()
			                && interViewResult.getStatus().toString().equalsIgnoreCase(ACTIVE) && asstUnit != null
			                && asstUnit.getId().isNotEmpty() && asstUnit.getProgramCode().isNotEmpty()) {
				// FEB Change
				if (interViewResult.getProgram().toString().equalsIgnoreCase(TANF)
				                && isFEPSupplementChange(asstUnit, interViewResult, getMAECFHouseholdBase(maEcf)
				                                .getMAClient(clientId))) {
					releaseDate = getNextCycleReleaseDate(wfData, interViewResult.getAuId(), true, dateValue, false);
					benEffDate = getNextCyclePaymentDate(wfData, interViewResult.getAuId(), true, false, dateValue,
					                false);
					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
				}
				else if (interViewResult.getProgram().toString().equalsIgnoreCase(SNAP)
				                && isOneAUGranteeInAnotherAUGrantee(maEcf, wfData, interViewResult, TANF)
				                && isFEPSupplementChange(asstUnit, interViewResult, getMAECFHouseholdBase(maEcf)
				                                .getMAClient(clientId))) {
					releaseDate = getNextCycleReleaseDate(wfData, interViewResult.getAuId(), true, dateValue, false);
					benEffDate = getNextCyclePaymentDate(wfData, interViewResult.getAuId(), true, false, dateValue,
					                false);
					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
				}
				// FEP supplement
				if (interViewResult.getProgram().toString().equalsIgnoreCase(TANF)
				                && isFEPSupplement(asstUnit, interViewResult, getMAECFHouseholdBase(maEcf).getMAClient(clientId))) {
					if (batch)
						releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
					else
						releaseDate = ctx.getEffectiveDate();
					if (batch)
						benEffDate = new DateData(ctx.getEffectiveDate().getPreviousWorkDate()).addDays(23);
					else
						benEffDate = new DateData(ctx.getEffectiveDate()).addDays(23);

					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
					interViewResult.setNotAdjustRelDteFlag(true);
				}
				else if (interViewResult.getProgram().toString().equalsIgnoreCase(SNAP)
				                && isOneAUGranteeInAnotherAUGrantee(maEcf, wfData, interViewResult, TANF)
				                && isFEPSupplement(asstUnit, interViewResult, getMAECFHouseholdBase(maEcf).getMAClient(clientId))) {
					if (batch)
						releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
					else
						releaseDate = ctx.getEffectiveDate();
					if (batch)
						benEffDate = new DateData(ctx.getEffectiveDate().getPreviousWorkDate()).addDays(23);
					else
						benEffDate = new DateData(ctx.getEffectiveDate()).addDays(23);
					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
					interViewResult.setNotAdjustRelDteFlag(true);
				}
			}
		}
		return returnFlag;
	}

