	/**
	 * This method do the logic to find the Release date and Benefit Effective Date for each Result as per doc Benefit
	 * Effective Date and Release Date.doc (10 & 11).
	 *
	 * @param ctx
	 *            is an Context object.
	 * @param maEcf
	 *            is an instance of MAECFHousehold.
	 * @param wfData
	 *            is an instance of MAClient.
	 * @param interViewResult
	 *            is an Instance of InterviewWrapUpEDBCResult.
	 * @param ebcObj
	 *            is an instance of EDBCResult.
	 * @param releaseDate
	 *            is an DateData.
	 * @param benEffDate
	 *            is an DateData.
	 * @return the boolean value
	 * @throws Exception
	 */
	public static boolean conditionFive(Context ctx, MAECFHousehold maEcf, InterviewWrapUpEDBCResult interViewResult,
	                                    DateData releaseDate, DateData benEffDate, boolean batch, int clientId)
	                throws Exception {
		boolean returnFlag = false;
		BaseAU asstUnit = null;
		EBCResultBase ebcResult = null;
		DateData applicationDate = null;
		BaseAUStatus auStatus = null;
		EbcCycleDate ebcCycleDate = null;
		MAClient wfData = maEcf.getMAClient(clientId);
		asstUnit = wfData.getAsstUnit(interViewResult.getAuId());
		// ebcResult = mAECFHouseholdBase.getEBCResult(asstUnit.getId());//@CodeClean
		ebcResult = maEcf.getEBCResultBase(asstUnit.getId());
		DateData dateValue = null;
		DateData tmpBenEffDte = null;
		auStatus = (BaseAUStatus) wfData.getFields().getField(BaseAUStatus.class, interViewResult.getAuId());
		if (interViewResult.getProgram().toString().equalsIgnoreCase(SNAP)) {
			// Expedited to Active
			if (!returnFlag && isExpeditedToActive(interViewResult, asstUnit, ebcResult)) {
				if (batch)
					releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
				else
					releaseDate = ctx.getEffectiveDate();
				dateValue = ebcResult.getRevalEnd();
				tmpBenEffDte = new DateData(ebcResult.getRevalEnd()).addMonths(1);
				tmpBenEffDte.setDate(1);
				benEffDate = tmpBenEffDte;
				/*benEffDate = getNextCyclePaymentDateForExpFSBasedOnRelReevalEndDte(wfData, interViewResult.getAuId(),
				                false, false, dateValue);*/
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			if (!returnFlag && isSpecialExpeditedToActive(interViewResult, asstUnit, ebcResult)) {
				EbcCycleDate twoMonthEbcCycleDate = null;
				DateData firstCyclStdPaymentDate = new DateData();
				if (batch)
					releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
				else
					releaseDate = ctx.getEffectiveDate();
				dateValue = (DateData) ebcResult.getBenefitEffective().clone();
				ebcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), dateValue);
				firstCyclStdPaymentDate = ebcCycleDate.getFirstCycStdPmtDate();
				if (dateValue.before(firstCyclStdPaymentDate)) {
					twoMonthEbcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), dateValue.addMonths(1));
				}
				else {
					twoMonthEbcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), dateValue.addMonths(2));
				}
				benEffDate = twoMonthEbcCycleDate.getFirstCycStdPmtDate();
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			//delayrelease recert 11.5
			if (!returnFlag && isEarlyFSReeval(ctx, maEcf, interViewResult, batch, clientId)) {
				DateData tmpReleaseDate = null;
				DateData tmpBenEffDate = null;
				MAClient maClient = maEcf.getMAClient(clientId);
				if (batch) {
					releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
				} else {
					releaseDate = ctx.getEffectiveDate();
				}
				BEACONAUEligReevaluation auEligReeval = (BEACONAUEligReevaluation) maClient.getFields().getField(BEACONAUEligReevaluation.class, interViewResult.getAuId());
				tmpBenEffDate = (DateData) auEligReeval.getRevalEndDate().copy();
                // Determine the last cycle month of original reeval period (e.g. reeval end between 4/30/2022 and 5/13/2022, last cycle month of period is 4/1/2022)
                DateData tmpBenMonDate = (DateData) auEligReeval.getRevalEndDate().copy();
                tmpBenMonDate.addDays(-15);      // last month of reeval period
                tmpBenMonDate.setDate(1); // start of month (i.e. ben_mon_dte)
				if (hasCashReevalSelected(ctx, maEcf, wfData, interViewResult.getRequestId())) {
					tmpReleaseDate = (DateData) getNextCycleIssuanceDateCash(wfData, interViewResult.getAuId(), tmpBenMonDate).clone();
				} else {
					tmpReleaseDate = (DateData) getNextCycleIssuanceDateFS(wfData, interViewResult.getAuId(), tmpBenMonDate).clone();
				}
				releaseDate = tmpReleaseDate.getNextWorkDate();
				if (!hasLaterCashRelease(ctx, maEcf, interViewResult, releaseDate)) {
					interViewResult.setTempReleaseDate(releaseDate);
					if (interViewResult.getStatus().equals(ACTIVE)) {
						//benEffDate = tmpBenEffDate.addDays(1);
						//interViewResult.setTempBenEffDate(benEffDate);
						DateData nxtCycPmtDte = getNextCyclePaymentDate(maClient, interViewResult.getAuId(), false, false, releaseDate, false);
						interViewResult.setTempBenEffDate(nxtCycPmtDte);
					} else if (interViewResult.getStatus().equals(CLOSED)) {
						benEffDate = tmpBenEffDate;
						interViewResult.setTempBenEffDate(benEffDate);
					}
					returnFlag = true;
					interViewResult.setNotAdjustRelDteFlag(true);
					setFinancialValue(interViewResult, EBCDATA, RELEASEDELAYEDBYREEVAL, "Y");
					interViewResult.setReleasedDelayByReeval("Y");
				}
			}
			if (!returnFlag && interViewResult.getReleasedDelayByReeval().equals("Y")) {
				interViewResult.setReleasedDelayByReeval("N");
				setFinancialValue(interViewResult, EBCDATA, RELEASEDELAYEDBYREEVAL, "N");
				interViewResult.setNotAdjustRelDteFlag(false);
				interViewResult.getTempReleaseDate().setNull();
				interViewResult.getTempBenEffDate().setNull();
			}
			// New or reopened CAP AU
			if (!returnFlag && isCAPAuNewOrReopened(asstUnit, interViewResult, maEcf, auStatus)) {
				applicationDate = getApplicationDate(wfData, interViewResult.getAuId());
				if (batch)
					releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
				else
					releaseDate = ctx.getEffectiveDate();
				if (ebcResult != null && ebcResult.getBenefitEnd() != null
				                && isReinstatedContinuation(maEcf, interViewResult)) {
					benEffDate = ((DateData) ebcResult.getBenefitEnd().copy()).addDays(1);
					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
					interViewResult.setNotAdjustRelDteFlag(true);
				}
				else if (applicationDate != null && applicationDate.isNotEmpty()) {
					DateData currentDate = new DateData(ctx.getEffectiveDate()); //DateData.getToday();
					if (differenceInMonths(applicationDate, currentDate)) {
						ebcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), currentDate);
						benEffDate = ebcCycleDate.getFirstCycStdPmtDate();
					}
					else {
						ebcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), currentDate.addMonths(1));
						benEffDate = ebcCycleDate.getFirstCycStdPmtDate();
					}
					interViewResult.setTempReleaseDate(releaseDate);
					interViewResult.setTempBenEffDate(benEffDate);
					returnFlag = true;
					// benEffDate = getNextCyclePaymentDate(wfData, interViewResult.getAuId(), false,
					// false,applicationDate, true);
					interViewResult.setNotAdjustRelDteFlag(true);
				}
				// Override benefit date for reinstatements where the client is at fault.
				if (returnFlag && isReinstatedFSAUAtFault(maEcf, wfData, interViewResult)){
					AUFault auFault = wfData.getAUFault(interViewResult.getAuId());
					if (auFault != null){
						interViewResult.setFaultTypeCd(auFault.getFaultTypeCd());
						interViewResult.setFaultClassCd(auFault.getFaultClassCd());
						if (auFault.getFaultTypeCd().equals("CLTDLY")){
							EBCResultBase ebcRsltBase = maEcf.getEBCResultBase(interViewResult.getAuId());
							if (ebcRsltBase != null) {
								if(ebcRsltBase.getAuEligFactReason().equals("001070")) {
									AuReinstatement auReinst = (AuReinstatement) wfData.getAuReinstatement(interViewResult.getAuId());
									if (auReinst != null && auReinst.getReinstateFlag().isTrue() &&
										auReinst.getFormRecvdDte().isNotEmpty() && auReinst.getFormRecvdDte().after(benEffDate)) {
										benEffDate = new DateData(auReinst.getFormRecvdDte());
										interViewResult.setTempBenEffDate(benEffDate);
									}
								} else if(StringDataUtil.isMatch(ebcRsltBase.getAuEligFactReason(), "001068", "001069", "001042")) {
									AuReinstatement auReinst = (AuReinstatement) wfData.getAuReinstatement(interViewResult.getAuId());
									if (auReinst != null && auReinst.getReinstateFlag().isTrue() &&
										auReinst.getVerRecvdDte().isNotEmpty() && auReinst.getVerRecvdDte().after(benEffDate)) {
										benEffDate = new DateData(auReinst.getVerRecvdDte());
										interViewResult.setTempBenEffDate(benEffDate);
									}
								}
							}
						}
					}
				}
			}
		}
		return returnFlag;
	}

	/**
	 * @param ctx
	 * @param maECFHH
	 * @param fsIntvwRslt
	 * @param releaseDate
	 * @return
	 * @throws Exception
	 */
	public static boolean hasLaterCashRelease(Context ctx, MAECFHousehold maECFHH, InterviewWrapUpEDBCResult fsIntvwRslt, DateData releaseDate) throws Exception {
		Vector<InterviewWrapUpEDBCResult> vIntRslt = maECFHH.getInterviewWrapUpEDBCResults(fsIntvwRslt.getRequestId());
		for (InterviewWrapUpEDBCResult intvwRslt : vIntRslt) {
			if (intvwRslt.getProgram().equals(TANF) || intvwRslt.getProgram().equals(EAEDC)) {
				EDBCResultFinancial financial = intvwRslt.getFinancialObject(EBCDATA, RELEASEDATE);
				if (financial != null) {
					DateData currRelDate = DateData.getInstance(financial.getValue().toString());
					if (currRelDate != null && currRelDate.after(releaseDate)) {
						return true;
					}
				}
			}

		}
		return false;
	}


