	public static SanctionDetails getRemovedLearnfareSanction(Context effCtx, MAECFHousehold maEcf, MAClient wfData, IntegerData clientId)
	    throws Exception {
		Vector<Sanction> sanctionVect = wfData.getSanction(clientId);
		for (Sanction sanctionObj : sanctionVect) {
			EligFactorSanction eligFactorSanc = wfData.getEligFactorSanction(sanctionObj.getEligFactorSanctionId());
			if (eligFactorSanc.getReason().equals(SANCT_TALRNF)) {
				SanctionDetails sanctionDetails = wfData.getSanctionDetails(sanctionObj.getSanctionId());
				if (sanctionDetails.getStatus().equals(SANCTION_REMOVED)
					&& !sanctionDetails.getRemovalReason().equals(GCAUSE) && !sanctionDetails.getRemovalReason().equals(ADHEAR)
				    && isVerificationSelectedForSanction(maEcf, sanctionDetails.getVerificationId(), sanctionObj.getSanctionId())) {
					return sanctionDetails;
				}
			}
		}
		return null;
	}
	/**
	 * This method do the logic to find the Release date and Benefit Effective Date for each Result as per doc Benefit
	 * Effective Date and Release Date.doc (14 to end).
	 * @param ctx
	 * @param maEcf
	 * @param interViewResult
	 * @param releaseDate
	 * @param benEffDate
	 * @param batch
	 * @param clientId
	 * @return
	 * @throws Exception
	 */
	public static boolean conditionSix(Context ctx, MAECFHousehold maEcf, InterviewWrapUpEDBCResult interViewResult,
	                                   DateData releaseDate, DateData benEffDate, boolean batch, int clientId)
	                throws Exception {
		boolean returnFlag = false;
		BaseAU asstUnit = null;
		DateData applicationDate = null;
		DateData releaseBenEffDte = null;
		BaseAUStatus auStatus = null;
		EbcCycleDate ebcCycleDate = null;
		AuReinstatement auReinst = null;
		MAClient wfData = maEcf.getMAClient(clientId);
		asstUnit = wfData.getAsstUnit(interViewResult.getAuId());
		auStatus = (BaseAUStatus) wfData.getFields().getField(BaseAUStatus.class, interViewResult.getAuId());
		applicationDate = getApplicationDate(wfData, interViewResult.getAuId());

		if (!returnFlag
		                && (interViewResult.getProgram().toString().equalsIgnoreCase(TANF)
		                                || interViewResult
		                                .getProgram().toString().equalsIgnoreCase(SNAP))
		                && isAuNewOrReopened(interViewResult, asstUnit, maEcf, auStatus)) {
			if (batch)
				releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
			else
				releaseDate = ctx.getEffectiveDate();
			EBCResultBase ebcResultBase = maEcf.getEBCResultBase(asstUnit.getId());
			EBCResultBase ebcResultBaseClosure = null;
			if (applicationDate != null && applicationDate.isNotEmpty()
				    && (interViewResult.getExpedited().equals(AlphaE) || interViewResult.getExpedited().equals(AlphaS))) {
				ebcResultBaseClosure = getEBCResultLatestBaseClosure(maEcf.getFields().getContext(), asstUnit.getId());
			}
			auReinst = (AuReinstatement) wfData.getAuReinstatement(asstUnit.getId());
			BaseAUEligReevaluation eligibleReevaluation = (BaseAUEligReevaluation) wfData.getBaseAUEligReevaluation(asstUnit.getId());
			if (ebcResultBase != null && ebcResultBase.getBenefitEnd() != null && ebcResultBase.getBenefitEnd().isNotEmpty()
	                && isReinstatedContinuation(maEcf, interViewResult)) {
				benEffDate = ((DateData) ebcResultBase.getBenefitEnd().copy()).addDays(1);
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			else if (applicationDate != null && interViewResult.getExpedited().toString().equalsIgnoreCase(AlphaC)) {
				DateData currentDate = new DateData(ctx.getEffectiveDate()); //DateData.getToday();
				if (differenceInMonths(applicationDate, currentDate)) {
					ebcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), currentDate);
					if(asstUnit.getProgramCode().equals(TANF))
						benEffDate = ebcCycleDate.getTanfCycStdPmtDate();
					else
						benEffDate = ebcCycleDate.getFirstCycStdPmtDate();	
				}
				else {
					ebcCycleDate = getEbcCycleDate(wfData, interViewResult.getAuId(), currentDate.addMonths(1));
					if(asstUnit.getProgramCode().equals(TANF))
						benEffDate = ebcCycleDate.getTanfCycStdPmtDate();
					else
					benEffDate = ebcCycleDate.getFirstCycStdPmtDate();
				}
				// benEffDate = getNextCyclePaymentDate(wfData, interViewResult.getAuId(), false, false,applicationDate,
				// true);
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			else if (interViewResult.getProgram().toString().equalsIgnoreCase(SNAP)
				&& ebcResultBase != null
				&& ebcResultBase.getAuStatus().isNotEmpty()
				&& ebcResultBase.getAuStatus().toString().equalsIgnoreCase(DENIED)
				&& auReinst != null && auReinst.getReinstateFlag() != null && auReinst.getReinstateFlag().isTrue()
				&& eligibleReevaluation != null && eligibleReevaluation.getRevalEndDate().isNotEmpty()
				&& applicationDate != null && applicationDate.isNotEmpty()
                && eligibleReevaluation.getRevalEndDate().after(applicationDate)
                && wasAUReleasedExpedited(ctx, asstUnit.getId())) {
				releaseBenEffDte = new DateData(eligibleReevaluation.getRevalEndDate());
				benEffDate = releaseBenEffDte.addDays(1);
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			else if (ebcResultBaseClosure != null && applicationDate != null && applicationDate.isNotEmpty()
			    && !applicationDate.after(ebcResultBaseClosure.getBenefitEffective())
			    && (interViewResult.getExpedited().equals(AlphaE) || interViewResult.getExpedited().equals(AlphaS))) {
				benEffDate = (new DateData(ebcResultBaseClosure.getBenefitEffective())).addDays(1);
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			else if (applicationDate != null && applicationDate.isNotEmpty()) {
				benEffDate = new DateData(applicationDate);
				interViewResult.setTempReleaseDate(releaseDate);
				interViewResult.setTempBenEffDate(benEffDate);
				returnFlag = true;
				interViewResult.setNotAdjustRelDteFlag(true);
			}
			// Override benefit date for reinstatements where the client is at fault.
			if (returnFlag && isReinstatedFSAUAtFault(maEcf, wfData, interViewResult)) {
				AUFault auFault = wfData.getAUFault(interViewResult.getAuId());
				if (auFault != null){
					interViewResult.setFaultTypeCd(auFault.getFaultTypeCd());
					interViewResult.setFaultClassCd(auFault.getFaultClassCd());
					if (auFault.getFaultTypeCd().equals("CLTDLY")){
						EBCResultBase ebcRsltBase = maEcf.getEBCResultBase(interViewResult.getAuId());
						if (ebcRsltBase != null) {
							if(ebcRsltBase.getAuEligFactReason().equals("001070")) {
								if (auReinst != null && auReinst.getReinstateFlag().isTrue() &&
									auReinst.getFormRecvdDte().isNotEmpty() && auReinst.getFormRecvdDte().after(benEffDate)) {
									benEffDate = new DateData(auReinst.getFormRecvdDte());
									interViewResult.setTempBenEffDate(benEffDate);
								}
							} else if(StringDataUtil.isMatch(ebcRsltBase.getAuEligFactReason(), "001068", "001069", "001042")) {
								if (auReinst != null && auReinst.getReinstateFlag().isTrue() &&
									auReinst.getVerRecvdDte().isNotEmpty() && auReinst.getVerRecvdDte().after(benEffDate)) {
									benEffDate = new DateData(auReinst.getVerRecvdDte());
									interViewResult.setTempBenEffDate(benEffDate);
								}
							}
						}
					}
				}
			}
		}
		return returnFlag;
	}

	/**
	 * @param maECFHouseholdDelta
	 * @param ebcRsltBase
	 * @return
	 * @throws Exception
	 */
	public static EBCResultBase getEBCResultLatestBaseClosure(Context ctx, IntegerData auId)
	    throws Exception {
		if (auId.isNotEmpty()) {
			Context baseCtx = ctx.copy();
			baseCtx.setContextIdentifier(Context.BASE_CONTEXT_ITENTIFIER);

			EqualityClause clause = null;
			SQLMapper mapper = SQLMapper.getInstance();
			ClassMap classMap = MetaModel.getInstance().getClassMapUsingClassName(EBCResultBase.class);
			SimpleStatement statement = mapper.createSelectStatement(EBCResultBase.class);
			String alias = statement.getTableAlias();
			WhereClause whereClause = statement.getWhereClause();
			
			FieldMap auIdMap = classMap.getFieldMapUsingColumn("AU_ID_K");
			clause = new EqualityClause(ClauseKeywords.EQ, new FieldMapAlias(auIdMap, alias), auId.intValue());
			whereClause.addClause(clause);

			FieldMap releasedFlag = classMap.getFieldMapUsingColumn("AU_STAT");
			clause = new EqualityClause(ClauseKeywords.EQ, new FieldMapAlias(releasedFlag, alias), new StringData(CLOSED));
			whereClause.addClause(ClauseKeywords.LINK_AND, clause);

			OrderByElement[] orderByElements = { new OrderByElement(StandardMappings.FIELD_CREATE_TIMESTAMP, false) };
			statement.addOrderedBy(orderByElements);

			Vector<EBCResultBase> ebcResultVec = mapper.fetchMany(baseCtx, statement);
			for (EBCResultBase ebcRslt : ebcResultVec) {
				return ebcRslt;
			}
		}
		return null;
	}

	/**
	 * Similar to MAClient.isLearnfareEligClient() but this version examines *result* statuses and EFRC instead of the tables themselves.
	 * @param ctx
	 * @param clientId
	 * @return
	 * @throws Exception
	 */
	private static boolean isLearnfareEligClient(Context ctx, MAClient wfData, InterviewWrapUpEDBCResult interViewResult, EDBCResultAUMember rsltMemb, boolean inclPendStatClnt) throws Exception {
		int minLearnfareAge=6;
		int maxLearnfareAge=15;
		ParameterCache parameterCache = ParameterCache.getInstance();
		Parameter parameter = parameterCache.getParameter(wfData.getFields().getContext(), MAConstants.LEARNFARE_SCHOOL_AGE_MIN);
		if (parameter!=null){
			minLearnfareAge=Integer.parseInt(parameter.getParameterValue());;
		}
		parameter = ParameterCache.getInstance().getParameter(wfData.getFields().getContext(),MAConstants.LEARNFARE_SCHOOL_AGE_MAX);
		if (parameter!=null){
			maxLearnfareAge=Integer.parseInt(parameter.getParameterValue());
		}
		int clientAge = wfData.getClientAge(rsltMemb.getClientId());
		if (clientAge < minLearnfareAge || clientAge > maxLearnfareAge) {
			return false;
		}
		Vector<BaseClientAUMember> clientAuMembVect = wfData.getAllClientAUMembers(rsltMemb.getClientId());
		for (BaseClientAUMember clientAuMemb : clientAuMembVect) {
			if (interViewResult.getProgram().equals(TANF)) {
				if (interViewResult.getStatus().equals(ACTIVE)) {
					ClientDisabilityPage clientDisability = wfData.getClientDisabilityPage(interViewResult.getGranteeId());
					if (clientDisability != null && clientDisability.getDisabledFlg().isTrue()) {
						return false;
					}
					if ((rsltMemb.getMemStatus().equals(ACTIVE))
					    || (rsltMemb.getMemStatus().equals(INELIG) && rsltMemb.getMemIneligReason().equals("001047"))
					    || (inclPendStatClnt && rsltMemb.getMemStatus().equals(PENDING)
					    		&& (rsltMemb.getMemIneligReason().isEmpty() || rsltMemb.getMemIneligReason().equals("001047")))) {
						if ((clientAge >= minLearnfareAge && clientAge <= maxLearnfareAge) && (!wfData.isClientInKindergarten(ctx, rsltMemb.getClientId()))) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

