	public static Boolean wasAUReleasedExpedited(Context ctx, IntegerData auId) throws Exception {
		Boolean result = false;
		EBCResultBase ebcResultPriorBase = getEBCResultPriorBase(ctx, auId);
		if (ebcResultPriorBase != null
        && ebcResultPriorBase.getAuStatus().isNotEmpty()
		&& ebcResultPriorBase.getAuStatus().toString().equalsIgnoreCase(PENDING)
		&& ebcResultPriorBase.getExpeditedCode() != null
		&& ebcResultPriorBase.getExpeditedCode().isNotEmpty()
		&& ebcResultPriorBase.getExpeditedCode().toString().equalsIgnoreCase(AlphaE)) {
			result = true;
		}
		return result;
	}



	/**
	 * Returns a vector of children. See also fetchOffspring which can return a singleton or a Vector. Frame doesn't
	 * support to fetch the deleted records, So EBC is using deleted record. this special logic to fetch
	 * @param context
	 * @param targetClass
	 * @param parentId
	 * @param constraints
	 * @return
	 * @throws SQLException
	 */
	private static final Vector fetchChildrenEBC(Context context, Class targetClass, int parentId,
	                                             Constraints constraints) throws SQLException {
		Connection connection = null;
		if (mapper == null) {
			mapper = SQLMapper.getInstance();
		}
		try {
			connection = SQLUtil.getConnection(context);
			Vector result = mapper.fetchChildren(context, connection, targetClass, parentId, constraints, false);
			return result;
		}
		catch (SQLException x) {
			connection.rollback();
			throw x;
		}
		finally {
			SQLUtil.releaseConnection(connection);
		}
	}

	/**
	 * This method to check the latest Deleted/Ended base record. This method will return RootObject, if there is any
	 * latest base record is deleted/Ended.
	 *
	 * @param baseVector
	 *            is an Vector object.
	 * @param classMap
	 *            is an ClassMap.
	 * @param foriegnKey
	 *            is an FieldMap
	 * @param fk
	 *            is an IntegerData.
	 * @param deltaSetId
	 *            is an String.
	 * @param deltaElement
	 *            is an Object.
	 * @return null if there is no latest Deleted/Ended record.
	 * @throws Exception
	 */
	private static RootObject getLatestBaseEndedDeletedRecord(Vector baseVector, ClassMap classMap,
	                                                          FieldMap foriegnKey, IntegerData fk, String deltaSetId,
	                                                          Object deltaElement, Vector deltaEnded) throws Exception {
		RootObject baseElement = null;
		if (baseVector != null) {
			for (int k = 0; k < baseVector.size(); k++) {
				baseElement = (RootObject) baseVector.elementAt(k);
				if (!deltaEnded.contains(baseElement)) {
					deltaEnded.add(baseElement);
				}
				if (!(baseElement.getClassName().equals(classMap.getName()))) {
					baseElement = null;
					continue;
				}
				String baseSetId = ((DataValue) classMap.getFieldMapForSetId().getReadMethod()
				                .invoke(baseElement, null)).toString();
				IntegerData baseId = (IntegerData) foriegnKey.getReadMethod().invoke(baseElement, null);
				if (classMap.hasEffectiveStartDate) {
					int effcompare = ((RootEffDateObject) baseElement).getEffDate().compareTo(
					                ((RootEffDateObject) deltaElement).getEffDate());
					int createCompare = ((RootEffDateObject) baseElement).getCreateTimestamp().compareTo(
					                ((RootEffDateObject) deltaElement).getCreateTimestamp());

					if (effcompare == 0) {
						if (createCompare > 0) {
							if (baseSetId.equalsIgnoreCase(deltaSetId) && fk.intValue() == baseId.intValue()) {
								break;
							}
						}
					}
					else if (effcompare > 0) {
						if (baseSetId.equalsIgnoreCase(deltaSetId) && fk.intValue() == baseId.intValue()) {
							break;
						}
					}
				}
				else if (classMap.hasCreateTimestamp()) {
					int createCompare = ((RootObject) baseElement).getCreateTimestamp().compareTo(
					                ((RootObject) deltaElement).getCreateTimestamp());
					if (createCompare > 0) {
						if (baseSetId.equalsIgnoreCase(deltaSetId) && fk.intValue() == baseId.intValue()) {
							break;
						}
					}
				}
				baseElement = null;
			}
		}
		return baseElement;
	}
	/**
	 * This method is used to remove the AU_STAT status CLOSED/ DENIED result from the cache.
	 * This logic added in the scenario like:
	 * AU status was became CLOSED/DENIED by different request, But current request has the ACTIVE result.
	 * In this case IW including this AU for the calculation.
	 * @param household is an MAECFHousehold instance.
	 * @param requestId is an IntegerData instance.
	 * @param clientId is an IntegerData.
	 * @throws Exception
	 * This logic needed after the defect fix DTA0011623.
	 */
	private static void resetIWUResultForBatch(MAECFHousehold household,
			IntegerData requestId, IntegerData clientId) throws Exception {
		Vector<InterviewWrapUpEDBCResult> returnVector = null;
		Vector<InterviewWrapUpEDBCResult> tempVector = new Vector<InterviewWrapUpEDBCResult>();
		returnVector = EBCServices.getInterviewWrapUpEDBCResults(household,
				requestId, true);
		for (InterviewWrapUpEDBCResult resultVect : returnVector) {
			BaseAUStatus austatus = (BaseAUStatus) household.getFields()
					.getField(BaseAUStatus.class, resultVect.getAuId());
			if (austatus.getStatus().equals(AU_CLOSED)
					|| austatus.getStatus().equals(AU_DENIED)
					|| (austatus.getStatus().equals(PENDING) && !isAuExistInSelection(
							household, resultVect.getAuId()))) {
				continue;
			}
			tempVector.add(resultVect);
		}
		if (tempVector.size() > 0) {
			household.getFields().setField(InterviewWrapUpEDBCResult.class,
					requestId, tempVector);
		}
	}
	/**
	 * * AU is excluded form the calculation, but those au is active in PENDREL request.
	 * Those result shouldn't be the part of the current calculation results.
	 * In this case IW including this AU for the calculation
	 * This logic needed after the defect fix DTA0011623
	 * @param household is an MAECFHousehold instance.
	 * @param requestId is an IntegerData instance.
	 * @param auExcludedVec is an  Vector.
	 * @param batchis an Boolean instance.
	 * @param calculated an Boolean instance.
	 * @return
	 * @throws Exception
	 *
	 */
	private static Vector resetCurrentResult(MAECFHousehold household, IntegerData requestId,Vector auExcludedVec, boolean batch, boolean calculated)throws Exception {
		Vector<InterviewWrapUpEDBCResult> interviewWrapupEDBCResultVect = null;
		InterviewWrapUpEDBCResult interviewWrapUpEDBCResult = null;
		Vector<InterviewWrapUpEDBCResult> tempVector = new Vector<InterviewWrapUpEDBCResult>();
		interviewWrapupEDBCResultVect  = EBCServices.getInterviewWrapUpEDBCResults(household, requestId, batch);
		if (interviewWrapupEDBCResultVect != null && interviewWrapupEDBCResultVect.size() > 0) {
			Enumeration eDBCResultEnum = interviewWrapupEDBCResultVect.elements();
			while (eDBCResultEnum.hasMoreElements()) {
				interviewWrapUpEDBCResult = (InterviewWrapUpEDBCResult) eDBCResultEnum.nextElement();
				if(auExcludedVec.size() > 0 && auExcludedVec
				                .contains(interviewWrapUpEDBCResult.getAuId())){
					interviewWrapupEDBCResultVect.remove(interviewWrapUpEDBCResult);
					eDBCResultEnum = interviewWrapupEDBCResultVect.elements();
				}
			}
		}
		if(interviewWrapupEDBCResultVect.size()>0){
			household.getFields().setField(InterviewWrapUpEDBCResult.class, requestId, interviewWrapupEDBCResultVect);
		}
		if(!calculated){
			interviewWrapupEDBCResultVect = new Vector();
		}
		return interviewWrapupEDBCResultVect;
	}

	/**
	 * Creates the Narrative details for WPR change.
	 * @param household is an instance of MAECFHousehold.
	 * @param requestId is an instance of IntegerData, holds the request ID.
	 * @param appUserID is an instance of IntegerData, holds the app user ID.
	 * @param clientId is an instance of IntegerData, holds the client ID.
	 * @param source is String value of narrative source.
	 * @throws Exception
	 * @throws SQLException
	 */
	public static void createWPRNarrative(MAECFHousehold household, IntegerData requestId, IntegerData appUserID,
	                                IntegerData clientId, String source) throws Exception, SQLException {
		if (household.getFields().isCached(EDBCResult.class, requestId)) {
			List<EDBCResult> edbcRslts = household.getFields().getFields(EDBCResult.class, requestId);
			for (EDBCResult ebcObject : edbcRslts) {
				if (ebcObject.getWorkProgramMessage().isNotEmpty()) {
					NarrativesDetail wprNote = new NarrativesDetail();
					wprNote.setBuId(appUserID);
					wprNote.setClientId(clientId);
					wprNote.setHhId(new IntegerData(household.getHouseholdId()));
					wprNote.getNoteDetail().setString(
					                ebcObject.getWorkProgramMessage().toString().replace("|BR|", "<BR>").replace(
					                                "<![CDATA[", "").replace("]]>", ""));
					wprNote.getSourceIndicator().setString(source);
					wprNote.setRequiresInsert();
					household.getFields().setSeqField(NarrativesDetail.class, wprNote.getId(), wprNote);
					
					
					/** Start - Added for COVID-19 */
					String covidExempt = (String) ParameterCache.getInstance().getParameter(household.getFields().getContext(), MAConstants.DEFAULT_ABAWD_COVID_EXEMPTION).getParameterValue();
					if(covidExempt != null && covidExempt.equals(MAConstants.FLAG_YES) && ebcObject.getWorkProgramMessage().toString().contains(MAConstants.ABAWD_COVID_EXEMPTION_RSN)){
						String caseNote = "Due to the COVID-19 emergency, the ABAWD Work Rules have been temporarily suspended.  All non-exempt household members have been given the following temporary exemption: ABAWD Rules Suspended (COVID-19)";
						NarrativesDetail wprNote1 = new NarrativesDetail();
						wprNote1.setBuId(appUserID);
						wprNote1.setClientId(clientId);
						wprNote1.setHhId(new IntegerData(household.getHouseholdId()));
						wprNote1.getNoteDetail().setString(caseNote);
						wprNote1.getSourceIndicator().setString(source);
						wprNote1.setRequiresInsert();
						household.getFields().setSeqField(NarrativesDetail.class, wprNote1.getId(), wprNote1);
					}
					
					/** End - Added for COVID-19 */
					
				}
			}
		}
	}

	/**
	 * This method is used to determine whether the reevaluation type can be changed to Simplified Reporting.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if AR
	 * @throws Exception
	 */
	public static boolean isSimplifiedReporting24(MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
					Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec,
            		InterviewWrapUpEDBCResult fsRlt)  throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		String tbaFlag;
		String capFlag;
		int clientAge = 0;
		EDBCResult ebcObject = null;
		boolean isClientDisabled = false;
		boolean hasUnIncome = false;
		boolean isGood = false;
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());
		Parameter parameter = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),ELDERLY_DEPENDENT_AGE);

		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP) && fsRlt.getStatus().equals(ACTIVE)) {
			if (ebcObjectVector != null && ebcObjectVector.size() > 0) {
				Enumeration ebcObjectEnum = ebcObjectVector.elements();
				while (ebcObjectEnum.hasMoreElements()) {
					EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
					if (ebcObj.getAuId().intValue() == fsRlt.getAuId().intValue()) {
						ebcObject = ebcObj;
						break;
					}
				}
			}
			for (InterviewWrapUpEDBCResult rslt : rsltVec) {
				if (rslt.getProgram().equals(SNAP) && rslt.getAuId().equals(fsRlt.getAuId())) {
					edbcResultFinancial = rslt.getFinancialObject(BENEFIT, TBAFLAG);
					tbaFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? edbcResultFinancial
					                .getValue().stringValue()
					                : null;
					if (tbaFlag != null && tbaFlag.equalsIgnoreCase(YES)) {
						return false;
					}
					if (rslt.getPgmStructParId().equals(100)) {
						Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
						if(!doesAUHaveSSIAndNoCash(fsRsltMemVec, maClientBase, maECF)) {
							return false;
						}
					}
					edbcResultFinancial = rslt.getFinancialObject(STANDARDAMOUNTS, CAPELIGIBILITYSTATUS);
					capFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? edbcResultFinancial
					                .getValue().stringValue()
					                : null;
					if (!capFlag.isEmpty() && capFlag.contains("Active")) {
						return false;
					}
					Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
					int elderlyDependentAge = Integer.parseInt(parameter.getParameterValue());
					for (EDBCResultAUMember fsRsltMemb : fsRsltMemVec) {
						isClientDisabled = false;
						hasUnIncome = false;
						/* requirement change
						if (fsRsltMemb.getMemStatus().equals(INELIGIBLE)  && (fsRsltMemb.getMemResponsibility().equals("OTHRDQ") || fsRsltMemb.getMemResponsibility().equals("NCITDQ")
								|| fsRsltMemb.getMemResponsibility().equals("SSNDQ ") || fsRsltMemb.getMemResponsibility().equals("SANCTN"))) {
							return false;
						}
						*/
						if (fsRsltMemb.getMemStatus().equals(ACTIVE) || fsRsltMemb.getMemStatus().equals(INELIGIBLE)) {
							clientAge = maClientDelta.findClientAge(fsRsltMemb.getClientId());
							ClientDisabilityPage clientDisability = maClientBase.getClientDisabilityPage(fsRsltMemb.getClientId());
							if (clientDisability != null && ebcObject != null
				                && clientDisability.getDisabledFlg().booleanValue()
				                && ebcObject.isFSFederallyCertified(maClientBase, clientDisability)) {
								isClientDisabled = true;
							}
							if (clientAge < 16) {
								isGood = true;
								continue;
							} else if (clientAge >= 16 && clientAge < 18) {
								if (isClientDisabled) {
									isGood = true;
									continue;
								} else {
									return false;
								}
							} else {
								//18 and older
								if (clientAge < 60 && !isClientDisabled) {
									return false;
								}
								Vector earnedIncomeVect = maClientBase.getEarnedIncome(fsRsltMemb.getClientId());

								Enumeration clientEIEnum = earnedIncomeVect.elements();
								while (clientEIEnum.hasMoreElements()) {
									EarnedIncome clientEI = (EarnedIncome) clientEIEnum.nextElement();
									EarnedIncProspectiveAvg clientEIPspAvg = null;
									clientEIPspAvg = maClientBase.getEarnedIncProspectiveAvg(clientEI.getEarnedIncomeId());
									if (clientEIPspAvg != null && clientEIPspAvg.getMonthlyProspAmount().isNotEmpty() && clientEIPspAvg.getMonthlyProspAmount().getValue() > 0 ) {
										return false;
									}
								}

								Vector clientUIVector = maClientBase.getClientUI(fsRsltMemb.getClientId());
								Enumeration clientUIEnum = clientUIVector.elements();
								while (clientUIEnum.hasMoreElements()) {
									ClientUI clientUI = (ClientUI) clientUIEnum.nextElement();
									if (clientUI.getOtherIncType().isNotEmpty()
								                && clientUI.getOtherIncStatus().isNotEmpty()
								                && clientUI.getOtherIncStatus().toString().equalsIgnoreCase("ACTIVE") ) {
										ClientUIPspAvg clientUIPspAvg = null;
										clientUIPspAvg = maClientBase.getClientUIPspAvg(clientUI.getUiId());
										if (clientUIPspAvg != null && clientUIPspAvg.getMonthlyAmt().isNotEmpty() && clientUIPspAvg.getMonthlyAmt().getValue() > 0 ) {
											hasUnIncome = true;
											break;
										}
									}
								}
								if (hasUnIncome) {
									isGood = true;
									continue;
								} else {
									return false;
								}
							}
						}
					}
				}
			}
		} else {
			//non fs program
			return false;
		}
		return isGood;
	}

	/**
	 * This method is used to determine whether the reevaluation type can be changed to Simplified Reporting 12 with out six month report.
	 * Elderly or   Disabled Person all adults in AU  with No Earned Income
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if SIMP12
	 * @throws Exception
	 */
	public static boolean isSimplifiedWithOutSixMonthsReporting12(MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
					Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec,
            		InterviewWrapUpEDBCResult fsRlt)  throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		int clientAge = 0;
		EDBCResult ebcObject = null;
		boolean isClientDisabled = false;
		boolean isGood = false;
		boolean isHavingActiveAdultElderlyOrDisabledPersonInAU = false;
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());
		
		int elderlyMaxAge = 0;
		int elderlyMinAge = 0;
		
		int buId = asstUnit.getBuId().isNotEmpty() ? asstUnit.getBuId().intValue() : 0;
		
		Parameter maxAgeParam = ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
				ELDERLY_DEPENDENT_AGE);
		Parameter minAgwParam= ParameterCache.getInstance().getParameter(maClientDelta.getFields().getContext(),
				DEPENDENT_AGE_CUTOFF);
		
		if(null != maxAgeParam)
			elderlyMaxAge = Integer.parseInt(maxAgeParam.getParameterValue());
		if(null != minAgwParam)
			elderlyMinAge = Integer.parseInt(minAgwParam.getParameterValue());
		
		
		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP)
							 && fsRlt.getStatus().equals(ACTIVE)  && (buId >= 100 || buId <= 170)) {
			
			if (ebcObjectVector != null && ebcObjectVector.size() > 0) {
				Enumeration ebcObjectEnum = ebcObjectVector.elements();
				while (ebcObjectEnum.hasMoreElements()) {
					EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
					if (ebcObj.getAuId().intValue() == fsRlt.getAuId().intValue()) {
						ebcObject = ebcObj;
						break;
					}
				}
			}
			
			for (InterviewWrapUpEDBCResult rslt : rsltVec) {
				if (rslt.getProgram().equals(SNAP) && rslt.getAuId().equals(fsRlt.getAuId())) {
			
					if (isEDSAPReporting(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					
					Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();

					for (EDBCResultAUMember fsRsltMemb : fsRsltMemVec) {
						isClientDisabled = false;
						if (fsRsltMemb.getMemStatus().equals(ACTIVE) ) {
							clientAge = maClientDelta.findClientAge(fsRsltMemb.getClientId());
							
							
							// min age is 19 and max age is 59
							if ((clientAge >= elderlyMinAge && clientAge <= elderlyMaxAge)) {
								ClientDisabilityPage clientDisability = maClientDelta
										.getClientDisabilityPage(fsRsltMemb.getClientId());
								if (clientDisability != null && ebcObject != null
										&& clientDisability.getDisabledFlg().booleanValue()
										&& ebcObject.isFSFederallyCertified(maClientDelta, clientDisability)) {
									isClientDisabled = true;
								}
								
								// Returns true if client is >= 59 years
								if (isClientDisabled) {
									isGood = true;
									if (fsRsltMemb.getMemStatus().equals(ACTIVE)) {
										isHavingActiveAdultElderlyOrDisabledPersonInAU = true;
									}
								} else {
									return false;
								}	
							} else if(clientAge > elderlyMaxAge) {
								isGood = true;
								if (fsRsltMemb.getMemStatus().equals(ACTIVE)) {
									isHavingActiveAdultElderlyOrDisabledPersonInAU = true;
								}
							} else {
								break;
							}
							// Return false if any member has Earned income with Countable SNAP Flag = 'Y'

							Vector earnedIncomeVect = maClientBase.getEarnedIncome(fsRsltMemb.getClientId());
							Enumeration clientEIEnum = earnedIncomeVect.elements();
							while (clientEIEnum.hasMoreElements()) {
								EarnedIncome clientEI = (EarnedIncome) clientEIEnum.nextElement();
								if (clientEI.getCountableFS().isNotEmpty() && clientEI.getCountableFS().booleanValue()) {
									EarnedIncProspectiveAvg clientEIPspAvg = null;
									clientEIPspAvg = maClientBase.getEarnedIncProspectiveAvg(clientEI.getEarnedIncomeId());
									if (clientEIPspAvg != null && clientEIPspAvg.getMonthlyProspAmount().isNotEmpty()
											&& clientEIPspAvg.getMonthlyProspAmount().getValue() > 0) {
										return false;
									}
								}
							}
							
							// Return false if any member has Other income with Earned Flag = 'Y' and Countable SNAP Flag = 'Y'

							Vector otherIncomeVect = maClientBase.getClientUI(fsRsltMemb.getClientId());
							Enumeration clientUIEnum = otherIncomeVect.elements();
							while (clientUIEnum.hasMoreElements()) {
								ClientUI clientUI = (ClientUI) clientUIEnum.nextElement();
								if (clientUI.getOtherIncStatus().isNotEmpty() 
										&&
										(clientUI.getOtherIncStatus().toString().equals(MAConstants.ACTIVE))) {
									if (clientUI.getFsCountableFlg().isNotEmpty() && clientUI.getFsCountableFlg().booleanValue()) {
										if (clientUI.getEarnedFlg().isNotEmpty() && clientUI.getEarnedFlg().booleanValue()) {
											ClientUIPspAvg clientUIPspAvg = null;
											clientUIPspAvg = maClientBase.getClientUIPspAvg(clientUI.getUiId());
											if (clientUIPspAvg != null && clientUIPspAvg.getMonthlyAmt().isNotEmpty()
													&& clientUIPspAvg.getMonthlyAmt().getValue() > 0) {
												return false;
											}
										}
									}
								}
							}
						}
					}
				}
			}
		} else {
			// fs program
			return false;
		}

		return isGood && isHavingActiveAdultElderlyOrDisabledPersonInAU;
	}
	
	/**
	 * This method is used to determine whether the reevaluation type can be changed to Simplified Reporting 12.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if SIMP12
	 * @throws Exception
	 */
	public static boolean isSimplifiedReporting12(MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
					Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec,
            		InterviewWrapUpEDBCResult fsRlt)  throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		String tbaFlag;
		String capFlag;
		EDBCResult ebcObject = null;
		boolean hasABAWDClient = false;
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());

		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP) && fsRlt.getStatus().equals(ACTIVE)) {
			for (InterviewWrapUpEDBCResult rslt : rsltVec) {
				if (rslt.getProgram().equals(SNAP) && rslt.getAuId().equals(fsRlt.getAuId())) {
					
					/*
					if (isSimplifiedReporting24(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					*/
					if (isEDSAPReporting(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					
					if (isSimplifiedWithOutSixMonthsReporting12(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					edbcResultFinancial = rslt.getFinancialObject(BENEFIT, TBAFLAG);
					tbaFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? edbcResultFinancial
					                .getValue().stringValue()
					                : null;
					if (tbaFlag != null && tbaFlag.equalsIgnoreCase(YES)) {
						return false;
					}
					if (rslt.getPgmStructParId().equals(100)) {
						Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
						if(!doesAUHaveSSIAndNoCash(fsRsltMemVec, maClientBase, maECF)) {
							return false;
						}
					}
					edbcResultFinancial = rslt.getFinancialObject(STANDARDAMOUNTS, CAPELIGIBILITYSTATUS);
					capFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty()) ? edbcResultFinancial
					                .getValue().stringValue()
					                : null;
					if (!capFlag.isEmpty() && capFlag.contains("Active")) {
						return false;
					}
				}
		  }
		} else {
			//non fs program
			return false;
		}
		return true;
	}

	/**
	 * This method is used to determine whether the reevaluation type can be changed to Simplified Reporting 04 ABAWD.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if SIMP04
	 * @throws Exception
	 */
	public static boolean isSimplifiedReporting04(MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
					Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec,
            		InterviewWrapUpEDBCResult fsRlt)  throws Exception {
		EDBCResultFinancial edbcResultFinancial = null;
		String tbaFlag;
		String capFlag;
		EDBCResult ebcObject = null;
		boolean hasABAWDClient = false;
		Context ctx = null;
		ctx = maECF.getFields().getContext();
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());

		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP) && fsRlt.getStatus().equals(ACTIVE)) {
			for (InterviewWrapUpEDBCResult rslt : rsltVec) {
				if (rslt.getProgram().equals(SNAP) && rslt.getAuId().equals(fsRlt.getAuId())) {
					
					if (isEDSAPReporting(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					
					if (isSimplifiedWithOutSixMonthsReporting12(maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						return false;
					}
					
					if (hasABAWDClient(ctx,maECF, maClientDelta, maClientBase, ebcObjectVector, rsltVec,fsRlt)) {
						hasABAWDClient = true;
					}
					
					if (rslt.getPgmStructParId().equals(100)) {
						Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
						if(!doesAUHaveSSIAndNoCash(fsRsltMemVec, maClientBase, maECF)) {
							return false;
						}
					}				
				}
		  }
		} else {
			//non fs program
			return false;
		}
		return hasABAWDClient;
	}
	
	/**
	 * @param ctx
	 * @param hhId
	 * @return
	 * @throws Exception
	 */
	public static boolean hasABAWDClient(Context ctx, MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
			Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec, InterviewWrapUpEDBCResult fsRlt) throws Exception {
		boolean hasABAWDClient = false;
		Vector<EDBCResultAUMember> auMembList = fsRlt.getAuMembResults();
		for(EDBCResultAUMember auMemb : auMembList) {
			IntegerData clientId = auMemb.getClientId();
			MAClient mAClient = maECF.getMAClient(clientId.intValue());
			Vector<ClientGeneralWorkRequirementStatus> gwrStatusList = mAClient.getClientGeneralWorkRequirementStatus(clientId);
			for(ClientGeneralWorkRequirementStatus gwrStatus : gwrStatusList) {
				if(gwrStatus.getAuId().equals(fsRlt.getAuId().intValue()) && (gwrStatus.getWorkExemptFlag().isNotEmpty() && gwrStatus.getWorkExemptFlag().isFalse())) {	
					Vector<ClientWorkRequirementStatus> wpStatusVect = mAClient.getClientWorkRequirementStatus(clientId);
					for(ClientWorkRequirementStatus camWprStat : wpStatusVect) {
			               if (camWprStat.getAuId().equals(fsRlt.getAuId().intValue())) {
			                     if (camWprStat.getWorkExemptFlag().isNotEmpty() && camWprStat.getWorkExemptFlag().isFalse() && camWprStat.getWorkExemptReason().isNotEmpty() 
			                  		   && camWprStat.getWorkExemptReason().equals("FN06AB") ) {
			                  	   hasABAWDClient = true;
			                     } else {
			                    	 return false;
			                     }
			               }
					}
				} else {
					return false;
                }
			}
		}
		return hasABAWDClient;
		
	}
	
	/**
	 * @param maClient
	 * @param clientId
	 * @return
	 * @throws Exception
	 */
	public static boolean isAPPresentInCurrentHH(MAClient maClient, IntegerData clientId) throws Exception {
		HHMember hhMember = maClient.getHHMember();
		Vector<HHAllMembers> clientHHMemberVec = maClient.getHHAllMembers(hhMember.getHhId());
		for (HHAllMembers hhMemb : clientHHMemberVec) {
			if (hhMemb.getClientId().equals(clientId) && hhMemb.getHhMemberStatusCode().equals(HH_PRESENT)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * @param program
	 * @param root
	 * @return
	 */
	public static Vector parseXML(String program, Element root) throws Exception {
		Vector setpVector = new Vector();
		if (root != null) {
			Element pgmElement = (Element) root.getElementsByTagName(program).item(0);
			if (pgmElement != null) {
				NodeList nodeList = pgmElement.getElementsByTagName("step");
				if (nodeList != null && nodeList.getLength() > 0) {
					for (int i = 0; i < nodeList.getLength(); i++) {
						Element element = (Element) nodeList.item(i);
						StringData workflowStepd = new StringData(element.getFirstChild().getNodeValue());
						setpVector.add(workflowStepd);
					}
				}
			}
		}
		return setpVector;
	}

	/**
	 * @param ctx
	 * @param stepName
	 * @return
	 * @throws SQLException
	 */
	public static Workflow getWorkflow(Context ctx, String stepName) throws SQLException {
		Workflow workflow = null;
		Vector workflowset = null;
		StringData stepNameWrapper = null;
		SimpleStatement stmt = new SimpleStatement(SQLActions.SELECT, Workflow.class);
		String alias = stmt.getTableAlias();
		WhereClause whereClause = stmt.getWhereClause();
		ClassMap classMap = stmt.getClassMap();
		FieldMap field = classMap.getFieldMap("stepName");
		stepNameWrapper = new StringData(stepName);
		whereClause.addClause(new EqualityClause(ClauseKeywords.EQ, new FieldMapAlias(field, alias), stepNameWrapper));
		workflowset = mapper.fetchMany(ctx, stmt);
		if (workflowset != null && workflowset.size() > 0) {
			workflow = (Workflow) workflowset.elementAt(0);
		}
		return workflow;
	}

	/**
	 * @param hhflag
	 * @param dataId
	 * @param statusChar
	 * @param statusChar1
	 * @param stepName
	 * @param workflowStates
	 * @return
	 * @throws SAXException
	 * @throws IOException
	 */
	public static boolean isStateOK(boolean hhflag, int dataId, char statusChar, char statusChar1, String stepName, String workflowStates) throws SAXException, IOException {
		boolean returnFlag = false;
		String workflowStep[];
		IntegerData clientId = new IntegerData(dataId);
		int workflowInfoIndex = workflowStates.indexOf("</workflowinfo>");
		int dataIdIndex = workflowStates.indexOf("DataId=");
		int hhId = workflowStates.indexOf("Master=");
		String[] householdState = workflowStates.substring(hhId, dataIdIndex).split("Master=");
		String workflowString = workflowStates.substring(dataIdIndex, workflowInfoIndex);
		String[] dataIdArray = workflowString.split("DataId=");
		String[] clientState;
		char[] states;
		char[] household = householdState[1].trim().toCharArray();
		String workflowStateString = workflowStates.substring(workflowInfoIndex + "</workflowinfo>".length());
		InputStream inputStream = new ByteArrayInputStream(workflowStateString.getBytes());
		Document xml = XMLDocHelper.getInstance().getDocBuilder().parse(inputStream);
		NodeList nodeList;
		Element element;
		if (xml != null) {
			nodeList = ((Element) xml.getElementsByTagName("masterworkflow").item(0)).getElementsByTagName("step");
			workflowStep = new String[nodeList.getLength()];
			for (int i = 0; i < nodeList.getLength(); i++) {
				element = (Element) nodeList.item(i);
				workflowStep[i] = element.getAttribute("name");
			}
			if ((hhflag) && household.length == workflowStep.length) {
				for (int tCnt = 0; tCnt < workflowStep.length; tCnt++) {
					if (workflowStep[tCnt].equals(stepName)
					        && ((household[tCnt] == statusChar) || (household[tCnt] == statusChar1))) {
						returnFlag = true;
						break;
					}
				}
			}
			for (int iCnt = 1; iCnt < dataIdArray.length; iCnt++) {
				clientState = dataIdArray[iCnt].split(":State=");
				if (clientState[0].equals(clientId.toString())) {
					states = clientState[1].trim().toCharArray();
					if (states.length == workflowStep.length) {
						for (int tCnt = 0; tCnt < workflowStep.length; tCnt++) {
							if (workflowStep[tCnt].equals(stepName)
							        && ((states[tCnt] == statusChar) || (states[tCnt] == statusChar1))) {
								returnFlag = true;
								break;
							}
						}
					}
				}
			}
		}
		return returnFlag;
	}

	/**
	 * This method is used to set reevaluation data on result.
	 * @param maECF
	 * @param maECFRule
	 * @param ebcObjectVector
	 * @param rsltBaseVec
	 * @param batchProcessFlg
	 * @param clientId
	 * @throws Exception
	 */
	public static boolean isEarlyFSReeval(Context ctx, MAECFHousehold maECF, InterviewWrapUpEDBCResult interViewResult, boolean batch, int clientId) throws Exception {
		BaseAUStatus auStatus = null;
		int reevalVerDataElementId = 140;
		int ssnChangeVerDataId = 16;
		DateData releaseDate = null;
		DateData tmpCycPmtDte = null;
		MAClient maClient = maECF.getMAClient(clientId);
		DateData nxtCycPmtDte = null;
		DateData nxtNextCycPmtDte = null;
		Parameter parameter = paramcache.getParameter(maECF.getFields().getContext(), RELEASE_DELAYED_BY_REEVAL_FLAG);
		String relDelayFlag = parameter.getParameterValue();

		auStatus = maClient.getAssistUnitStatus(interViewResult.getAuId());

		if (!relDelayFlag.equalsIgnoreCase("Y")) {
			return false;
		}

		if (interViewResult.getProgram().equals(SNAP) && auStatus.getStatus().equals(AU_ACTIVE) && (interViewResult.getStatus().equals(ACTIVE))
				&& (isReevaluationVerificationSelected(maECF, maClient, interViewResult.getAuId(), reevalVerDataElementId, true, false))) {
			String tbaFlg = getFinancialObjectStringValue(interViewResult, BENEFIT, TBAFLAG);
			if (tbaFlg.equalsIgnoreCase("Y")) {
				return false;
			}
			BEACONAUEligReevaluation auEligReeval = (BEACONAUEligReevaluation) maClient.getFields().getField(BEACONAUEligReevaluation.class, interViewResult.getAuId());
			if ((auEligReeval.getReevalType().equals(ANNUAL_REPORTING) || (auEligReeval.getReevalType().isNotEmpty() && simpReevalTypesVec.contains(auEligReeval.getReevalType())))
					&& auEligReeval.getReevalProcess().equals(SNAP_IR_REEVAL_SUBMIT)) {
				return false;
			} else if (auEligReeval.getRevalEndDate().isNotEmpty()) {
				if (batch) {
					releaseDate = ctx.getEffectiveDate().getPreviousWorkDate();
				} else {
					releaseDate = ctx.getEffectiveDate();
				}
				nxtCycPmtDte = getNextCyclePaymentDate(maClient, interViewResult.getAuId(), false, false, releaseDate, false);
				tmpCycPmtDte = (DateData) nxtCycPmtDte.clone();
				//Add 14 days to nxtCycPmtDte and nxtNextCycPmtDte before comparing to the reevaluation end date to 
				//handle scenario where SSN changes at the same time as a reevaluation
				nxtCycPmtDte.addDays(14);  
				nxtNextCycPmtDte = getNextCyclePaymentDate(maClient, interViewResult.getAuId(), false, false, tmpCycPmtDte.addDays(1), false);
				nxtNextCycPmtDte.addDays(14);
				if (auEligReeval.getRevalEndDate().after(nxtCycPmtDte) && auEligReeval.getRevalEndDate().before(nxtNextCycPmtDte)) {
					return true;
				}
			}
		}
		return false;
	}

