	/**
	 * This method is used to determine whether the reevaluation type can be changed
	 * to Elderly Disabled SNAP Reporting.
	 *
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param interviewWrapUpEDBCResult
	 *            is an instance of InterviewWrapUpEDBCResult.
	 * @param ebcObject
	 *            is an instance of EDBCResult.
	 * @return true if AR
	 * @throws Exception
	 */
	public static boolean isEDSAPReporting(MAECFHousehold maECF, MAClient maClientDelta, MAClient maClientBase,
			Vector ebcObjectVector, Vector<InterviewWrapUpEDBCResult> rsltVec, InterviewWrapUpEDBCResult fsRlt)
			throws Exception {

		EDBCResultFinancial edbcResultFinancial = null;
		String tbaFlag;
		String capFlag;
		int clientAge = 0;
		EDBCResult ebcObject = null;
		boolean isClientDisabled = false;
		boolean isGood = false;
		boolean isHavingActiveAdultElderlyOrDisabledPersonInAU = false;
		BaseAU asstUnit = maClientDelta.getAsstUnit(fsRlt.getAuId());
		
		int buId = asstUnit.getBuId().isNotEmpty() ? asstUnit.getBuId().intValue() : 0;
		
		if (asstUnit != null && asstUnit.getProgramCode().equals(SNAP)
							 && fsRlt.getStatus().equals(ACTIVE)  && (buId >= 100 || buId <= 170)) {
			
			if (ebcObjectVector != null && ebcObjectVector.size() > 0) {
				Enumeration ebcObjectEnum = ebcObjectVector.elements();
				while (ebcObjectEnum.hasMoreElements()) {
					EDBCResult ebcObj = (EDBCResult) ebcObjectEnum.nextElement();
					if (ebcObj.getAuId().intValue() == fsRlt.getAuId().intValue()) {
						ebcObject = ebcObj;
						break;
					}
				}
			}
			
			for (InterviewWrapUpEDBCResult rslt : rsltVec) {
				if (rslt.getProgram().equals(SNAP) && rslt.getAuId().equals(fsRlt.getAuId())) {
					edbcResultFinancial = rslt.getFinancialObject(BENEFIT, TBAFLAG);
					tbaFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty())
							? edbcResultFinancial.getValue().stringValue()
							: null;
					if (tbaFlag != null && tbaFlag.equalsIgnoreCase(YES)) {
						return false;
					}
					if (rslt.getPgmStructParId().equals(100)) {
						Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();
						if (!doesAUHaveSSIAndNoCash(fsRsltMemVec, maClientBase, maECF)) {
							return false;
						}
					}
					edbcResultFinancial = rslt.getFinancialObject(STANDARDAMOUNTS, CAPELIGIBILITYSTATUS);
					capFlag = (edbcResultFinancial != null && edbcResultFinancial.getValue().isNotEmpty())
							? edbcResultFinancial.getValue().stringValue()
							: null;
					if (!capFlag.isEmpty() && capFlag.contains("Active")) {
						return false;
					}
					Vector<EDBCResultAUMember> fsRsltMemVec = rslt.getAuMembResults();

					for (EDBCResultAUMember fsRsltMemb : fsRsltMemVec) {
						//isClientDisabled = false;
						if (fsRsltMemb.getMemStatus().equals(ACTIVE) || fsRsltMemb.getMemStatus().equals(INELIGIBLE)) {
							clientAge = maClientDelta.findClientAge(fsRsltMemb.getClientId());
							/*ClientDisabilityPage clientDisability = maClientBase
									.getClientDisabilityPage(fsRsltMemb.getClientId());
							if (clientDisability != null && ebcObject != null
									&& clientDisability.getDisabledFlg().booleanValue()
									&& ebcObject.isFSFederallyCertified(maClientBase, clientDisability)) {
								isClientDisabled = true;
							}*/
							// Returns true if client is >= 60 years
							if (clientAge >= 60 ) {
								isGood = true;
								if (fsRsltMemb.getMemStatus().equals(ACTIVE)) {
									isHavingActiveAdultElderlyOrDisabledPersonInAU = true;
								}
							}
							else {
								return false;
							}

							// Return false if any member has Earned income with Countable SNAP Flag = 'Y'

							Vector earnedIncomeVect = maClientBase.getEarnedIncome(fsRsltMemb.getClientId());
							Enumeration clientEIEnum = earnedIncomeVect.elements();
							while (clientEIEnum.hasMoreElements()) {
								EarnedIncome clientEI = (EarnedIncome) clientEIEnum.nextElement();
								if (clientEI.getCountableFS().isNotEmpty() && clientEI.getCountableFS().booleanValue()) {
									EarnedIncProspectiveAvg clientEIPspAvg = null;
									clientEIPspAvg = maClientBase.getEarnedIncProspectiveAvg(clientEI.getEarnedIncomeId());
									if (clientEIPspAvg != null && clientEIPspAvg.getMonthlyProspAmount().isNotEmpty()
											&& clientEIPspAvg.getMonthlyProspAmount().getValue() > 0) {
										return false;
									}
								}
							}
							
							// Return false if any member has Other income with Earned Flag = 'Y' and Countable SNAP Flag = 'Y'

							Vector otherIncomeVect = maClientBase.getClientUI(fsRsltMemb.getClientId());
							Enumeration clientUIEnum = otherIncomeVect.elements();
							while (clientUIEnum.hasMoreElements()) {
								ClientUI clientUI = (ClientUI) clientUIEnum.nextElement();
								if (clientUI.getOtherIncStatus().isNotEmpty() 
										&&
										(clientUI.getOtherIncStatus().toString().equals(MAConstants.ACTIVE))) {
									if (clientUI.getFsCountableFlg().isNotEmpty() && clientUI.getFsCountableFlg().booleanValue()) {
										if (clientUI.getEarnedFlg().isNotEmpty() && clientUI.getEarnedFlg().booleanValue()) {
											ClientUIPspAvg clientUIPspAvg = null;
											clientUIPspAvg = maClientBase.getClientUIPspAvg(clientUI.getUiId());
											if (clientUIPspAvg != null && clientUIPspAvg.getMonthlyAmt().isNotEmpty()
													&& clientUIPspAvg.getMonthlyAmt().getValue() > 0) {
												return false;
											}
										}
									}
								}
							}

						}

					}
				}
			}
		} else {
			// fs program
			return false;
		}

		return isGood && isHavingActiveAdultElderlyOrDisabledPersonInAU;
	}

	/**
	 * This method is used to check whether the verification for an EFRC Reasons and
	 * Verification data element ID is selected.
	 *
	 * @param maECFHouseholdDelta
	 *            is a delta instance of MAECFHousehold.
	 * @param maClientDelta
	 *            is a delta instance of MAClient.
	 * @param auId
	 *            an IntegerData value.
	 * @return true if verification is selected for reevaluation
	 * @throws Exception
	 */
	public static boolean isVerificationSelectedForMembEFRC(MAECFHousehold maECFHouseholdDelta, MAClient maClientDelta,
			IntegerData auId, String... efrcReasons) throws Exception {
		boolean verSelectFlg = false;
		RequestId requestId = maECFHouseholdDelta.getRequestId();
		ClientAuMembIneligFactorEntityExists clientAUMembInEligFactor = null;
		Vector eligibilityRequestVerDataVector = maECFHouseholdDelta.getFields()
				.getFields(EligibilityRequestVerData.class, requestId.getReqId());
		Enumeration eligibilityRequestVerDataEnum = eligibilityRequestVerDataVector.elements();
		while (eligibilityRequestVerDataEnum.hasMoreElements()) {
			EligibilityRequestVerData eligibilityRequestVerData = (EligibilityRequestVerData) eligibilityRequestVerDataEnum
					.nextElement();
			com.albionintl.service.verification.entity.ViewVerification viewVerification = (ViewVerification) maECFHouseholdDelta
					.getFields().getSeqField(com.albionintl.service.verification.entity.ViewVerification.class,
							eligibilityRequestVerData.getVerId());
			if (viewVerification != null && viewVerification.getVerificationElementId() == VER_DATA_ID_78
					&& auId.intValue() == viewVerification.getAuId().intValue()) {
				Vector eligFactor = maClientDelta.ClientAuMembIneligFactorEntityExists(viewVerification.getClientId());
				if (eligFactor.size() > 0) {
					Enumeration eligEnum = eligFactor.elements();
					while (eligEnum.hasMoreElements()) {
						clientAUMembInEligFactor = (ClientAuMembIneligFactorEntityExists) eligEnum.nextElement();
						if (clientAUMembInEligFactor.getAuId().equals(auId)
								&& clientAUMembInEligFactor.getVerId().isNotEmpty()
								&& clientAUMembInEligFactor.getVerId().intValue() == viewVerification.getId()) {
							if (AssertUtil.match(clientAUMembInEligFactor.getEligFactorReason().getString(), efrcReasons)) { 
								verSelectFlg = true;
								break;
							}
						}
					}
				}
			}
			if (verSelectFlg) {
				break;
			}
		}
		return verSelectFlg;
	}
	
	/**
	 * Checks if is pending SNAP expedited.
	 *
	 * @param rsltBaseVec the rslt base vec
	 * @param intWrapRslt the int wrap rslt
	 * @param maClient    the ma client
	 * @return the interview wrap up EDBC result
	 * @throws Exception the exception
	 */
	protected static DateData getPendingFSExpeditedRevalStartDate(Vector rsltBaseVec, InterviewWrapUpEDBCResult intWrapRslt,MAClient maClient,MAECFHousehold maECFRule)
			throws Exception {
		DateData reevalStartDate = null;
		DateData benefitEffectiveDate = null;
		if (rsltBaseVec != null && rsltBaseVec.size() > 0) {
			Enumeration rsltBaseEnum = rsltBaseVec.elements();
			while (rsltBaseEnum.hasMoreElements()) {
				InterviewWrapUpEDBCResult baseRslt = (InterviewWrapUpEDBCResult) rsltBaseEnum.nextElement();
				EBCResultBase ebcResult = maECFRule.getEBCResultBase(intWrapRslt.getAuId());
				if (null != ebcResult && baseRslt.getAuId().equals(intWrapRslt.getAuId())) {
					DateData appDate = getApplicationDate(maClient, intWrapRslt.getAuId());
					if (baseRslt.getStatus().equals(AU_PENDING)) {
						reevalStartDate = ebcResult.getRevalStart();
						break;
					}
					if (baseRslt.getStatus().equals(AU_DENIED)) {
						Connection cnx = null;
						ResultSet rs = null;
						try {
							SQLMapper sqlMapper = SQLMapper.getInstance();
							StringBuilder selectQuery = new StringBuilder();
							selectQuery.append(" SELECT EBCR.BEN_EFF_DTE,EBCR.REEVAL_START_DTE ");
							selectQuery.append("  FROM EBC_RSLT EBCR ");
							selectQuery.append(" WHERE EBCR.CREATE_TS = ");
							selectQuery.append("       (SELECT MAX (EBCR1.CREATE_TS) ");
							selectQuery.append("          FROM EBC_RSLT EBCR1 ");
							selectQuery.append("         WHERE     EBCR1.AU_ID_K = EBCR.AU_ID_K ");
							selectQuery.append("               AND EBCR1.AU_ID_K = ? ");
							selectQuery.append("               AND EBCR1.AU_STAT = 'PEND' ");
							selectQuery.append("               AND EBCR1.EXPEDITED_CD_CODE_K = 'E' ");
							selectQuery.append("               AND EBCR1.STATE_IND = 'C' AND EBCR1.CREATE_TS <= ?) ");
							cnx = SQLUtil.getConnection(maClient.getFields().getContext());
							PreparedStatement ps = cnx.prepareStatement(selectQuery.toString());
							ps.setInt(1, baseRslt.getAuId().intValue());
							ps.setTimestamp(2, maClient.getFields().getContext().getAsOfDate().getSQLTimestamp());
							rs = ps.executeQuery();
							if (rs.next()) {
								if (null != rs.getDate(1)) {
									benefitEffectiveDate = new DateData(rs.getDate(1));
									DateData reevalStart = new DateData(rs.getDate(2));
									if (null != appDate && appDate.equals(benefitEffectiveDate)) {
										reevalStartDate = reevalStart;
										break;
									}
								}
							}
						} finally {
							if (null != rs) {
								rs.close();
							}
							SQLUtil.releaseConnection(cnx);
						}
					}
				}
			}
		}
		return reevalStartDate;
	}	
	
